window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q06"]=window.__LIBQ["pham-nhan-tu-tien"]["q06"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q06"]["cotTruyen"]=[{"chuong":793,"tieuDe":"Trụy Ma Chi Địa","tomTat":"Đông Dụ quốc là quốc gia nhỏ trung lập ở Thiên Nam, không thuộc bốn đại thế lực, tài nguyên tu luyện phong phú. Phía bắc Đông Dụ có Xương Châu, trung tâm là Vạn Lĩnh Sơn Mạch bị chướng khí kịch độc bao phủ quanh năm, mười năm tan một lần. Trong đó có Trụy Ma Cốc — bí cốc tồn tại từ thời man hoang, được mệnh danh Thiên Nam đệ nhất hung địa, chứa bảo vật thượng cổ. Nửa năm trước, Quỷ Linh Môn truyền tin tìm ra phương pháp nhập Trụy Ma Cốc, muốn độc chiếm nhưng bị các tông phái bức bách, phải phát hành Trụy Ma Lệnh bài thu linh thạch cho vài trăm tu sĩ cùng vào. Nhóm ba tu sĩ (nho sinh cẩm bào, nam tu áo lam, nữ tu cung trang) bỏ mười vạn linh thạch mua ba lệnh bài, kỳ vọng tìm thượng cổ linh đan để ngưng kết Nguyên Anh. Tu sĩ đông đảo từ khắp nơi đổ về Xương Châu, kể cả Mộ Lan pháp sĩ cũng tham gia, tông phái bản địa hoảng sợ cấm đệ tử ra ngoài."},{"chuong":794,"tieuDe":"Hàn Lập Trở Về","tomTat":"Tại thành Diệp Hoa ở Xương Châu, Tử Linh Tiên Tử, Mai Ngưng và nữ tử họ Tống chờ đợi Hàn Lập tại khách điếm Hồng Phúc để cùng bàn kế hoạch nhập Trụy Ma Cốc lấy Linh Chúc Quả. Nữ tử họ Tống cho biết uy danh Hàn Lập hiện tại ở Thiên Nam chỉ thấp hơn tam đại tu sĩ, có thể giết tu sĩ Nguyên Anh Trung Kỳ. Mai Ngưng cương quyết không vào cốc vì chỉ là Kết Đan Sơ Kỳ và đã có linh dược trợ kết đan, trong lòng phiền muộn vì trước đây do dự bỏ lỡ cơ hội với Hàn Lập. Quỷ Linh Môn đột nhiên thừa nhận công khai tin tức về Trụy Ma Cốc, tạo thế cạnh tranh. Hàn Lập bất ngờ xuất hiện sau hơn hai năm đi cực tây, tinh thần khí chất biến hóa trầm ổn thâm sâu khó lường, mang theo ống trúc vàng bí ẩn dài khoảng một trượng sau lưng. Hàn Lập xác nhận giữ lời hứa cùng Tử Linh nhập Trụy Ma Cốc, chỉ có hai người quyết đi."},{"chuong":795,"tieuDe":"Đại Diễn Thần Quân","tomTat":"Hàn Lập gặp Tử Linh để xác nhận thông tin Linh Chúc Quả qua ngọc giản của trưởng lão Quỷ Linh Môn năm xưa, khẳng định linh dược có thật nhưng vị trí hơi mập mờ. Hai người thống nhất kế hoạch nhập Trụy Ma Cốc: luyện chế Tạo Hóa Đan ngay trong cốc vì Linh Chúc Quả giảm hiệu lực nếu mang ra ngoài, Tử Linh đã chuẩn bị hơn mười mấy phần phụ liệu. Hàn Lập dùng truyền âm thuật bàn kế hoạch bí mật riêng với Tử Linh rồi vội vã rời đi. Nguyên nhân là trong đầu hắn có tiếng Đại Diễn Thần Quân — linh hồn cổ đại trú trong ống trúc dưới dạng khôi lỗi, là người khai sáng Thiên Trúc Giáo năm xưa, đã sống hơn ngàn năm. Lão từng dùng Thất Tình Quyết nhằm khống chế chủ nguyên thần Hàn Lập nhưng thất bại vì đệ nhị nguyên anh, tuy nhiên đã liên kết hỉ nộ ái ố của Hàn Lập với đệ nhị nguyên anh khiến tâm tư hắn bị xao động. Hàn Lập không tiêu diệt lão vì cần ba tầng cuối Đại Diễn Quyết và phương pháp luyện chế khôi lỗi đại uy lực, hơn nữa sưu hồn thuật vô hiệu trước thần thức cường đại của lão. Tinh hồn Đại Diễn Thần Quân nhiều nhất còn hơn mười năm rồi tan."},{"chuong":796,"tieuDe":"Ký Thần Thuật","tomTat":"Hàn Lập và Đại Diễn Thần Quân tiếp tục đối thoại, lão kể lại toàn bộ quá khứ lừng lẫy của mình. Năm xưa lão tự phụ tài trí, phân tâm sáng tạo Đại Diễn Quyết cường hóa thần thức, sáng lập Thiên Trúc Giáo, nghiên cứu Khôi Lỗi Thuật thất truyền, đồng thời tu đến Nguyên Anh Hậu Kỳ, đánh bại hai tu sĩ Chánh Ma đệ nhất Thiên Nam và chiếm Cực Tây lập giáo. Tuy nhiên do phân tâm quá nhiều, thọ nguyên cạn kiệt mà không thể đột phá Hóa Thần Kỳ. Không cam chờ chết, lão dùng hai trăm năm cuối đời sáng lập Ký Thần Thuật lấy Đại Diễn Quyết làm trụ cột nhằm bảo trì thần trí, nhưng chỉ hoàn thành một nửa, bất đắc dĩ sử dụng dẫn đến mất tu vi, thần thức nhập Khôi Lỗi đặc chế và bị nhốt vạn năm. Hàn Lập tìm được lão trong mật thất, trải qua xung đột khi lão dùng Thất Tình Quyết tập kích và Hàn Lập phản kích bằng Đồng Hóa Thuật tạo thế giằng co, cuối cùng cho lão mượn Dưỡng Hồn Mộc đổi lấy ba tầng sau Đại Diễn Quyết và Khôi Lỗi Thuật. Lão muốn thu Hàn Lập làm đệ tử truyền tuyệt học nhưng bị từ chối vì Hàn Lập không tu công pháp của lão. Lão cũng giải thích ba tầng sau Đại Diễn Quyết không truyền đệ tử vì không ai đạt Nguyên Anh, truyền chỉ chuốc họa sát thân."},{"chuong":797,"tieuDe":"Thượng Cổ Ma Giới","tomTat":"Hàn Lập hỏi Đại Diễn Thần Quân lần nữa về phong hồn chú, Thần Quân khẳng định có năng lực nhưng thọ nguyên có hạn không đủ thời gian phá giải, khiến Hàn Lập quyết chí phải đi Trụy Ma Cốc. Thần Quân cảnh báo trong cốc có thượng cổ cấm chế và khe hở không gian có thể thông tới Thượng Cổ Ma Giới — nơi sinh sống của Cổ ma, loại sinh vật thần thông quỷ dị từng xâm lăng nhân giới thời thượng cổ. Cuộc đại chiến thượng cổ tu sĩ và cổ ma khiến nguyên khí nhân giới tổn thương trầm trọng, nhiều công pháp và linh thú diệt tuyệt. Thần Quân tiết lộ ma công của tu sĩ ma đạo hiện tại vốn bắt nguồn từ đường lối tu luyện của Cổ ma, tu tới cùng phi thăng sẽ đi Ma Giới thay vì Linh giới. Thần Quân giao cho Hàn Lập ngọc giản chứa khẩu quyết tầng thứ năm Đại Diễn Quyết cùng hai phương pháp luyện chế và kết đan Khôi Lỗi, rồi tuyên bố cần dưỡng tinh thần nghiên cứu Khôi Lỗi Thuật. Hàn Lập ra ngoài thành kiểm tra sinh vật bí ẩn tóc xanh mắt bích lục đã bồi dưỡng được thần thức đơn giản, hài lòng. Cuối chương Hàn Lập lấy ra lệnh bài vàng khắc ba chữ Thiên Cực Môn, mắt nheo phát tinh quang suy tư."},{"chuong":798,"tieuDe":"Trần Xảo Thiến","tomTat":"Hàn Lập thu hồi Thiên tuyệt ma thi rồi lên đường tới Vạn Linh Sơn, nhận thấy đệ tử Thiên Cực Môn chưa có mặt nên lệnh bài không dùng được, tự tin Nam Lũng Hầu sẽ chủ động tìm đến nhờ Lưỡng nghi hoàn. Hắn suy đoán Bắc Cực hoang nguyên là thông đạo bên trong Trụy Ma Cốc chứ không phải lối vào, đồng thời dự định tìm chỗ tạm trú gần Vạn Linh Sơn để luyện chế Khôi Lỗi cấp Kết Đan kỳ, vẫn còn thiếu tài liệu Huyết phượng mộc cho Khôi Lỗi thượng cổ cấp Nguyên Anh. Trên đường phát hiện trận đấu pháp, hai tu sĩ Ngự Linh Tông khu sử cự đại phi nga ép ba tu sĩ Hoàng Phong Cốc và Hóa Đao Ổ vào thế hạ phong. Hàn Lập nhận ra tiêu ký hình chiếc lá vàng của Hoàng Phong Cốc trên cổ tay nho sinh, dừng lại can thiệp buộc hai tu sĩ Ngự Linh Tông thu quân rút lui. Nho sinh cầm đầu tự xưng Trần Xảo Thiên — đệ tử Hoàng Phong Cốc, anh trai Trần Xảo Thiến. Trần Xảo Thiên cho biết Trần Xảo Thiến không phải Kết Đan tu sĩ, đã mắc quái bệnh qua đời hơn trăm năm trước. Hàn Lập nghe tin, trong lòng bi ai nhớ lại hình ảnh Trần Xảo Thiến xinh đẹp và lần cuối nàng thổ lộ tiếng lòng khi cùng du sơn."},{"chuong":799,"tieuDe":"Khôi Lỗi Cấp Bậc Kết Đan Kỳ","tomTat":"Trần Xảo Thiên kể cho Hàn Lập rằng tiểu muội Trần Xảo Thiến năm đó bị hủy hôn vì bên kia ngả phe ma đạo, sau đó trầm mặc ít nói, độc thân đến cuối đời. Hàn Lập xúc động nhưng đè nén nỗi thương nhớ, cảnh báo ba người Trần Xảo Thiên cẩn thận vì Trụy Ma Cốc chánh ma tề tụ rồi hóa thanh hồng bay đi. Ba người bàn luận về lai lịch Hàn Lập: xuất thân Hoàng Phong Cốc, từng phá Mộ Lan thánh cầm, trảm ma tu trưởng lão, địa vị chỉ dưới Thiên Nam tam đại tu sĩ. Trần Xảo Thiên tiết lộ vừa luyện chế xong pháp bảo tổ truyền Kim Thư ngân bút từ pháp khí phỏng chế, có thể ngăn độc phấn độc nga. Hàn Lập bay đến Vạn Linh Sơn, dùng thần thức ngang Nguyên Anh Hậu Kỳ quét phương viên hơn trăm dặm, hỏi đường đến phường thị mua tài liệu luyện khí, rồi khai mở động phủ tạm trong tiểu sơn, bố trí pháp trận che mắt. Hắn thả Ngân Nguyệt tu luyện, Thiên tuyệt ma thi nhập thổ, rồi nghiên cứu ngọc giản Đại diễn Thần Quân ba ngày ba đêm, nắm rõ hai loại Khôi Lỗi Kết Đan Kỳ (hình cự quy phòng ngự phun lôi hỏa cầu và hình hổ yêu cận chiến nhanh nhẹn), quyết định luyện chế cả hai loại và bắt đầu luyện chế."},{"chuong":800,"tieuDe":"Tìm Kiếm","tomTat":"Hàn Lập bế quan mấy tháng trong mật thất, luyện chế thành hơn ba mươi khối Khôi Lỗi gồm Quy hình và Hổ yêu nhờ đại lượng yêu hồn cấp cao lấy từ Loạn Tinh Hải. Đại diễn Thần Quân trong Động phúc thiên đang nghiên cứu Khôi Lỗi Thuật, thấy yêu hồn cấp cao liên tục được lấy ra liền kinh ngạc gọi Hàn Lập là Tiểu quái vật. Sau khi xuất quan, Ngân Nguyệt bẩm báo tình hình: chướng khí sơn mạch dần mỏng, tu sĩ cao giai đổ về Diệp Hoa Thành kéo bè kết cánh chuẩn bị vào Trụy Ma Cốc. Hàn Lập thu Thiên tuyệt ma thi, thu Ngân Nguyệt vào tay áo rồi rời động phủ. Hắn buông thần thức quét phương viên trăm dặm tìm một người cụ thể nhưng không thấy, bèn bay đến phường thị gần Vạn Linh Sơn. Tại đây phát hiện Bạch Thư Quân đang cùng nữ tu họ Viên mua Kim linh tử, liền ném Thiên cực lệnh xác nhận thân phận, yêu cầu dẫn đường gặp Lỗ Vệ Anh. Bạch Thư Quân hoảng sợ cung kính tuân lệnh, dẫn Hàn Lập cùng nữ tử họ Lỗ bay vào sâu Vạn Linh Sơn đến chỗ ẩn cư của Lỗ Vệ Anh. Lỗ Vệ Anh vui mừng mở thạch môn đón tiếp, đuổi hết đệ tử ra ngoài để nói chuyện riêng với Hàn Lập."},{"chuong":801,"tieuDe":"Cốc Hiện","tomTat":"Hàn Lập đến động phủ Lỗ trưởng lão Thiên Cực Môn tại Vạn Lĩnh Sơn Mạch gặp Nam Lũng Hầu và Lỗ Vệ Anh — hai người đã chờ hơn một tháng. Cả hai bán tín bán nghi trước danh tiếng Hàn Lập giết tu sĩ Nguyên Anh Trung Kỳ đỉnh giai Ma Tông Tần quốc. Ba người đàm phán phân chia bảo vật trong Trụy Ma Cốc, thống nhất chia đều ba phần, riêng nội đan Hỏa Thiềm cổ thú thuộc về Hàn Lập. Nam Lũng Hầu tiết lộ chính bọn họ đã cố ý truyền phương pháp nhập cốc ra ngoài nhằm phá kế hoạch độc chiếm của Quỷ Linh Môn, đồng thời tuyên bố sau khi ra cốc sẽ tính sổ vụ Lưỡng Nghi Hoàn bị đoạt. Bảy ngày sau, chướng khí Vạn Lĩnh Sơn Mạch tan hết, tu sĩ ùn ùn bay về phía Trụy Ma Cốc — hung địa diện tích mười vạn dặm, lối vào duy nhất tràn ngập khe không gian nguy hiểm di chuyển bất quy luật, từng giết cả lão quái Nguyên Anh Kỳ."},{"chuong":802,"tieuDe":"Cốc Ngoại Quần Tu","tomTat":"Một thế lực bí mật đóng trú trong tiểu cốc ẩn giấu gần Trụy Ma Cốc, lão giả ngồi giữa pháp trận ngũ giác cùng năm tu sĩ áo lục, phái nữ tử áo lục (Hạm sư điệt) cưỡi linh cầm do thám Quỷ Linh Môn, quyết định chờ đối phương động thân mới hành động. Đạo sĩ áo bào tro sở hữu cặp thượng cổ khôi lỗi sức mạnh ngang Nguyên Anh, tự đắc bay hướng Trụy Ma Cốc. Lệnh Hồ lão tổ cùng trưởng lão Yểm Nguyệt Tông (sư tỷ Nam Cung Uyển) và một lão giả lạ mặt song song phi hành đến nơi. Hàn Lập đến phụ cận lối vào, cảm nhận hơn ngàn tu sĩ tụ tập, thử dùng thần thức dò cốc khẩu nhưng chỉ xâm nhập được hơn trăm trượng thì bị cấm chế ngăn cản. Hơn mười pháp sĩ Mộ Lan đến bằng phi xa hình nón do Trọng Thần Sư và Nhạc thượng sư dẫn đầu, gây chấn động tu sĩ Thiên Nam vì thâm cừu chiến tranh biên giới. Quỷ Linh Môn hơn trăm tu sĩ áo đen xuất hiện, ba tu sĩ Nguyên Anh dẫn đầu gồm Vương Thiên Cổ, tu sĩ hắc bào rộng sắc mặt âm lệ và lão giả mắt chim ưng Nguyên Anh Trung Kỳ. Hàn Lập nhận ra Vương Thiền tay chân dường bình thường và Yến Như Yên thần sắc tiều tụy, đặc biệt chú ý lão giả Nguyên Anh Trung Kỳ."},{"chuong":803,"tieuDe":"Đan Hướng Truyền Tống Trận","tomTat":"Hàn Lập quan sát Quỷ Linh Môn thiết trí pháp trận lớn tại cốc khẩu Trụy Ma Cốc, nhận thấy Toái Hồn Chân Nhân vắng mặt và có một lão giả lạ là tu sĩ Nguyên Anh thứ ba của Quỷ Linh Môn. Ngụy Vô Nhai — đại trưởng lão Cửu Quốc Minh — bất ngờ giáng lâm, hợp tác cùng Quỷ Linh Môn khiến các tu sĩ chấn động. Ngụy Vô Nhai lạnh lùng cảnh cáo trung niên tu sĩ Quỷ Linh Môn rằng nếu trong cốc không có kiện đồ vật đã hẹn ước sẽ trở mặt. Hàn Lập tự nhận định nếu xung đột với cả Ngụy Vô Nhai, hắn chỉ có cách chạy trối chết. Sau hơn nửa ngày, pháp trận hoàn thành — Vương Thiên Cổ lấy ra linh thạch bậc cao kim hoàng sắc cực hiếm đặt vào trung tâm. Trung niên tu sĩ sắc mặt âm lệ tự xưng Vương Thiên Thắng, tông chủ Quỷ Linh Môn, tuyên bố pháp trận là Đan Hướng Truyền Tống Trận đặc chế — đơn hướng truyền tống vào Trụy Ma Cốc, vị trí đích không cố định, có rủi ro nhỏ rơi vào khe hở không gian, chỉ người có Trụy ma lệnh mới được dùng, Quỷ Linh Môn sẽ vào cuối cùng rồi hủy trận. Vương Thiên Thắng cũng giải đáp rằng bên trong Trụy Ma Cốc có thượng cổ Truyền Tống Trận hoàn hảo nên xuất cốc rất đơn giản."},{"chuong":804,"tieuDe":"Nhập Cốc","tomTat":"Vương Thiên Thắng chỉ huy Truyền Tống Trận tại cốc khẩu Trụy Ma Cốc, cho Vương Thiền cùng Yến Như Yên và lão giả Nguyên Anh Trung Kỳ đi trước thị phạm. Trọng Thần Sư dẫn hơn mười pháp sĩ Mộ Lan vào trận, trước khi đi cảnh cáo Ngụy Vô Nhai rằng trong cốc gặp nhau thì coi là thiên ý. Hơn 300 tu sĩ lần lượt truyền tống, linh thạch tiêu hao 7-8 phần. Đông Môn Đồ dẫn Ngũ Hành Linh Anh (5 Nguyên Anh Sơ Kỳ) tới trận, khiến đệ nhị Nguyên Anh trên người Hàn Lập phản ứng kịch liệt suýt xuất khiếu, Hàn Lập dùng thần thức trấn trụ. Đông Môn Đồ phát hiện linh anh trên người Hàn Lập, liếc với ánh mắt bất thiện rồi truyền tống đi. Ngụy Vô Nhai chủ động khuyên Hàn Lập rút lui nhưng bị từ chối. Vương Thiên Thắng nhận ra danh tính Hàn Lập, hồi tưởng quá khứ Vương Thiền để mất hắn, nay đối phương đã thành Nguyên Anh chỉ thấp hơn tam đại tu sĩ, trong lòng kiêng kỵ. Hàn Lập được truyền tống tới sườn núi đổ nát trong cốc, xoay đầu nhìn thấy điều gì đó ngạc nhiên."},{"chuong":805,"tieuDe":"Sát Khí Trong Cốc","tomTat":"Hàn Lập được truyền tống thành công vào ngoại cốc Trụy Ma Cốc, phát hiện hố tròn trăm trượng do thần thông thượng cổ tạo thành với thạch bích dung nham đỏ sậm. Hắn dùng Phệ Kim Trùng thử nghiệm cấm chế thiên không, xác nhận bay quá năm sáu mươi trượng sẽ bị sét đánh, nhưng Phệ Kim Trùng thân thể kiên cố chịu được. Khai thần thức toàn bộ kèm Minh Thanh Linh Nhãn bay về phía tây, phát hiện khe hở không gian hữu hình hình trăng non và tránh được. Cách hắn hơn trăm dặm, một lão giả mập mạp phát hiện khe hở nhỏ nhưng bị khe hở vô hình khác bất ngờ phân thây chết tại chỗ. Hàn Lập xác lập thứ tự ưu tiên: hội hợp Nam Lũng Hầu diệt hỏa thiềm thú lấy nội đan cho Nam Cung Uyển trước, sau đó mới tìm linh chúc quả. Ba tu sĩ cẩm bào bị truyền tống vào cấm chế bảy sắc thái hà trong đống loạn thạch, chửi mắng Quỷ Linh Môn rồi hợp lực dùng thạch ấn tứ phương và phi kiếm phá cấm chế."},{"chuong":806,"tieuDe":"Các Hành Kỳ Sự","tomTat":"Ba tu sĩ dùng thạch ấn và phi kiếm tấn công cấm chế bảy màu trong Trụy Ma Cốc, bị hỏa vân kích phát thiêu chết cả ba. Hàn Lập toàn lực thi triển Minh Thanh Linh Nhãn, xác nhận có thể phát hiện khe hở không gian ẩn hình mà thần thức không phát hiện được, cho rằng không phụ công dùng Minh Thanh Linh Thủy thanh tẩy mắt. Hắn mang áo choàng thanh quang che giấu lam quang dị dạng trong mắt, phỏng đoán chỉ Trọng Thần Sư và Ngụy Vô Nhai mới nhìn thấu. Tử Linh dịch dung giả trang thành nữ tử bình thường, tìm dấu hiệu trưởng lão Quỷ Linh Môn lưu lại liên quan đến linh chúc quả, phát hiện ba lão giả Nguyên Anh bay qua và ẩn thân kịp thời, nhận ra lão giả tóc bạc họ Trình là sư huynh Vương Thiên Cổ tại Lạc Vân Tông. Sáu đệ tử Quỷ Linh Môn dưới chỉ huy Chung trưởng lão tìm được đại thụ hình người khổng lồ chứa âm khí đen, xác nhận đúng mục tiêu. Hàn Lập không tìm bảo vật, chọn đường an toàn tránh cấm chế, đã đến gần điểm hẹn với Nam Lũng Hầu."},{"chuong":807,"tieuDe":"Đường Vào Nội Cốc","tomTat":"Nam Lũng Hầu và Lỗ Vệ Anh chờ đợi trên đỉnh tiểu sơn phía tây Trụy Ma Cốc, lo lắng vì Hàn Lập chưa đến. Hai người bàn bạc về hỏa thiềm thú theo di thư của Thương Khôn Thượng Nhân, Lỗ Vệ Anh phán đoán con thú có thể là hỏa thiềm biến dị. Hàn Lập bay tới với áo choàng xanh chặn thần thức, gây kinh ngạc cho hai người. Ba người thương lượng kế sách diệt hỏa thiềm thú rồi lên đường bay về phía nội cốc. Nam Lũng Hầu dùng cảm ứng linh cảnh báo khe hở không gian, nhưng Hàn Lập phát hiện bằng linh nhãn loại khe hở ẩn hình mà chuông không phát hiện được, song giữ bí mật. Sau hơn nửa ngày bay, ba người đến trước dãy núi nhỏ ngoài nội cốc, phía sau là mảnh huyết quang cấm chế che kín bầu trời. Nam Lũng Hầu dùng ngọc bội trắng do Thương Khôn Thượng Nhân để lại phá tan huyễn thuật che cửa thông đạo bí mật, lộ ra cảnh tượng xa lạ trước mặt ba người."},{"chuong":808,"tieuDe":"Sương Mù","tomTat":"Hàn Lập, Nam Lũng Hầu và Lỗ Vệ Anh đến trước thông đạo dẫn vào nội cốc Trụy Ma Cốc, phát hiện giữa hai sườn núi có dải sương mù xám rộng hơn trăm trượng không được di thư Thương Khôn Thượng Nhân đề cập. Nam Lũng Hầu thả linh điểu vàng kim bay vào thăm dò, qua thần cảm xác nhận linh điểu bị cự mãng phun yêu vụ nuốt chết, ba người kết luận đây là thượng cổ yêu thú đến sau khi di thư được viết. Trước khi động thủ, Hàn Lập dùng linh nhãn phát hiện tu sĩ Kết Đan tên Hoàng Thiên Minh dùng thượng cổ ẩn hình phù ẩn nặc theo dõi, liền bắn kiếm khí ép hiện hình. Lỗ Vệ Anh quyết đoán dùng Cự Phong Kỳ hóa cơn lốc băm nát Hoàng Thiên Minh diệt khẩu, thu túi trữ vật và ẩn hình phù. Sau đó Hàn Lập dùng trận kỳ trong suốt bày đại trận che giấu động tĩnh tại hai tòa sơn phong, rồi cả ba chuẩn bị khai chiến với cự mãng — Lỗ Vệ Anh cầm Cự Phong Kỳ sẵn sàng thổi tan yêu vụ, Nam Lũng Hầu kích hoạt kim sắc tiểu kiếm hóa cự kiếm dài năm sáu trượng."},{"chuong":809,"tieuDe":"Cự Mãng Cổ Thú","tomTat":"Ba người Hàn Lập, Nam Lũng Hầu và Lỗ Vệ Anh liên thủ tấn công cự mãng ẩn trong biển sương mù. Lỗ Vệ Anh dùng pháp kỳ tạo phong long kích nổ quét sạch sương, lộ ra thân hình cự mãng khổng lồ đen thui như tòa núi nhỏ. Kim sắc cự kiếm và Kinh Long chung cùng tấn công nhưng bị lục sắc linh quang hộ thể chặn lại, cự mãng kéo dài thân nhanh như chớp nuốt gọn cả hai pháp bảo vào bụng. Nam Lũng Hầu mất bổn mạng pháp bảo bồi luyện trăm năm, lo lắng vì tâm thần tương liên, rút chiếc nhẫn xanh biếc bí ẩn làm vũ khí thay thế. Hàn Lập thả sáu con Khôi Lỗi thú lần đầu ra trận thực chiến, hồng ngưu bắn xích mang vào họng mãng gây đau nhưng bạch lang không phá nổi lân phiến. Cự mãng hít mạnh tạo hấp lực khổng lồ hút cả ba tu sĩ, Hàn Lập dùng thanh quang tăng trọng chống lại. Cự mãng phun hắc khí lộ chân tướng Tam Thủ Ô Xà với hai đầu rắn phụ, hai đầu phụ nuốt hai bạch lang Khôi Lỗi, Hàn Lập lạnh lùng ra lệnh kích nổ hai con Khôi Lỗi trong miệng xà."},{"chuong":810,"tieuDe":"Chém Giết Mãng Thú","tomTat":"Ba người Hàn Lập, Nam Lũng Hầu và Lỗ Vệ Anh hiệp lực tiêu diệt tam thủ cự mãng. Hàn Lập kích nổ hai bạch lang Khôi Lỗi trong miệng rắn gây thương tích, Nam Lũng Hầu dùng nhẫn xanh biếc ghìm chặt vị trí thất thốn dưới đầu rắn chính, Lỗ Vệ Anh dùng bạch hỏa bao vây và hỏa liên cuốn giữ. Hàn Lập tung cổ bảo Thiên Trọng Phong hóa hắc sắc sơn phong nện xuống nghiền nát phần lớn thân cự mãng, Lỗ Vệ Anh chém rơi đầu rắn cuối cùng kết liễu. Lỗ Vệ Anh lấy ba viên thanh sắc nội đan từ ba đầu rắn chia mỗi người một viên. Qua thảo luận, Nam Lũng Hầu chỉ ra cự mãng thiếu nhục sí và ba đầu không có thần thông bất đồng thuộc tính nên không phải tam thủ ô xà chính thức, có lẽ là xà thú biến dị. Ba người bay thêm hai mươi dặm tới thạch bích vàng nhạt có sơn động rộng bảy tám trượng dẫn vào nội cốc, Nam Lũng Hầu cho biết bên trong có bắc cực nguyên quang dài hơn mười dặm cần lưỡng nghi hoàn mới qua được, Lỗ Vệ Anh thử dùng phi đao pháp bảo dạng đoản nhận tấn công thạch bích tìm đường khác."},{"chuong":811,"tieuDe":"Cương Ngân Sa","tomTat":"Ba người tiến vào sơn động Trụy Ma Cốc, Lỗ Vệ Anh chém thạch bích phát hiện mỏ quặng Cương Ngân Sa tự nhiên — tài liệu cực cứng gần bằng Luyện Tinh, có thể khảm vào pháp bảo hoặc trộn vào khôi lỗi. Nam Lũng Hầu nhắc nhở mục tiêu chính là linh dược kéo dài tuổi thọ, không nên lãng phí thời gian khai thác. Đại Diễn Thần Quân trong thần thức Hàn Lập hưng phấn, truyền pháp quyết cổ văn (đoạt từ tu sĩ bị giết năm xưa) cho phép điều khiển Phệ Kim Trùng chui vào đá cắn nuốt khoáng vật. Hàn Lập bí mật phóng thích toàn bộ Phệ Kim Trùng vào thạch bích khai thác mà hai đồng hành không hay biết. Hàn Lập tiết lộ phi kiếm đã dùng Luyện Tinh tốt hơn, không còn thừa cho Đại Diễn Thần Quân. Ba người đi sâu hơn, gặp Bắc Cực Nguyên Quang phát ra từ thạch nhũ chặn đường — Nam Lũng Hầu cảnh báo tuyệt đối không được dùng linh lực hay pháp bảo ngoại trừ Lưỡng Nghi hoàn, nếu không chỉ có chết. Hàn Lập lấy ra chiếc nhẫn đen Lưỡng Nghi hoàn chuẩn bị vượt qua."},{"chuong":812,"tieuDe":"Bắc Cực Nguyên Quang","tomTat":"Hàn Lập kích hoạt Lưỡng Nghi hoàn phóng to thành cự hoàn, chứng minh pháp bảo này có thể bẻ cong ngân ti Bắc Cực Nguyên Quang, che chắn ba người vượt qua an toàn. Hắn ném viên châu phòng hộ linh khí thử nghiệm, viên châu bị ngân ti xuyên thủng nổ tung, cho thấy uy lực kinh khủng của Bắc Cực Nguyên Quang với pháp bảo phòng ngự thông thường. Tại thung lũng băng tuyết khác, lão giả họ Chung dẫn nhóm Quỷ Linh Môn diệt bích hổ cổ thú bằng Mặc Giao và cự võng lửa, dưới thi thể cổ thú lộ ra khe băng có bạch quang, cả nhóm bay vào. Vương Thiên Cổ vắng mặt khỏi nhóm. Tử Linh một mình tìm được tiêu ký của Quỷ Linh Môn tại rừng sâu, nhận định bọn họ không ngờ có người khác biết tiêu ký, dán phù xanh đánh dấu rồi bay đi. Trước hạp cốc lớn có cấm chế cổ xưa, Thiên Tinh Chân Nhân cùng hai con Khôi lỗi thượng cổ (luyện từ Hồn Thạch, thực lực Nguyên Anh Sơ Kỳ) đang chần chừ thì Đông Môn Đồ dẫn năm tu sĩ Nguyên Anh Kỳ Ngự Linh Tông đến đề nghị liên thủ phá trận, hai bên thỏa thuận vào nội cốc rồi ai nấy tự lo."},{"chuong":813,"tieuDe":"Nội Cốc Chi Địa","tomTat":"Hàn Lập, Nam Lũng Hầu và Lỗ Vệ Anh đi qua động khẩu trên vách núi cao ngàn trượng, chính thức bước vào nội cốc Trụy Ma Cốc — chiến trường thượng cổ với thiên linh khí hoàn toàn hỗn loạn và khe hở không gian mật độ gấp mười lần bên ngoài. Hàn Lập phát hiện khe hở vô hình cách trăm trượng khiến Lỗ Vệ Anh thất thanh lo lắng. Nam Lũng Hầu trấn an hai người bằng thông tin từ di thư Thương Khôn Thượng Nhân: khe hở vô hình không di động, Thương Khôn Thượng Nhân thoát Trụy Ma Cốc nhờ thần thông cảm ứng khe hở không gian chứ không nhờ may mắn. Ba người phi hành theo lộ tuyến quanh co mà Nam Lũng Hầu đã thuộc lòng, Hàn Lập âm thầm ghi nhớ toàn bộ đường đi và phát hiện 3-4 chỗ có cấm chế thượng cổ nhưng đè nén lòng tham, xác định mục tiêu chính là yêu đan Hỏa Thiềm thú, bảo vật bên hài cốt cổ tu sĩ, Linh Chúc quả và Cương Ngân Sa. Sau hơn nửa ngày phi hành, Nam Lũng Hầu đột ngột dừng lại, sắc mặt âm tình bất định, cảnh báo phiền toái liên quan đến hai ngọn núi cao lớn phía trước."},{"chuong":814,"tieuDe":"Thập Tuyệt Độc","tomTat":"Ba người Hàn Lập, Nam Lũng Hầu và Lỗ Vệ Anh đứng trước hai ngọn núi dẫn đến sào huyệt Hỏa Thiềm thú. Nam Lũng Hầu tiết lộ ngọn trái có hơn mười con Phi Thiên Tử Vân hạt cực kỳ hung ác, ngọn phải có khe hở không gian vô hình dày đặc. Lỗ Vệ Anh kiên quyết từ chối đối đầu Tử Vân hạt, kể lại quá khứ từng đại biểu Thiên Cực Môn tham gia vây sát loài này ở Vọng Thủy Quốc. Hàn Lập dù có Linh nhãn thần thông nhìn thấy khe hở không gian nhưng giấu kín bí mật, thay vào đó lấy ra Bích Cưu — một trong Thập Tuyệt độc lấy từ hộp bảo vật Thương Khôn Thượng Nhân — đề xuất dùng mùi cay của nó bôi lên khôi lỗi dẫn dụ phi hạt rời đi. Hàn Lập nghi ngờ Nam Lũng Hầu cố tình giấu thông tin về Tử Vân hạt đến phút cuối nhằm đào hố, đồng thời bất mãn vì bị đổ hết việc lên mình. Hồi tưởng về tượng yêu thú ba đầu sáu tay trong di chỉ Thương Khôn, Hàn Lập mơ hồ cảm thấy có huyền cơ ẩn giấu và quyết tâm lấy xong yêu đan sẽ lập tức chia tay. Cuối cùng, Hàn Lập triệu bốn năm cự viên khôi lỗi mang bình Bích Cưu bay lên đỉnh núi trái, ba người thi triển pháp thuật ẩn giấu khí tức tiếp cận, khôi lỗi bóp nát bình phóng thích mùi cay rồi bay đi hướng khác dẫn dụ đám phi hạt."},{"chuong":815,"tieuDe":"Dung Nham Chi Địa","tomTat":"Ba người Hàn Lập, Nam Lũng Hầu và Lỗ Vệ Anh dùng khôi lỗi cự viên tẩm Bích Cưu độc làm mồi dụ đàn Tử Vân hạt mười ba, mười bốn con rời tổ. Âm công bén nhọn của đàn hạt khiến cả ba khí huyết quay cuồng; Hàn Lập nhận ra nó đánh thẳng chân nguyên chứ không qua thần thức, hiểu rằng điển tịch ghi về Thập Tuyệt độc không đầy đủ. Cả ba giải ẩn nặc phá không vượt đỉnh núi an toàn, nhưng đám khôi lỗi cự viên dần mất liên lạc, coi như tổn thất toàn bộ. Được đồng bạn khen công, Hàn Lập chỉ hàm hồ đáp cho qua, giấu việc Bích Cưu độc là bảo vật Thương Khôn Thượng Nhân để lại. Sau nửa ngày bay, ba người tiến vào vùng dung nham nóng bỏng như hỏa lò địa ngục, trước mặt là tòa núi lửa đỏ đậm cao mấy ngàn trượng bị mây lửa bao phủ. Nam Lũng Hầu cho biết động quật dưới chân núi là sào huyệt Hỏa Thiềm thú, bên trong có di hài tu sĩ thượng cổ; con thú chỉ cần nhảy vào dung nham là hồi phục như cũ nên không thể đánh thẳng. Ba người quyết định bày đại trận Thủy thuộc tính của Nam Lũng Hầu cùng mấy pháp trận phụ của Hàn Lập rồi ẩn hình mai phục; Hàn Lập thao túng con khôi lỗi bạch lang còn sót lại bay về phía sơn động dụ thú ra ngoài."},{"chuong":816,"tieuDe":"Dụ Phục","tomTat":"Hàn Lập điều khiển phân thân khôi lỗi bạch lang tiến vào hang động dưới chân núi lửa, phát hiện thế giới ngầm rộng lớn với hồ dung nham sôi sục, Hỏa Thiềm Thú khổng lồ đang ngủ trên nham thạch giữa hồ, và di hài tu sĩ cổ mặc trường bào xanh phi phàm trên thạch thai đối diện. Khi dùng tia phân thần thăm dò di hài, trường bào bùng linh quang ngăn thần thức, đánh thức cổ thú truy đuổi khôi lỗi ra ngoài. Hỏa Thiềm Thú phun hỏa cầu thiêu hủy hoàn toàn khôi lỗi bạch lang, yêu hỏa của nó mạnh hơn cả anh hỏa tu sĩ Nguyên Anh Kỳ. Vì quyết tâm lấy yêu đan cứu Nam Cung Uyển, Hàn Lập chủ động lộ thân bên pháp trận, triệu sáu khôi lỗi cự quy mới luyện giao đấu thử sức, dùng lam sắc băng diễm đối kháng ngang ngửa yêu hỏa. Giả vờ thua chạy dẫn dụ Hỏa Thiềm Thú lọt pháp trận thủy mạc đã bố trí sẵn, phối hợp Nam Lũng Hầu tế bích ngọc chỉ hoàn và Lỗ Vệ Anh dùng hai thanh phi qua hợp kích. Tuy nhiên cổ thú thi triển thần thông bảo mệnh tạo vòng bảo vệ ba tầng quang thuẫn đỏ chặn mọi công kích, rồi bắn quang trụ xuyên thủng thủy mạc pháp trận tạo lỗ hổng lớn."},{"chuong":817,"tieuDe":"Trảm Thú","tomTat":"Hỏa Thiềm thú bị kích hoạt pháp trận cấm chế, chớp cơ hội lỗ hổng đang khép lại để thoát ra ngoài. Nam Lũng Hầu và Lỗ Vệ Anh vội điều khiển bảo vật ngăn chặn nhưng chậm một bước. Hàn Lập kịp thời dùng Âm Ma trảm từ xa chém đứt chân trước yêu thú, khiến nó rơi trở lại pháp trận. Sáu khôi lỗi phun quang trụ lam đè ép yêu thú, trong khi Lỗ Vệ Anh dùng bích lục chỉ hoàn và phi qua băng mãng nhưng hiệu quả hạn chế trước quang thuẫn hỏa thuộc tính tái sinh liên miên. Hàn Lập triển khai hơn mười thanh Thanh Trúc Phong Vân kiếm hợp nhất thành cự kiếm, phủ Cực Hàn lam diễm kết hợp Ích Tà Thần Lôi, khiến Nam Lũng Hầu và Lỗ Vệ Anh ngỡ ngàng. Hỏa Thiềm thú phản công bằng viên hỏa đạn trông như yêu đan giả, tách thành quang xà cầm cố kiếm, nhưng Hàn Lập dùng điện võng bắn ngược rồi cự kiếm phá mười lớp quang thuẫn liên tiếp. Cự kiếm chém đứt lưỡi yêu thú cứng như pháp bảo nhờ đã thêm Canh Tinh, rồi trảm đầu Hỏa Thiềm thú. Tuy nhiên Hàn Lập cảnh giác ngăn Nam Lũng Hầu triệt pháp trận, vì linh quang yêu thú vẫn phiêu phù không rơi — cho thấy nó chưa chết hẳn."},{"chuong":818,"tieuDe":"Cổ Tu Di Hài","tomTat":"Hỏa Thiềm thú thể hiện thiên phú Bất diệt chi thể — đầu và thân bị chém đứt tỏa hồng quang tự tiếp cận tái sinh. Hàn Lập bình tĩnh dùng cự kiếm phân hai đạo kim quang kết hợp băng diễm đông kết rồi phá hủy hoàn toàn yêu thú, thu được yêu đan đỏ rực, đạt một mục đích vào Trụy Ma Cốc. Nam Lũng Hầu và Lỗ Vệ Anh đều động tâm trước yêu đan nhưng tự xét thần thông không bằng Hàn Lập, liên thủ cũng chỉ 5:5 nên bỏ ý tranh đoạt. Ba người vào sào huyệt Hỏa Thiềm thú, bay qua hồ dung nham đáp trước thạch thai nơi bộ hài cốt cổ tu sĩ nằm. Thanh bào trên hài cốt phản xạ thần thức, được Nam Lũng Hầu nhận ra là Thanh Tàm bào dệt từ tơ tằm cổ xưa và thu lấy, lộ ra túi trữ vật da đen tinh xảo. Nam Lũng Hầu đổ ra nhiều khối sắt đỏ (linh liệu luyện cổ bảo), kính tím, tiểu kiếm vàng, bộ phi châm xanh lục, hộp ngọc trắng và hai dược bình đen — ngoại trừ hộp ngọc và dược bình không thể dùng thần thức tra xét thì đều là cổ bảo không tầm thường. Lỗ Vệ Anh đặt vấn đề phân chia bảo vật, chương kết thúc trong thế giằng co ngầm giữa ba người."},{"chuong":819,"tieuDe":"Thất Diễm Phiến","tomTat":"Hàn Lập, Nam Lũng Hầu và Lỗ Vệ Anh bàn cách phân chia ba kiện bảo vật thu được. Nam Lũng Hầu mở hộp ngọc trắng phá cấm chế bạch quang, phát hiện bên trong là ngọc giản màu vàng đất ghi phương pháp luyện chế Thất Diễm phiến — cần 81 loại tài liệu Hỏa thuộc tính và nhiều linh liệu hiếm đã tuyệt tích. Nam Lũng Hầu và Lỗ Vệ Anh đánh giá ngọc giản ít giá trị thực tế, nhưng Ngân Nguyệt bí mật nhận ra Thất Diễm phiến chính là một loại Thông Thiên Linh Bảo, Đại Diễn Thần Quân cũng hưng phấn muốn nghiên cứu. Ngân Nguyệt và Đại Diễn Thần Quân xảy ra khẩu chiến ngắn vì chuyện cũ. Nam Lũng Hầu mở hai dược bình, mỗi bình chứa một viên cổ linh đan xanh biếc tỏa thanh hương. Hàn Lập dùng mưu kế giả vờ đòi linh đan, ép hai người nhượng bộ, cuối cùng chỉ lấy chiếc cổ kính tím, ngọc giản Thất Diễm phiến và linh liệu — thực chất đã đoạt được vật giá trị nhất. Nam Lũng Hầu và Lỗ Vệ Anh mỗi người được một viên linh đan và chia nhau cổ bảo còn lại."},{"chuong":820,"tieuDe":"Huyết Chú Chi Môn","tomTat":"Ba người Hàn Lập, Nam Lũng Hầu, Lỗ Vệ Anh phân chia hai kiện cổ bảo còn lại — Hàn Lập nhường bảo vật cho hai người để đổi lấy linh thạch, đồng thời tùy tiện thu lấy Thanh Tàm bào mà Nam Lũng Hầu vứt bỏ. Cả ba hái linh thảo Kim Dương chi bên hồ dung nham. Hàn Lập cáo từ hai người, chọn xuất cốc theo đường cũ vì ưu tiên tìm Linh Chúc quả. Sau khi Hàn Lập rời đi, Nam Lũng Hầu thả linh cầm Thiên Lý ly xác nhận hắn đã thực sự rời xa. Hai người bố trí cách âm rồi thảo luận: theo di thư Thương Khôn thượng nhân, bộ hài cốt cổ tu sĩ trong suốt chính là chìa khóa phá giải Huyết chú chi môn — cánh cửa được phong bế bằng cấm chế huyết chú thượng cổ, phía sau chứa trọng bảo. Hai người quyết định nhanh chóng hành động. Trong khi đó Hàn Lập bay hơn trăm dặm, xé góc Thanh Tàm bào phát hiện bên trong giấu một tấm địa đồ vẽ sơ đồ Trụy Ma Cốc có tiêu ký thô to bắt mắt, cho thấy hai người kia đã bỏ lỡ bảo vật thực sự."},{"chuong":821,"tieuDe":"Thủy Đàm Cùng Huyết Chú Chi Môn","tomTat":"Hàn Lập xem bản đồ Trụy Ma Cốc, nhận thấy khoảng cách tới mục tiêu còn rất xa, quyết ưu tiên tìm Linh Chúc Quả trước rồi mới xét bí mật trong bản đồ. Hắn dùng kích tướng pháp thách Đại Diễn Thần Quân nghiên cứu phương pháp thay thế vật liệu luyện chế Thông Thiên Linh Bảo Thất Diễm Phiến, đổi lại sẽ đáp ứng một yêu cầu của lão trong tương lai. Đại Diễn Thần Quân tiết lộ lão chỉ còn mười năm nữa hồn phi phách tán, chấp nhận thử thách. Hàn Lập nội tâm bộc lộ đã sở hữu Hư Thiên Đỉnh nhưng chưa biết cách mở ra. Tuyến khác, Nam Lũng Hầu dẫn Lỗ Vệ Anh vào thông đạo dưới sào huyệt Tử Vân Hạt, tiết lộ thông tin Huyết Chú Chi Môn là bí sự truyền miệng riêng của hắn, không nằm trong di thư Thương Khôn Thượng Nhân, và cần hai tu sĩ Nguyên Anh mới mở được. Nam Lũng Hầu dùng Phân Thủy Kỳ rẽ nước thủy đàm bích lục sâu ba trăm trượng, rồi dùng ngọc bội trắng vén màn nước, lộ ra thạch môn Huyết Chú Chi Môn — hình vòm cao ba trượng, lóe huyết sắc hồng quang, điêu khắc đầu quỷ một sừng. Lỗ Vệ Anh nhìn thấy thạch môn thì hoảng sợ bất an."},{"chuong":822,"tieuDe":"Linh Miểu Viên","tomTat":"Nam Lũng Hầu cùng Lỗ Vệ Anh tới thạch môn đáy thủy đàm, xác nhận đây là cửa vào Linh Miểu Viên — nơi do Thượng cổ tu sĩ dùng tinh huyết toàn thân phong ấn. Hai người bố trí cấm chế ngoài cửa phòng đường lui rồi thiết trí pháp trận chuẩn bị giải huyết cấm. Ở nơi khác, môn chủ Quỷ Linh Môn dẫn Ngụy Vô Nhai, Vương Thiên Cổ và bốn đệ tử Kết Đan Kỳ leo hắc sơn thạch tiến về Linh Miểu Viên, khẳng định nơi này có thật và cả Trụy Ma Cốc do Thượng cổ tu sĩ tu kiến chuyên để trông coi Linh Miểu Viên, hứa Quỷ Linh Môn sẽ thành ma đạo đệ nhất đại tông phái. Ngụy Vô Nhai ngoài mặt hợp tác nhưng trong lòng không tin nửa phần. Chung trưởng lão được tiết lộ đã tách ra tìm bảo vật trân hi ở chỗ bí mật khác trong nội cốc. Tại cửa đại hạp cốc, Thiên Tinh Chân Nhân và Đông Môn Đồ cùng năm tu sĩ Ngự Linh Tông phá cấm chế lao ra, sau đó Thiên Tinh cảnh giác từ chối liên thủ tiếp, mang hai con Khôi Lỗi rời đi. Đông Môn Đồ âm thầm thả đám biên bức ngân quang nuốt dược hoàn đen để truy tung Thiên Tinh rồi dẫn năm tu sĩ bay theo."},{"chuong":823,"tieuDe":"Huyết Chú Giải Cấm","tomTat":"Nam Lũng Hầu và Lỗ Vệ Anh hoàn thành bố trí pháp trận phòng bị quanh khu vực hồ, tạo tầng hà quang bảo vệ trước khi tiến hành phá cấm chế trên thạch môn. Lỗ Vệ Anh thử công kích thạch môn bằng hỏa cầu và phong long, nhưng huyết quang trên cửa ngưng tụ thành mặt quỷ khổng lồ nuốt chửng mọi đòn đánh. Nam Lũng Hầu lấy hài cốt cổ tu đã tọa hóa từ túi trữ vật, dùng phi kiếm nghiền thành cốt phấn chứa tinh nguyên, rồi theo phương pháp của Thương Khôn Thượng Nhân bắt quyết điều khiển cốt phấn đánh vào mặt quỷ, hóa giải huyết quang cấm chế trong sương mù xám. Hai người hợp lực tổng công kích phá hủy hoàn toàn thạch môn, các mảnh vỡ chảy ra dòng máu đỏ sậm hôi thối. Sau thạch môn là cầu thang dẫn xuống đại sảnh dưới lòng đất, trên bàn bày nhiều linh dược quý hiếm gồm Thiên nguyên quả kéo dài thọ trăm năm, tử sắc linh chi ngàn năm tuổi, và đặc biệt là Kim Lôi Trúc thuộc hàng tam đại thần mộc. Lỗ Vệ Anh suýt lỗ mãng xông lên lấy bảo vật nhưng bị Nam Lũng Hầu cảnh tỉnh, sau đó lão nhận ra các ký hiệu trên vách tường bốn phía chính là Tiểu tu di kim cương trận, một pháp trận Phật tông, và vô cùng kinh ngạc vì gặp pháp trận chính đạo ở nơi bảo tàng đầy tà thuật này."},{"chuong":824,"tieuDe":"Tiểu Tu Di Kim Cương Trận","tomTat":"Nam Lũng Hầu và Lỗ Vệ Anh trong đại sảnh phía sau huyết chú chi môn phát hiện cấm chế bảo vệ linh dược trên bàn. Lỗ Vệ Anh nhận ra đây là Tiểu Tu Di Kim Cương Trận của Phật tông, trận pháp có khả năng tự hồi phục bất diệt, không có pháp quyết phá mà chỉ có thể cường công liên tục. Khi Lỗ Vệ Anh bắn hỏa cầu thử nghiệm, phật văn kim sắc hiện ra cùng bảo vật ẩn giấu thật sự: ngân viên bát to cỡ đầu người với phù văn thâm ảo, tám khối ngọc phù vây quanh, phía trên có ba pháp khí tinh xảo tản tam sắc linh quang bao bọc. Hai người thỏa thuận chia đều rồi lập tức hợp lực cường công phá trận. Trong khi đó Hàn Lập bay nhanh quay về sơn động, cảm nhận linh khí ba động phía xa nơi có tu sĩ khác đang phá cấm, thoáng nảy ý đục nước béo cò nhưng lập tức kiềm chế, chỉ đảo thần thức nhanh rồi tiếp tục bay đi. Cách hơn mười dặm, đoàn hơn mười Mộ Lan pháp sĩ do Trọng Thần Sư và Nhạc thượng sư dẫn đầu đang cường công cấm chế ở đỉnh núi nhỏ. Nhạc thượng sư tiết lộ đã mất hai người vào khe hở không gian và mọi linh cầm kể cả ô sí điêu ngũ cấp vào nội cốc đều sợ hãi nổi điên. Trọng Thần Sư nhấn mạnh cơ hội này do giao dịch với cao tầng Thiên Nam tứ đại thế lực mà có, quyết không được lãng phí."},{"chuong":825,"tieuDe":"Hội Hợp","tomTat":"Hàn Lập dùng Lưỡng Nghi Hoàn xuyên qua thông đạo và Bắc Cực Nguyên Quang, rời khỏi nội cốc Trụy Ma Cốc trở về ngoại cốc. Tại vách núi cửa động, hắn thu hoạch lượng lớn cương ngân sa tinh thể do đàn Phệ Kim Trùng tinh luyện, trữ lượng vượt xa dự liệu khiến Đại Diễn Thần Quân vui mừng vì có thể dùng cho nghiên cứu cơ quan Khôi Lỗi. Hàn Lập dùng viên cầu truy tung trong suốt dẫn đường phi độn tìm điểm hẹn, dọc đường phát hiện ba thi thể tu sĩ bị đồng loại giết hoặc chết trong khe hở không gian, cho thấy tình hình ngoại cốc ngày càng hỗn loạn. Đến khu rừng rậm rạp, hắn tìm được tiêu ký giấu trong thân đại thụ, đốt thanh phù phát tín hiệu triệu tập Tử Linh Tiên Tử. Tử Linh xuất hiện với hình dáng thật vì bảo vật dịch dung bị Trụy Ma Cốc hạn chế đã mất hiệu lực, nàng tiết lộ tiêu ký ban đầu bị Quỷ Linh Môn phá hủy nhưng nàng đã cài sẵn kỳ hương vô sắc vô vị của Diệu Âm Môn lên một đệ tử Quỷ Linh Môn từ một tháng trước để truy tung. Hai người quyết định đuổi theo và vượt qua Quỷ Linh Môn để đoạt linh chúc quả, một con ngân mao phi thử bay ra dẫn đường, hai đạo trường hồng theo sát phía sau xuất phát."},{"chuong":826,"tieuDe":"Họa Trục","tomTat":"Đoàn người Quỷ Linh Môn cùng Ngụy Vô Nhai bay qua cự sơn, phát hiện phiến bồn địa âm u với tòa tế đàn đá trắng khổng lồ ở trung tâm — kiến trúc hoàn chỉnh đầu tiên từ khi vào cốc. Cấm chế mạnh đến mức bay lên liền bị huyết sắc thiểm điện phách xuống, cả đoàn buộc phải đi bộ. Một đệ tử Quỷ Linh Môn đi đầu bị khe hở không gian ẩn hình cắt đôi thân thể chết tại chỗ, gây chấn động vì lộ tuyến vốn được cam đoan an toàn. Quỷ Linh Môn môn chủ buộc phải tiết lộ sớm: lấy ra họa trục — một không gian pháp khí cực hiếm chứa nguyên thần nho sinh bên trong, khẳng định mọi thông tin về Linh Miểu Viên đều từ đây. Vương Thiên Cổ nhận ra đây là bức họa vẽ hình Thương Khôn Thượng Nhân lấy từ bảo khố Mộ Lan thảo nguyên. Nguyên thần nho sinh bị ép hiện thân, kiểm tra khe hở rồi kết luận đây là khe hở mới xuất hiện, lộ tuyến năm xưa vốn an toàn. Vương Thiên Cổ kinh hãi hỏi phải chăng là Thương Khôn Thượng Nhân bảo trì nguyên thần bất diệt nhưng nho sinh không xác nhận. Trong khi đó Hàn Lập đang ở tuyến khác truy tìm đoàn Chung trưởng lão."},{"chuong":827,"tieuDe":"Thần Thức Hóa Ngàn","tomTat":"Quỷ Linh Môn môn chủ giải thích rằng nho sinh trong họa trục chỉ là hóa thân tàn hồn của Thương Khôn Thượng Nhân, bản thể đã chết từ lâu, tàn hồn được tĩnh dưỡng trong họa trục luyện từ mảnh vụn Dưỡng Hồn Mộc. Ngụy Vô Nhai tuyên bố không quan tâm hiệp nghị, chỉ muốn tiến Hóa Thần Kỳ rồi phi thăng linh giới. Hàn Lập đã lẻn vào nội cốc Trụy Ma Cốc qua băng phùng, phát hiện phi thử của Tử Linh và linh cầm Mộ Lan pháp sĩ mất khống chế, trong khi Phệ Kim Trùng và Đề Hồn Thú hoàn toàn bình thường. Hàn Lập thi triển Đại Diễn Quyết đến cực hạn, phân hóa thần thức thành hơn ngàn phân thần ký phụ lên Phệ Kim Trùng bay tản bốn phương trinh sát, mất hơn mười phân thần nhưng nhờ thần thức cường đại nhanh hồi phục. Cuối cùng tìm được lộ tuyến Quỷ Linh Môn, phát hiện hố trống ở đám loạn thạch là một trong ba địa điểm có linh chúc quả. Hàn Lập triệu Ngự Phong Xa chở Tử Linh tăng tốc truy đuổi, Tử Linh lo lắng vì khe hở không gian trong nội cốc rất nguy hiểm."},{"chuong":828,"tieuDe":"Huyễn Hóa Chi Phong","tomTat":"Hàn Lập thuyết phục Tử Linh lên Ngự Phong Xa, dùng Thanh Minh Linh Nhãn né khe hở không gian ẩn hình trên đường đi. Đuổi kịp đám người Quỷ Linh Môn do trưởng lão họ Chung dẫn đầu đang bị kẹt bởi thượng cổ tiểu cấm chế mà đệ tử vô tình kích hoạt, Hàn Lập lợi dụng cơ hội điều khiển Ngự Phong Xa đi chếch lộ tuyến vượt qua bỏ xa họ phía sau. Hai người đến khu vực núi non xanh biếc, Tử Linh nhận ra đỉnh núi hình đại điểu là tiêu ký trung gian chỉ hướng đến tiêu ký tối hậu. Hàn Lập dùng kiếm khí tay không dài hơn mười trượng cắt sập hai cánh đỉnh núi để xóa dấu hiệu, khiến Tử Linh lần đầu tin vào thực lực thật sự của hắn. Sau đó Hàn Lập triệu hoán Ngân Nguyệt, giao hai bộ khí cụ bày trận để nàng kết hợp huyễn thuật bố trí ảo trận biến toàn bộ ngọn núi thành rừng rậm ảo, che giấu tiêu ký trước Quỷ Linh Môn. Cắt sang cảnh khác cách đó hàng ngàn dặm, Nam Lũng Hầu và Lỗ Vệ Anh sau gần hai ngày ngày đêm liên tục tiêu hao pháp lực và tinh nguyên chỉ huy pháp bảo, cuối cùng phá được Tiểu Tu Di Kim Cương Trận trong đại sảnh dưới lòng đất. Cả hai tổn hao nguyên khí, sắc mặt tái nhợt nhưng cực kỳ hưng phấn khi nhìn thấy bảo vật, linh dược cùng viên bát trên bàn hiện ra trước mắt."},{"chuong":829,"tieuDe":"Ma Động","tomTat":"Nam Lũng Hầu và Lỗ Vệ Anh tiến vào điện thờ dưới đáy thủy đàm, thỏa thuận phân chia bảo vật: Nam Lũng Hầu chỉ lấy viên bát trên điện thờ, còn ba kiện pháp khí cùng ngọc phù thuộc về Lỗ Vệ Anh. Nam Lũng Hầu nhìn ra viên bát mới là cổ bảo đứng đầu, còn ba pháp khí và ngọc phù kia thực chất là vật thượng cổ tu sĩ dùng để trấn áp nó, nên lập tức dán phù phong ấn. Khi hai người định thu linh dược, toàn bộ thiên nguyên quả cùng tử sắc linh chi lóe lục quang rồi tan biến, ngay sau đó phù lục trên viên bát bị thiêu hủy, một đạo ô quang bắn ra đánh trúng mặt Nam Lũng Hầu. Chỉ trong nháy mắt, thần thức Nguyên Anh Trung Kỳ của hắn bị đoạt xá, thân thể biến dị với cánh tay quỷ trảo đen bóng hắc khí, dễ dàng gạt bay pháp khí tấn công của Lỗ Vệ Anh. Kẻ chiếm xác tự xưng bổn tôn, tuyên bố thánh tổ sẽ phủ xuống và giới này phải thuộc về thánh giới, những khái niệm hoàn toàn xa lạ khiến Lỗ Vệ Anh kinh sợ. Lão vội dùng Hạo dương sa hộ thân rồi thi triển độn thuật bỏ chạy, nhưng bị kẻ đoạt xá chặn trước lối ra, một quyền đấm xuyên quang mạc hộ thân hất lão cắm sâu vào thạch bích. Lỗ Vệ Anh lưng tê dại mất kiểm soát thân thể, sắc mặt tái nhợt nhìn kẻ địch đứng chắn cửa cười lạnh."},{"chuong":830,"tieuDe":"Thôn Anh","tomTat":"Nam Lũng Hầu trong thân thể ma hóa tiếp tục dồn Lỗ Vệ Anh vào tuyệt cảnh, dùng liên tiếp quyền kích đánh tan pháp lực khiến Cổ Bảo Hạo Dương Sa dù cố chống đỡ cũng dần suy yếu rồi vỡ nát. Lỗ Vệ Anh buộc phải để Nguyên Anh ôm bổn mạng lam sắc tiểu kiếm xuất khiếu bỏ chạy, nhưng mặt quỷ hiện trên lưng Nam Lũng Hầu phun lưỡi tím xuyên thủng trán Nguyên Anh rồi nuốt trọn, sau đó hắn còn móc tim nhục thân lão bóp nát, hoàn toàn diệt sát đối phương. Rời khỏi thủy đàm, Nam Lũng Hầu bay lên không trung Trụy Ma Cốc, kích động vô số tia chớp đỏ của cấm chế nhưng các đòn đánh đều tự lệch khỏi thân hắn, rồi hắn xác định phương hướng và hóa thành hắc khí biến mất. Ở một nơi khác, đoàn Quỷ Linh Môn do môn chủ dẫn đầu cùng Ngụy Vô Nhai, Vương Thiên Cổ tiến tới tế đàn cổ xưa sau khi mất hơn nửa ngày phá cấm chế phạm vi lớn. Khi bước lên cầu thang tế đàn, họ lại gặp cấm chế trọng lực khiến tu sĩ Kết Đan khó nhọc, còn Ngụy Vô Nhai gần như không bị ảnh hưởng, cả đoàn tiếp tục leo lên để tìm tung tích Linh Miểu Viên. Trong ốc đảo bị cấm chế che giấu giữa sa mạc, Hàn Lập và Tử Linh phát hiện giữa hồ xanh có linh thảo kết bốn Linh Chúc Quả hỏa hồng tỏa hương nồng đậm. Sau khi Tử Linh xác nhận đây đúng là linh quả cần tìm, Hàn Lập quyết định lập tức hái lấy để tránh phát sinh biến cố, và Tử Linh đồng ý."},{"chuong":831,"tieuDe":"Dị Thú","tomTat":"Hàn Lập không vội hái Linh Chúc Quả mà nhận định linh thảo lâu năm thường có cổ thú thủ hộ, lại thấy trên cây có dấu hai quả từng bị cắn mất. Hắn giải thích quả này không trực tiếp tăng cảnh giới nhưng có tác dụng hỗ trợ đột phá bình cảnh, rồi dùng Thanh Minh Linh Nhãn nhìn thấu đáy hồ và phát hiện cổ thú ẩn nấp. Sau khi bảo Tử Linh lui xa, Hàn Lập thả mấy vạn Phệ Kim Trùng, tế xuất ba mươi sáu khẩu Thanh Trúc Phong Vân Kiếm bố Đại Canh Kiếm Trận, rồi dùng điện cầu kim sắc đánh xuống mặt hồ ép cổ thú lộ diện. Cổ thú hiện thân với hình dáng như khối thịt đen, chỉ có một mắt và được hắc bạch nhị khí bao quanh, nhưng các đòn lục dịch và lục hỏa của nó đều không khắc chế được Phệ Kim Trùng. Hàn Lập dùng lam sắc hỏa cầu đóng băng hồ nước, phối hợp kiếm quang hóa kim ti phá khí hộ thể để đàn trùng tràn vào cắn nuốt cổ thú. Sau khi cổ thú chết, Hàn Lập biết sở trường thật sự của nó là liễm tức biến hình nhưng đã bị linh nhãn khắc chế, rồi thu lấy viên Yêu Đan hắc bạch lưỡng sắc. Tử Linh kinh ngạc và khen hắn là người lợi hại nhất dưới tam đại tu sĩ, còn Hàn Lập chỉ khiêm tốn phủ nhận."},{"chuong":832,"tieuDe":"Đắc Quả","tomTat":"Hàn Lập thu dọn chiến trường, cất yêu đan cổ thú, Phệ Kim Trùng và ba mươi sáu thanh phi kiếm rồi cùng Tử Linh nhanh chóng hái Linh Chúc quả trước khi tu sĩ Quỷ Linh Môn thoát khỏi huyễn trận. Tử Linh chỉ lấy một quả, nói mình không ra sức nhiều và tiết lộ Linh Chúc quả ngoài luyện Tạo Hóa đan còn có thể phục dụng trực tiếp tăng tu vi; Hàn Lập thu ba quả còn lại vào hộp gỗ và có ấn tượng tốt hơn về sự tự chế của nàng. Trước khi rời đi, Hàn Lập xem bản đồ Trụy Ma Cốc tìm được trong Thanh Tàm bào, phát hiện tiêu ký bí bảo cách sa mạc hiện tại không xa, nhưng vẫn quyết định luyện Tạo Hóa đan trước. Hắn thử cắt nhánh cây Linh Chúc quả để mang đi nhưng nhánh vừa rơi xuống đất đã khô vàng hóa tro, xác nhận linh mộc này không thể di thực. Khoảng một thời thần sau, trưởng lão họ Chung dẫn người Quỷ Linh Môn tới ốc đảo, chỉ thấy hồ băng chưa tan và cây linh thảo đã trơ trọi nên vô cùng tức giận. Hàn Lập và Tử Linh dùng Ngự Phong Xa rời sa mạc, đi qua vùng cao nguyên màu vàng đến một dãy núi, mỗi người mở nơi luyện đan riêng. Hàn Lập lập động phủ tạm, bố trí pháp trận và Khôi Lỗi Kết Đan Kỳ canh gác, lấy Linh Chúc quả, phụ liệu và tiểu đỉnh cổ xưa ra, phun anh hỏa xanh bắt đầu luyện Tạo Hóa đan."},{"chuong":833,"tieuDe":"Tế Đàn","tomTat":"Hàn Lập tiếp tục luyện đan trong mật thất, lần lượt xử lý nhiều loại nguyên liệu rồi đưa Linh Chúc quả vào thanh sắc tiểu đỉnh, dùng anh hỏa màu xanh và pháp quyết điều khiển quá trình luyện đan. Cùng lúc đó, đoàn Quỷ Linh Môn sau hơn một ngày một đêm vượt qua cấm chế trọng lực đã lên tới đỉnh tế đàn đá trắng trong Trụy Ma Cốc. Đỉnh tế đàn có bàn thờ ngọc xanh biếc, bốn thạch trụ khắc phù văn cổ và tượng kỳ lân, bầu trời phía trên phủ sắc đỏ cùng vô số hào quang. Trước nghi vấn của Ngụy Vô Nhai, Quỷ Linh Môn môn chủ triệu nho sinh trong họa trục ra, để hắn xác nhận nơi đây là trung tâm Trụy Ma Cốc và lối vào Linh Miểu viên nằm trên bầu trời tế đàn. Theo chỉ dẫn của nho sinh, Vương Thiên Cổ và ba đệ tử Kết Đan kỳ rót linh lực vào bốn cột đá, khiến tượng kỳ lân biến đổi và phun ngũ sắc hào quang tụ thành quang cầu. Vụ nổ linh quang kinh thiên xảy ra, sau khi hào quang tan đi, cảnh tượng hiện ra khiến mọi người thất kinh và Ngụy Vô Nhai lạnh giọng chất vấn nho sinh rằng đó có phải lối vào Linh Miểu viên hay không."},{"chuong":834,"tieuDe":"Thông Đạo","tomTat":"Trên tế đàn hiện ra một khe hở không gian hình trăng khuyết, nho sinh cho biết muốn vào Linh Miểu Viên phải vượt qua nơi này nhưng tỷ lệ thành công không cao, tu sĩ Kết Đan đi vào gần như chắc chết. Môn chủ Quỷ Linh Môn nổi giận vì bị giấu nguy hiểm, liền dùng huyết sắc lệnh bài thi triển Kinh Hồn Chú hành hạ nho sinh, sau đó buộc hắn ngoan ngoãn mở đường. Nho sinh phun ra Phá Giới Châu, tiêu hao hơn nửa hồn lực để kích phát khe hở, rồi nhờ ba Nguyên Anh và ba đệ tử Kết Đan rót linh lực ổn định thành một thông đạo đen; phép thử bằng tiểu quỷ của Vương Thiên Cổ lập tức thất bại, chứng tỏ yêu quỷ vô hình không thể đi qua. Ngụy Vô Nhai dẫn đầu tiến vào, Môn chủ Quỷ Linh Môn và Vương Thiên Cổ theo sau, phát hiện bên trong là một không gian xám xịt hoàn toàn không giống Linh Miểu Viên, nhưng ma khí lại nồng đậm gấp bội Nhân giới, khiến hai tu sĩ ma đạo mừng thầm. Bất ngờ nho sinh thoát khỏi họa trục và bỏ chạy, Kinh Hồn Chú của Môn chủ Quỷ Linh Môn chỉ khiến hắn khựng lại trong chốc lát rồi mất tác dụng, làm cả ba kinh nghi truy đuổi. Ở gần trung tâm không gian, họ nhìn thấy một yêu vật khổng lồ hai đầu bốn tay bị phong ấn trong khối thủy tinh như lửa, tỏa ra ma khí cực kỳ đáng sợ. Nho sinh lúc này tiết lộ Linh Miểu Viên thật sự có lẽ đã sớm bị hái sạch hoặc hủy hoại từ thượng cổ, còn nơi họ đang đứng chỉ là vùng giao giữa Nhân giới và Thánh giới; Ngụy Vô Nhai lập tức nhận ra điều bất thường, kinh hãi gọi hắn là Cổ ma và vội thi pháp phòng ngự."},{"chuong":835,"tieuDe":"Ma Khu","tomTat":"Vương Thiên Cổ phái Tiểu quỷ thăm dò thông đạo dẫn vào Linh Miểu Viên, nhưng Tiểu quỷ vừa vào liền nổ tung tan biến. Nho sinh giải thích thông đạo có cơ chế diệt trừ mọi hình thể quỷ mị, bản thân hắn phải mượn họa trục ký thể mới vào được rồi hóa lục quang bay vào bức tranh. Ngụy Vô Nhai dò xét, đi đầu vào thông đạo; Môn chủ Quỷ Linh Môn phân phó ba thuộc hạ trấn thủ, thu tranh rồi cùng Vương Thiên Cổ theo sau. Sang bên kia, cả ba phát hiện không gian toàn màu xám, không hề có linh dược, tuyệt không phải Linh Miểu Viên, song ma khí gấp đôi nhân giới khiến hai kẻ ma tu vừa giận vừa mừng. Khi bị ném tranh xuống gọi ra chất vấn, nho sinh tự bắn ra thoát đi; Môn chủ Quỷ Linh Môn dùng huyết sắc lệnh bài kích hoạt Kinh Hồn Chú kiềm hãm nhưng thất bại. Đuổi tới trung tâm, ba người thấy một yêu vật khổng lồ hai đầu bốn tay bị phong ấn trong khối thủy tinh, tỏa ma khí cực dày. Nho sinh tiết lộ nơi này chỉ là không gian giao giới Nhân giới với Thánh giới; nghe tới Thánh giới, Ngụy Vô Nhai hoảng sợ nhận ra đối phương là Cổ ma và vội kích hoạt lục sắc độc vụ phòng thân."},{"chuong":836,"tieuDe":"Giải Thể Hóa Hình","tomTat":"Nho sinh lộ rõ quan hệ với thượng cổ ma giới và đề nghị ba tu sĩ giúp giải phong ấn ma thể để đổi lấy chân ma chi khí cùng vô thượng ma thể, khiến Vương Thiên Cổ và Quỷ Linh Môn môn chủ thoáng dao động. Ngụy Vô Nhai kịp thời cảnh tỉnh rằng ma khí nhập thể sẽ hủy thần trí, rồi dùng Phá Hồn xà đánh xuyên bụng nho sinh, phá hơn nửa hồn thạch khiến hình thể quỷ mị của hắn tan vỡ. Khi ba người định rời đi, khí xám trắng của nho sinh tái ngưng thành quỷ đầu độc giác và đe dọa giữ họ lại nơi phong ấn. Quỷ đầu được ma thể mở mắt bắn ra huyết quang tạo thành huyết tráo bảo hộ, khiến nhiều đòn ma công bị hấp nạp trong lúc Phá Hồn xà và đầu lâu vàng vẫn tiếp tục công kích. Ma thể phát ô quang và huyết mang, còn quỷ đầu dùng Giải Thể Hóa Hình để hút lực từ ma thể, ngưng tụ huyết ti thành da thịt xương cốt. Vương Thiên Cổ nhận ra bí thuật vô thượng này và phóng phiến đồng phù văn đen chém đứt huyết sắc quang trụ, nhưng quỷ đầu đã kịp hình thành thân thể bên dưới và mở đôi mắt một đen một tím cười ác độc."},{"chuong":837,"tieuDe":"Kinh Biến","tomTat":"Hàn Lập tỉnh lại sau huyễn cảnh do Tạo Hóa Đan gây ra, nhớ rõ cảm ngộ về cách khống chế thiên địa linh lực dù không thể nhớ khẩu quyết trong mộng. Hắn nhận ra thu hoạch này rất có ích cho việc đột phá cảnh giới, lại nhớ trước đó đã nuốt hết Linh Chúc quả nên tu vi tăng lên không ít. Ngân Nguyệt dưới dạng tiểu hồ báo rằng hắn đã bế quan hai ngày hai đêm, Tử Linh từng đến thăm, đồng thời giải thích vì thân phận lang yêu mượn thân yêu hồ nên không dám dùng Tạo Hóa Đan. Hàn Lập xuất quan, thu hồi khôi lỗi thú và trận kỳ trận bàn, rồi gặp Tử Linh; nàng cho biết mình nhờ Tạo Hóa Đan mà chỉ cần đả tọa vài năm có thể tiến vào Kết Đan trung kỳ. Hai người đang trò chuyện thì một tiếng nổ kinh thiên động địa vang lên từ phương hướng tiêu ký trên bản đồ, kéo theo sóng khí trắng vô biên san phẳng mọi thứ trên đường đi. Hàn Lập lập tức phóng Bạch lân thuẫn và phun băng diễm dựng thành băng sơn cao lớn để phòng ngự, còn Tử Linh dùng khăn lụa hộ thân rồi hạ xuống đứng cạnh hắn khi sóng khí ập tới làm băng sơn rung rẩy rạn nứt."},{"chuong":838,"tieuDe":"Ma Ảnh Sơ Hiện","tomTat":"Tử Linh lo lắng khi băng sơn của Hàn Lập bị khí lãng công kích, nhưng lam sắc băng sơn chống đỡ được toàn bộ biến động mà không rạn nứt. Sau khi khí lãng qua đi, Hàn Lập suy đoán linh khí nơi xa hỗn loạn do khe hở không gian xảy ra vấn đề và quyết định theo đường cũ rút khỏi Trụy Ma Cốc. Hắn thu hồi cự thuẫn, rồi lần đầu vận dụng thủ pháp cảm ngộ trong huyễn cảnh để thu lam sắc băng diễm vào cơ thể, từ đó xác nhận hy vọng tiến giai Nguyên Anh trung kỳ tăng lên. Đúng lúc ấy, hai đạo độn quang một vàng một trắng bay tới trong tình trạng hoảng hốt, Hàn Lập nhận ra là Lệnh Hồ lão tổ và Đại trưởng lão Yểm Nguyệt Tông. Vì lo kẻ truy đuổi có thể là cao thủ Mộ Lan, Hàn Lập lập tức dùng thanh hà ẩn thân che giấu mình và Tử Linh. Kẻ xuất hiện sau đó lại là Nam Lũng Hầu bị ma hóa, ma khí trùng thiên, đang truy sát hai tu sĩ Nguyên Anh để cắn nuốt nguyên thần. Ma hồn trong thân thể Nam Lũng Hầu dễ dàng đánh văng Đại trưởng lão, nghe tin trong cốc có hơn mười Nguyên Anh kỳ thì càng vui mừng và lao tới tấn công Lệnh Hồ lão tổ."},{"chuong":839,"tieuDe":"Đánh Lén, Hiện Thân","tomTat":"Lệnh Hồ lão tổ bị Nam Lũng Hầu do cổ ma phụ thân áp đảo hoàn toàn, ngay cả ngọc ấn, phi đao phá tà và vòng bảo hộ của Ngọc Như Ý cũng lần lượt bị phá hoặc rạn nứt. Đúng lúc nguy cấp, đại trưởng lão Yểm Nguyệt Tông dùng Ngưng Quang Bảo Kính phóng ngũ sắc quang trụ cứu viện, phối hợp với Lệnh Hồ lão tổ phản công bằng phù lôi hỏa, phi xoa và phi kiếm đen trắng. Ở gần đó, Hàn Lập đang ẩn nấp cùng Tử Linh và trò chuyện với Đại Diễn Thần Quân, được xác nhận kẻ trong người Nam Lũng Hầu là cổ ma đến từ Thượng cổ Ma giới, thực lực cực mạnh. Ngay sau đó, Nam Lũng Hầu thi triển kế kim thiền thoát xác, để lại hóa thân trong quang trụ còn bản thể âm thầm áp sát chỗ Hàn Lập. Nhờ Thanh Minh Linh Nhãn vô tình quét qua, Hàn Lập kịp phát hiện và cuốn Tử Linh bay lên tránh đòn đánh lén. Lệnh Hồ lão tổ thấy Hàn Lập lộ diện thì mừng rỡ kêu gọi liên thủ, còn Hàn Lập cũng hiểu rằng Ẩn nặc thuật của mình đã bị cổ ma nhìn thấu nên trận chiến này không thể tránh nữa."},{"chuong":840,"tieuDe":"Sơ Đấu Ma Hồn","tomTat":"Hàn Lập thấy tu vi Tử Linh quá thấp nên khuyên nàng rời khỏi chiến trường trước, còn cổ ma trong thân xác Nam Lũng Hầu lạnh lùng đứng nhìn không ngăn cản. Khi khai chiến, Hàn Lập dùng Ích Tà Thần Lôi công kích, khiến cổ ma nhận ra hắn qua ký ức tàn dư của Nam Lũng Hầu và đặc biệt kiêng dè thần lôi từng gây đau khổ cho ma tộc. Cổ ma thi triển ẩn hình thuật khiến thần thức không dò được, nhưng Hàn Lập dùng Minh Thanh Linh Nhãn phát hiện hai lần liên tiếp. Bị dồn ép, cổ ma phun hắc hồng ma diễm triệt tiêu Ích Tà Thần Lôi, song thủ đoạn này tiêu hao tinh nguyên rõ rệt. Sau đó cổ ma bám theo Lôi Độn Thuật, đánh trúng sau lưng Hàn Lập, khiến hắn bị kích bay và pháp lực tan hơn phân nửa dù có Bạch Lân Thuẫn chống đỡ. Hàn Lập phóng mấy ngàn Phệ Kim Trùng phản công, còn Lệnh Hồ lão tổ và bạch y nữ tử lần lượt dùng viên hoàn và Ngưng Quang Bảo Kính hiệp trợ nhưng không giữ chân được cổ ma. Cuối chương, Hàn Lập tiếp tục triệu ra mười mấy Khôi Lỗi đầu hổ mình người, xếp hàng chặn đường truy kích của cổ ma."},{"chuong":841,"tieuDe":"Liên Thủ Kháng Ma","tomTat":"Ma hồn chiếm thân xác Nam Lũng Hầu phá vây đám hồ yêu Khôi Lỗi, dùng hắc khí đánh vỡ trảo mang rồi hủy diệt hai con Khôi Lỗi để lao thẳng tới Hàn Lập. Hàn Lập đã lặng lẽ thả Thiên Tuyệt ma thi đánh lén phía sau, buộc ma hồn phải thu quyền né tránh, nhờ đó hắn khôi phục quyền khống chế pháp lực. Khi Hàn Lập hiện ích Tà Thần Lôi và Tử La cực hỏa, ma hồn nhận ra cơ hội áp sát đã mất, đồng thời càng kiêng kỵ vì Phệ Kim Trùng cũng phá được quỷ trảo bay trở về. Ma hồn quyết giết Hàn Lập để trừ hậu hoạn, bắt đầu ma hóa thân xác Nam Lũng Hầu, tỏa ma khí và biến hình dữ dội. Hàn Lập cùng Lệnh Hồ lão tổ và Đại trưởng lão Yểm Nguyệt Tông liên thủ dùng thần lôi, tử hỏa, Phệ Kim Trùng, ngũ sắc quang trụ và viên hoàn trắng truy kích, nhưng ma hồn hóa thành đoàn hắc khí né tránh cực nhanh. Đại Diễn Thần Quân truyền âm khuyên Hàn Lập bỏ chạy vì Cổ ma thực chiến quá phong phú, song Hàn Lập vẫn phóng hơn mười thanh kim sắc tiểu kiếm, hóa thành hơn trăm đạo kim quang để bày Đại Canh Kiếm Trận đối địch."},{"chuong":842,"tieuDe":"Hai Đầu Bốn Tay","tomTat":"Hàn Lập hỏi Đại Diễn Thần Quân về Trụy Ma cốc và được cảnh tỉnh rằng cổ ma trong cốc cực kỳ lợi hại, đến mức hảo hữu của Thần Quân năm xưa liên thủ mà chỉ một người thoát được. Hắc khí tan đi, Nam Lũng Hầu do Ma hồn chiếm xác hiện thành quái vật hai đầu bốn tay, khiến Lệnh Hồ lão tổ và bạch y nữ tử kinh hãi. Trong giao chiến, Ma hồn bắt lấy Minh Dương Hoàn, phun hắc dịch ô uế cổ bảo, cắt đứt liên hệ của Lệnh Hồ lão tổ với bảo vật và cưỡng đoạt thành công; hắn còn lộ ra lá cờ đen của Lỗ Vệ Anh và tiểu kiếm từ cổ tu di hài đã bị ma hóa. Phệ Kim Trùng của Hàn Lập sợ hãi trước hình dạng cổ ma, khiến Hàn Lập liên tưởng đến Phạm Thánh Chân Phiến và tượng yêu ma ba đầu sáu tay của Thương Khôn Thượng Nhân. Khi một tiếng rống bí ẩn vang lên từ xa, Ma hồn lập tức bỏ chiến trường bay về hướng đó và phát tiếng huýt sáo hô ứng, làm Hàn Lập nghi ngờ còn có cổ ma khác. Sau đó Lệnh Hồ lão tổ và bạch y nữ tử tạ ơn Hàn Lập; lão tiết lộ các tu sĩ đồng hành đều bị Nam Lũng Hầu móc lấy Nguyên Anh, còn bạch y nữ tử sau khi chứng kiến thần thông của Hàn Lập thì bỏ ý định báo thù. Hàn Lập muốn cùng hai người theo dõi Ma hồn nhưng bị từ chối vì nguy hiểm quá lớn, rồi khi ngẩng đầu nhìn về hướng tiếng rống, sắc mặt hắn đột nhiên đại biến."},{"chuong":843,"tieuDe":"Phi Nga Phác Hỏa","tomTat":"Hàn Lập, Lệnh Hồ lão tổ và Đại trưởng lão Yểm Nguyệt Tông nhìn thấy ở chân trời hắc tử quang mang chứa ma khí ngập trời đang ép lục sắc vân vụ của Ngụy Vô Nhai xuống phía dưới. Đại trưởng lão Yểm Nguyệt Tông nhận ra đó là Phúc Thi Độc Vân, nhưng cả ba nhanh chóng hiểu rằng Ngụy Vô Nhai đang rơi vào thế hạ phong trước ma vật cực mạnh. Một đạo thần thức âm lãnh quét qua khiến họ biết mình đã bị chú ý; Hàn Lập phân tích nếu ma vật vừa truy kích họ cũng nhập cuộc thì Ngụy Vô Nhai khó chống nổi. Đúng lúc đó, hắn phát hiện Thiên Tinh Chân Nhân, Trình sư huynh của Lạc Vân Tông và một lão giả xa lạ đang bay tới chiến trường vì tưởng có dị bảo. Vì Trình sư huynh từng đối xử tốt với mình, Hàn Lập quyết định tiến đến trợ giúp nếu còn cơ hội, nhưng cũng chuẩn bị dùng Huyết Ảnh Độn chạy trốn nếu tình thế tuyệt vọng, đồng thời ép Lệnh Hồ lão tổ và Đại trưởng lão Yểm Nguyệt Tông đi cùng. Ở phía sau, Đông Môn Đồ dẫn ba Ngũ Hành Linh Anh còn lại tiếp cận với ý định nhân loạn thủ lợi. Trưởng lão họ Chung của Quỷ Linh Môn cũng mang đệ tử bay tới, vì Linh Chúc quả mấu chốt để ông tiến vào Nguyên Anh hậu kỳ đã bị người khác hái mất và ông nghi kẻ hái đang ở gần chiến trường."},{"chuong":844,"tieuDe":"Song Ma Hội","tomTat":"Hàn Lập không thu hồi Thiên Tuyệt ma thi và hồ yêu Khôi Lỗi mà còn xuất thêm mười mấy cự quy Khôi Lỗi, cùng Lệnh Hồ lão tổ và Đại trưởng lão Yểm Nguyệt Tông tiến gần chiến trường. Nhóm tu sĩ quan sát thấy Cổ ma đầu quỷ thân người đang bị ma khí bao phủ, dùng hỏa cầu đen giao tranh với lục sắc độc vân của Ngụy Vô Nhai. Hàn Lập nhận định ma vật này đáng sợ hơn Nam Lũng Hầu và truyền âm cảnh báo Trình sư huynh, để ông chuyển lời cho Thiên Tinh Chân Nhân cùng lão giả mặt đầy nếp nhăn. Ngụy Vô Nhai tiết lộ Cổ ma là yêu ma thượng cổ bị phong ấn trong Trụy Ma Cốc, do bọn Vương môn chủ vô ý giải thoát; Vương môn chủ và Vương Thiên Cổ đã chết trong vụ nổ khe hở không gian, còn ông bị thương nặng và đã cầu viện Mộ Lan pháp sĩ. Khi Cổ ma mở mắt quét thần thức, nhiều tu sĩ chấn động lùi bước, riêng Hàn Lập nhờ Đại Diễn Quyết nên nhìn thẳng đáp trả. Cuối chương, Cổ ma dùng hỏa cầu buộc Nam Lũng Hầu dạng hai đầu bốn tay hiện thân, hai bên đối thoại hé lộ Nam Lũng Hầu từng phóng xuất Cổ ma để thôn phệ nguyên thần một tu sĩ, nhưng nay Cổ ma đã tự chủ và phản lại hắn."},{"chuong":845,"tieuDe":"Ma Mạc","tomTat":"Cổ ma đối diện Ma hồn và tuyên bố phân hồn đã có ý thức riêng, không còn nghe lệnh chủ nguyên thần. Hắn cho biết mình đã chiếm ma thể bị phong ấn, dùng Giải Thể Hóa Hình tạo lại thân thể, tổn thất lớn tu vi nhưng vẫn muốn thôn phệ Ma hồn rồi mở thông đạo về Thánh giới. Ma hồn tự nhận thân thể bị ma hóa tạm thời không bằng Cổ ma, nhưng dựa vào thân phận chủ nguyên thần và cấm chế từng hạ để giữ thế, đồng thời đề nghị tạm liên thủ cắn nuốt các Nguyên Anh tu sĩ trước. Hàn Lập trấn định phân công Ngụy Vô Nhai tiếp tục kiềm chế Cổ ma, để Lệnh Hồ lão tổ và Đại trưởng lão Yểm Nguyệt Tông hiệp trợ, còn mình cùng nhóm Trình sư huynh đối phó Ma hồn nhằm kéo dài thời gian. Cổ ma phát động ma quang hắc tử bao trùm phạm vi hơn mười dặm, Ngụy Vô Nhai dùng độc vụ và Độc Giao chống đỡ, Lệnh Hồ lão tổ dùng Ngọc Như Ý cùng bích lục tiểu ấn, Đại trưởng lão Yểm Nguyệt Tông dùng Ngưng Quang Bảo Kính phá quang. Trình sư huynh cùng hai đồng bạn lập trận phòng thủ và mời Hàn Lập tụ lại, nhưng Hàn Lập từ chối vì không quen phối hợp. Khi phát hiện ma quang có thể hấp thu pháp lực qua vòng bảo hộ, Hàn Lập dùng điện hồ đẩy ma quang ra xa, điều động Thiên Tuyệt ma thi cùng khôi lỗi phòng thủ rồi thi triển Thanh Minh Linh Nhãn quan sát phía trước và giật mình."},{"chuong":846,"tieuDe":"Tái Chiến Ma Hồn","tomTat":"Hàn Lập dốc toàn lực vận Minh Thanh Linh Nhãn nhưng vẫn chỉ nhìn thấy thân ảnh Ma hồn mơ hồ trong ma quang, nên nhanh chóng đổi sang thả Phệ Kim Trùng tản thành lưới cảm ứng để tự bảo vệ trước thế đánh lén. Ma hồn bị ép hiện thân, dùng Hám Ba ma công phun sóng khí đen đánh rơi đàn trùng, nhưng Hàn Lập bất ngờ tung ra lôi cầu Ích Tà Thần Lôi áp súc làm quỷ đầu của đối phương bị thương. Khi Phệ Kim Trùng tự hồi phục bay lên, Ma hồn nhận ra đây là linh trùng chưa trưởng thành và tiết lộ bản thể của mình ở Thánh giới có Ma điệp lấy chúng làm thuốc bổ. Cùng lúc đó, nhóm Trình sư huynh từ bên ngoài ra tay bằng phi kiếm, ngọc xích và pháp bảo hình thoi nhưng lập tức bị Ma hồn dùng ba bảo vật ma hóa phong tỏa toàn bộ. Hàn Lập nhân cơ hội phóng ra hàng chục phi kiếm để bố trí Đại Canh Kiếm Trận, song Ma hồn cảm nhận uy hiếp nên quyết định xông thẳng tới ngăn cản, còn tuyên bố sẽ nuốt Nguyên Anh của hắn trước. Để kéo dài thời gian, Hàn Lập buộc phải huy động Phệ Kim Trùng cùng các khôi lỗi phối hợp chặn địch. Cuối cùng Ma hồn bộc phát ma công Thánh giới, phun hắc mang, làm chấn động không gian và hiện ra một tầng vảy đen như chiến giáp, khiến Hàn Lập kinh hãi cực độ."},{"chuong":847,"tieuDe":"Ma Kiếm Tái Hiện","tomTat":"Ma hồn biến thân thành hình thái hai đầu sáu tay, đối đầu Thiên Tuyệt ma thi và nhanh chóng chiếm thượng phong. Hắn dùng trảo mang xuyên thủng lồng ngực thi tiêu, kẹp cứng tiêm trùy tam sắc, rồi thi triển Ma âm phá hủy toàn bộ Phệ Kim trùng tam sắc bùng ra từ tiêm trùy. Sau đó Ma hồn dùng gai xương và hắc hỏa diễm hạ gục Thiên Tuyệt ma thi, rồi tiếp tục phá hủy từng con hồ yêu khôi lỗi của Hàn Lập với tốc độ gần như thuấn di. Hàn Lập nhận ra Đại Canh Kiếm trận khó bố trí, lần đầu sau khi kết Nguyên Anh cảm thấy bất an, nên lập nhiều lớp phòng ngự bằng kiếm khí, kim sắc điện y và Tử La Thiên Hỏa. Trong thế nguy cấp, Hàn Lập rút Huyết Ma kiếm ra; thanh kiếm đỏ như máu tự bay lên, phóng lớn sau khi nhận tinh khí xanh nhưng hút mạnh chân nguyên khi hắn thử vung. Ma hồn vừa thấy kiếm liền chấn động, gọi đó là thánh khí Thánh giới năm xưa lưu lại nhân giới và đề nghị Hàn Lập giao kiếm để đổi mạng. Hàn Lập dò hỏi nguồn gốc pháp khí Thượng cổ ma giới, nhưng khi Ma hồn né tránh và tiếp tục dụ dỗ, hắn từ chối với vẻ trào phúng vì không tin lời hứa của đối phương."},{"chuong":848,"tieuDe":"Hắc Nhận","tomTat":"Ma hồn không bị lời khiêu khích của Hàn Lập làm dao động, sau khi đánh giá kiếm ảnh, tử hỏa và Huyết Ma Kiếm liền nhận ra không thể nhanh chóng hạ hắn. Đúng lúc ba tu sĩ Nguyên Anh sơ kỳ hợp lực phá vòng cấm ma hóa, Ma hồn lập tức chuyển mục tiêu sang họ, dùng độn tốc cực nhanh áp sát khiến Hàn Lập phải lên tiếng cảnh báo. Ba người vội thi triển thủ đoạn phòng thân: phù lục hóa hỏa vân, hỏa hồ tinh thông Hỏa độn và hai ác quỷ khôi lỗi của Thiên Tinh chân nhân cùng xuất chiến. Ma hồn vận dụng bốn tay ngưng tụ ra bốn thanh Hắc Nhận quỷ dị, khiến không gian vặn vẹo, đổi lại cái đầu người phía sau bị rút mất lượng lớn tinh huyết. Chỉ trong chớp mắt, Hắc Nhận chém nát hai khôi lỗi, giết hỏa hồ trong biển lửa, làm ba tu sĩ kinh hãi. Hàn Lập tế Thiên Trọng Phong cứu viện, nhưng Ma hồn hợp bốn nhận thành một cự nhận màu đen, chẻ đôi cự phong ngay giữa không trung. Ba tu sĩ hoảng loạn tách ra bỏ chạy, ngân phát lão giả lao về phía Hàn Lập còn hai người kia bay về hướng Ngụy Vô Nhai. Vì đang hoàn thành những bước cuối của Đại Canh Kiếm Trận, Hàn Lập không thể tự mình tới cứu, chỉ có thể điều khiển cự quy khôi lỗi phóng băng trùy nhằm kéo chậm Ma hồn đôi chút."},{"chuong":849,"tieuDe":"Ma Uy Bạo Ngược","tomTat":"Ma hồn dùng đao mang đen phá vỡ nhiều tầng phòng ngự của nhóm tu sĩ Nguyên Anh, rồi biến cự nhận thành hai cây quang mâu đen để đồng thời công kích nhiều hướng. Một mâu nhắm vào lão giả, một mâu bắn về phía Trình lão, khiến cục diện nhanh chóng nghiêng hẳn về phía ma hồn. Sau khi phá thế phòng thủ, ma hồn tiếp tục bộc phát ma uy dữ dội, truy sát và áp chế các đối thủ còn lại trong chiến trường. Đến cuối chương, một cự kiếm thuận thế mang theo diện hồ hung hăng chém xuống, đẩy trận chiến tới thời khắc nguy cấp."},{"chuong":850,"tieuDe":"Khốn Ma","tomTat":"Ma hồn dùng độn tốc quỷ dị tránh cự kiếm Kim Lôi Trúc, phun tinh huyết hóa hai quang mâu thành huyết mâu đỏ để đánh văng cự kiếm, khiến Hàn Lập bị chấn động thần thức nhẹ nhưng nhanh chóng hồi phục. Hàn Lập thu kiếm, tản phi kiếm thành nhiều đạo thanh mang để dụ Ma hồn đuổi theo, đồng thời ngăn ngân phát lão giả ra tay quá sớm. Ma hồn phóng ma khí che mắt rồi ẩn thân tập kích từ dưới đất, nhưng Hàn Lập kịp kéo ngân phát lão giả né khỏi hai đạo huyết mang. Khi Ma hồn xông tới, Hàn Lập phát động Đại Canh Kiếm Trận, để vô số kim sắc ti tuyến co lại từ bốn phía và cắt nát các đòn phá vây của đối thủ. Bị nhốt trong không gian ngày càng hẹp, Ma hồn thử nhiều độn thuật và binh khí ma công nhưng không thoát, buộc phải hú dài cầu viện Cổ ma. Cổ ma từ trong ma hỏa phóng ra với thân hình đại ma vật hai đầu bốn tay, trong lúc ngân phát lão giả phát hiện hai nhóm tu sĩ viện binh cũng đang tới từ hai phía chân trời. Hàn Lập dập tắt ý định rút lui, sai tử sắc hỏa điểu nghênh kích Cổ ma, rút Huyết Ma Kiếm và dán Hàng Linh Phù lên người. Giao ảnh Độc Giao cấp tám dài hơn mười trượng hiện ra gầm vang, khiến Cổ ma, Ma hồn và ngân phát lão giả đều kinh ngạc."},{"chuong":851,"tieuDe":"Ý Ngoại Kinh Biến","tomTat":"Giao ảnh nhập vào lưng Hàn Lập, khiến hắn hiện huyết sắc lân phiến, mọc sừng giao và nhờ Hàng Linh Phù tạm thời đạt tới Nguyên Anh Sơ Kỳ đỉnh cấp. Hắn dốc toàn bộ pháp lực khu sử Huyết Ma Kiếm, quyết giết Ma hồn trước khi cổ ma bên ngoài tới cứu. Ma hồn hoảng sợ, tự chặt tay hóa thành cốt kiếm bạch cốt phủ ma khí đen để đối đầu kiếm quang huyết sắc. Hai luồng kiếm quang va chạm dữ dội, đúng lúc đó một khe hở không gian bất ngờ mở ra, phát ánh sáng mờ hút cả Hàn Lập lẫn Ma hồn vào, còn Ngân phát lão giả nhờ bị khí lãng đẩy ra xa nên thoát nạn. Hàn Lập phát hiện linh lực toàn thân biến mất, chỉ kịp dùng thần thức gọi Thanh Trúc Phong Vân Kiếm bay theo, nhưng cổ ma thuấn di tới chụp giữ được hai thanh phi kiếm. Khe hở biến mất, các nhóm tu sĩ Ngự Linh Tông và Quỷ Linh Môn kéo tới, trong khi cổ ma hiện bốn khẩu quang nhận đen chuẩn bị giao chiến."},{"chuong":852,"tieuDe":"Ngân Diễm","tomTat":"Hàn Lập bị khe không gian nuốt vào, pháp lực nhất thời mất sạch nhưng nhờ thân thể bán giao bán nhân nên không hôn mê và nhanh chóng khống chế được thân hình khi linh lực hồi phục. Hắn rơi vào một mảnh không gian nhỏ linh khí nồng đậm, có linh dược và kiến trúc dang dở; Ma hồn cũng bị hút vào, nhận ra đây là hài cốt không gian Linh Miểu Viên và lập tức chuẩn bị giao chiến. Hàn Lập phát hiện Thanh Trúc Phong Vân Kiếm thiếu hai phi kiếm mắc kẹt ngoài không gian, khiến Đại Canh Kiếm Trận không thể bố trí, nên chỉ có thể dựa vào Ích Tà Thần Lôi, Tử La Thiên Hỏa và Hàng Linh Phù. Khi Ma hồn tung ma khí phối hợp Cổ ma phong áp tới, cấm chế trong không gian bỗng phát động ngân sắc hỏa diễm, trong nháy mắt thiêu diệt Ma hồn và quét sạch ma khí. Đại Diễn Thần Quân giải thích ngọn lửa bạc này là cấm chế của tu sĩ Linh giới, từ đó suy ra Linh Miểu Viên là dược viên không gian do đại thần thông Linh giới tạo ra và có liên hệ với biến cố thượng cổ chống cổ ma. Sau trận, Hàn Lập thu các pháp khí Ma hồn đã gần như phế bỏ, giải trừ Hàng Linh Thuật và nhận ra Hàng Linh Phù chỉ còn dùng thêm một lần. Hắn triệu Ngân Nguyệt ra dò xét cấm chế, đồng thời dùng thần thức kiểm tra từng tấc không gian, cuối cùng phát hiện điều bí ẩn ở một góc và tỏ vẻ hưng phấn."},{"chuong":853,"tieuDe":"Giáng Vân Đan Và Tuyết Phách Hoàn","tomTat":"Hàn Lập cùng Đại Diễn Thần Quân khảo sát tàn tích dược viên trong không gian lạ và phát hiện nhiều linh dược thượng cổ, trong đó Uyển Mộng Quả có dược tính vài vạn năm. Nhờ ngọc giản xanh nhạt do nữ tử họ Tống từng đưa, Hàn Lập đối chiếu linh dược với các đan phương thượng cổ và nhận ra có thể miễn cưỡng luyện Giáng Vân Đan, đồng thời Tuyết Phách Hoàn cũng có hi vọng thành đan. Giáng Vân Đan là linh đan tinh tiến tu vi, có thể giúp hắn đẩy tới Nguyên Anh sơ kỳ đỉnh cấp rồi thử phá trung kỳ, còn Tuyết Phách Hoàn phụ trợ thần thông băng hàn như Kiềm lam Băng Diễm và Tử La Thiên Hỏa. Khi di thực linh thảo, Hàn Lập phát hiện ba loại không thể mang đi, trong đó có một nguyên liệu chủ yếu của Giáng Vân Đan, khiến số đan có thể luyện bị hạn chế. Hắn thử dùng tiểu bình thần bí nhưng vì không gian này không có nhật nguyệt tinh thần nên tiểu bình mất hiệu dụng. Sau đó Hàn Lập chuyển sang tìm đường rời khỏi không gian, nghe Ngân Nguyệt báo lòng đất chỉ có cấm chế không đầy đủ và không có dị thường, rồi quyết định mạo hiểm bay lên dò vùng vân vụ trên không dù nơi đó từng diệt sát Ma hồn."},{"chuong":854,"tieuDe":"Trệ Lưu","tomTat":"Hàn Lập bay lên đỉnh không gian để kiểm tra tầng cấm chế phía trên, dùng quang cầu thử đường rồi tự mình xuyên qua lớp ngân sa màu bạc mà không gặp nguy hiểm. Sau đó hắn phối hợp thần thức và Minh Thanh Linh Nhãn dò xét vách ngăn không gian nhưng vẫn không phát hiện lối thoát, nên tiếp tục dùng hơn mười thanh phi kiếm hợp thành cự kiếm vàng, gia trì Ích Tà Thần Lôi cùng tử sắc hỏa diễm để chém vách không gian. Đòn đánh làm cả không gian rung chuyển nhưng vách chỉ vặn vẹo chốc lát rồi trở lại bình thường. Đại Diễn Thần Quân liền chỉ ra rằng lần Hàn Lập lọt vào đây là do đòn giao kích tại nhân giới vô tình đánh trúng điểm yếu của tàn hài không gian, đồng thời nhắc hắn điểm yếu ấy không cố định ở bốn vách. Theo gợi ý này, Hàn Lập mở rộng thần thức tìm khắp không gian và cuối cùng phát hiện một lam sắc quang diễm nhỏ như hạt gạo, chính là điểm yếu không gian. Dù từng nghĩ tới việc dùng Huyết ma kiếm phá điểm đó, hắn vẫn bị khuyên rằng với tu vi hiện tại chưa đủ, cần khổ tu tới Nguyên Anh trung kỳ rồi mới có vài phần hy vọng mở đường ra. Cân nhắc việc Phong hồ chú của Nam Cung Uyển còn có thể bị bí thuật trì hoãn hơn trăm năm, Hàn Lập chấp nhận bị kẹt hai ba mươi năm và quyết định tận dụng linh khí cùng linh dược nơi đây để luyện Giáng Vân Đan, bắt đầu chuẩn bị tu luyện dài hạn."},{"chuong":855,"tieuDe":"Thoát Thân","tomTat":"Trữ Châu thuộc Đông Dụ quốc ở Thiên Nam, nằm cạnh Xương Châu có Trụy Ma Cốc, là vùng nhỏ nghèo linh khí nên chỉ có vài tiểu gia tộc tu tiên cư trú. Tại Linh Lân sơn phía tây nam Trữ Châu, ba gia tộc Hoàng, Lý, Vương cùng chiếm một linh mạch nhỏ và gắn bó với nhau vì linh tuyền vô danh trên chủ phong. Linh tuyền này không phải Linh Nhãn Chi Tuyền, nhưng nước suối hòa linh dược tẩm linh trà có thể giúp đệ tử Luyện Khí cấp thấp tẩy tủy dịch kinh, nên ba nhà phong kín lại và mười năm mới mở một lần. Trong ngày mở tuyền, Hoàng Nguyên Minh cùng hai Trúc Cơ trưởng lão dẫn hơn mười tu sĩ cao giai vận hành pháp trận, tháo cấm chế phù triện trên thạch bích để lộ ngọc trì bạch ngọc. Khi các đệ tử chuẩn bị lấy nước pha linh trà, phía trên ngọc trì bỗng xuất hiện tiếng sấm, ngũ sắc hà quang, quang cầu đen rồi hóa thành khe hở không gian. Một nam tử áo xanh bị ngũ sắc thải hà ném xuống ngọc trì, sau đó đứng dậy hong khô y phục và hỏi nơi này có phải Đông Dụ quốc không. Người ấy chính là Hàn Lập vừa thoát khỏi tàn tích Linh Miểu Viên, còn thời điểm hiện tại đã cách lúc khởi đầu đại chiến Trụy Ma Cốc hơn hai mươi bảy năm."},{"chuong":856,"tieuDe":"Thiên Nam Ma Ảnh","tomTat":"Hoàng Nguyên Minh cùng hai lão giả ba gia tộc đau lòng vì Linh tuyền trong ngọc trì bị Hàn Lập làm hao đi nhiều, nhưng vì e sợ tu vi của hắn nên chỉ dám cung kính tiếp đãi. Hàn Lập không có ý chiếm Linh tuyền mà hỏi các đại sự Thiên Nam gần đây, sau đó được mời về đại sảnh Hoàng gia uống linh trà. Trên đường và trong đại sảnh, hắn hỏi thêm tình hình Đông Dụ quốc, nghe lão giả mặt tròn giải thích vì sao tiểu gia tộc khó đưa đệ tử vào đại phái. Hàn Lập hứa sẽ ban lợi ích nếu câu trả lời khiến hắn hài lòng rồi truy vấn chuyện Trụy Ma cốc mở ra hơn hai mươi năm trước. Hoàng Nguyên Minh kể Quỷ Linh Môn từng tìm được cách nhập cốc ổn thỏa nhưng toán vào nội cốc vô ý thả hai yêu ma có thể cắn nuốt Nguyên Anh, khiến môn chủ chết tại chỗ. Một yêu ma bị các Nguyên Anh tu sĩ, Ngụy tiền bối và Mộ Lan thần sư liên thủ diệt sát, còn một con thoát ra ngoài, ở lại Nhân giới thôn phệ Nguyên Anh và gây đại kiếp cho Thiên Nam. Tam đại tu sĩ lập Diệt ma đội, sau có Đại Thượng Sư Mộ Lan tham gia, nhưng yêu ma giảo hoạt còn huyết tẩy nhiều gia tộc và tiểu phái trước khi bị bí thuật của một trưởng lão Ma đạo truy dấu. Cuối cùng nó bị vây tại Lạc Hồn sơn ở Phong Đô quốc khi gần khôi phục tới Hóa Thần kỳ, trận chiến với hai đại tu sĩ và một Mộ Lan thần sư khiến cả ngọn núi bị san phẳng."},{"chuong":857,"tieuDe":"Xoáy Nước","tomTat":"Hàn Lập nghe Hoàng Nguyên Minh kể về trận vây công Cổ ma và nhận thấy kết cục của Cổ ma vẫn mơ hồ, bởi có tin nói nó chết tại chỗ nhưng cũng có tin nói nó dùng bí thuật thoát vây. Từ việc nhóm Ngụy Vô Nhai không công khai kết quả, Hàn Lập nghi rằng trận chiến năm xưa còn biến cố chưa rõ. Hoàng Nguyên Minh tiếp tục kể sau khi yêu ma biến mất, gần bờ Vô Biên Hải phía Khê Quốc xuất hiện Đại tuyền qua phun linh khí, tinh lọc vùng biển và khiến bảy đảo linh mạch nổi lên, dẫn tới Đoạt đảo đại hội do tam đại tu sĩ mở ra. Nhiều tu sĩ từng xuống xoáy nước dò xét nhưng đều bị áp lực ép lui, ngay cả Chí Dương thượng nhân cũng không thể vượt quá khoảng ba ngàn trượng. Hàn Lập hỏi thêm tình hình Thiên Nam gần hai mươi năm, nhất là Mộ Lan nhân và chính ma lưỡng đạo, rồi tặng ba lão giả một đôi đoản qua thượng cấp pháp khí trước khi rời đi. Sau đó lão giả áo trắng suy ra vị tiền bối vừa đi có thể là Hàn Lập mất tích sau sự kiện Trụy Ma cốc, khiến Hoàng Nguyên Minh và lão giả mặt tròn kinh hãi. Khi đã bay xa, Hàn Lập trao đổi với Đại Diễn Thần Quân về việc phải tới Đại Tấn tìm tài liệu luyện Khôi Lỗi và trừ tà khí Huyết ma kiếm đang cản trở hắn tiến vào Nguyên Anh Trung Kỳ."},{"chuong":858,"tieuDe":"Trở Về Lạc Vân Tông","tomTat":"Hàn Lập bàn với Đại Diễn Thần Quân về Cổ ma, Ma giới và nguồn gốc ma công, qua đó biết rằng tu sĩ nhân loại ma hóa chưa chắc biến thành hình dạng quái dị, còn yêu tộc và Cổ ma có thể tồn tại liên hệ sâu xa từ thời thượng cổ. Hắn liên tưởng đến Phạm Thánh Chân Phiến và công pháp ba đầu sáu tay trên đó, nhưng vì chỉ có tàn phiến và chuyện này tạm thời không liên quan đến bản thân nên quyết định không truy cứu. Sau đó, Hàn Lập yêu cầu Đại Diễn giao phương pháp luyện chế bảo phiến phỏng chế; Đại Diễn đưa ra bản đã gia giảm từ Thất Diễm Phiến thành Tam Diễm Phiến, tuy uy lực giảm nhiều nhưng vẫn là pháp bảo rất đáng gờm. Khi xem ngọc giản, Hàn Lập nhận ra lông Hạo Dương Điểu và vảy Xích Hỏa Giao cực khó kiếm, còn Đại Diễn lại nhân cơ hội chỉ ra Đại Tấn là nơi có manh mối và cũng là trung tâm tu tiên giới đáng để hắn đi một chuyến. Trước khi rời Đông Dụ quốc, Hàn Lập quay lại ngoài Trụy Ma cốc để cảm ứng Thiên Tuyệt ma thi, xác nhận nó vẫn còn sống nhưng bị kẹt trong cốc, đành tạm gác việc cứu ra đến lần cốc mở sau. Hai tháng sau, Hàn Lập trở về Vân Mộng Sơn và được đệ tử Lạc Vân Tông phát hiện, khiến toàn tông ra nghênh đón vị trưởng lão tưởng như đã mất tích sau biến cố Trụy Ma cốc. Trong đại điện, Trình sư huynh cảm tạ hắn từng cứu mạng và báo Nam Cung Uyển vẫn bình an, còn Lữ Lạc sau khi quan sát kỹ thì kinh ngạc nhận ra Hàn Lập đã tiến cấp Nguyên Anh Trung Kỳ."},{"chuong":859,"tieuDe":"Uy Đan","tomTat":"Trình sư huynh và Lữ Lạc kinh ngạc phát hiện Hàn Lập đã tiến cấp Nguyên Anh Trung Kỳ, còn Hàn Lập giải thích mình nhờ cơ duyên trong Trụy Ma Cốc và nhiều năm khổ tu mới đạt được. Hàn Lập hỏi lại những chuyện xảy ra sau khi mình bị khe hở không gian cuốn đi, qua đó biết tu sĩ Thiên Nam và Mộ Lan nhân từng hợp lực chống Cổ ma, Nhạc thượng sư triệu Mộ Lan thánh cầm, Trọng Thần Sư chém rụng một đầu Cổ ma, nhưng phe tu sĩ cũng thương vong nặng và Quỷ Linh Môn gần như mất sạch lực lượng cấp cao nhập cốc. Trình sư huynh và Lữ Lạc cho biết Cổ ma sau đó bị trọng thương trong trận vây diệt nhưng dùng bí thuật trốn thoát, bị truy đến gần Mộ Lan thảo nguyên rồi mất dấu, nên chỉ có thể đoán nó đã chết vì thương thế hoặc trốn sang Đại Tấn. Hàn Lập nói mình đã tìm được dược vật trong Trụy Ma Cốc và được hai lão đưa đến mật thất phong băng Nam Cung Uyển. Trong mật thất, hắn thấy Nam Cung Uyển vẫn bị phong như nữ đồng, lấy Yêu Đan đỏ sậm trong hộp ngọc và dùng pháp quyết đưa vào miệng nàng để thử giải Phong Hồn Chú. Sau khi mặt nàng hiện hồng quang nhưng chưa tỉnh, Hàn Lập ở lại quan sát hồi lâu rồi rời đi, nói cần thêm thời gian mới biết hiệu quả. Trên đường trở về Tử Mâu Phong, hắn biết động phủ vẫn được giữ nguyên và Mộ Phái Linh đã đạt Giả Đan Kỳ, từ đó suy tính lại kế hoạch liên quan Điên Đảo Phượng Bồi Nguyên Công vì bản thân đã sớm đột phá bình cảnh."},{"chuong":860,"tieuDe":"Thản Ngôn","tomTat":"Hàn Lập trở lại động phủ sau hơn hai mươi năm, thấy mọi thứ vẫn nguyên vẹn, từ tam sắc Phệ Kim Trùng trong đại sảnh đến Huyền Thiên Tiên Đằng và Cửu Khúc Linh Sâm trong dược viên. Hắn đưa Phệ Kim Trùng chờ tiến hóa vào trùng thất, rồi thả hơn hai mươi ấu trùng Lục Dực Sương Công từ Túi linh thú đặc chế rất lạnh vào nơi nuôi riêng. Từ kinh nghiệm giao chiến với Cổ ma ở Trụy Ma Cốc, hắn nhận ra Lục Dực Sương Công nếu bồi dưỡng lên cao có thể bù nhược điểm phi độn chậm của Phệ Kim Trùng và còn hỗ trợ tu luyện Tử La Thiên Hỏa. Sau đó Hàn Lập cảm ứng Mộ Phái Linh tới ngoài cửa, sai Ngân Nguyệt dẫn nàng vào đại sảnh. Mộ Phái Linh chúc mừng Hàn Lập bình an trở về và tiến giai Nguyên Anh Trung Kỳ, đồng thời nói mình vẫn ở lại vì thân phận thị thiếp và ân tình với hắn. Hàn Lập thẳng thắn hỏi chuyện Kết Đan, hứa dùng linh dược không thuộc Thiên Nam để tăng xác suất thành công cho nàng, nhưng yêu cầu nàng sau khi Kết Đan chuyển tu Điên Đảo Phượng Bồi Nguyên Công nhằm về sau trợ hắn trùng kích bình cảnh Nguyên Anh Hậu Kỳ. Hắn cũng nói rõ nếu nàng không muốn thì sẽ không ép, để nàng tự Kết Đan rồi giải trừ Cấm thần thuật, trả tự do và cắt đứt liên quan. Mộ Phái Linh nghe điều kiện này thì ngoài ý muốn, trong lòng rối loạn và chưa đưa ra quyết định."},{"chuong":861,"tieuDe":"Thư Mời","tomTat":"Hàn Lập nói rõ với Mộ Phái Linh rằng Điên Đảo Phượng Bồi Nguyên Công yêu cầu nữ tử giữ thân xử nữ trước khi đạt Kết Đan hậu kỳ, nên quan hệ hai người tạm thời vẫn giữ như cũ. Hắn hứa nếu Mộ Phái Linh giúp mình tiến tới Nguyên Anh hậu kỳ thì sẽ tìm cách hỗ trợ nàng kết Nguyên Anh, dựa vào Bạn Yêu Thảo cấp tám và Cửu Khúc Linh Sâm. Mộ Phái Linh hỏi rõ công pháp, biết nó tu luyện nhanh nhưng yếu khi đối địch, rồi chấp nhận an bài và xem tiền đồ mình phó thác cho Hàn Lập; nàng còn ở lại nghe hắn chỉ điểm kết đan hơn nửa ngày trước khi về Tư Phong. Sau đó Hàn Lập giải thích với Ngân Nguyệt rằng hắn muốn bồi dưỡng Mộ Phái Linh thành trợ thủ thân cận để xử lý việc ngoài và chuyện tông môn, còn bản thân sẽ bế quan luyện hóa tia Kiền Lam Băng Diễm cuối cùng rồi nghiên cứu cách mở Hư Thiên Đỉnh. Ngày hôm sau, Trình sư huynh và Lữ Lạc đến động phủ, mang thư mời của Cổ Kiếm Môn và Bách Xảo Viện, đồng thời báo Bách Xảo Viện sắp làm lễ nhận chủ cho một pháp bảo mới luyện chế. Hàn Lập nhận lời đi xem lễ, lại nghe tin Kim Võ Hoàn của Cổ Kiếm Môn vừa xuất quan sau bảy tám mươi năm bế quan. Cuối chương, Hàn Lập phát hiện thân thể Trình sư huynh không ổn; Trình sư huynh thừa nhận mình chỉ còn khoảng mười năm thọ nguyên và chuẩn bị giao việc Lạc Vân Tông về sau cho Hàn Lập cùng Lữ Lạc trông coi."},{"chuong":862,"tieuDe":"Phi Kiếm Cùng Khôi Lỗi","tomTat":"Hàn Lập an ủi Trình sư huynh về chuyện thọ nguyên rồi giao ngọc giản liệt kê nhiều tài liệu hiếm, nhờ Trình sư huynh và Lữ Lạc phái đệ tử đi các phường thị Thiên Nam thu mua. Lữ Lạc giao lại túi trữ vật chứa số tài liệu nội tông đã thu thập nhiều năm cùng một khối Canh Tinh nhỏ, đồng thời từ chối nhận linh thạch vì xem đó là bù đắp công lao Hàn Lập từng xuất chiến khi Mộ Lan Nhân xâm chiếm. Khi Hàn Lập hỏi về hai khẩu phi kiếm thất lạc, Trình sư huynh cho biết chúng đã bị Cổ ma lấy mất; Hàn Lập ngoài mặt xem nhẹ nhưng sau đó thừa nhận với Ngân Nguyệt rằng hai thanh thuộc Đại Canh Kiếm Trận nhất định phải thu hồi. Ngân Nguyệt gợi ý luyện kiếm thay thế bằng Canh Tinh, nhưng Hàn Lập cho rằng khối Canh Tinh quá nhỏ và chỉ tính tìm Cổ ma sau khi mở được Hư Thiên Đỉnh hoặc luyện thành Thất Diễm Phiến. Đại Diễn Thần Quân nhắc Hàn Lập luyện chế khôi lỗi, khẳng định nếu khôi lỗi thành phẩm được luyện ra thì uy lực không dưới ông lúc đương thời, đủ làm chỗ dựa tự vệ. Hàn Lập quyết định trước ngày đi xem lễ sẽ luyện hóa nốt tia Kiền Lam Băng Diễm cuối cùng, nếu còn thời gian thì luyện hai thượng cổ khôi lỗi cấp Nguyên Anh. Sáng hôm sau, Hàn Lập cùng Trình sư huynh và Lữ Lạc tới Bách Xảo Viện trong Vân Mộng Sơn mạch, được ba đệ tử Kết Đan Kỳ nghênh đón. Hàn Lập nhận ra lão giả cầm đầu từng chủ trì Thí Kiếm Đại Hội, còn đối phương cũng nhận ra hắn nhưng nhanh chóng che giấu sắc mặt, khiến Hàn Lập đánh giá người này có tâm cơ."},{"chuong":863,"tieuDe":"Càn Khôn Tháp","tomTat":"Ba người của Phó lão giả dẫn nhóm Hàn Lập vượt qua cấm chế đại trận, tiến sâu vào Bách Xảo Viện và nhìn thấy sân rộng, đài đá cùng vách núi đầy động phủ. Trình sư huynh giải thích dưới núi có Phế Hỏa Trì, nhờ đó Bách Xảo Viện đặt luyện khí thất và động phủ cao giai trong vách núi, khiến Hàn Lập chú ý suy nghĩ. Tại cửa động trên cao, Phùng trưởng lão và Đinh trưởng lão tiếp đón nhóm Lạc Vân Tông, kinh ngạc khi phát hiện Hàn Lập đã là Nguyên Anh Trung Kỳ, còn Hàn Lập vẫn khiêm tốn tự nhận căn cơ chưa vững. Đinh trưởng lão tiết lộ ba huynh đệ Bách Xảo Viện vừa luyện chế thành Càn Khôn Tháp, một trong tam đại chi bảo trấn phái, sắp làm nghi thức nhận chủ. Khi bị hỏi chuyện Trụy Ma Cốc, Trình sư huynh chỉ nói thu được vài bảo vật bình thường, còn Hàn Lập giấu chuyện Linh Miểu Viên và nói nửa thật nửa giả rằng mình không được cổ bảo lợi hại nhưng tu vi tăng một tầng. Sau đó Lữ Lạc hỏi việc Kim lão quái Cổ Kiếm Môn xuất quan, các trưởng lão Bách Xảo Viện cho biết Kim lão quái đã gửi Truyền Âm phù báo sẽ dự lễ và có thể muốn gặp Hàn Lập. Lữ Lạc nhận ra buổi tụ hội có dấu hiệu liên quan tới việc phân chia lại thứ tự Vân Mộng Sơn, nhưng Phùng trưởng lão nói danh nghĩa vẫn là ba tông phái gặp mặt trao đổi. Cuối chương, Truyền Âm phù báo người Cổ Kiếm Môn đã tới, Phùng trưởng lão ra đón rồi dẫn vào ba tu sĩ, trong đó người đi đầu là một lão giả khôi ngô tóc bạc, ánh mắt hung tợn và đôi tay to khác thường."},{"chuong":864,"tieuDe":"Xem Lễ","tomTat":"Hàn Lập cùng các tu sĩ tam tông dự buổi xem lễ tại Bách Xảo Viện, nhưng vừa gặp mặt đã bị Kim lão quái chú ý và nhận ra tu vi Nguyên Anh Trung kỳ. Kim lão quái xoáy vào tốc độ tiến cấp và xuất thân Hoàng Phong cốc của Hàn Lập, khiến Trình sư huynh phải đứng ra khẳng định hiện tại Hàn Lập là trưởng lão Lạc Vân Tông. Phùng trưởng lão dâng Hỏa Lưu quả để làm dịu không khí, trong lúc các lão quái tiếp tục dò xét nhau và Minh Hĩnh của Cổ Kiếm Môn được giới thiệu cùng công pháp Bách Hoa Dương Xuân Quyết, pháp bảo ngàn năm Hoàng Mộc. Liệt Hỏa lão quái xuất hiện, xác nhận mọi việc đã chuẩn bị xong và mời mọi người vào xem nghi thức nhận chủ Càn Khôn Tháp. Tại đài cao, Ngọc sư đệ của Bách Xảo Viện đã tế bái hơn nửa canh giờ trước đỉnh đỏ để chuẩn bị nhận Càn Khôn Tháp làm bổn mạng pháp bảo. Khi chiếc đỉnh rung chuyển, linh quang và sóng nhiệt bùng lên, Ngọc sư đệ chống đỡ rồi đứng dậy chờ thời khắc mở đỉnh, còn Hàn Lập thầm đánh giá Bách Xảo Viện rất coi trọng người đệ tử trẻ này."},{"chuong":865,"tieuDe":"Khách Không Mời","tomTat":"Bách Xảo Viện bắt đầu nghi thức khai đỉnh: lão giả họ Phùng ra lệnh, các tu sĩ Kết Đan bày trận màn hào quang lam, hai tu sĩ trung niên kích hoạt cự đỉnh đỏ sậm để phóng ra pháp bảo cho thanh niên họ Ngọc truy đuổi nhận chủ. Hàn Lập dùng Minh Thanh Linh Nhãn nhìn ra bạch quang chính là Càn Khôn Tháp, một tháp nhỏ màu trắng có linh tính, còn thanh niên họ Ngọc vẫn chưa luyện hóa được pháp bảo nên chỉ dựa vào phi hành pháp khí đuổi theo. Trong lúc quan sát, Minh Hĩnh chủ động bắt chuyện và dò xét Hàn Lập bằng các tin đồn về Trụy Ma Cốc, Mộ Lan Thần sư và Đại Tấn; Hàn Lập giữ thái độ khiêm tốn nhưng nhận ra hương hoa trên người nàng có tác dụng ảnh hưởng tâm thần. Hắn nêu thẳng Bách Hoa Dương Xuân quyết khiến Minh Hĩnh biến sắc, cho thấy đã nhìn ra phần nào thủ đoạn của nàng. Ngay sau đó Hàn Lập cảm ứng có tu sĩ mạnh đang tới, rồi Chí Dương Thượng Nhân của Thái Chân Môn xưng danh từ xa khiến nghi thức nhận chủ bị tạm gác. Chí Dương vào Bách Xảo Viện, vui mừng thấy Hàn Lập ở đó và nói mình đang đi qua Khê Quốc thì nghe tin Hàn Lập bình an trở về nên đuổi tới. Ông xin các tu sĩ tam tông cho mình nói chuyện riêng với Hàn Lập, báo hiệu việc cần bàn có mức độ quan trọng vượt khỏi lễ nhận chủ đang diễn ra."},{"chuong":866,"tieuDe":"Yêu Cầu Của Chí Dương","tomTat":"Sau khi các tu sĩ hạ xuống, Chí Dương Thượng nhân dùng Cách âm trảo nói riêng với Hàn Lập và cảm tạ việc hắn từng ngăn Cổ ma chủ hồn trong Trụy Ma Cốc. Hàn Lập xác nhận Cổ ma chủ hồn đã bị tiêu diệt hoàn toàn, khiến Chí Dương yên tâm vì nguy cơ chủ hồn và phân hồn hợp thể tại Thiên Nam tạm thời không còn. Chí Dương kể Cổ ma phân hồn sau khi thoát cốc đã cắn nuốt nhiều tu sĩ Nguyên Anh, biến thành yêu dạng ba đầu sáu tay gần sánh Hóa Thân sơ kỳ, bị ba đại tu sĩ hợp lực đánh trọng thương nhưng vẫn trốn sang Đại Tấn. Sau đó ông hỏi thẳng về Kim Lôi Trúc và Ích Tà Thần Lôi của Hàn Lập, nói việc này liên lụy cả Thiên Nam tu tiên giới và vô danh đại tuyền qua ở Vô Biên Hải. Hàn Lập cảnh giác nhưng cuối cùng nhận lời ba tháng sau tới Thất Linh đảo gặp Chí Dương, Ngụy Vô Nhai và Hợp Hoan lão ma để nghe giải thích rõ. Trước khi rời đi, Chí Dương úp mở rằng chuyến đi này có thể đem lại thu hoạch ngoài ý muốn và lợi ích cho Lạc Vân Tông. Tại Bách Xảo Viện, Kim lão quái lấy địa vị Cổ Kiếm Môn và phân chia tài nguyên Vân Mộng Sơn làm lý do đòi tỷ thí với Hàn Lập; hai bên lập tức khai màn khi Kim lão quái tế ba khẩu kim sắc tiểu kiếm còn Hàn Lập gọi lam sắc hỏa cầu hóa thành hỏa điểu."},{"chuong":867,"tieuDe":"Thắng Bại","tomTat":"Kim lão quái vì cho rằng Hàn Lập khinh địch nên lập tức dùng kiếm quyết mạnh nhất, thi triển Hóa kiếm vi ti và Xuân ti trảm bằng hơn trăm đạo kim ti. Hàn Lập dùng Kiền Lam Băng Diễm hóa thành lam sắc hỏa điểu rồi quang liên, không những chống được kim sắc cự võng mà còn phong ấn ba khẩu phi kiếm vàng trong lam băng. Trước khi Kim lão quái kịp dùng thêm ngọc bội, Hàn Lập vận dụng Phong Lôi Sí xuất hiện sau lưng, phá hộ thể linh quang và dùng hàn diễm chế trụ, khiến đối thủ nhận thua. Đại Diễn Thần Quân truyền âm khen Hàn Lập đã thao túng băng diễm tới mức tinh vi, nhưng Hàn Lập vẫn xem nó chưa đủ để trở thành công pháp chủ tu. Sau trận, các Nguyên Anh lão quái thừa nhận thế cục mới, chúc mừng Lạc Vân Tông trở thành đệ nhất tông Vân Mộng Sơn và tái xác lập cơ chế phân chia lợi ích giữa ba tông. Hàn Lập tham gia trao đổi tâm đắc, thu được vài kinh nghiệm hữu ích, rồi chủ động xin tham quan Phế hỏa mạch của Bách Xảo Viện. Trên đường về, lão giả họ Trình nói tâm nguyện nhiều đời đưa Lạc Vân Tông thành đệ nhất tu tiên tông môn Khê quốc đã thành hiện thực, đồng thời đề nghị sau khi mình tọa hóa sẽ giao chức Đại trưởng lão cho Hàn Lập."},{"chuong":868,"tieuDe":"Luyện Hóa","tomTat":"Trình sư huynh và Lữ Lạc đề nghị Hàn Lập đảm nhiệm chức Đại trưởng lão Lạc Vân Tông vì hắn đã tiến cấp Nguyên Anh Trung Kỳ, lập công lớn và có thần thông cao nhất tông. Hàn Lập kiên quyết từ chối do chỉ muốn khổ tu, không muốn quản lý tông môn, thậm chí cảnh báo nếu tiếp tục ép thì chẳng khác nào buộc hắn rời Lạc Vân Tông, nhưng vẫn cam kết sẽ che chở tông môn hưng thịnh lâu dài. Khi bàn đến lời mời của Chí Dương thượng nhân, Trình sư huynh cho biết Thất Linh đảo và dòng suối mới gần Vân Mộng Sơn đã được trinh sát nhưng chưa phát hiện gì ngoài linh khí dồi dào và linh mạch hiếm. Sau khi về tông, Trình sư huynh và Lữ Lạc đến Nghị sự đại điện chuẩn bị tuyên bố Lạc Vân Tông trở thành đệ nhất tông Vân Mộng Sơn, còn Hàn Lập đi kiểm tra Nam Cung Uyển. Hắn xác nhận yêu đan Hỏa Thiềm Thú có tác dụng với Phong hồn chú, khiến thần thức Nam Cung Uyển xuất hiện một tia yếu ớt, nhưng hiệu quả thấp hơn dự đoán nên vẫn cần quan sát lâu dài. Trở lại mật thất Tử Mẫu phong, Hàn Lập nhập định để tránh tâm ma tình chướng, luyện hóa tia Kiền Lam Băng Diễm cuối cùng từ Hư Thiên Đỉnh trong hơn nửa tháng rồi điều khiển lam diễm hóa thành hỏa xà có cánh. Cuối cùng hắn lấy Hư Thiên Đỉnh ra, dùng Kiền Lam Băng Diễm bao phủ để thử khu sử; tiểu đỉnh dung hợp với băng diễm nhưng chưa biến hóa rõ rệt, khiến hắn phải vận linh lực vào mắt để quan sát kỹ hơn."},{"chuong":869,"tieuDe":"Thông Bảo Quyết","tomTat":"Hàn Lập dùng Thanh minh linh nhãn quan sát Hư Thiên Đỉnh rồi bắn linh ti lam sắc vào đỉnh, khiến bảo vật phóng lớn, băng diễm hóa thành lam giao nhập vào trong và cổ văn lam sắc hiện lên. Những cổ văn này hợp thành một thiên pháp quyết hơn ngàn chữ, cho biết muốn khu sử Hư Thiên Đỉnh phải luyện hóa Kiềm Lam Băng Diễm và tu luyện Thông bảo quyết. Hàn Lập biết pháp quyết chia ba tầng với yêu cầu cảnh giới rất cao nên tuy thất vọng vì hiện chưa thể phát huy toàn lực của đỉnh, hắn vẫn tham ngộ tầng đầu để phong ấn đỉnh vào cơ thể bồi luyện. Sau hơn hai mươi ngày, hắn thuận lợi phong ấn Hư Thiên Đỉnh, rồi dùng tài liệu của Trình sư huynh và xác khôi lỗi từ Hư Thiên Điện luyện thành một con khôi lỗi cấp Nguyên Anh Kỳ, được Đại Diễn Thần Quân trấn an về phương pháp luyện chế cao cấp hơn. Rời mật thất, Hàn Lập sắp xếp việc thăm Nam Cung Uyển, luyện đan trợ kết đan cho Mộ Phái Linh, rồi được Trình sư huynh và Lữ Lạc tiễn khỏi Vân Mộng Sơn để đi phó ước với Chí Dương thượng nhân. Hắn bay ra Vô Biên Hải phía bắc Khê Quốc, nhận thấy vùng Thất Linh Hải có nước biển trong hơn, sinh vật và linh khí tăng mạnh, đồng thời cảm ứng nguồn linh khí lớn cùng bảy điểm linh ba động. Khi đến gần khu vực ấy, Hàn Lập bị một tiểu đội Hợp Hoan Tông do cung trang phụ nhân Kết Đan Kỳ dẫn đầu chặn hỏi; nàng nói phụng mệnh phong tỏa hải vực và nhận ra hắn là Hàn Lập của Lạc Vân Tông, khiến nhóm tu sĩ đối diện xôn xao."},{"chuong":870,"tieuDe":"Vô Biên Ma Khí","tomTat":"Hàn Lập tới khu vực Thất Linh đảo và được tu sĩ canh giữ kính sợ vì danh tiếng đại tu sĩ đã lan khắp Thiên Nam. Cung trang phụ nhân dẫn hắn tới Linh Quy đảo, đồng thời giới thiệu Hợp Hoan Tông chiếm Linh Phượng đảo còn Thái Chân môn chiếm Linh Quy đảo gần Đại tuyền qua. Chí Dương Thượng nhân tự mình ra nghênh tiếp Hàn Lập vào động phủ mới mở, chờ Ngụy Vô Nhai tới rồi mới bàn việc chính. Ngụy Vô Nhai tiết lộ dị biến Đại tuyền qua có liên quan Cổ ma, vì Cổ ma từng tàn sát các thế lực có Ma khí, lấy đi ba kiện Ma khí và để lại dấu vết tà hài Ma khí bị hủy gần Đại tuyền qua. Chí Dương nói Đại tuyền qua thực chất là trận nhãn của Thượng cổ Phong ấn đại trận, bảy tòa linh đảo chỉ là một bộ phận pháp trận. Ông từng lặn xuống dưới đáy và thấy vô biên ma khí sâu không lường được đang bị linh khí tinh thuần trấn áp, nếu bộc phát sẽ gây đại kiếp cho Thiên Nam. Cuối cùng, Chí Dương tiết lộ Thái Chân môn vốn là một nhánh của Chân Cực môn tại Đại Tấn, được cử tới Thiên Nam để trông coi phong ấn thượng cổ này."},{"chuong":871,"tieuDe":"Thăm Dò Đại Tuyền Qua","tomTat":"Chí Dương thượng nhân giải thích Thái Chân Môn có nguồn gốc Đại Tấn nhưng truyền thừa cũ đã đoạn tuyệt, chỉ nhờ một thượng cổ điển tịch trong bí địa nội tông mà biết được vị trí cấu hình phong ấn pháp trận dưới Đại Tuyền Qua. Ngụy Vô Nhai nói phương án chữa trị cần nhiều tu sĩ cao cấp phối hợp và phải chôn một trận bàn xuống vị trí chỉ định sâu dưới đáy biển, nên ba đại tu sĩ muốn mời Hàn Lập vì Ích Tà Thần Lôi có thể khắc chế ma khí nhập thể. Hàn Lập thận trọng hỏi rõ phương án cũ, chưa lập tức nhận lời mà yêu cầu tận mắt xem ma khí vô biên lợi hại ra sao. Nhóm rời Linh Quy Đảo, tới Đại Tuyền Qua và gặp Hợp Hoan lão ma đang giám thị biến hóa ma khí trên đá ngầm gần quang đoàn. Hợp Hoan lão ma tỏ thái độ lạnh nhạt với Hàn Lập vì Ích Tà Thần Lôi khắc chế ma công, còn Hàn Lập tự tin đủ sức tự bảo vệ nếu có biến. Khi bay lên trung tâm Đại Tuyền Qua để thử hấp lực, Hàn Lập chỉ rơi hơn một trượng rồi đứng vững, khiến ba đại tu sĩ đánh giá lại pháp lực của hắn. Chí Dương cho biết thần thức bị vạn trượng linh khí ngăn cách và bên dưới còn có xoáy nước nhỏ nguy hiểm, sau đó cùng Hàn Lập đi xuống thăm dò, để Ngụy Vô Nhai và Hợp Hoan lão ma ở lại bàn riêng về vị Hàn đạo hữu của Lạc Vân Tông."},{"chuong":872,"tieuDe":"Ma Khí Chi Uyên","tomTat":"Hợp Hoan lão ma lo ngại Hàn Lập đã tiến cấp Nguyên Anh Trung Kỳ, lại mang nhiều thần thông mạnh, nên gợi ý Ngụy Vô Nhai liên thủ kiềm chế hoặc đối phó hắn. Ngụy Vô Nhai bác bỏ vì tuổi thọ mình không còn nhiều, Hàn Lập khó bị diệt sát hoàn toàn, và việc kết thù với một tu sĩ đồng cấp như vậy có thể gây họa lớn cho tông môn. Trong khi đó, Hàn Lập cùng Chí Dương thượng nhân xuống sâu hơn vạn trượng trong lốc xoáy linh khí, dùng pháp bảo và thần thông hộ thân để tới gần quang mạc trấn ma. Chí Dương thượng nhân âm thầm đánh giá Hàn Lập là kiểu khổ tu không ham tranh bá, rồi giải thích bên dưới quang mạc là Ma Khí Chi Uyên sâu rộng khó lường. Hàn Lập kiểm tra quang mạc, dùng Ích Tà Thần Lôi kết thành điện võng quanh Lam Quang Thuẫn rồi tự mình tiến vào ma khí thăm dò gần hai trăm trượng. Sau khi trở ra, hắn cho biết có thể thử mang trận bàn vào, nhưng phải biết rõ vị trí đặt trận vì nếu xuống quá sâu thì Ích Tà Thần Lôi chưa chắc chịu nổi mức tiêu hao. Hợp Hoan lão ma đề nghị quay về động phủ lấy trận bàn từ các pháp trận đại sư, sau đó mới bàn kỹ vị trí bố trí và đường lui cho Hàn Lập."},{"chuong":873,"tieuDe":"Đắc Linh Đảo","tomTat":"Sau khi nghe Hợp Hoan lão ma, nhóm Hàn Lập trở về Quy Linh Đảo; Hàn Lập nghỉ trong mật thất, còn Ngụy Vô Nhai và những người khác đi lấy trận bàn từ các trận pháp sư. Sáng hôm sau, Ngụy Vô Nhai giao ngọc giản ghi vị trí chôn trận bàn, nhưng Hàn Lập nhận ra điểm đặt quá sâu trong ma khí nên chất vấn ba đại tu sĩ về mức nguy hiểm. Hàn Lập giải thích ma khí càng sâu thì ma tính càng mạnh, khiến Ích Tà Thần Lôi tiêu hao nhanh, và Chí Dương thượng nhân xác nhận bản thân cũng từng cảm thấy pháp lực mất nhanh hơn khi xâm nhập sâu. Trước tình thế ngoài Hàn Lập khó ai hoàn thành nhiệm vụ, hắn yêu cầu được dùng thêm các chí bảo tru ma ích tà để bảo đảm đường trở về. Ba đại tu sĩ đồng ý, đồng thời hứa phân một tòa linh đảo trong Thất Linh Đảo cho Lạc Vân Tông, kèm nghĩa vụ về sau cùng bảo vệ phong ấn pháp trận. Ngụy Vô Nhai giao trận bàn bạch ngọc, còn ba đại tu sĩ đưa thêm giao ngọc như ý, Bát quái kính hỏa hồng, chiến giáp vàng rực và tiểu kỳ đen thui cho Hàn Lập hộ thân. Vài canh giờ sau, Hàn Lập một mình tới đáy xoáy nước, dùng Ích Tà Thần Lôi tạo điện võng hộ thân và chuẩn bị xuống ma khí. Hắn thầm cho rằng ba đại tu sĩ không biết mình có bảy mươi hai thanh Kim Lôi Trúc phi kiếm, nên việc mặc cả vừa để đáp lại thiện ý trước đó của Chí Dương thượng nhân vừa để che giấu lá bài trước các tồn tại còn có thể uy hiếp mình ở Thiên Nam."},{"chuong":874,"tieuDe":"Thạch Bi Tàn Phiến","tomTat":"Hàn Lập được kim cô và Ích Tà Thần Lôi che chở, nhảy xuống thâm uyên ma khí để xử lý trận nhãn dưới đáy xoáy nước. Trên mặt biển, Ngụy Vô Nhai hỏi Chí Dương Thượng Nhân liệu lượng thần lôi của Hàn Lập có đủ chống ma khí hay không, còn Hợp Hoan lão ma im lặng quan sát. Xuống sâu khoảng ba nghìn trượng, Hàn Lập dùng ngọc giản định vị và phóng tiểu kiếm mang điện hồ dò đường, từ đó phát hiện mặt bằng bên dưới không phải cự thạch mà là một tế đàn thượng cổ. Ở trung tâm tế đàn, hắn thấy bia đá bị chấn vỡ, thu các mảnh bia kỳ dị vào túi trữ vật và giao một mảnh cho Đại Diễn Thần Quân nghiên cứu. Hàn Lập suy đoán bia đá là vật trấn áp trận nhãn, rồi đào hố cạnh gốc bia, đặt trận bàn vào và thấy cột sáng trắng sữa phát ra, chứng tỏ bố trí vận hành bình thường. Khi hắn định rời đi, Đại Diễn Thần Quân nhắc nơi ma khí nồng đậm bị trấn áp lâu năm có thể sinh ra Ma Tủy Toản, khiến Hàn Lập lấy lang thủ ngọc như ý từng do Ngân Nguyệt ký thân để chuẩn bị thổ độn tìm kiếm dưới đất."},{"chuong":875,"tieuDe":"Tu Phiến","tomTat":"Hàn Lập gọi Ngân Nguyệt trong hình dạng tiểu hồ trắng ra, dùng Ích Tà Thần Lôi hóa thành điện võng bảo hộ nàng xuống bãi đá trong ma khí tìm Ma Tủy Toản, còn Đại Diễn Thần Quân giải thích đặc điểm của loại tinh thạch ma đạo này. Hàn Lập tự dùng Ngọc Như Ý xuống dưới đài và tìm được một khối, sau đó Ngân Nguyệt cũng trở về với ba khối nữa, khiến hắn thu được tổng cộng bốn khối Ma Tủy Toản. Chưa rời khỏi khu vực ma khí ngay, Hàn Lập lấy Âm La phiến không trọn vẹn ra thử tu bổ bằng ma khí tinh thuần, khiến ma bảo hút ma khí cuồn cuộn, phục hồi lỗ hổng và đổi sang màu đen thui tỏa sáng. Sau đó hắn phá linh khí phía trên để bay ra khỏi vũng xoáy, gặp lại Ngụy Vô Nhai, Chí Dương thượng nhân và người đi cùng. Ngụy Vô Nhai kiểm tra trận bàn, xác nhận trận bàn dưới ma khí đã bố trí tốt và có thể mời tu sĩ đến chữa trị pháp trận, tạm thời không lo ma khí đột ngột bạo phát. Hàn Lập trả lại bốn kiện thối ma chi bảo, từ chối lời mời đến Thất Linh đảo chờ thêm vì có việc quan trọng. Nửa tháng sau, hắn trở về Lạc Vân Tông, báo chuyện bản vẽ linh đảo cấp cho tông môn, xem xét tình trạng Nam Cung Uyển rồi vào mật thất bế quan để tăng pháp lực và hoàn thành đệ nhị Nguyên Anh. Sau nhiều biến cố, tu tiên giới Thiên Nam cũng bước vào thời kỳ ổn định, các tông phái chuyển sang bồi dưỡng đệ tử và tĩnh dưỡng."},{"chuong":876,"tieuDe":"Rời Xa","tomTat":"Một năm sau, Hàn Lập xuất quan trong động phủ dưới Tử Mẫu phong; trước khi bản thể bước ra, Nguyên anh thứ hai của hắn hiện thành mây đen rồi hóa thành anh nhi hắc lục nhỏ bé. Hàn Lập cho biết Nguyên anh thứ hai đã gần như đại thành nhờ Huyền Mẫu Hóa Anh Đại Pháp, đồng thời dùng ma khí tinh thuần trong Âm La phiến và biến hóa của Huyền Âm Đại Pháp để bồi dưỡng nó, nhưng vẫn dè chừng nguy cơ phản phệ nếu cấp nhục thân. Ngân Nguyệt báo Mạc cô nương đã kết đan thành công và được giao Điên Phượng Bồi Nguyên Công cùng đan dược Kết Đan Kỳ; Nam Cung Uyển vẫn bình yên, Phong Hồn Chú trên người nàng đang suy yếu nhờ Hỏa Thiềm Đan. Hàn Lập kiểm tra Lục Dực Sương Công trong trùng thất, nhận ra chúng không sinh sôi như kỳ vọng mà chỉ lột xác một lần, nhưng sau lột xác lại mạnh hơn nhiều và có dấu hiệu biến dị do Nghê Thường Thảo. Sau đó hắn quyết định rời Thiên Nam đi Đại Tấn để giải quyết sát khí, tìm tài liệu quý và tìm khẩu quyết giải Phong Hồn Chú từ Âm La Tông, trước khi đi còn muốn gặp Trình sư huynh để xem Khôi Lỗi và tài liệu Thất Diễm phiến. Nửa tháng sau, Hàn Lập rời Vân Mộng Sơn bằng độn quang; tin Hàn trưởng lão Lạc Vân Tông viễn du lan ra nhưng không ai biết đích đến. Thiên Nam chỉ dao động ngắn rồi yên ổn trở lại, Lạc Vân Tông vẫn giữ thế đệ nhất tại Khê Quốc, còn Hàn Lập từ đó biệt tích hơn trăm năm không có tin tức."},{"chuong":877,"tieuDe":"Thương Lộ Bộ","tomTat":"Một đội xe hơn ba mươi người của Thương Lộ Bộ đang đi qua phía nam Thiên Lan thảo nguyên để tiến cống Thiên Lan thánh điện trong kỳ khai linh nhật. Chương giải thích Thiên Lan thảo nguyên vốn là Mộ Lan thảo nguyên, sau cuộc chiến ba mươi năm trước đã bị người Đột Ngột đánh bại Mộ Lan rồi chiếm giữ toàn bộ. Anh Lộ, thủ lĩnh Thương Lộ Bộ, từng lập chiến công khi trẻ nhưng nay già yếu, vẫn dốc sức đưa các thiếu niên có linh căn đến thánh điện vì bộ lạc chưa có tiên sư riêng. Đội xe mang theo cống phẩm hữu dụng với tiên sư nên luôn lo bị cướp, lại càng khó khăn vì trước đó phải bỏ lại hai xe lương thực khi thoát đàn dã lang. Khi Anh San phát hiện thanh quang lấp lóe dưới bụi cây phía trước, Anh Lộ nghi có tiên sư ẩn nấp hoặc ra tay với cống phẩm. Sau một lúc quan sát không thấy động tĩnh, ông sai Thố Mãnh tiến lên dò xét. Thố Mãnh cung kính gọi hỏi nhưng không được đáp, rồi cắn răng vén bụi cây ra, để lại điểm treo về nguồn phát thanh quang."},{"chuong":878,"tieuDe":"Ngũ Quỷ Tỏa Thần Đại Pháp","tomTat":"Thô Mãnh tách bụi cây thì kinh hãi phát hiện một tiên sư ẩn bên trong, khiến đội xe Thương Lộ bộ lập tức cảnh giác. Nam tử áo trắng đội áo choàng xanh bước ra, tự xưng họ Hàn, nói mình vừa tu luyện trong bụi cây và chưa nhận bộ lạc nào cung phụng. Anh Lộ nhận ra cơ hội nên cung kính thương lượng, dùng hai mươi lăm khối linh thạch thuê Hàn Lập hộ tống đội xe đến thánh điện, còn Hàn Lập đồng ý với điều kiện nhận trước một nửa. Sau khi nhận linh thạch và xe ngựa tốt nhất, Hàn Lập cảnh cáo Thô Mãnh không được để chuyện nhìn thấy diện mạo của mình lan truyền, còn Anh Lộ sai Anh San đi theo bên cạnh xe ngựa chờ phân phó. Trong xe, Đại Diễn Thần Quân giải thích Ngũ Quỷ Tỏa Thần là bí thuật do ông sáng chế, nay dùng sát khí làm mồi dẫn ngũ quỷ phụ thân để áp chế sát khí cho Hàn Lập. Bí thuật này đồng thời phong ấn một phần tu vi, khiến Hàn Lập hiện nhiều nhất chỉ phát huy khoảng Trúc Cơ Trung Kỳ; Đại Diễn Thần Quân cũng chỉ ra sát khí cắn trả sớm vì Hàn Lập chưa trừ sát khí đã giao chiến với tu sĩ mạnh và bị nguyên khí đại thương."},{"chuong":879,"tieuDe":"Vô Vọng Chi Tai","tomTat":"Sau khi rời Thiên Nam, Hàn Lập trà trộn trên Thiên Lan thảo nguyên dưới thân phận tiên sư tự do, nhưng trong lúc thả Phệ Kim Trùng để chuẩn bị bồi dưỡng, hắn bất ngờ gặp một trưởng lão Nguyên Anh trung kỳ của Đột Ngột nhân đang điều khiển một con Phệ Kim Trùng thành thục. Vì đối phương nhận ra mức độ nghiêm trọng của đàn linh trùng và muốn đưa hắn đi gặp thánh nữ, Hàn Lập ra tay diệt sát, song công pháp phân chia Nguyên Anh của trưởng lão khiến một phân thần dùng Mộc độn trốn thoát. Tin tức bị lộ lập tức kéo tới cuộc truy sát quy mô lớn của các tiên sư Đột Ngột, thậm chí có Hô đại tiên sư tham gia, khiến Hàn Lập tuy giết được vài cao thủ nhưng cũng trọng thương nặng, phải dựa vào Vạn niên linh dịch và Huyết Ảnh độn mới thoát thân. Do đại chiến làm nguyên khí tổn hao, sát khí trong cơ thể hắn phản phệ sớm; Hàn Lập buộc phải thi triển Ngũ Quỷ Tỏa Thần đại pháp do Đại Diễn Thần Quân truyền, tạm thời áp chế sát khí nhưng phong bế phần lớn tu vi. Nhận thấy mình đang suy yếu, hắn quyết định lẫn vào đoàn tiến cống của Thương Lộ bộ đi về Thiên Lan thánh điện, lấy nơi nguy hiểm nhất làm chỗ ẩn thân, đồng thời học thêm pháp quyết dùng Vạn niên linh dịch để tạm giải phong ấn trong lúc nguy cấp. Trong xe, Hàn Lập hỏi thăm Ngân Nguyệt, rồi lập cấm chế và sai đệ nhị Nguyên Anh dùng Quỷ La phiên luyện hóa nguyên thần con Phệ Kim Trùng thành thục vừa bắt được, tránh hậu họa khi bản thân không còn toàn lực. Hơn mười ngày sau, đoàn Thương Lộ bộ vẫn bình an tiến gần nơi nghỉ chân do thánh điện dựng tạm, trong khi nhiều tiên sư cao giai âm thầm dò xét khu vực. Hai tiên sư Kết Đan họ Lê và họ Tú sau khi trao đổi mới hiểu mục tiêu là một tu sĩ Nguyên Anh ngoại tộc cực kỳ nguy hiểm, bèn từ bỏ ý ham thưởng Độc long hoàn, chỉ định lục soát qua loa để giữ mạng chờ Khai linh nhật."},{"chuong":880,"tieuDe":"Lòng Mang Tâm Sự","tomTat":"Trong xe của đoàn Thương Lộ bộ, Hàn Lập vì tu vi suy giảm nên quyết định không trì hoãn việc xử lý Phệ Kim Trùng thành thục bắt được từ trưởng lão Đột Ngột. Hắn dựng cấm chế bằng trận kỳ, gọi đệ nhị nguyên anh ra dùng Quỷ La phiên, pháp bảo duy nhất không bị Ngũ quỷ tỏa thần hạn chế, để rút nguyên thần đám trùng và luyện hóa bằng ma khí. Bên ngoài, Anh Lộ nghiêm cấm bộ chúng quấy rầy Hàn Lập, tiếp tục dẫn đoàn xe đi hơn mười ngày bình yên và sắp tới nơi nghỉ chân do Thiên Lan thánh điện lập trước Khai linh nhật. Anh Lộ nhận thấy nhiều đạo độn quang cao giai tiên sư bay thấp lục soát vùng phụ cận, đoán có đại sự liên quan đến vụ cống phẩm bị đoạt. Ở một nơi khác, Lê tiên sư gặp Tú tiên sư và muốn vì phần thưởng Độc long hoàn mà tìm kỹ ngoại tộc tu sĩ. Tú tiên sư tiết lộ người bị truy tìm là Nguyên Anh kỳ từng giết ba thượng bậc tiên sư, chỉ bị Hô đại tiên sư đánh trọng thương khi đang bị vây công, và nàng nghi nhóm kết đan kỳ bị thi triển dẫn hồn thuật để làm mồi. Lê tiên sư vì thế bỏ ý định mạo hiểm, đồng ý cùng Tú tiên sư chỉ giả vờ lục soát rồi bay về phương nam đến nơi nghỉ chân của thánh điện."},{"chuong":881,"tieuDe":"Ma Trùng Yêu Thi","tomTat":"Trong một mật thất kín, bốn lão giả Thiên Lan dùng pháp kỳ xanh biếc, pháp trận lâm thời và trận bàn bát tròn màu ngọc xanh để giúp Nguyên Anh Quế tiên sư hồi phục. Họ bàn về Hàn Lập, gọi hắn là ngoại tộc nhân cực kỳ đáng sợ vì đã dùng Phệ Kim Trùng, tử sắc hỏa diễm, kim sắc lôi điện, bộ phi kiếm kim thanh và đôi cánh trắng khiến nhiều tiên sư Nguyên Anh tử vong, chỉ từng bị Hô đại tiên sư dùng Đại Ngũ Hành Cầm Tiên Thủ đánh trọng thương. Khi Quế tiên sư vừa ổn định, Nguyên Anh của ông lại đột nhiên kêu thảm và tán loạn do Phệ Kim Trùng trưởng thành có nguyên thần tương liên với ông bị diệt sát. Ở nơi xa lạ trên xe ngựa, Hàn Lập sau nửa tháng làm phép đã rút nguyên thần Phệ Kim Trùng trưởng thành vào Âm La phiên mà không biết việc này suýt giết Quế tiên sư. Sau đó hắn để đệ nhị Nguyên Anh giữ xác trùng, đưa nguyên thần đã bị ma hóa nhập lại thân thể Phệ Kim Trùng và khiến nó sống lại dưới dạng yêu thi. Hàn Lập nhận định yêu thi Phệ Kim Trùng tuy uy lực giảm so với lúc sống nhưng vẫn rất mạnh, chỉ cần luyện hóa thêm ma khí lên trùng thi mới có thể điều khiển như ý."},{"chuong":882,"tieuDe":"Viên Thứu","tomTat":"Trong lúc tu vi vẫn bị phong ấn, Hàn Lập điều vài con Phệ Kim Trùng màu vàng chui vào Âm La Phiên, rồi để hắc lục đệ nhị nguyên anh hút phiên vào cơ thể và lặn trở lại thiên linh cái làm thủ đoạn dự phòng. Hắn định nhập định tham ngộ khẩu quyết phá giải phong ấn, đồng thời cảm ứng được Đột Ngột nhân tiên sư hơn mười ngày qua vẫn nhiều lần bay quanh đoàn xe như đang tìm mình nhưng chưa xuống tra hỏi. Đoàn xe Thương Lộ bộ lạc của Anh Lộ sắp tới trạm dừng chân do thánh điện chỉ định thì gặp đoàn Tố Hồng Lang do đại hán họ Bạt dẫn đầu, hai bên quen biết nên nhập đoàn cùng đi. Anh Lộ đề nghị sau khi nghỉ chân nên liên hợp thêm vài tiểu bộ lạc để vượt qua địa bàn đại bộ lạc, nhưng họ Bạt còn do dự vì sợ bị cống phẩm quý của bộ lạc khác liên lụy. Đúng lúc đó, ba con yêu cầm Viên Thứu đầu vượn thân chim xuất hiện, khiến hai đoàn xe hoảng loạn xuống ngựa ẩn nấp và phải mời các tiên sư ra tay. Phong tiên sư của Tố Hồng Lang cưỡi khăn gấm phi hành nghênh chiến, dùng phù Hoả xà thuật nhưng điều khiển kém nên bị Viên Thứu né tránh và kích phát hung tính. Y tiếp tục tế tiểu kiếm thượng phẩm pháp khí chém rụng một lợi trảo của một con yêu cầm, song hai con còn lại đã lao xuống từ hai bên, chụp thẳng vào thiên linh cái của y."},{"chuong":883,"tieuDe":"Lãnh Mạc","tomTat":"Trên Thiên Lan thảo nguyên, Phong Nhạc bị tiếng rú của viên thứu làm chấn động đầu óc và suýt bị yêu cầm tập kích từ trên cao. Hàn Lập kịp thời phóng hỏa cầu cứu hắn, rồi thả hai con Hàn tuyết ngô công khiến hai viên thứu sợ hãi và bị hàn khí đóng băng mà chết. Con viên thứu còn lại vẫn áp đảo Phong Nhạc, nhưng khi nó định bỏ chạy, Hàn Lập dùng phi châm đỏ hạ sát để tránh hậu hoạn. Phong Nhạc kinh ngạc trước linh trùng và phi châm, tự giới thiệu tên rồi muốn trả giá cao mua hai thứ này, song Hàn Lập lạnh nhạt từ chối. Hàn Lập chỉ lấy móng vuốt, đuôi và cánh của viên thứu, giao phần còn lại cho đoàn người thảo nguyên xử lý theo quy củ địa phương. Sau đó hắn trở về xe, cố ý giữ khoảng cách với Phong Nhạc và âm thầm quan sát đối phương. Trong xe, Ngân Nguyệt sau thời gian tĩnh dưỡng đã có thể truyền âm lại với Hàn Lập, hỏi vì sao hắn lạnh nhạt với người có vẻ có lai lịch như Phong Nhạc."},{"chuong":884,"tieuDe":"Trú Địa","tomTat":"Hàn Lập nói với Ngân Nguyệt rằng Phong Nhạc không phải người Đột Ngột, vì pháp khí đeo bên hông người này có khắc cổ văn Đại Tấn và từng tự hộ chủ khi yêu cầm áp sát. Ngân Nguyệt nhận ra cổ văn ấy, cùng Hàn Lập suy đoán Phong Nhạc có liên hệ với thế gia hoặc địa vực Đại Tấn, nên Hàn Lập quyết định tránh tiếp xúc sâu để khỏi sinh thêm phiền phức. Sau trận yêu cầm, Phong Nhạc bí mật xem chiếc chìa khóa bạc khắc chữ Phong, biểu hiện tâm trạng phức tạp rồi cất lại. Đội xe tiếp tục đến trú địa do thánh điện chỉ định, nơi có pháp trận bảo vệ, cấm chế cấm không, nhiều tu tiên giả cấp thấp và khu nghỉ dành cho tiên sư. Anh Lộ mời Hàn Lập vào thạch điện nghỉ tạm, nhưng hắn lo gặp tu sĩ Đột Ngột cao cấp hoặc Nguyên Anh kỳ nên rời khỏi trú địa, hẹn hai ngày sau quay lại. Hàn Lập bay đến bãi loạn thạch cách đó năm sáu mươi dặm, khoét cự thạch làm nơi ẩn thân, bố trí trận pháp ẩn hình rồi nhập định nghiên cứu khẩu quyết Đại Diễn Thần Quân đưa cho. Khi việc tham ngộ đã thuận lợi quá nửa, hắn đột nhiên mí mắt giật, thần thức lập tức tản ra và kinh hãi mở mắt."},{"chuong":885,"tieuDe":"Khổ Độc","tomTat":"Ngân Nguyệt cảm ứng thấy Hàn Lập khác thường, còn Hàn Lập phát hiện gần đó có một tu sĩ Kết Đan và một tu sĩ Trúc Cơ với khí tức giống Phong Nhạc. Sau khi hỏi Đại Diễn Thần Quân về bí thuật Phật tông giải sát khí và dấu hiệu thất sắc linh quang, hắn quyết định cứu người vì Phong Nhạc có thể liên quan tới manh mối mình cần. Tại rừng nhỏ trên thảo nguyên, lão giả mắt ưng đang dùng hồng sắc phi kiếm công kích quang tráo bảo vệ Phong Nhạc, rồi khinh địch phóng Tam lăng đinh định giết Hàn Lập diệt khẩu. Hàn Lập vận dụng Nguyên anh thứ hai bắt pháp khí, diệt sát lão giả và thu lại lục sắc quang đoàn. Hắn phát hiện quang tráo đến từ ngọc bội khắc Trữ Trung Phùng, được Đại Diễn nhận định đã qua gia trì cấm chế Phật môn. Sau khi phá quang tráo, Hàn Lập xác nhận Phong Nhạc trúng Khổ độc trong Thập tuyệt độc, trong khi chìa khóa bạc trước ngực vẫn phát linh quang xua bớt độc khí. Dù Đại Diễn cho rằng Phong Nhạc khó cứu, Hàn Lập vẫn lấy linh dược định làm hắn tỉnh lại để hỏi rõ quan hệ với Phật tông Đại Tấn."},{"chuong":886,"tieuDe":"Hạo Nguyên Đan","tomTat":"Hàn Lập lấy ra một viên Hạo Nguyên đan để cứu tỉnh Phong Nhạc vì pháp thuật của hắn đang bị phong ấn, Ngân Nguyệt lại bị thương nên không tiện dùng sưu hồn. Sau khi đưa đan vào miệng Phong Nhạc, Hàn Lập dùng ngân châm dẫn độc huyết ra ngoài và khống chế tình trạng của đối phương. Phong Nhạc tỉnh lại, nhìn thấy thi thể tử bào lão giả, rồi hoảng sợ phát hiện mình đã trúng độc rất nặng. Hàn Lập nhận định đó là Khổ độc thuộc Thập tuyệt độc, còn Phong Nhạc lập tức cho rằng tử bào lão giả đã đầu phục Khổng gia vì chỉ Khổng gia có loại độc này. Hàn Lập nói Hạo Nguyên đan không giải độc mà chỉ áp chế độc khí tạm thời, khiến Phong Nhạc phải cầu xin cách giữ mạng. Khi Hàn Lập nhắc đến đoạt xá, Phong Nhạc thừa nhận mình đã từng đoạt xá một lần nên không thể dùng lại cách đó. Cuối chương, Hàn Lập dùng nhu cầu Hạo Nguyên đan của Phong Nhạc để buộc hắn trả lời về thân phận, chìa khóa bạc, ngọc bội và manh mối Trữ Trung, Phùng gia."},{"chuong":887,"tieuDe":"Phùng Gia Mật Quật","tomTat":"Hàn Lập tiếp tục truy hỏi Phong Nhạc về lai lịch Phùng gia, Linh hà bội và Quan Trữ phủ, qua đó biết Phong Nhạc là trưởng tử Phùng gia, người giữ tín vật trực hệ và chìa khóa mật quật. Phong Nhạc kể Phùng gia có tổ tiên từng là tục gia đệ tử Thiên Quang tự, mà Thiên Quang tự thuộc Kim La môn, nên Phùng gia vốn lưu truyền Phật gia công pháp. Đại Diễn Thần Quân nhắc Hàn Lập hỏi chuyện xá lợi tử, và Phong Nhạc xác nhận tổ tiên Phùng gia từng tu ra vật này, khiến Hàn Lập thấy có hy vọng tìm được pháp môn tiêu trừ sát khí. Phong Nhạc cũng nói Phùng Chẩm là ma đạo tán tu được Phùng gia thu lưu nhưng đã đầu phục Khổng gia, dùng khổ độc đánh lén hắn để né bí thuật cấm chế của Phùng gia. Từ lời Phong Nhạc, cục diện tứ đại tu tiên thế gia Quan Trữ phủ lộ ra: Khổng gia liên hợp Trương gia và Kim gia âm thầm hại Phùng gia, khiến Phùng gia gần như tan tác và Phong Nhạc lưu lạc thảo nguyên. Hàn Lập đưa Hạo nguyên đan ra giao dịch để kéo dài mạng Phong Nhạc, còn Phong Nhạc không đủ linh thạch nên dùng chìa khóa bạc mở mật quật làm vật thế nợ. Cuối chương, Hàn Lập yêu cầu Phong Nhạc phối hợp cho mình dò thần thức để xác minh chuyện mật quật và Phật tông công pháp, Phong Nhạc miễn cưỡng đồng ý nhưng đặt điều kiện không được đụng tới chuyện khác."},{"chuong":888,"tieuDe":"Nguy Cơ","tomTat":"Hàn Lập không tiếp tục tra hỏi ở nơi lộ liễu mà dùng mây màu đánh ngất Phong Nhạc, sau đó nhận nguyên thần lão mắt ưng từ nguyên anh thứ hai và ra lệnh hủy diệt. Hắn thiêu sạch thi thể lão mắt ưng, thu túi trữ vật cùng mấy tiểu kiếm màu hồng rồi mang Phong Nhạc rời đi, đồng thời suy xét tình trạng pháp lực bị phong ấn và nguy cơ không dám phóng thần thức xa. Một ngày sau, Hàn Lập trở lại đội xe của Anh Lộ, theo bộ lạc Thương Lộ rời nơi nghỉ chân và nhập cùng nhiều đội xe bộ lạc nhỏ khác. Khi một luồng thần thức cao giai quét qua đoàn xe, hắn lập tức thu liễm hơi thở nên tránh bị phát hiện. Tại lầu đá, Ưng tiền bối cùng đại hán họ Lê và nữ tu mặc cung trang bàn về dấu vết ngoại nhân, hé lộ Thánh Điện Đột Ngột muốn đoạt phương pháp nuôi dưỡng Phệ Kim Trùng và đang bố trí lưới vây. Ưng tiền bối tuy không giữ đoàn xe lại nhưng vẫn bất an vì từng thoáng cảm nhận một luồng áp lực bất thường."},{"chuong":889,"tieuDe":"Cự Phúc","tomTat":"Sau khi dùng thần thức dò xét đoàn xe, Ưng tiền bối cân nhắc khả năng đối phương là ngoại tộc có thần thức vượt xa và từng dùng hàn băng tím giết nhiều tu sĩ, nên bỏ ý định truy đuổi để chờ Đại tiên sư cùng Thánh Nữ xử lý. Hàn Lập nhận ra thần thức kia có liên quan đến bí thuật đặc biệt, tiếp tục che giấu khí tức rồi lục túi trữ vật của lão mắt ưng, tìm được khổ độc còn sót lại trong bình ngọc xanh biếc. Hắn âm thầm quan sát Phong Nhạc dùng dị bảo hút độc và nhiều đan dược nhưng vẫn thất bại, tóc chuyển bạc và chỉ còn sống khoảng hai ba ngày. Trên đường, đoàn xe gặp hai Thiết Đề Thú cấp thấp bị các tiên sư Đột Ngột đánh chết, còn Hàn Lập đã tìm hiểu xong khẩu quyết Đại Diễn Thần Quân đưa nên bớt lo nếu thân phận bại lộ. Khi đoàn xe dừng bên một nhánh nhỏ của Thiên Thuỷ Hà, Hàn Lập rời xe nói chuyện với Anh San, kiểm tra linh căn và tặng cô một bình đan dược cải thiện tư chất trước nghi thức khai linh. Qua lời Anh San, hắn biết vị trí dòng sông và nhớ đến quan hệ giữa Thiên Thuỷ Hà với Thuấn Giang ở Đại Tấn. Cuối chương, Hàn Lập phát hiện có vật lạ bay tới từ phía bên kia sông, sai Anh San báo Anh Lộ; ngay sau đó một con dơi lớn bao trong lục quang hiện ra khiến đoàn xe và các tiên sư Đột Ngột căng thẳng."},{"chuong":890,"tieuDe":"Kim Diễm Thạch","tomTat":"Hàn Lập đang theo đoàn xe trên Thiên Lan thảo nguyên thì một con cự bức chở tám tu sĩ lạ xuất hiện, tạo cuồng phong làm xe cộ lật đổ và hàng hóa rơi vãi. Cố thống lĩnh của Cửu Tiên cung quát lui Anh Lộ, buộc Hàn Lập tháo nón lá để dùng mật thuật kiểm tra dung mạo rồi xác nhận hắn không phải phản đồ đang truy tìm. Nhóm Cửu Tiên cung sau đó vây xe ngựa, dùng hỏa cầu ép Giang Kiếm Anh hiện thân và vạch rõ hắn đã mang Tuyết Tinh châu bỏ trốn. Giang Kiếm Anh tố nhiệm vụ mời Bắc Huyền lão nhân chỉ là cái cớ để đưa người có băng linh căn như hắn làm vật huyết tế cho Bắc Huyền Thiên Yêu tế luyện châu. Hắn thúc Tuyết Tinh châu tạo hàn vụ chống cự, nhưng sáu tu sĩ Trúc Cơ dùng hồng mông pháp kỳ hợp thành hỏa vân áp chế, để Cố thống lĩnh xông vào bắt sống và đoạt lại bảo châu. Qua cuộc đối thoại bằng ngôn ngữ Đại Tấn, Hàn Lập nhận ra thế lực ở Đại Tấn phức tạp hơn mình tưởng. Sau giao tranh, hơi nước rửa sạch một khối đá trong hàng hóa rơi vãi, để lộ Kim Diễm thạch là tài liệu mấu chốt để luyện chế phỏng chế Thất Diễm phiến. Đại Diễn Thần Quân nhắc đây là cơ duyên hiếm cho Hàn Lập, trong khi Cố thống lĩnh cũng nhận ra giá trị của khối đá và định nhặt lấy."},{"chuong":891,"tieuDe":"Xuất Thủ","tomTat":"Kim Diễm thạch bất ngờ rời tay Cố thống lĩnh và rơi vào tay Hàn Lập; sau khi được Đại Diễn Thần Quân xác nhận, Hàn Lập thu viên kỳ thạch vào túi trữ vật, bất chấp lời uy hiếp của đối phương. Cố thống lĩnh giải thích giá trị Kim Diễm thạch cho bạch y nữ tử, khiến nàng quyết định giết sạch tiên sư và phàm nhân Đột Ngột để không còn nhân chứng. Nhóm Đại Tấn nhanh chóng tàn sát các tu sĩ Đột Ngột, rồi Cố thống lĩnh và bạch y nữ tử cùng pháp bảo tấn công Hàn Lập nhưng không phá nổi quầng sáng đen do tiểu phiên tạo ra. Khi sáu Trúc Cơ Đại Tấn chuẩn bị bố trí Hỏa Viêm trận, đệ nhị Nguyên Anh của Hàn Lập hiện thân, phóng đại tiểu phiên thành Âm La phiên và cuốn sạch pháp bảo pháp khí của địch. Cố thống lĩnh nhận lầm Hàn Lập là chấp pháp trưởng lão Âm La tông, lập tức bỏ chạy; bạch y nữ tử cưỡi cự bức chạy hướng khác, còn sáu Trúc Cơ tản ra trốn thoát. Hàn Lập thả Lục Dực Sương Công truy sát sáu Trúc Cơ, dùng Phệ Kim Trùng ma hóa giết Cố thống lĩnh, và để đệ nhị Nguyên Anh điều khiển ma vân tiêu diệt bạch y nữ tử. Sau trận, phàm nhân Đột Ngột kinh hãi không dám tới gần, còn Hàn Lập chờ đệ nhị Nguyên Anh trở về trong lúc cầm Tuyết tinh châu và nhìn đống đồ vật của tu sĩ Đại Tấn bỏ lại."},{"chuong":892,"tieuDe":"Thiên Lan Thánh Nữ","tomTat":"Sau trận chiến, Hàn Lập phát hiện thanh niên bị bắt đã uống độc tự sát nên không thể cứu tỉnh để tra hỏi lai lịch nhóm tu sĩ Đại Tấn. Hắn thiêu thi thể, thu hồi ma khí cùng Nguyên anh thứ hai, rồi cùng Phong Nhạc rời đoàn xe để tìm mật quật trước khi độc trên người Phong Nhạc phát tác. Phong Nhạc hiểu lầm Hàn Lập là trưởng lão Âm La tông vì thấy thủ đoạn giống Quỷ La phiên và biết hắn có Hạo Nguyên đan. Vài ngày sau, Thiên Lan thánh điện điều tra sự kiện, nhận lầm Hàn Lập là trưởng lão Âm La tông và triển khai truy sát, đồng thời dò xét vùng giáp giới Đại Tấn để đề phòng tiếp ứng. Trong cấm địa thánh điện, nghi thức khai linh bị rút ngắn và hơn trăm cao giai tiên sư Đột Ngột nhân tập hợp quanh cự hình trận đồ. Thiên Lan thánh nữ cùng hai vị đại tiên sư xuất hiện, tuyên bố nghi thức triệu hoán không chỉ để truy sát người ngoại tộc mà còn để giữ phân thân thánh thú vĩnh cửu ở thánh điện. Hai yêu thú thất cấp đỉnh là Thanh Phong Ngưu và Băng Giáp Mãng được đưa tới làm tế phẩm. Thiên Lan thánh nữ dùng ngân ti trói Thanh Phong Ngưu lên tế đàn rồi lấy ra cổ đỉnh thanh diễm có hình dáng rất giống Hư Thiên đỉnh."},{"chuong":893,"tieuDe":"Thánh Thú Chú Thân","tomTat":"Thiên Lan thánh nữ chủ trì nghi thức huyết tế, dùng thanh sa và ngân liên phân giải Thanh Phong Ngưu, hút sạch huyết nhục lẫn nguyên thần của nó, rồi tiếp tục đưa Băng Giáp Mãng lên tế đàn hiến tế. Khi thanh sa hóa thành huyết vân, nàng nhờ Từ đạo hữu và Tôn tiên sứ truyền linh lực, kích hoạt pháp trận cùng cự đỉnh để mở lối cho xích mang thánh thú nhập vào huyết vân, kết thành kén máu. Kén máu được thu vào cự đỉnh, dùng thanh diễm và pháp trận nuôi luyện; Thiên Lan thánh nữ cho biết phân thân thánh thú chưa chắc lưu lại lâu dài, nhưng bảy tám ngày đã đủ để truy tìm kẻ ngoại tộc. Hai ngày sau, Thiên Lan thánh điện vang chuông, hơn mười đạo độn quang cấp cao rời thánh điện bay về phía nam. Ba ngày tiếp đó, Thiên Lan thánh nữ cưỡi phân thân thánh thú dạng ngưu giao long đỏ đậm tới Thiên Thủy hà, dựa vào linh giác thánh thú xác nhận Hàn Lập đang lẩn dưới sông vì trên người có nhiều Phệ Kim Trùng. Hàn Lập phát hiện bị truy tung liền hóa huyết ảnh bỏ chạy; ba đại tiên sư phát truyền âm cho nhóm sau rồi tự mình tăng tốc đuổi theo. Dù Hàn Lập nhiều lần dùng Huyết ảnh độn bỏ xa cả ngàn dặm, phân thân thánh thú vẫn giúp nhóm truy binh chỉnh hướng bám sát, khiến y phải liên tiếp giải phong ba lần mà vẫn chưa thoát."},{"chuong":894,"tieuDe":"Dụ Địch","tomTat":"Hàn Lập đang trong tình trạng nguy cấp sau nhiều lần giải phong, liên tục dùng Huyết ảnh độn và uống linh nhũ vạn năm, nhưng nhóm Đột Ngột nhân vẫn lần ra tung tích cực kỳ chuẩn xác. Đại Diễn Thần Quân phân tích rằng việc truy tung này không giống thần thức tu sĩ nhân giới, mà nhiều khả năng do Thiên Lan thánh thú, một phân thần thượng giới mượn yêu thú thật thể giáng xuống, gây ra. Vì không có cách chắc chắn cắt truy tung, Hàn Lập quyết định liều mạng diệt thánh thú, trước hết gọi đệ nhị nguyên anh ra, giao Quỷ La phiên và Huyết Ma kiếm để tạo ma vân bay lệch hướng dụ địch. Phe truy kích phát hiện nguyên anh tách ra nhưng bản thể Hàn Lập vẫn chạy, nên tử phát mỹ phụ và Từ đạo hữu nghi ngờ đây là đệ nhị nguyên anh hoặc bí thuật đặc biệt. Do Thiên Lan thánh thú hiện chỉ là một tia phân thần chưa mở đủ linh trí, Từ đạo hữu tách đội truy theo nguyên anh, còn Thiên Lan thánh nữ cùng tử phát mỹ phụ tiếp tục đuổi bản thể. Khi khoảng cách truy binh rút xuống còn rất gần, Hàn Lập lại thả Ngân Nguyệt ra, để nàng hóa thành một Hàn Lập khác, nhận túi Phệ Kim Trùng và lôi châu rồi bay lệch hướng nhằm tiếp tục chia nhỏ truy binh và tạo cơ hội đánh thánh thú."},{"chuong":895,"tieuDe":"Cấm Mạt Ngân Tàm","tomTat":"Hàn Lập để Ngân Nguyệt biến ảo thành chính mình và mang theo một phần Phệ Kim Trùng, khiến Thiên Lan thánh nữ cùng Tôn tiên sứ nhìn thấy hai Hàn Lập có khí tức giống nhau. Thiên Lan thú được sai truy tung bằng khí tức linh trùng nhưng không thể phân biệt thật giả, nên hai truy binh buộc phải tách nhau mỗi người đuổi một hướng. Hàn Lập nhân cơ hội quay lại, xác định mục tiêu là nhanh chóng diệt Thiên Lan thú trước khi hai đại tiên sư hội hợp, rồi bày Phệ Kim Trùng, phi kiếm hợp nhất, tử diễm, tiểu thuẫn màu lam, cổ kính tím và Hàng Linh Phù để chuẩn bị phản kích. Khi Thiên Lan thánh nữ cưỡi Thiên Lan thú đuổi tới, nàng dùng vòng tay bích lục cuốn kiếm ảnh và thả kim sắc cự trùng thành thục thể áp chế đàn Phệ Kim Trùng của Hàn Lập. Trước sức ép đó, Hàn Lập kích hoạt Hàng Linh Phù, hóa thành hình thái nửa giao long nửa người. Thiên Lan thánh nữ tiếp tục phóng pháp bảo Cấm Mạt Ngân Tàm, để cự tằm bạc trên khăn tay phun vô số ngân ti phủ kín không gian. Hàn Lập lập tức dùng lam quang thuẫn bảo hộ và bạo phát tử diễm thành tường băng tím cao lớn chắn trước người."},{"chuong":896,"tieuDe":"Song Đỉnh","tomTat":"Hàn Lập tiếp tục giao chiến với Thiên Lan thánh nữ và Thiên Lan thú trên không trung. Hắn dùng băng diễm màu tím men theo ngân tia phản kích pháp bảo khăn gấm, ép bạch diễm của đối phương lùi lại cho tới khi Thiên Lan thú phun thanh diễm trợ lực. Thiên Lan thánh nữ tế thiết bài bát giác hóa thành bát quái đồ, buộc Hàn Lập dùng lôi độn né tránh và áp sát, nhưng nàng lại phối hợp Thiên Lan thú phun sương trắng che giấu. Hàn Lập dùng cổ kính màu tím phá vụ hải và thúc cự kiếm chém Thiên Lan thú, song mục tiêu chỉ là hư ảnh do huyễn thuật tạo ra. Sau đó Thiên Lan thánh nữ tế một tiểu đỉnh giống Hư Thiên đỉnh, khiến Hàn Lập kinh hãi vì Hư Thiên đỉnh của mình vẫn nằm trong cơ thể. Tiểu đỉnh hóa cự đỉnh phun thanh quang và thanh sa vây Hàn Lập thành kén, đồng thời tiếng gầm Thiên Lan thú khiến lôi độn của hắn tạm mất hiệu lực. Trong thế bị khống chế, Hàn Lập xuất Hư Thiên đỉnh của mình, vận tầng thứ nhất Thông Bảo quyết phát lam hà và làm thanh sa mất liên hệ với Thiên Lan thánh nữ. Cuối chương, Thiên Lan thánh nữ tiếp tục thúc cự đỉnh phun thanh quang mạnh hơn trùm xuống Hàn Lập, trận chiến chưa phân thắng bại."},{"chuong":897,"tieuDe":"Kinh Chuyến","tomTat":"Hàn Lập vận tầng thứ nhất Thông Bảo quyết vào Hư Thiên đỉnh, khiến tiểu đỉnh phát sinh dị biến hút thanh hà, đoạt thánh đỉnh của Thiên Lan thánh nữ và tự động thu luôn phân thân Thiên Lan thánh thú. Thiên Lan thánh nữ nhận ra tiểu đỉnh của Hàn Lập có quan hệ sâu với thánh đỉnh, lập tức muốn đoạt lấy, nhưng Hàn Lập thu cự kiếm, phun tinh huyết thi triển Huyết ảnh độn và thoát khỏi phạm vi thần thức của nàng. Ở hai chiến trường khác, đại tiên sư thanh niên tuấn tú tưởng Cổ Ma đã trọng thương khó sống, trong khi nguyên anh hắc lục thực ra đang được tiểu phiên ma khí âm thầm chữa trị; Tử phát mỹ phụ dùng cổ bảo ngọc vây Phệ Kim Trùng nhưng chỉ đánh trúng hóa thân giả. Ba người Đột Ngột hội hợp, thừa nhận không đoạt được công pháp bồi dưỡng Phệ Kim Trùng, lại mất thánh đỉnh và phân thân thánh thú, nên Thiên Lan thánh nữ quyết sang Đại Tấn truy tìm Hàn Lập và trước hết thăm dò Âm La tông. Cuối chương, bối cảnh chuyển sang Liêu Châu của Đại Tấn, nơi Thuấn Giang mùa đông không đóng băng và Vương Thiết Thương đang hộ tống thuyền. Khi ông đang nghĩ đến tiền công và gia đình, một nữ tử trên thuyền kêu lên rằng có khối băng lớn bên trong hình như có người."},{"chuong":898,"tieuDe":"Trên Thuyền","tomTat":"Trên thuyền đi Thuấn Giang, Vương Thiết Thương và Cao Đại Phong thấy giữa thời tiết nóng có một khối băng trong suốt trôi trên sông, bên trong là một người. Chu sư gia ban đầu muốn mặc kệ để tránh phiền phức cho phu nhân và tiểu thư, nhưng Cao Đại Phong khẳng định người trong băng còn sống vì vừa chớp mắt. Nhị tiểu thư nghe Hoàng Oanh báo lại liền ra lệnh cứu người, cho rằng cứu một mạng người là công đức, nên Hàn Lập được đưa lên thuyền. Hai ngày sau Hàn Lập tỉnh lại, nghe lão phu tử không hiểu nổi mạch tượng khác thường của mình. Hắn tự kiểm tra và biết mình đã vào sâu Đại Tấn, thân thể suy kiệt vì Huyết ảnh độn, chân nguyên tổn hại nặng, tu vi tạm rơi xuống Luyện Khí kỳ. Hàn Lập tìm thấy nguyên thần Ngân Nguyệt đang hôn mê trong phi kiếm, nhưng đệ nhị nguyên anh vẫn thất lạc dù còn liên hệ mơ hồ. Đại Diễn Thần Quân truyền âm cho biết Hàn Lập đã trôi dưới đáy sông hơn một năm, đồng thời trách hắn giấu chuyện có thông linh chi bảo và đòi xem tiểu đỉnh để nghiên cứu."},{"chuong":899,"tieuDe":"Tào Mộng Dung","tomTat":"Hàn Lập tỉnh lại trên thuyền Tào gia sau khi được nhị tiểu thư cứu khỏi khối băng giữa Thuấn Giang, đồng thời tạm hẹn với Đại Diễn thần quân rằng phải đợi tu vi khôi phục mới lấy chiếc đỉnh trong cơ thể ra cho nghiên cứu. Qua Hà Văn và việc âm thầm dùng thần thức dò xét, hắn biết đây là gia quyến của một huyện úy họ Tào đang đi sau chủ nhà, trên thuyền có một nữ tu cấp thấp, Vương quản gia có chân khí và vài tôi tớ ẩn sát khí. Hai ngày sau, Tào nhị tiểu thư gặp riêng Hàn Lập, tự xưng Tào Mộng Dung, đệ tử Huyền Ngọc đạo ở Liêu Châu, rồi dò hỏi lai lịch của hắn. Hàn Lập che giấu thân phận, tự nhận là tán tu mới vào Đại Tấn tu tiên giới và được nàng mời ở lại vài ngày để trao đổi tu luyện. Trở về phòng, hắn giải thích với Đại Diễn thần quân rằng hiện tại tu vi suy giảm, Đại Tấn nhiều tu sĩ và linh địa bị các tông môn chiếm cứ nên không nên mạo hiểm rời đi ngay. Hắn quyết định tạm ẩn trên thuyền, dùng đan dược và linh nhãn vật để trong một năm khôi phục đến Trúc Cơ kỳ, đồng thời tìm hiểu Đại Tấn và lưu tâm việc giải trừ sát khí, thu thập tài liệu cho Đại Diễn thần quân. Cuối cùng, Hàn Lập lấy trận kỳ bày cấm chế đơn giản quanh phòng, uống đan dược rồi khoanh chân tĩnh tọa."},{"chuong":900,"tieuDe":"Ác Khách","tomTat":"Hai nữ tu Huyền Ngọc phái đến ngọn núi nhỏ phía tây Ngũ Nguyên phủ để gặp Tào Mộng Dung, bàn chuyện nàng bị người Tê Linh Tông dùng hình thức khiêu chiến ép không can dự vào việc cứu một trọng phạm quan phủ. Trên đỉnh núi, họ phát hiện Tào Mộng Dung đã mời Hàn Lập tọa trấn; Hàn Lập tự xưng là tán tu đang làm khách tại Tào gia, còn Tào Mộng Dung cho biết nàng đột phá bình cảnh nhờ được hắn chỉ điểm. Chương hồi thuật rằng sau nửa năm được cứu và dưỡng thương, Hàn Lập đã bổ sung phần lớn nguyên khí, âm thầm khôi phục tu vi đến Trúc Cơ kỳ và nhân dịp này chuẩn bị lấy cớ rời Tào gia. Khi tiếng thét từ chân núi vang lên, Ngô Hiểu Vũ và Mã Ngọc Lâm xuất hiện bằng phi hành pháp khí, khiến nhóm nữ tu Huyền Ngọc phái kinh ngạc vì loại pháp khí này hiếm với tu sĩ tầng thấp. Hàn Lập nhìn ra đối phương chỉ ở Luyện Khí tầng tám và tầng mười một nên không để trong lòng, chủ động bước ra hỏi ai xuất thủ hoặc cả hai cùng lên. Lỗ sư tỷ nhận ra Mã Ngọc Lâm là chấp pháp đệ tử Tê Linh Tông và chất vấn tư cách giao đấu của hắn, nhưng hắn lấy quan hệ họ hàng với Ngô Hiểu Vũ làm lý do thay mặt xuất thủ. Cuối chương, Mã Ngọc Lâm thu pháp khí tấm ván gỗ, lấy ra một tiểu xoa màu vàng từ túi trữ vật, chuẩn bị giao đấu với Hàn Lập."},{"chuong":901,"tieuDe":"Đại Hội Tham Vương","tomTat":"Hàn Lập đối đầu Mã Ngọc Lâm nhưng cố ý không dùng pháp khí, chỉ phóng nhiều phù lục hỏa cầu hợp thành hỏa mãng để quấn chặt Liên Hoàng Phượng xoa, buộc đối phương nhận thua. Hai đệ tử Lợi Linh tông rút lui, còn Tào Mộng Dung cùng hai sư tỷ tiếp tục vây quanh Hàn Lập hỏi về pháp thuật và công pháp. Một thời gian sau, tam nữ quay lại nhà tranh chỉ thấy Hàn Lập để lại thư từ biệt, khiến Tào Mộng Dung hụt hẫng. Trên đường phi hành, Hàn Lập bàn với Đại Diễn thần quân về việc Ngũ quỷ tỏa thần mất hiệu quả và xác định cần tới Giang Lăng phủ mở Phùng gia mật quật để tìm công pháp Phật môn hóa giải sát khí. Hắn cũng cân nhắc nếu Phùng gia không giúp được thì sẽ tìm cơ hội vào Phật môn hoặc chuyển sang Nho môn. Sau hơn mười ngày, Hàn Lập tới địa giới Trữ phủ, hạ xuống Chuẩn Vân trấn và gặp hai đệ tử Khổng gia đang tiếp dẫn tu sĩ. Hai người cho biết Đại hội Tham Vương tại Tuyết Lăng sơn do Giang Trữ tam đại gia tổ chức, có linh dược trăm năm và nhân sâm thiên niên đấu giá, đồng thời giải thích Chuẩn Vân trấn đã thuộc sở hữu ba nhà Khổng, Triệu, Đổng từ nhiều năm trước."},{"chuong":902,"tieuDe":"Quan Trung Nhân","tomTat":"Hàn Lập nhận lời theo hai tu sĩ tới thịnh hội giao dịch ở Tuyết Lăng sơn, dùng phi kiếm thượng giai phi hành và tiếp tục che giấu lai lịch bằng lý do sư môn có quy định. Trên đường, Tuyết Lăng sơn được hé lộ là sơn mạch lớn ở Liêu châu, sâu trong núi từng có yêu quái và nhiều vụ tu sĩ mất tích, còn đại hội chỉ đặt ở khu ngoài. Khi tới khu kiến trúc trên đỉnh núi, Hàn Lập phóng thần thức dò xét và phát hiện một tu sĩ Nguyên Anh có thi khí rất kín, khiến hắn nhớ tới lời Phùng Chẩm về Khổng lão quái. Dưới mật thất sâu, một hoàng bào nam tử trong quan tài đen bị kinh động, dùng thần thức rà soát toàn núi nhưng không phát hiện gì rồi tin hắc ngọc đã che giấu thi khí của mình. Hàn Lập vào trang viện, thấy hội giao dịch có hàng trăm tu sĩ, trướng bồng pháp khí, điện đường và nhiều tu sĩ Trúc Cơ, Kết Đan, quy mô khiến hắn cảm thán thực lực thế gia Đại Tấn. Hắn biết đấu giá bảo vật thật sự sẽ diễn ra ngày thứ ba và suy đoán cổ linh vật ngàn năm sẽ xuất hiện lúc đó. Sau khi dạo hội không thấy nhiều vật đáng giá, Hàn Lập phát hiện Kim Nguyên đang theo dõi mình; Kim Nguyên nói có một kiện dị bảo chưa rõ lai lịch muốn nhờ xem xét hoặc bán lại. Hàn Lập chấp nhận nhưng yêu cầu vào mật thất bên thiên điện để trao đổi riêng và tự trả linh thạch thuê chỗ."},{"chuong":903,"tieuDe":"Thiên Cơ Ốc","tomTat":"Hàn Lập đưa Kim Nguyên sang điện đường bên cạnh để thuê nơi kín đáo trao đổi, tại đó gặp một nữ tu Trúc Cơ trung niên và nhận một thạch ốc nhỏ gọi là Thiên Cơ ốc. Nữ tu giải thích Thiên Cơ ốc là pháp khí tiện dụng có thể phóng to thu nhỏ, loại cao cấp còn có trận pháp cấm chế, còn Kim Nguyên bổ sung rằng loại cao nhất Thiên ky các giống một động phủ nhỏ và rất đắt. Hàn Lập kiểm nghiệm cấm chế chống thần thức của thạch ốc, sau đó rót linh lực khiến nó hóa thành căn phòng đá để cùng Kim Nguyên vào trao đổi. Trong phòng kín, Hàn Lập hỏi tin về thế gia tông môn Quan Trữ phủ vì dự định ở lại nơi này một thời gian. Kim Nguyên kể rằng cách gọi tam đại thế gia đã cũ, mười năm gần đây phải tính là tứ đại thế gia, đồng thời tiết lộ Phùng gia từng bị ba nhà còn lại liên thủ diệt trong một đêm. Sau khi nắm thêm tình hình Liêu Châu, Hàn Lập chuyển sang chuyện dị bảo; Kim Nguyên lấy hộp ngọc từ túi trữ vật ra nhờ hắn giám định. Hàn Lập phát hiện vỏ hộp bài xích thần thức, còn vật kim quang như bọt khí bên trong tuy không có linh khí nhưng lại phản ứng kỳ dị, phồng lên co rút như tim đập khi bị thăm dò."},{"chuong":904,"tieuDe":"Thượng Cổ Cự Mộ","tomTat":"Hàn Lập truyền âm hỏi Đại Diễn Thần Quân về bọt khí màu vàng trong hộp ngọc, nhưng Đại Diễn Thần Quân cũng chưa từng thấy vật này, chỉ nhận định khả năng kháng thần thức của nó đủ để tạm coi là dị bảo. Trước mặt Kim Nguyên, Hàn Lập che giấu nhận định thật và nói dị biến chỉ là phản ứng khi bị lượng lớn thần thức bao vây; Kim Nguyên thử lại cũng thấy bọt khí phát kim quang, co dãn và bành trướng. Kim Nguyên kể mình là tán tu tu luyện thổ thuộc tính công pháp, có thổ linh thân thể và sở trường độn thổ thuật, từng được hảo hữu mời vào một tòa nghi là cổ tu cự mộ thời thượng cổ trong Tuyết Lăng sơn mạch. Trong chủ mộ thất, nhóm ông thấy tài liệu quý hiếm và pháp khí, nhưng thây khô chôn cùng đột nhiên sống lại thành hành thi, nhiều người bị giết, còn quan tài có động tĩnh như Huyễn Diệp vương muốn hồi sinh; Kim Nguyên nhờ độn thổ thuật trốn thoát và thuận tay lấy bọt khí màu vàng trên quan tài. Về sau ông dẫn một nhóm cao giai tu sĩ quay lại nhưng cổ mộ đã biến mất, chỉ còn cỏ hoang và ký hiệu lối vào cũ, khiến Hàn Lập liên hệ tới chuyện tu sĩ mất tích trong Tuyết Lăng sơn mạch. Kim Nguyên đưa ngọc giản ghi vị trí cổ mộ cho Hàn Lập và bán dị vật với giá hai trăm linh thạch trung giai; khi giao dịch xong, túi linh thú bên hông Hàn Lập bất ngờ động đậy và phát tiếng kêu nhỏ."},{"chuong":905,"tieuDe":"Tam Thi","tomTat":"Sau khi Kim Nguyên rời thạch ốc, Hàn Lập thu lại vẻ tươi cười và nói với Đại Diễn Thần Quân rằng hắn không tin đối phương mới gặp đã dễ dàng tiết lộ bí mật đế vương chi mộ. Hắn lấy hộp ngọc ra, thả Đề Hồn thú kiểm tra bọt khí vàng; tiểu hầu vừa sợ vừa thèm khát rồi nhảy vào trong, dùng âm khí đối kháng và hấp thu hôi sắc thi diễm. Đại Diễn Thần Quân nhận ra vật này liên quan đến kim cương xá lợi của Phật môn, có thể hóa thành kim cương tráo phòng hộ cực mạnh, đồng thời suy đoán bảo vật chưa nhận chủ hoàn toàn nên Hàn Lập có cơ hội thu lấy. Khi một đoàn lục quang nhỏ định thoát khỏi bọt khí, Hàn Lập dùng thần niệm chi bích chặn lại để Đề Hồn thú cuốn về và nuốt mất. Ở một mộ thất cách xa mấy nghìn dặm, bóng người cao lớn trong quan tài trái nổi giận vì mất một phân thần và kim cương tráo. Trung niên nam tử trong quan tài giữa cùng nữ tử trong quan tài nhỏ nhất đối thoại, hé lộ kim cương tráo vốn do lão hòa thượng luyện từ xá lợi, sau bị trung niên nam tử đoạt được và giao cho Vương nhi hộ thân."},{"chuong":906,"tieuDe":"Chương 906","tomTat":"Trong mộ thất, ái phi của đại vương thuật lại nguồn gốc Kim cương tráo: Vương Nhi từng mang bảo vật lên mặt đất mượn nguyệt hoa luyện hóa, rồi dùng một tu sĩ bị khống chế làm tay sai, giấu phân thần và cấm chế trong bảo vật để dụ tán tu đến cổ mộ hoặc giết từ xa nhằm thu nguyên thần. Đại vương đoán Kim cương tráo đã bị thất lạc vì kẻ kia làm hỏng việc, đồng thời chuẩn bị phát động cấm chế bắt nguyên thần hắn về tra hỏi. Hắn cũng hé lộ âm mưu lớn hơn tại Giang Ninh phủ: Qua tướng quân đã hóa thân khống chế thế gia tu sĩ, thậm chí liên hợp các thế gia tiêu diệt một gia tộc Phật tông để che giấu kế hoạch gom tinh hồn tu sĩ. Kế sách này vốn do Thiên Phong chân quân ở Phương Tiêm sơn đề xuất, khiến nữ tử nghi ngờ song ma nơi đó có ý đồ riêng, nhưng đại vương vẫn quyết tâm dùng lượng lớn tinh hồn để luyện thành thiên thi thân thể, thoát khỏi ràng buộc mộ thất và sau này giải thoát cả nàng cùng Vương Nhi. Kim cương tráo được nhấn mạnh là dị bảo có thể tạm thời tạo thành Kim cương bất hoại thân, nên đại vương quyết định khi xác định vị trí sẽ phái hai hóa thân đi đoạt lại, còn bóng người cao lớn trong hắc khí bị quát lui vì không thể che giấu thi khí. Ở nơi cách xa mấy ngàn dặm, Hàn Lập hoàn toàn không biết mình đã vì diệt một tia thần niệm mà bị cuốn vào nguy cơ truy sát, lúc này chỉ đang quan sát Đề Hồn thú trong bọt khí vàng. Cùng lúc đó, Kim Nguyên vừa trở về phòng liền bị hỏa diễm xám từ cấm chế thiêu rụi thân xác, nguyên thần kinh hoàng bị cuốn bay đi mà không ai hay biết lão đã biến mất."},{"chuong":907,"tieuDe":"Hỏa Dong Tinh","tomTat":"Hàn Lập thấy Đề Hồn thú chưa thể thôn phệ xong Kim Cương tráo trong thời gian ngắn, bèn thu cả hai vào túi linh thú, rời Thiên cơ ốc và trả lại cho trung niên nữ tu. Hắn tới thạch điện đối diện quảng trường, nộp ba khối linh thạch để vào đấu giá hội và nhận ngọc bàn số hai trăm bốn mươi ba. Trong đại sảnh, hắn chứng kiến phượng vĩ hoa năm trăm năm được bán cho một lão già mập mạp, đồng thời được hai nữ tu ngồi cạnh giải thích về ôn thạch, đặc sản Tuyết lĩnh sơn mạch dùng làm ngọc bàn. Khi quan sát nhiều vật phẩm, Hàn Lập nhận ra giá linh dược và pháp khí ở Đại Tấn cao hơn Thiên Nam, nhưng tài liệu hiếm cũng phong phú hơn. Ba khối Hỏa dong tinh được đưa ra đấu giá khiến hắn chú ý vì có điểm khác thường liên quan tới yêu đan, dù Đại Diễn thần quân ban đầu không tin phán đoán ấy. Hàn Lập nâng giá mua được ba khối tinh thạch với tám trăm linh thạch, sau đó theo người dẫn đường vào hậu đường, không uống linh trà được dâng mà chờ lão già đầu hói đem hộp ngọc tới để kiểm tra từng khối."},{"chuong":908,"tieuDe":"Tinh Hóa Yêu Đan Cùng Phi Châm","tomTat":"Hàn Lập xác nhận hỏa dong tinh là vật mình cần, thu ba viên tinh thạch rồi rời chỗ lão giả bán hàng, khiến đối phương nhìn hộp ngọc trống mà sinh nghi. Trở lại phòng đấu giá, hắn lấy tinh thạch ra xem, làm hai nữ tu ngồi cạnh chú ý vì số linh thạch bỏ ra quá cao. Khi Đại Diễn Thần Quân hỏi rõ nguyên do, Hàn Lập tiết lộ trong ba viên có một viên là nội đan yêu thú cấp bảy đã tinh hóa, bề ngoài và thần thức đều khó phân biệt, nhưng hắn nhận ra nhờ sát khí do từng giết nhiều yêu thú. Hắn giải thích tinh hóa yêu đan có độc nên không thích hợp luyện đan, song lại là tài liệu tuyệt hảo để luyện pháp bảo phi châm tốc độ cao, độn quang mờ ảo và có khả năng ẩn hình. Đại Diễn Thần Quân nghe vậy cảm khái thiên hạ rộng lớn, rồi bộc lộ nỗi không cam lòng vì thọ nguyên mà phải nghiên cứu ký thần thuật và ký hồn trên khôi lỗi. Lời ấy khiến Hàn Lập nghĩ đến khả năng chính mình cũng có thể rơi vào kết cục thê lương nếu không tiến vào Hóa Thần kỳ, nên hắn mất hứng thú với hội đấu giá và rời hội trường. Ra quảng trường, Hàn Lập tìm tới một đại hán Trúc Cơ kỳ tự nhận là ngoại đường chấp sự Khổng gia, giả vờ muốn gặp gia chủ để bàn về một vật trong phòng đấu giá. Khi đại hán nhận hỏa dong tinh kiểm tra, lam mang từ tinh thạch bắn ra đóng băng toàn thân hắn, rồi Hàn Lập cuốn hắn vào trong lầu và lặng lẽ theo sau."},{"chuong":909,"tieuDe":"Khách Điếm","tomTat":"Hàn Lập dùng ngân châm, pháp quyết và trận pháp ngăn cách khí tức khống chế Khổng Đấu để thẩm vấn, biết hắn là ngoại đường chấp sự Khổng gia và moi được tin Khổng gia đã chiếm Chuẩn Vân trấn từ bảy năm trước. Sau khi lấy được tin về Tuyết Giang tiểu thành, Hàn Lập cho Khổng Đấu uống đan dược, dùng Vô Ưu châm che một đoạn ký ức rồi rời Chuẩn Vân trấn. Hắn đến Tuyết Giang lúc trời tối, thả thần thức dò xét toàn thành và xác nhận nơi này không có cao thủ đáng ngại, người mạnh nhất chỉ là một tu sĩ Kết Đan trong trạch viện phía tây nam. Tại trung tâm thành, Hàn Lập tìm thấy Duyệt Lai khách điếm có dấu hiệu ấm trà dưới chiêu bài, lẻn vào phòng lão bản và dùng chìa khóa bạc làm tín vật. Lão bản nhận ra tín vật, gọi hắn là đại thiếu gia, cho biết gia chủ Phùng gia nhiều năm không liên hệ nhưng từng dặn rằng thiếu gia lần sau đến sẽ đổi hình dáng. Theo yêu cầu của Hàn Lập, lão bản dẫn hắn ra hậu viện đào lấy viên gạch xanh có cấm chế liên quan mật thất Phùng gia. Hàn Lập dặn lão bản lập tức rời đi mai danh ẩn tích, ban vài viên đan dược cường thân kéo thọ, rồi rời Tuyết Giang đến một hoang sơn gần đó để kiểm tra viên gạch xanh."},{"chuong":910,"tieuDe":"Sát Khí","tomTat":"Hàn Lập dùng khẩu quyết Phùng Chẩm để lại mở viên gạch pháp khí trữ vật, lấy ra một ngọc giản và tập văn thư khế ước tài sản. Ngọc giản chỉ rõ mật quật Phùng gia nằm ở Tuyết Lăng sơn, nơi nổi tiếng cổ quái và thường có tu chân mất tích, khiến Hàn Lập phải cân nhắc nguy hiểm. Đại Diễn Thần Quân giải thích cơ chế thế gia tu tiên Đại Tấn gắn chặt với triều đình, phú hào, tông môn và tài nguyên thế tục, rồi nhắc Hàn Lập ưu tiên tìm công pháp Phật môn để giải sát khí. Trong mộ thất Tuyết Lăng sơn, một Đại vương trong thạch quan sai hai nhân ảnh lục sắc truy sát Hàn Lập và đoạt bảo vật, dựa vào khí tức Vương thi còn trong Kim Cương Tráo để truy tung. Đại vương nhân ngày âm khí bạo phát rời mộ thất, giao người ở lại dựng cấm chế và nói sẽ hỗ trợ tướng quân, xử lý người của các thế gia. Hàn Lập tới Tuyết Lăng sơn, thu liễm khí tức, tìm được thác nước khớp ngọc giản rồi dùng pháp quyết tị thủy xuyên vào lối mật quật. Hai nhân ảnh lục sắc mất dấu mục tiêu ở ngoài ngàn dặm, trong khi phía sau chúng còn có hai người bí ẩn đang ẩn nấp quan sát."},{"chuong":911,"tieuDe":"Vào Mật Quật","tomTat":"Hai kẻ mai phục âm thầm theo dõi hai lục sắc nhân ảnh, nhận ra đó là hóa thân hoặc phân thân của Huyễn Vương lão ma và bàn cách diệt chúng trước khi kinh động bản thể. Thiên Phong chân quân tiết lộ kế hoạch đã bố trí gần mười năm nhằm dụ Huyễn Vương rời mộ thất, kéo hai thế gia cùng tông môn sau lưng vào vòng vây, rồi chia bảo vật, thiên thi châu và thi binh trong lăng mộ. Hai kẻ mai phục ra tay bằng mây đen và bạch sắc cuồng phong, vô tình hóa giải nguy cơ hai hóa thân truy tới Hàn Lập. Ở cửa đá sau thác nước, Hàn Lập dùng chìa khóa bạc mở cơ quan, bước vào động khẩu và gặp truyền tống trận có bẫy đặt linh thạch. Nhờ nắm được ảo diệu, hắn chỉ đặt năm khối đê giai linh thạch vào đúng lỗ, truyền tống an toàn tới đại sảnh mật quật. Trong kho tàng Phùng gia, hắn kiểm tra giá gỗ, hơn trăm ngọc giản và các rương bạc nhưng không thấy công pháp phật môn trong ngọc giản thường. Cuối cùng, Hàn Lập phát hiện hộp gỗ đỏ khắc văn phù phật môn, bên trong có xá lợi tử, hai pháp khí và ngọc giản vàng, rồi lập tức đưa thần thức vào ngọc giản."},{"chuong":915,"tieuDe":"Nhất Chiến Kinh Ma","tomTat":"Hàn Lập dùng điện quang phá ma vân, lộ ra vị trí thanh bào lão giả rồi lấy lôi độn áp sát. Hắn phối hợp tử sắc hỏa diễm và kim sắc tiểu kiếm phá cổ thuẫn, chém đứt tay đối phương, sau đó xuất hiện sau lưng xuyên ngực và đóng băng thân thể lão giả. Nguyên Anh của thanh bào lão giả vừa thoát ra liền bị kim sắc lưới điện chụp lại, không thể độn đi và bị tiêu diệt hoàn toàn. Hoàng bào đại hán cùng Thiên Phong chân quân thấy Hàn Lập giết tu sĩ cùng cấp quá nhanh thì kinh sợ, ngừng vây công Huyễn Diệp vương và rút vào sa vụ. Huyễn Diệp vương cũng kinh hãi, đánh giá thần thông của Hàn Lập gần Nguyên Anh hậu kỳ, đồng thời cảnh báo về Lạc hồn sa khi Cuồng Sa thượng nhân phóng toàn bộ hắc sa vào cấm chế. Hàn Lập gọi Đề Hồn thú ra, linh thú hóa thành cự viên, phóng hoàng hà và kim sắc quang trụ hút âm khí cùng hắc sa, khiến thế công Lạc hồn sa bị phá và các đối thủ ẩn trong sa vụ chết lặng."},{"chuong":917,"tieuDe":"Song Châu","tomTat":"Hàn Lập nhận Thiên Thi Châu từ Huyễn Diệp vương, nghe giải thích viên châu có nguồn gốc từ mộ thất rồi nhận ra người của đối phương đang tới nên lập tức cáo từ rời đi. Sau khi hắn bỏ đi, cổ mộ vang tiếng quỷ khóc, lục vụ và thi khí kéo tới, Huyễn Diệp vương hóa hôi quang nghênh tiếp. Hàn Lập cấp tốc độn xa khỏi sơn mạch để tránh nguy cơ pháp lực bị phong tỏa, hai ngày sau chọn một núi nhỏ vắng vẻ mở động phủ tạm và bày trận che giấu. Trong mật thất, hắn bàn với Đại Diễn Thần Quân về Minh Vương Quyết, xác định tầng một dễ tu hơn nhưng tầng hai cần linh mạch tốt, nên dự tính mượn đường lui của Phùng gia tại Nam Châu để trà trộn vào đại tông môn. Hắn kiểm tra Tuyết Tinh Châu và Thiên Thi Châu; Tuyết Tinh Châu có lợi cho Tử La Thiên Hỏa, còn Thiên Thi Châu có thể tẩy tủy dịch kinh và tăng cường luyện thể nhưng phải dùng linh dịch khử thi độc. Đại Diễn Thần Quân nhắc Hàn Lập về hóa thân Thiên Lan Thánh Thú bị giam trong Thông Thiên linh bảo tiểu đỉnh, đồng thời nói Thất Diễm Phiến là linh bảo chuyên công kích và có thể luyện chế chế phẩm nếu gom đủ tài liệu."},{"chuong":919,"tieuDe":"Cam Gia","tomTat":"Chương mở đầu bằng bối cảnh một quận nhỏ nhưng giàu có của Đại Tấn, nơi phong khí thờ Phật phụng Đạo và hệ thống học viện đều rất thịnh hành. Tại Thái Xương phủ, Cam gia được giới thiệu là phú thương trung lưu ở bờ Tây thành, có nhiều tửu lâu, cự trạch và nô bộc. Hàn Lập sau một năm bế quan đã nhờ Thiên Thi Châu cùng Kim Cương xá lợi tu thành tầng thứ nhất Minh Vương Quyết, ổn định sát khí rồi cải trang thành thanh niên nho sam đến Cam phủ. Cam Dụ thay phụ thân tiếp khách, mời Hàn Lập vào khách sảnh và trò chuyện về Tứ Thư Ngũ Kinh, trong khi Hàn Lập âm thầm dùng thần thức dò xét tu tiên giả trong thành. Khi Cam Trì trở về, Hàn Lập đưa ra nửa khối bạch ngọc làm tín vật, khiến Cam Trì nhận ra tuyến liên lạc bí mật và đưa hắn vào thư phòng. Trong cuộc nói chuyện riêng, Hàn Lập xác nhận từ nay mình phụ trách liên lạc với Cam gia, đồng thời yêu cầu Cam Trì dùng thân phận thế tục để hỗ trợ việc trọng yếu của hắn."},{"chuong":920,"tieuDe":"Bạch Lộ Thư Viện","tomTat":"Bạch Lộ thư viện được giới thiệu là một thư viện bậc trung ngoài thành Thái Xương nhưng lại tọa lạc trên Huyễn Vân phong của Ngọc Điền Sơn, linh sơn nổi danh phủ Thái Xương. Nơi này tồn tại hơn nghìn năm, thu nhận đệ tử thất thường, người vào viện hiếm khi rời đi và được các tăng đạo lân cận đối đãi khách khí, nên mang sắc thái thần bí. Một tháng sau sự kiện ở Cam phủ, Hàn Lập ngụy trang thành thư sinh trẻ tu vi Luyện khí kỳ thấp, nhờ Cam Trì và Nghiêm Nghiêu dẫn tới Bạch Lộ thư viện để tìm nơi tu luyện trên linh mạch. Trên đường lên núi, Nghiêm Nghiêu nói mình có quen biết Lỗ Đại tiên sinh và nhắc tới Thanh Thiền Chung của Bảo Linh tự, còn Hàn Lập nhận ra chuông này chỉ là thượng phẩm pháp khí. Đến rừng trúc trước thư viện, hai người gặp thanh niên nho sam áo trắng canh cửa phụ; người này dùng truyền âm phù thông bẩm vào trong. Sau đó một đạo thần thức khá mạnh quét qua, khiến Hàn Lập nhận định Lỗ Đại tiên sinh có tu vi Kết đan sơ kỳ, cao hơn dự liệu và có khả năng nhìn ra thủ đoạn che giấu của hắn. Cuối chương, Lỗ Đại tiên sinh truyền âm mời Nghiêm Nghiêu cùng Hàn Lập vào thư phòng gặp vị khách quý."},{"chuong":921,"tieuDe":"Đạo Cô Và Hoàng Thanh Quan","tomTat":"Thanh niên áo trắng dẫn Hàn Lập và Nghiêm Nghiêu đi sâu vào Bạch Lộ thư viện, nơi đệ tử hạ viện đọc sách vào giờ ngọ để bồi dưỡng Hạo Nhiên chi khí phụ trợ công pháp nho môn. Ba người tới một tiểu viện có cấm chế cách âm, rồi thanh niên áo trắng cáo từ, để Nghiêm Nghiêu đưa Hàn Lập vào gặp Lỗ Đại tiên sinh. Trong phòng còn có Hoa Liên tiên cô của Hoàng Thanh quan, một đạo cô trẻ tuổi Trúc Cơ hậu kỳ nhưng tỏ ra có lai lịch. Nghiêm Nghiêu giới thiệu Hàn Lập là thế chất của bạn cũ, muốn thử tư cách vào Bạch Lộ thư viện. Lỗ Đại tiên sinh kiểm tra và thấy Hàn Lập là tứ linh căn thiếu kim, từng tu pháp thuật mộc thuộc tính bậc thấp, miễn cưỡng đủ điều kiện nhập viện nhưng tiền đồ Trúc Cơ rất thấp. Khi được hỏi sở trường, Hàn Lập cố ý hạ thấp bản thân và chỉ nói hơi biết luyện khí, khiến Hoa Liên tiên cô lập tức muốn đưa hắn sang Hoàng Thanh quan làm trợ thủ luyện chế bảo vật. Nghiêm Nghiêu phản đối vì Hàn Lập vốn định vào Bạch Lộ thư viện, còn Hoa Liên giải thích Hoàng Thanh quan tuy là nữ quan nhưng vẫn có nam tử môn nhân và tu sĩ tại gia. Lỗ Đại tiên sinh kết luận Hàn Lập chưa nhập viện nên có quyền tự quyết, khiến Hàn Lập lúng túng vì hắn chưa hiểu rõ Hoàng Thanh quan."},{"chuong":922,"tieuDe":"Phệ Chân Hợp Nguyên Quyết","tomTat":"Hàn Lập vốn định vào Bạch Lộ thư viện nhưng Hoa Liên tiên cô chủ động mời hắn nhập Hoàng Thanh quan, khiến hắn khó từ chối vì sợ Lỗ Đại tiên sinh sinh nghi. Hắn thử lấy lý do Hoàng Thanh quan là nữ quan và pháp môn chưa chắc hợp nam tu, nhưng Hoa Liên giải thích Hoàng Thanh quan thuộc Tam Hoàng quan, các nhánh khác có đủ pháp môn cho nam tu, còn Lỗ Đại tiên sinh cũng khuyên hắn thuận theo. Đồng tử Bạch Lộ thư viện mang tử tinh đồng từ nhà kho tới, Lỗ Đại tiên sinh giao cho Hoa Liên và dò hỏi chuyện luyện bảo, nhưng nàng chỉ nói phụng mệnh tứ sư thúc rồi cất vật liệu đi. Sau khi Hoa Liên và Hàn Lập rời đi, Lỗ Đại tiên sinh bàn với Nghiêm Nghiêu về việc dùng thân người này trợ mình tu thành Phệ Chân Hợp Nguyên quyết để đối phó Ngưu Thiên Đức. Nghiêm Nghiêu vì mối thù diệt tộc mà chấp nhận hy sinh, nhưng yêu cầu Lỗ Đại tiên sinh hạ Tỏa Tâm Chú để bảo đảm không thất hứa. Lỗ Đại tiên sinh giải thích hạo nhiên chi khí kế thừa sẽ mang oán khí, nếu chưa diệt Ngưu Thiên Đức thì không thể hoàn toàn hóa thành của mình, rồi hẹn một tháng sau bắt đầu an bài tu luyện. Cuối chương, Hoa Liên tiên cô dùng pháp khí hình khăn gấm mang Hàn Lập rời Huyễn Vân phong, đi tới một ngọn núi thấp hơn."},{"chuong":923,"tieuDe":"Luyện Khí Điện","tomTat":"Hoa Liên tiên cô đưa Hàn Lập tới một mật thất trong Hoàng Thanh quan, giới thiệu Vi lão là một trong hai luyện khí đại sư của Tam Hoàng quan và giao Hàn Lập làm trợ thủ tạm thời cho việc luyện chế trọng bảo. Vi lão ban đầu nghi ngại tuổi tác, tu vi và năng lực luyện khí của Hàn Lập, nhưng sau khi Hoa Liên tiên cô nhấn mạnh pháp lực tinh thuần cùng khả năng khống chế pháp lực của hắn, ông đồng ý thử dùng và truyền thụ một tháng luyện khí chi đạo. Hàn Lập chính thức vào Luyện Khí điện, nơi thực chất là một biệt viện giữa núi của Hoàng Thanh quan, có địa hỏa đại điện, luyện khí các, động phủ, Vi lão, hai tu sĩ trung niên và bốn đệ tử. Trong quá trình sinh hoạt, hắn lạnh nhạt quan sát ba nam đệ tử bị nữ tu làm mê muội, còn bản thân thì phát hiện tạo nghệ luyện khí của Vi lão vượt xa dự đoán, bao gồm cả thủ pháp thượng cổ và kỹ thuật mới của Đại Tấn. Hàn Lập vì thế chuyên tâm ghi nhớ các thủ pháp, dự định sau khi khôi phục pháp lực sẽ dùng kiến thức này để chuẩn bị luyện chế Thất Diễm phiến và hoàn thiện khôi lỗi của Đại Diễn thần quân. Một tháng sau, hắn dễ dàng hoàn thành các nhiệm vụ tinh luyện tài liệu Vi lão giao, đồng thời tiếp tục tu luyện Minh Vương Quyết trong thời gian rảnh. Vi lão ngày càng bận rộn trong mật thất địa hỏa điện, còn Hoa Liên tiên cô nhiều lần tới bàn bạc kín, khiến Hàn Lập tuy tò mò nhưng không mạo hiểm nghe lén. Cuối chương, Hàn Lập vận công trong động quật, thân phủ kim quang, da thịt nổi tơ máu và gân xanh, chịu đau đớn vì dị vật chạy dưới da trước khi mọi dị tượng biến mất."},{"chuong":924,"tieuDe":"Lục Tú Quận Chúa","tomTat":"Sau khi nhiệt độ trong cơ thể hạ xuống, Hàn Lập thu công và hỏi Đại Diễn thần quân về sự đau đớn khi tu luyện Minh Vương Quyết. Đại Diễn giải thích pháp quyết này vốn dành cho yêu tộc và Cổ ma, còn Phật tông khi cải biến hẳn có cách giảm đau, trong khi Hàn Lập tự kiểm nghiệm thân thể và nhận ra hiệu quả luyện thể rất rõ rệt. Hàn Lập rời mật thất tới Địa Hỏa đại điện, chuẩn bị tiếp tục mượn địa hỏa giữa trưa để tế luyện yêu đan phi châm nhằm tăng thêm uy lực. Đúng lúc đó, Lục Tú quận chúa cùng nhóm tu sĩ trẻ được ba đệ tử Luyện Khí điện dẫn vào, muốn tinh luyện Huyết ty ngân để luyện pháp khí. Đệ tử họ Cao vốn có địch ý với Hàn Lập gọi hắn lại, viện lệnh Tứ quán chủ khiến hắn khó từ chối, đồng thời chương hé lộ Hoàng Thanh quan có bốn quán chủ Kết Đan kỳ và một tu sĩ Nguyên Anh kỳ ở Thiên Thanh viện. Nhóm Lục Tú nghi ngờ tu vi thấp của Hàn Lập, nhưng Vi sư bá đang bế quan luyện trọng bảo nên không thể ra mặt, còn ba đệ tử thừa nhận chỉ Hàn Lập được truyền phương pháp tinh luyện Huyết ty ngân. Cuối cùng Lục Tú quận chúa mềm mỏng giao tài liệu cho Hàn Lập thử, Hàn Lập đồng ý với điều kiện không để nhiều người chứng kiến, và nàng chấp nhận chỉ một mình đứng cạnh hắn khi tinh luyện."},{"chuong":925,"tieuDe":"Hoàng Tộc Đại Tấn","tomTat":"Hàn Lập đưa Lục Tú quận chúa vào mật thất luyện khí ở trung tầng Hỏa điện, nơi có đại đỉnh và tám pháp khí hình hồ lô dùng dẫn hỏa luyện khí. Trong lúc trò chuyện, Lục Tú quận chúa tiết lộ mình không phải quận chúa hoàng tộc trực hệ, từ nhỏ theo Ngọc di tu luyện, chưa từng gặp hoàng thượng Đại Tấn và chỉ có quan hệ sâu xa với hoàng tộc. Nàng bỏ vẻ đoan trang khi không có người ngoài, lộ tính cách tinh ranh, đồng thời cho biết tổ phụ mình là một trong Đại Tấn tứ đại tán tu. Sau đó nàng giao huyết ty ngân cho Hàn Lập luyện hóa và yêu cầu bồi thường nếu hắn làm hỏng, còn Hàn Lập kích hoạt đại đỉnh cùng tám hồ lô phun lửa để bắt đầu xử lý tài liệu. Ở một lầu các trên đỉnh núi, đạo cô lớn tuổi họ Diệp và trung niên mỹ phụ Diệp gia bàn về kế hoạch hoàng tộc đã chuẩn bị hơn bốn trăm năm để mưu đoạt hai món linh bảo. Mỹ phụ cho rằng Diệp gia tuy mang danh đệ nhất thế gia tu tiên giới nhưng thực chất bị các thế lực lớn kìm kẹp, nên phải mạo hiểm để thoát khỏi tình thế bị hi sinh. Hai người tiếp tục tranh luận về uy lực Thông thiên linh bảo, sức ép từ Phật, Đạo, Nho và sự tồn tại của tu sĩ Hóa Thần kỳ tại nhân giới. Cuối chương, mỹ phụ tiết lộ tin tức về Hóa Thần kỳ đến từ một trưởng lão Diệp gia mới thu nhận, khiến đạo cô càng chú ý đến nguồn tin này."},{"chuong":926,"tieuDe":"Ô Phong Linh","tomTat":"Trong nội bộ hoàng tộc Diệp gia, đạo cô lớn tuổi và trung niên mỹ phụ bàn về vị trưởng lão mới đến từ Thiên Lan thảo nguyên, việc giữ kín bí mật gia tộc và kế hoạch đoạt hai kiện thông thiên linh bảo. Họ nhận ra vài thế lực lớn ở kinh thành đã tăng tu sĩ Kết Đan kỳ, nhưng Tam Hoàng quan tung tin luyện trọng bảo đang giúp phân tán chú ý, còn Bình Sơn ấn nếu luyện thành sẽ là chiến lực rất lớn. Mỹ phụ cũng báo rằng hai người trong Tứ đại tán tu đã nhận cung phụng hoàng tộc, Tây Bỉnh sơn Quỷ Vương và phó cốc chủ hùng sư Vạn yêu cốc cũng sẵn lòng giúp sức. Ở Địa hỏa điện, Hàn Lập luyện thành Huyết Ti Ngân cho Lục Tú Quận chúa và tiếp tục được nàng giao hộp ngọc chứa Ô Phượng linh để xử lý. Khi hộp mở ra, hồng mang khiến Hàn Lập vô thức vận Minh Thanh Linh Mục, buộc hắn phải che giấu bằng lời nói dối về linh thủy lau mắt. Lục Tú kể Ô Phượng linh là lông đuôi nàng lén nhổ từ linh cầm của một vị đại thần thông tiền bối ở hải ngoại. Đại Diễn Thần Quân nhận định vật này không thể thay lông Hạo Dương Điểu nhưng có thể cải biến để tăng uy lực Tam Diễm Phiến, tiếc là linh tính đã hao tổn nhiều. Cuối cùng Hàn Lập nhận xử lý Ô Phượng linh, đổi lại Lục Tú hứa nếu biết sẽ giúp hắn xác nhận một việc."},{"chuong":927,"tieuDe":"Phong Khởi Sạ Khởi","tomTat":"Sau khi giúp quận chúa tinh luyện Huyết ti ngân, Hàn Lập lặng lẽ rời Địa Hỏa Điện, đồng thời xác nhận mình đã dò được manh mối về Ô Phượng Linh để sau này tăng uy lực Tam Diễm Phiến. Hắn cố ý bế quan tránh quận chúa, tiếp tục làm nhiệm vụ tinh luyện tài liệu trong Hoàng Thanh Quan, được Vi lão coi trọng và truyền thêm kỹ nghệ, còn bản thân thì chuyên tâm tu luyện Minh Vương Quyết. Một thời gian sau, tin Nghiêm nho sinh đột ngột chết bệnh cùng sự xuất hiện của nhiều tu sĩ lạ khiến Hàn Lập cảm thấy phong ba sắp nổi, nên âm thầm rời khỏi Hoàng Thanh Quan sau hơn một năm ẩn thân tại đây. Việc một đệ tử Luyện khí điện biến mất không dấu vết khiến cao tầng Hoàng Thanh Quan kinh động; lão đạo cô tra hỏi lai lịch Hàn Lập, chú ý đến sự trùng tên với trưởng lão mới của Nghiệp gia và nghi ngờ Bạch Lộ thư viện có liên quan. Bà vừa ra lệnh điều tra Hoa Liên cùng lai lịch Hàn Lập, vừa yêu cầu Luyện khí điện không được đình trệ việc luyện chế trọng yếu trong thời hạn ba năm. Sau đó hơn một năm, Đại Tấn nam bộ liên tiếp xuất hiện ba kẻ kỳ lạ chuyên thu gom tài liệu quý: một người trẻ tuổi hỏi mua khoáng thạch vô danh, một tu sĩ che mặt vung linh thạch mua Hỏa tích mộc, và một đại hán xấu xí Nguyên Anh trung kỳ cưỡng ép Tông Bình thế gia giao Ngũ Quang mộc. Các vụ mua vét, mất trộm và cưỡng ép giao dịch làm nhiều tông môn, thế gia chấn động, khiến khắp nam bộ Đại Tấn nổi lên làn sóng truy lùng kẻ thần bí đang săn tìm thiên tài địa bảo."},{"chuong":928,"tieuDe":"Nhạc Dương Cung","tomTat":"Lũng châu được giới thiệu là đại châu biên giới phía tây Đại Tấn, địa hình hiểm trở và gần như nằm dưới sự khống chế chung của chính đạo Nhạc Dương Cung cùng ma đạo Ma Mộc Tông. Nhạc Dương Cung đặt tại Nam Thiên Phong trong Thiên Nhạc sơn mạch, có mấy vạn đệ tử, phòng ngự kiên cố và đại trận mười ba tầng cấm đoạn. Hàn Lập bí mật xuất hiện gần rìa sơn mạch, cho Đại Diễn Thần Quân biết hắn cần lông đuôi Hạo Dương Điểu để hoàn thiện vật liệu luyện Tam Diễm Phiến. Sau khi cân nhắc nguy cơ đối đầu đại tu sĩ Nguyên Anh hậu kỳ của Nhạc Dương Cung, hắn bác bỏ phương án trao đổi công khai và quyết định nhắm vào Hạo Dương Điểu nhỏ cấp bảy thay vì con lớn cấp tám. Hàn Lập tiết lộ mình đã dùng Dẫn Mộng Thuật hỏi được quy luật xuất cung của linh cầm, đồng thời xác định sau vụ này sẽ tới Tấn Kinh rồi sang đông bộ Đại Tấn tìm ác giao. Đại Diễn Thần Quân thừa nhận nguyên thần chỉ còn duy trì khoảng ba bốn năm dù có Dưỡng Hồn Mộc, khiến Hàn Lập càng quyết tâm giúp ông gom vật liệu luyện con rối Nguyên Anh cấp. Hai ngày sau, Hàn Lập tìm được sơn cốc rừng đào hẻo lánh, bày bảy tám bộ trận kỳ gồm các trận che khí tức, ngăn linh khí, vây địch và ảo trận, rồi ngồi nhập định chờ thời cơ."},{"chuong":929,"tieuDe":"Hạo Dương Điểu","tomTat":"Đến tối ngày thứ ba, Hàn Lập kết thúc nhập định trong rừng đào, dùng nguyệt quang thạch chiếu sáng rồi lấy san hô hồng và Nghê Thường thảo ra bố trí mồi nhử. Hắn giải thích với Đại Diễn Thần Quân rằng linh thảo này còn gọi là Dụ yêu thảo, mục tiêu là dụ con Hạo Dương điểu nhỏ của Nhạc Dương cung khi nó được thả ra hít thở. Phương Chử, tu sĩ Trúc Cơ chuyên chăm sóc Hạo Dương điểu nhờ hiểu một phần ngôn ngữ linh điểu, mang liễm tức phù theo dõi linh cầm nhưng không ngờ nó đột nhiên bốc hỏa đổi hướng bay đi. Hắn dùng ngọc bài và tiếng chim gọi về không được, liền gửi truyền âm phù báo động về Nhạc Dương cung rồi truy đuổi theo cảm ứng. Cùng lúc, nhiều linh thú trong Thiên Nhạc sơn mạch cũng náo loạn: linh cầm bị đệ tử cấp thấp ghì giữ, nhện đen trong hang bí ẩn nổi giận, và một Hạo Dương điểu khác ở bí điện Nam Thiên phong bị nữ tu áo tím trấn áp. Khi Nghê Thường thảo nở sáu lá, yêu thú cấp thấp tụ tập thành thú triều quanh sơn cốc, Hàn Lập khởi động ảo trận để che phủ rừng đào. Cuối chương, từ hai hướng đông tây đồng thời xuất hiện tiếng thú gầm và tiếng chim hót, một khối sáng vàng lớn cùng một hỏa cầu đỏ khổng lồ đều lao về sơn cốc khiến Hàn Lập kinh ngạc."},{"chuong":930,"tieuDe":"Đắc Linh","tomTat":"Ngoài Hạo Dương điểu đang bị Nghê Thường thảo hấp dẫn, một yêu thú vàng xấu xí cũng lao tới sơn cốc và được Đại Diễn Thần Quân nhận ra là Thổ Giáp Long, loài hiếm có phòng ngự mạnh, giỏi tìm thiên tài địa bảo và có thổ độn. Hàn Lập lập tức dùng trận bàn kích hoạt nhiều tầng cấm chế, vây Hạo Dương điểu trước và trì hoãn Thổ Giáp Long để xử lý từng mục tiêu. Hắn dùng hắc phù hóa quỷ trảo ép linh cầm ứng phó, rồi dựa vào tốc độ đôi cánh bạc phóng lưới điện vàng trói chặt Hạo Dương điểu. Khi Thổ Giáp Long phá cấm chế cuối cùng và định chạm đất độn đi đoạt Nghê Thường thảo, mười hai Lục Dực Sương công do Hàn Lập phục sẵn đồng loạt phun hàn khí, biến nó thành băng điêu. Hàn Lập uy hiếp Hạo Dương điểu tự rụng vài cọng lông đuôi mang hỏa linh, cất vào hộp ngọc rồi đánh ngất linh cầm để chuyển sang xử lý Thổ Giáp Long. Sau đó tử bào lão ẩu của Nhạc Dương cung bí điện cùng Phương Chử tới sơn cốc, phát hiện Hạo Dương điểu mất lông đuôi nhưng còn sống. Lão ẩu dò dấu rồi truy tới vùng trụ đá ngoài trăm dặm, nơi bà gặp Mã đạo hữu của Ma Mộc tông và nghi ngờ hắn liên quan đến biến cố."},{"chuong":931,"tieuDe":"Ám Lưu","tomTat":"Tôn lão ẩu của Nhạc Dương cung chặn Mã đạo hữu vì nghi ông liên quan chuyện yêu thú trong cung gặp nạn, nhưng Mã đạo hữu phủ nhận và cảnh báo việc vu oan có thể làm bùng phát xung đột chính ma. Ông khai rằng mình truy bắt Thổ Giáp Long cấp bảy suốt sáu ngày sáu đêm đến Thiên Nhạc sơn mạch, sau đó mất dấu vì yêu thú gặp biến cố và chỉ thấy một đạo thanh hồng độn quang bay khỏi núi. Tôn lão ẩu rời đi truy tìm đầu mối nhưng không có kết quả, còn Mã đạo hữu nhận ra kẻ kia có thủ đoạn dẫn dụ yêu thú nên quyết định về bẩm báo sư huynh. Nhạc Dương cung phong tỏa tin Hạo Dương điểu bị lấy Hỏa linh, đồng thời bí mật phái đệ tử điều tra cao giai tu sĩ luyện bảo vật; Ma Mộc Tông cũng lặng lẽ dò xét cao giai tu sĩ ngoại lai ở Lũng châu. Động thái của hai thế lực lớn khiến các tông môn, gia tộc và tiểu thế lực trong châu bất an, cho rằng cân bằng mong manh sắp bị phá vỡ. Trong khi đó, Hàn Lập không biết mình đã gây ra ám lưu, đang ẩn trong thạch thất vô danh để kiểm kê chiến lợi phẩm, bàn với Đại Diễn Thần Quân về Hỏa linh, Thổ Giáp Long và chuyến đi Tấn kinh dự đại hội đấu giá. Cuối chương, hắn dùng anh hỏa bao bọc Hỏa linh để dẫn tinh hỏa đỏ sậm bên trong ra, bắt đầu xử lý tài liệu."},{"chuong":932,"tieuDe":"Bất Ngờ Gặp Cố Nhân","tomTat":"Sau một đêm trong thạch thất, Hàn Lập rời Lũng châu để tiến về Tấn kinh, ban đầu chỉ lộ tu vi Kết Đan rồi dùng Ngự phong xa toàn lực phi độn sau khi ra khỏi địa giới này. Khi đến Kim giang quận gần Tấn kinh, hắn lại thu liễm khí tức và đổi sang xe ngựa phàm tục vì quanh đô thành có quy định ngầm cấm tu tiên giả phi hành, đánh nhau. Trên đường, Hàn Lập âm thầm luyện hóa Tuyết phách hoàn, nhận thấy Kiền lam băng diễm và hàn khí Lục dực sương công tinh thuần hơn, tạp chất Tử la thiên hỏa cũng dần dung hợp biến mất. Trên quan đạo, một đội kỵ binh giáp bạc khoảng ba bốn trăm người mang cờ chữ Vương vượt qua hắn, giữa đoàn có xe bích ngọc phát linh quang và có tu sĩ Luyện Khí bên trong. Hàn Lập cảm thấy ánh mắt trong xe có phần quen thuộc nhưng không cưỡng ép dùng thần thức dò xét vì xe có cấm chế. Đến ngã ba có hàng nước, hắn được binh sĩ mời vào gặp “tiểu thư” và nhận ra nữ tu Luyện Khí tầng năm chính là Tào Mộng Dung, cố nhân từng được hắn chỉ điểm khi mới đến Đại Tấn. Tào Mộng Dung vui mừng nhắc ân cũ rồi giới thiệu Vương sư tỷ và bá phụ của nàng, Trụ Nam tướng quân đang trấn đóng Nam Cương và phụng mệnh về kinh."},{"chuong":933,"tieuDe":"Kiếm Minh","tomTat":"Hàn Lập gặp Trụ Nam tướng quân, một trong tám đại tướng quân nổi danh của Đại Tấn, và từ đó nhận ra quân quyền triều đình có liên hệ sâu với các thế lực tu tiên lớn. Vương tiểu thư dò xét thân phận Hàn Lập qua chuyện Tào Mộng Dung từng được hắn chỉ điểm mà tiến bộ nhanh, còn Hàn Lập dùng lý do từng trọng thương để che giấu tu vi thật. Trụ Nam tướng quân mời Hàn Lập cùng đi kinh thành, Hàn Lập nhận lời vì muốn tìm hiểu tình hình nơi đó và tin tức đấu giá hội. Trong lúc Tào Mộng Dung vẫn lộ vẻ lưu luyến Hàn Lập, Vương tiểu thư âm thầm đánh giá và cho rằng hắn không xứng với sư muội. Hàn Lập và Trụ Nam tướng quân trò chuyện hợp ý về cổ thư, Man hoang, khe nứt không gian, dị giới yêu ma và Côn Ngô tiên sơn. Khi câu chuyện vừa nhắc đến Côn Ngô tiên sơn, bổn mạng phi kiếm trong cơ thể Hàn Lập bỗng phát tiếng long ngâm vì hắn cảm ứng được một cố nhân phi độn ngang qua. Hàn Lập giải thích pháp bảo trong người làm loạn, cáo từ mọi người rồi hóa thành ánh sáng thanh hồng bay đi, khiến người phàm quanh quán trà kinh hãi xôn xao."},{"chuong":934,"tieuDe":"Khiêu Lương Tiểu Sửu","tomTat":"Hàn Lập hiện thân trên một đỉnh núi gần Tấn kinh và bàn với Đại Diễn Thần Quân về cổ ma đang giữ hai thanh Thanh Trúc Phong Vân Kiếm. Vì tu vi chưa hồi phục hoàn toàn, Tam Diễm Phiến chưa luyện xong và phần thắng quá thấp, hắn quyết định tạm gác việc đoạt kiếm, chờ khôi lỗi cùng pháp bảo hoàn thành rồi mới tính quyết chiến. Đại Diễn Thần Quân phân tích tiềm năng đáng sợ của kiếm trận nếu Hàn Lập dùng Anh hỏa tế luyện phi kiếm lâu dài, đồng thời đoán cổ ma tới Tấn kinh để dự đấu giá hội và nhắc Hàn Lập phải cẩn thận. Vào Tấn kinh, Hàn Lập không tìm Trụ Nam tướng quân mà đến tửu lâu Phùng gia, dùng ngọc bội chữ Phùng để Phùng Thuyên nhận thân phận Đại công tử và sắp xếp chỗ ở kín đáo. Phùng Thuyên dẫn hắn tới một căn nhà hẻo lánh bằng xe ngựa do lão già gù lưng đánh xe, nhưng Hàn Lập đã sớm nhìn ra nơi này là bẫy có cấm chế và người mai phục. Khi Phùng Thuyên định chạy vào sân, Hàn Lập vạch trần âm mưu rồi dùng hỏa tuyến giết hắn. Lão già gù lưng cùng ba tu sĩ trong hoàng vụ lập tức phóng phi đao, phi xoa và hỏa quang tấn công, nhưng Hàn Lập chỉ phất tay áo và chụp hư không đã thu giữ, khống chế pháp khí. Nhận ra chênh lệch thực lực, lão già dùng huyết phù độn tẩu còn ba tu sĩ trong hoàng vụ cũng chia hướng bỏ chạy."},{"chuong":935,"tieuDe":"Ra Oai","tomTat":"Hàn Lập ra tay dứt khoát với toán phục kích: ba kẻ bỏ chạy bị kiếm quang đuổi kịp giết chết, còn lão gù cố trốn về nơi đông người nhưng bị phi châm trong suốt hồng quang xuyên thủng huyết vụ và bị quang thủ màu xanh bắt về. Hắn kiểm tra phi châm mới luyện từ tinh hóa yêu đan, hài lòng vì tốc độ, khả năng ẩn giấu và tiềm năng tăng uy lực đều đúng dự tính. Lão gù tự xưng là người Khổng gia và cầu xin tha mạng, nhưng Hàn Lập dùng phù làm lão mê muội rồi thi triển Mộng dẫn thuật cưỡng ép lấy tin tức, sau đó thiêu lão thành tro. Từ ký ức lão, Hàn Lập biết Phùng chưởng quỹ đã bị Khổng gia khống chế từ trước và đã báo tin ngọc bội Phong Nhạc, khiến Phùng đại công tử tự mình sắp đặt cạm bẫy nhưng thất bại. Hắn cũng biết biến cố sau Tham vương đại hội: lão tổ Khổng gia bị quỷ chiếm xác, Huyễn vương nổi giận thả hàng nghìn thi vệ, lập quỷ trận vây tu sĩ ba nhà và nhờ cổ mộ tăng tới Nguyên Anh hậu kỳ. Sau hơn một tháng, một cao thủ Nguyên Anh ở phụ cận đánh lui tam thi, còn Hàn Lập thì suy đoán Thiên thi châu có thể liên quan đến khả năng hồi phục kỳ dị của Huyễn vương và nhớ đến công dụng của nó khi tu luyện Minh vương quyết. Vì nơi ở hiện tại đã dính đến Phùng chưởng quỹ, Hàn Lập quyết định đổi chỗ, cân nhắc thuê đạo quan hoặc tự miếu trong Tấn kinh rồi rời khỏi căn nhà không dấu vết."},{"chuong":936,"tieuDe":"Thiên Cơ Các","tomTat":"Sau khi xác nhận các đạo quan nhỏ trong Tấn kinh chỉ có phàm nhân, Hàn Lập ở tạm một đêm rồi sáng hôm sau phát hiện một thư viện có khí tức tu sĩ. Hắn vào gặp lão nho áo trắng, thả khí tức Nguyên Anh kỳ khiến đối phương không dám chống cự, rồi hỏi rõ vị trí phường thị, nơi giao dịch và tin tức đấu giá riêng. Lão nho phục chế bản đồ vào ngọc giản và cho biết đại đấu giá hội sau chín ngày sẽ tổ chức tại Bảo Quang Điện trong Tây Tấn phường thị, chia cấp Kết Đan và Nguyên Anh. Hàn Lập theo ngọc giản tới Tây Tấn phường thị được pháp trận ẩn giấu, vừa dò mua tài liệu hiếm vừa tính bán vật phẩm quý đổi linh thạch để chuẩn bị đấu giá. Hắn chọn Thiên Cơ Các, một thương các ba tầng có vẻ đủ thế lực, và được trung niên áo bào trắng mời lên tầng ba tiếp đãi. Sau khi xem danh sách tài liệu của Hàn Lập, trung niên cho biết Thiên Cơ Các chỉ có một khối nhỏ Lôi Linh thạch, nhưng vật này thuộc về một tiền bối Nguyên Anh kỳ giao hảo với bổn các và trước mắt chỉ ưu tiên trao đổi, nếu không đổi được mới đưa ra đấu giá."},{"chuong":937,"tieuDe":"Thiên Cơ Phủ","tomTat":"Triệu chưởng quỹ đưa cho Hàn Lập ngọc giản ghi các tài liệu và đan dược mà chủ nhân lôi linh thạch muốn đổi, còn Hàn Lập dùng thần thức xem qua nhưng không lộ phản ứng. Hàn Lập nói có thể cung cấp một hai loại vật trong danh sách, song yêu cầu tận mắt xem phẩm chất lôi linh thạch trước khi quyết định, vì vậy Triệu chưởng quỹ phát truyền âm phù mời Phú tiền bối tới Thiên Cơ các. Trong lúc chờ, Hàn Lập hỏi về loại Thiên Cơ Ốc cao giai có thể thu cả động phủ, được Triệu chưởng quỹ giải thích rằng cấp cao nhất gọi là Thiên Cơ Phủ, cực kỳ hiếm và chỉ đổi bằng vật quý. Triệu chưởng quỹ còn tiết lộ chi nhánh kinh đô Đại Tấn chỉ còn một kiện Thiên Cơ Phủ tinh phẩm làm trấn các chi bảo, do Hoa Vận Tử luyện chế, cấm chế có thể sánh với cổ bảo cực phẩm và quyền quyết định thuộc Vương trưởng lão. Phú tiền bối xuất hiện, được nhận ra là tu sĩ Nguyên Anh trung kỳ đỉnh giai, và Hàn Lập đề nghị dùng một gốc xích tinh chi hỏa thuộc tính hơn nghìn năm hỏa hầu để đổi lôi linh thạch. Phú tiền bối vui mừng cho rằng nếu phẩm chất đúng thì đủ giá trị, đồng thời sai Triệu chưởng quỹ đi lấy linh thạch ra cho Hàn Lập xem. Khi bị dò hỏi lai lịch, Hàn Lập tự nhận là tu sĩ hải ngoại ít vào Đại Tấn, khiến Phú tiền bối tin quá nửa và đoán hắn đến Tấn kinh vì hội đấu giá. Cuối chương, Vương trưởng lão Thiên Cơ các bước vào thính đường để tự mình tiếp đãi Hàn Lập và Phú tiền bối."},{"chuong":938,"tieuDe":"Giao Dịch Hội Dưới Lòng Đất","tomTat":"Vương trưởng lão Thiên Cơ các ra mặt tiếp Hàn Lập vì nghe có tu sĩ Nguyên Anh trung kỳ muốn mua Thiên Cơ phủ, đồng thời nói Quy linh quyết của mình chỉ dừng ở tầng thứ bảy. Lão Phú chen vào hoàn tất giao dịch trước, đem Lôi linh thạch đổi lấy Xích tinh chi của Hàn Lập; Hàn Lập kiểm tra khối đá, xác nhận đúng là Lôi linh thạch nhưng phẩm chất bình thường. Do Xích tinh chi là cực phẩm linh dược, lão Phú định bù thêm linh thạch, nhưng Hàn Lập đưa danh sách tài liệu cần tìm và muốn đổi lấy tin tức hữu dụng. Lão Phú không có sẵn tài liệu, bèn truyền âm tiết lộ đấu giá hội Tấn Kinh mười năm một lần chia thành hội Minh công khai do chính đạo duy trì và hội Ám dưới lòng đất do ma đạo tà tông chủ trì. Biết hội dưới lòng đất thường có vật phẩm cấm và tài liệu quý hiếm theo hình thức lấy vật đổi vật, Hàn Lập quyết định tham dự và hẹn ngày cuối đại hội đấu giá quay lại Thiên Cơ các để được lão Phú tiến cử. Sau khi hai bên thu vật giao dịch, Vương trưởng lão chuyển sang chuyện Thiên Cơ phủ, nhấn mạnh giá trị của nó vượt xa Xích tinh chi ngàn năm và muốn dẫn Hàn Lập vào giới tử không gian đặc chế để xem. Trước sự kinh ngạc của Hàn Lập, Vương trưởng lão giải thích giới tử không gian là bí thuật của Đại Tấn dùng vết nứt không gian luyện thành tư nhân không gian, mới được nghiên cứu ra gần ngàn năm."},{"chuong":939,"tieuDe":"Giới Tử Không Gian","tomTat":"Hàn Lập nghe Vương trưởng lão nói Thiên Cơ Các có thể luyện chế khe hở không gian thành giới tử không gian thì kinh ngạc, vì điều này vượt xa nhận thức hắn từng biết ở Thiên Nam. Vương trưởng lão và Phú tiền bối giải thích giới tử không gian không thần kỳ như tưởng tượng, số lượng ở Đại Tấn rất ít, còn bí thuật liên quan vốn do luyện khí đại sư Thiên Cơ Các vô ý tạo ra, Thiên Cơ Ốc và Thiên Cơ Phủ cũng dựa trên đó mà nghiên cứu. Phú tiền bối cáo từ để xử lý Xích Tinh Chi, đồng thời truyền âm nhắc Hàn Lập đừng bỏ lỡ giao dịch hội dưới lòng đất ngày cuối cùng. Sau đó Vương trưởng lão đưa Hàn Lập tới Truyền Tống Trận phía sau lầu các, tiêu hao linh thạch bậc trung để vào một không gian chết đầy đá trắng, bầu trời xám tro và không có linh khí. Hàn Lập thất vọng khi biết giới tử không gian chủ yếu dùng để cất giữ, tránh địch hoặc thí nghiệm pháp khí, không thể tùy thân mang theo, nhưng lập tức chú ý khi nghe Thiên Cơ Các có thể củng cố vết nứt không gian chưa sụp đổ. Hắn hàm hồ nói mình từng phát hiện một vết nứt không gian ở hải ngoại, khiến Vương trưởng lão hiểu hắn không muốn nói sâu nên không truy hỏi. Cuối chương, Vương trưởng lão lấy Thiên Cơ Phủ từ hộp ngọc, thi pháp cho nó hóa thành động phủ ngọc thạch có quầng sáng bao phủ, rồi dùng bạch ngọc lệnh bài mở cấm chế để Hàn Lập bay vào kiểm tra."},{"chuong":940,"tieuDe":"Không Hẹn Mà Gặp","tomTat":"Hàn Lập quay lại hỏi Vương trưởng lão Thiên Cơ các về khả năng thu nhỏ của Thiên Cơ phủ, đặc biệt là việc có thể chứa linh thú, linh dược và vật sống hay không. Vương trưởng lão giải thích Thiên Cơ phủ chỉ thích hợp biến hóa nhà cửa như vật chết, còn khi thu nhỏ sẽ phong bế linh khí và tạo áp lực không gian khiến vật sống khó tồn tại. Sau khi xem ngọc giản danh sách tài liệu, Hàn Lập dùng một cái giá lớn đổi lấy Thiên Cơ phủ, bán thêm yêu đan và dược thảo để lấy nhiều linh thạch, rồi cảnh giác vì sợ lộ tài. Hắn đổi dung mạo thành trung niên nho sinh lam bào để tiếp tục tìm tài liệu luyện khôi lỗi và Tam Diễm phiến, nhưng các thương hào đều không có thứ cần mua. Khi tới Bảo Quang điện, Hàn Lập gặp nhóm tu sĩ Nguyên Anh đi ra, trong đó có Thiên Lan thánh nữ từng giao chiến với hắn trên thảo nguyên. Nàng nhận ra cảm giác quen thuộc và chi tiết bọc dài sau lưng, khiến Cát Thiên Hào của Âm La tông nghi hắn liên quan Quỷ La phiên. Cát Thiên Hào dùng thần thức dò xét nhưng bị thần thức của Hàn Lập bắn ngược, rồi yêu cầu hắn mở bọc sau lưng. Các tu sĩ Nguyên Anh còn lại lập tức áp sang hai bên, làm sát khí trước Bảo Quang điện dâng cao và tình thế trở nên căng thẳng."},{"chuong":941,"tieuDe":"Uy Hiếp","tomTat":"Trong Tấn Tây phường thị, Hàn Lập bị Cát Thiên Hào và Thiên Lan thánh nữ Lâm Ngân Bình ép lại khi đối phương nghi hắn là đại địch của Thiên Lan thánh điện. Hắn ban đầu lộ sát khí nhưng lập tức viện quy củ cấm đấu pháp của phường thị để khiến đối phương không thể tùy tiện ra tay. Ô Ích và một tăng nhân xấu xí xuất hiện, đại diện quy củ phường thị chất vấn nhóm Âm La Tông, đồng thời cho biết họ chỉ ngăn đấu pháp trong phường thị chứ không can dự ân oán bên ngoài. Lâm Ngân Bình công khai thân phận, yêu cầu xem gói đồ trên lưng Hàn Lập, và qua đối đáp với Ô Ích còn tiết lộ Từ tiên sư của Đột Ngột nhân đã là một trong bốn đại tiên sư. Khi tình thế nghiêng bất lợi, Đại Diễn Thần Quân truyền âm khiến Hàn Lập bình tĩnh lại. Hàn Lập sau đó đổi thế, tuyên bố mình tinh thông độn thuật, nếu bị ép oan thì sẽ thoát thân rồi dùng thủ đoạn âm độc trả thù Âm La Tông hoặc Thiên Lan. Lời uy hiếp khiến Cát Thiên Hào, Lâm Ngân Bình, Ô Ích và tăng nhân đều phải kiêng dè, buộc Lâm Ngân Bình xuống giọng đề nghị nếu thật sự nhận nhầm thì Hàn Lập có thể nêu một điều kiện hợp lý để được bồi thường."},{"chuong":942,"tieuDe":"Ngọc Bội","tomTat":"Thiên Lan thánh nữ vì nhận lầm bao đồ của Hàn Lập nên không muốn vô cớ dựng thêm kẻ địch, bèn đề nghị bồi thường linh thạch. Hàn Lập không nhận linh thạch mà mở bao sau lưng, để lộ một thanh trường đao kim sắc, khiến Cát Thiên Hào và các tu sĩ Âm La Tông xấu hổ vì đoán sai. Sau khi Lâm Ngân Bình dùng thần thức kiểm tra và xác nhận không có chướng nhãn pháp, Hàn Lập chỉ lấy ngọc bội hồ điệp bên hông nàng làm bồi thường rồi rời khu chợ dưới thân phận Lệ Phi Vũ tán tu Hải ngoại. Lâm Ngân Bình vẫn nghi ngờ lai lịch này nên hỏi Cát Thiên Hào, còn hắn giải thích tu sĩ hải ngoại đông đảo, tự hoạt động và khó kiểm chứng. Trên đường rời đi, Hàn Lập trao đổi với Đại Diễn Thần Quân, biết ngọc bội mang khí tức của Lâm Ngân Bình có thể luyện thành ngọc cảm ứng cảnh báo trong phạm vi trăm dặm. Hàn Lập cũng nhận định Thiên Lan thánh nữ và Âm La Tông sẽ còn là phiền phức vì thánh thú phân thân và tiểu đỉnh đều nằm trong Hư thiên đỉnh. Cuối chương, hắn phát hiện kẻ bám theo, cố ý dẫn vào sân bỏ hoang rồi vạch trần lão giả áo xanh dùng quỷ ảnh độn; lão giả hiện thân và nói muốn làm một cuộc giao dịch."},{"chuong":943,"tieuDe":"Xảo Trá","tomTat":"Tiểu lão đầu tiếp cận Hàn Lập để đề nghị giao dịch, nhưng khi bị từ chối liền đưa Nhuyễn trùng thú biến dị ra làm bằng chứng rằng hắn đã nhìn thấu thủ đoạn Hàn Lập biến ống sáo bằng trúc thành trường đao. Lão đòi ba món bảo vật hoặc lượng lớn linh thạch, đồng thời nói đã phái đệ tử theo sau Âm La Tông và Thiên Lan Thánh Nữ để tố giác nếu mình gặp chuyện. Hàn Lập giả vờ nhượng bộ, lấy ra viên Vân Tiêu châu khiến lão tin là cổ bảo thật sau khi kiểm tra bằng Nhuyễn trùng thú. Khi tiểu lão đầu rót pháp lực vào viên cầu, hơn mười con Tam sắc Phệ kim trùng phóng ra cắn xé mặt lão, còn Hàn Lập dùng tiếng hừ lạnh công kích thần thức để chặn tiếng cầu viện. Hàn Lập tiếp tục dùng kim kiếm phủ tử diễm chém đôi thân thể, đóng băng Nguyên Anh rồi dùng lôi điện diệt sạch, sau đó thu túi trữ vật, giết Nhuyễn trùng thú, thiêu hủy dấu vết và rời đi. Một khắc sau, Lâm Ngân Bình, Cát Thiên Hào, nam tu sĩ Kết Đan và những người khác tới nơi; nam tu sĩ xác nhận khí tức sư phụ biến mất tại đây, còn Cát Thiên Hào nhận ra khí tức họ Lệ cùng vết máu và kết luận tiểu lão đầu đã bị diệt khẩu."},{"chuong":944,"tieuDe":"Hàn Tuỷ","tomTat":"Sau khi Tiếu lão nhi biến mất, nhóm Âm La Tông và Lâm Ngân Bình tìm thấy mảnh mộc thuẫn bị hủy, qua đó xác nhận ông đã chết dưới tay Hàn Lập. Cát Thiên Hào đánh giá thần thông của Hàn Lập không dưới tu sĩ Nguyên Anh hậu kỳ, rồi cùng Lâm Ngân Bình thương lượng điều kiện hợp tác truy sát. Ông lệnh Hồ sư đệ phát truyền âm phù triệu tập trưởng lão, đệ tử Âm La Tông tại Tấn Kinh, chủ trương âm thầm truy tìm và dụ Hàn Lập vào pháp trận thay vì để đệ tử cấp thấp giao chiến. Ở phía khác, Hàn Lập kiểm tra túi trữ vật của Tiểu lão đầu và phát hiện một bình ngọc xanh biếc chứa chất lỏng khiến thần thức khó thẩm thấu. Đại Diễn Thần Quân cảnh báo hắn đã lộ thân phận nhưng Hàn Lập vẫn quyết dự đại hội đấu giá để tìm tài liệu cần thiết, đồng thời nhận được lời hứa trợ giúp bằng Kinh Thần Thứ nếu gặp nguy hiểm. Khi trở về đạo quán, Hàn Lập bày cấm chế rồi mở bình, hàn khí phun ra khiến căn phòng đóng băng và buộc hắn dùng Tử La Cực Hoả chống đỡ. Đại Diễn Thần Quân nhận ra chất lỏng bạc là Hàn tuỷ sinh trong Huyền Ngọc vạn năm, vật cực hiếm từng nghe Bắc Dạ Tiểu Cực Cung có một bình nhỏ làm trấn sơn chi bảo."},{"chuong":945,"tieuDe":"Hồi Dương Thuỷ Và Thái Dương Tinh Hoả","tomTat":"Hàn Lập hỏi Đại Diễn Thần Quân về ngân châu, được biết đó là Hàn tuỷ, vật vừa là tài liệu luyện đan luyện khí quý hiếm vừa có thể giúp yêu thú giảm thương tổn khi vượt hoá hình lôi kiếp. Đại Diễn Thần Quân kể Hàn tuỷ liên quan Bắc Dạ Tiểu Cực Cung ở Bắc Minh Đảo, nơi nhiều lần bị yêu thú cấp cao Đại Tấn do lão yêu Vạn Yêu Cốc dẫn đầu tấn công để ép giao vật này. Hàn Lập kiểm tra đáy bình nhỏ, thấy hoa văn bông tuyết, còn Đại Diễn Thần Quân nhận ra đó là dấu hiệu Bắc Minh Đảo nên suy ra bình vốn thuộc Tiểu Cực Cung. Đại Diễn Thần Quân tiếp tục tiết lộ mình từng giết một phó cung chủ Tiểu Cực Cung và dùng sưu hồn thuật biết được Hàn tuỷ là nguyên liệu chủ chốt luyện bí dược thượng cổ Hồi Dương Chân Thuỷ, linh dược có thể kéo dài một phần tư tuổi thọ tu sĩ. Tuy vậy, việc luyện dược còn cần Thái Dương Tinh Hoả ở sâu dưới vạn trượng dung nham để rèn Hàn tuỷ, khiến Hàn Lập hiểu đây là mục tiêu cực khó thực hiện. Đại Diễn Thần Quân vẫn sao chép cách điều chế Hồi Dương Thuỷ vào ngọc giản vàng nhạt giao cho Hàn Lập, đồng thời nhắc Hàn tuỷ cũng có thể tăng uy lực Tuyết tinh châu. Cuối chương, Hàn Lập dùng Tử La Cực Hoả dẫn hàn khí bạc từ Hàn tuỷ vào cơ thể, để Nguyên Anh trong đan điền thử dung hợp ngọn lửa tím với ánh bạc."},{"chuong":946,"tieuDe":"Hàn Trưởng Lão","tomTat":"Hàn Lập ở đạo quán chờ một ngày một đêm, xác định Tử La Cực Hỏa vẫn chưa dung hợp được hàn khí trong hàn tủy nên chuyển sang dùng hàn tủy làm tài liệu để luyện lại Tuyết Tinh Châu. Ở góc bắc Tấn kinh, một thanh niên mặc thanh sam được gọi là Hàn trưởng lão xuất hiện trong phủ Nghiệp gia với diện mạo giống Hàn Lập đến bảy phần. Vân Dật đưa cho hắn bạch ngọc giản chứa bức họa người mà Âm La tông đang âm thầm truy tìm, và Hàn trưởng lão xác nhận đó chính là kẻ thù mình muốn tìm. Sau khi Vân Dật rời đi, Hàn trưởng lão lấy ra một thanh phi kiếm Kim Lôi trúc bị hắc tia trói chặt, dùng máu đen áp chế nhưng vẫn chưa xóa được linh tính, rồi tính rằng giết Hàn Lập sẽ báo thù chủ hồn bị diệt và khiến phi kiếm thành vật vô chủ. Trong một lầu gác khác, Vân Dật, nhị trưởng lão Nghiệp gia và phụ nhân xinh đẹp bàn rằng Hàn trưởng lão có ích cho đại sự nhưng tà môn, phải lung lạc mà vẫn đề phòng. Nhị trưởng lão cũng yêu cầu Nghiệp gia bí mật mua vật liệu tại đại hội đấu giá để luyện chế mấy món pháp khí phục vụ kế hoạch đoạt bảo mấy năm sau."},{"chuong":947,"tieuDe":"Đấu Giá Đại Hội","tomTat":"Nghiệp gia bí mật bàn bạc về hội đấu giá, xác nhận đã mua chuộc một số tán tu và dự định diệt khẩu sau khi sự việc kết thúc để tránh lộ liên hệ. Trung niên mặt chữ điền giải thích Bình Sơn ấn sắp luyện thành là con mồi ngoài sáng, dùng để khiến Thái Nhất môn và Thiên Ma tông chú ý mà bỏ qua kế hoạch chính thức của Nghiệp gia. Gia tộc này cũng đề phòng Huyền Thanh và Thất Diệu chân nhân ám toán các trưởng lão rồi cưỡng ép dò thần thức. Trong lúc đó Âm La tông tìm Hàn Lập quanh Tấn kinh không có kết quả, vì hắn vẫn ở đạo quán tu luyện Tuyết Tinh châu. Đến ngày hội đấu giá, Hàn Lập cải trang thành đại hán mặt đen, thu liễm tu vi biểu hiện xuống Kết Đan kỳ và tiến vào Tây Tấn thị, qua được thần thức dò xét của Âm La tông. Cát Thiên Hào tiết lộ việc canh cửa chỉ là đả thảo kinh xà, còn kế hoạch thật là chờ Diệu Âm bảo kính của Thất Diệu chân nhân phá ngụy trang mục tiêu. Hàn Lập đến Bảo Quang điện, nộp linh thạch, nhận ngọc bài rồi bay vào Cửu Tiêu điện tham dự hội đấu giá cấp Nguyên Anh. Sau khi mấy trăm tu sĩ Nguyên Anh lần lượt vào điện, ba tiếng chuông vang lên và đại hội đấu giá chính thức bắt đầu."},{"chuong":948,"tieuDe":"Mặc Kim","tomTat":"Hàn Lập ngồi ở góc khuất đại điện dự ngày đầu đấu giá hội, chủ yếu quan sát các tu sĩ Nguyên Anh Đại Tấn thay vì vội ra tay. Hắn đặc biệt chú ý ba cao tăng Phật tông áo xám, trong đó lão tăng ở giữa cảm ứng được thần thức của hắn khiến hắn thầm cảnh giác. Khi Mặc kim nặng ba cân bốn lạng được đưa ra, Hàn Lập nhận ra đây là tài liệu mình tìm kiếm đã lâu nên quyết định tranh mua. Một lão giả bị hắc khí che phủ bất ngờ cạnh tranh, nhưng Hàn Lập nâng giá lên mười hai vạn linh thạch khiến đối phương bỏ cuộc và Mặc kim rơi vào tay hắn. Lão giả hắc khí sau đó mua Cách hỏa sa với giá hơn hai mươi vạn linh thạch, trở thành người tiêu phí nổi bật nhất ngày đầu. Sau khi rời phường thị, Hàn Lập phát hiện tu sĩ Âm La Tông từng theo dõi mình đã biến mất. Ở Tấn kinh, lão giả họ Cao giao Cách hỏa sa cho Ô quan lão giả của Nghiệp gia, nhận linh đan, linh thạch và ngọc giản tình báo để tiếp tục chuẩn bị giao dịch ngầm liên quan tới Mặc kim."},{"chuong":949,"tieuDe":"Diệu Âm Bảo Kính","tomTat":"Sau ngày đầu mua được Mặc kim, Hàn Lập tiếp tục dự đấu giá hội ở Cửu Tiêu điện nhiều ngày nhưng thu hoạch ít, đến ngày cuối mới mua được một loại tài liệu cần thiết với giá hơn mười vạn linh thạch. Hắn biết ngày cuối còn có giao dịch hội dưới đất dành cho tu sĩ Nguyên Anh, cần quan hệ ma đạo hoặc người giới thiệu mới tham gia được, nên sau khi đấu giá kết thúc không rời phường thị mà đi thẳng tới Thiên Cơ các. Ở lối ra phường thị, Lâm Ngân Bình dùng Diệu Âm bảo kính soi xét tu sĩ qua lại để tìm Hàn Lập nhưng không phát hiện mục tiêu, rồi cùng Cát Thiên Hào phân tích rằng hắn có thể vẫn còn trong phường thị hoặc đã dùng cách khác rời đi. Cát Thiên Hào phóng truyền âm phù gọi tu sĩ thấp giai Âm La tông vào trong phường thị dò xét, đồng thời tiếp tục bố trí người canh cửa. Trong lúc đó, Hàn Lập khôi phục dung mạo thật tại Thiên Cơ các, gặp Vương trưởng lão và lão giả họ Phú, cùng trao đổi kinh nghiệm tu luyện gần nửa ngày. Sau khi rời Thiên Cơ các, Hàn Lập đổi thành khuôn mặt tu sĩ mặt vàng, theo lão giả họ Phú tới Sấu Linh trai và dùng truyền tống trận tạm thời rời phường thị tới một sơn động bí mật phía nam Tấn kinh. Chờ mãi không thấy Hàn Lập, Cát Thiên Hào rủ Lâm Ngân Bình chuyển sang giao dịch hội dưới đất, còn nhóm trưởng lão Âm La tông phân tán theo các hướng khác nhau."},{"chuong":950,"tieuDe":"Cửu U Tông","tomTat":"Sau khi nhóm Âm La Tông rời khu chợ, hai tu sĩ bí ẩn lập tức xuất hiện rồi chia nhau hành động: một người dùng quạt nhỏ tạo mây tía để ẩn thân bám theo hướng Cát Thiên Hào, người còn lại bay về hoàng thành. Ở một ngọn núi hoang gần Tấn kinh, lão giả họ Phú giải thích với Hàn Lập rằng mình cố ý dùng truyền tống trận đưa hắn tránh khỏi đám tu sĩ Âm La Tông đang chờ ở lối ra khu chợ. Ông thẳng thắn lộ thân phận là chấp pháp trưởng lão Cửu U Tông, cho biết tông môn mình vốn bất hòa với Âm La Tông, đồng thời ngỏ ý sau giao dịch hội sẽ nhờ Hàn Lập giúp một việc riêng. Hàn Lập hiểu đối phương là người của một ma đạo đại tông nên không muốn tùy tiện trở mặt, bèn tạm nhận nhân tình và theo ông tới địa điểm giao dịch hội ngầm cách Tấn kinh ba nghìn dặm. Lão giả họ Phú dùng vòng tròn pháp khí mở cấm chế trên vách đá, đưa Hàn Lập vào cửa hang do hai tu sĩ áo tía canh giữ; nhờ sự tiến cử của ông, Hàn Lập nộp một vạn linh thạch và nhận pháp khí thân phận cấp Nguyên Anh để tham gia hội. Trên đường vào trong, lão giả họ Phú giới thiệu lai lịch hai tu sĩ áo tía là đệ tử của Dịch Tẩy Thiên, một trong tứ đại tán tu Đại Tấn, đồng thời nhắc đến Bích Nguyệt thiền sư của Tịnh tông như một kỳ tài khác có hi vọng tiến giai Hóa Thần. Ở một nơi cách giao dịch hội hơn trăm dặm, Cát Thiên Hào bắt được kẻ theo dõi, dùng sưu hồn bí thuật cướp ký ức khiến người này chết thảm rồi thiêu xác, trong khi Lâm Ngân Bình hỏi hắn đã tra ra thân phận và mục đích của đối phương hay chưa."},{"chuong":951,"tieuDe":"Lá Bùa Và Trận Pháp","tomTat":"Cát Thiên Hào cho biết kẻ theo dõi nhóm hắn là tán tu được Diệp gia chào mời, do một trưởng lão họ Hàn của Diệp gia sai tới, mà vị trưởng lão này lại có dung mạo giống mục tiêu họ đang truy đuổi. Hắn đánh giá Diệp gia là hoàng tộc Đại Tấn, đệ nhất thế gia với nhiều trưởng lão Nguyên Anh và thế lực ngầm, nhưng vẫn khẳng định Âm La Tông không lùi vì việc liên quan trấn tông pháp bảo và sinh mạng một chấp pháp trưởng lão. Lâm Ngân Bình nhắc thỏa thuận đồng hành giữa Thiên Lan thánh điện và Âm La Tông, còn thanh niên áo xanh bí ẩn ẩn thân nghe lén, quyết tạm lợi dụng hai phe để tìm Hàn Lập và báo thù cũ. Ở tuyến khác, Hàn Lập được tu sĩ thủ vệ dán lá bùa đặc chế rồi truyền tống vào đại sảnh giao dịch hội ẩn danh. Hắn thử dùng thần thức dò xét và nhận ra lá bùa phối hợp với trận pháp cổ quái trong đại sảnh để tạo quầng sáng che giấu thân phận người dự hội. Giao dịch hội bắt đầu với quy tắc đấu giá vật liệu quý hiếm bằng linh thạch trước, sau đó lấy vật đổi vật, đồng thời hé lộ có một trọng bảo cuối phiên do khách hàng lớn ủy thác. U minh táo, Huyết dương thiết và các vật liệu âm tà lần lượt được bán giá cao, khiến Hàn Lập lo linh thạch không đủ. Khi Ngọc tượng giao xuất hiện và được giới thiệu là vật liệu chế tạo pháp bảo cùng cơ quan khôi lỗi, Hàn Lập lập tức ra giá."},{"chuong":952,"tieuDe":"Xôn Xao","tomTat":"Sau khi mua được món liên quan khôi lỗi, Hàn Lập tiếp tục bỏ ra lượng lớn linh thạch để mua thêm vật phẩm và tranh đoạt nhiều tài liệu luyện khí, khiến linh thạch trong túi hao mất bảy tám phần. Khi đấu giá kết thúc, Bạch Hà trung nhân tuyên bố mở giai đoạn trao đổi tự do, địa hội chỉ cung cấp nơi giao dịch và thu thủ tục phí mỗi bên một vạn linh thạch nếu giao dịch thành công. Nhiều tu sĩ lần lượt lên ngọc bàn đổi vật, ban đầu khá thuận lợi nhưng về sau số người tay không rời bàn tăng lên vì yêu cầu quá hiếm hoặc vật đưa ra chưa đủ hấp dẫn. Hàn Lập âm thầm dùng linh thảo ngàn năm, cao giai yêu đan và tài liệu trong túi để đổi thêm vật liệu khôi lỗi, cuối cùng chỉ còn thiếu Ngũ Hành Ngọc và Huyễn Quang Tinh. Đại Diễn Thần Quân truyền âm hỏi hắn định dùng thứ gì để đổi hai loại cuối, còn Hàn Lập đáp đã chuẩn bị một món ma đạo chí bảo dù rất tiếc cũng phải đem ra. Hắn lên ngọc bàn, công khai hai quả Ma Tuỷ Toản để đổi Ngũ Hành Ngọc và Huyễn Quang Tinh, lập tức khiến toàn trường xôn xao vì vật này được nhận ra là tài liệu luyện chế Long Nhận. Bạch Hà trung nhân nói thương khố của mình có Huyễn Quang Tinh, tự tay kiểm nghiệm Ma Tuỷ Toản bằng lửa trắng, hàn khí xanh và ma khí rồi xác nhận là thật. Sau đó một tu sĩ áo bào tro che mặt hiện ra đưa hộp ngọc cho Bạch Hà trung nhân, mở đường cho cuộc trao đổi giữa hai bên."},{"chuong":953,"tieuDe":"Thu Hoạch Ngoài Ý Muốn","tomTat":"Tại trao đổi hội, Hàn Lập kiểm tra Huyễn Quang Tinh do tu sĩ trong bạch hà đưa ra và xác nhận đúng vật mình cần, rồi dùng một quả Ma Tuỷ Toản hoàn tất giao dịch. Quả Ma Tuỷ Toản còn lại lập tức khiến nhiều người tranh đoạt, trong đó nữ tu trong ngân sắc hà quang đưa ra Ngũ Hành Ngọc, còn ma tu hắc hà cường thế cấm người khác tranh với mình. Ma tu hắc hà bị nhận ra là Khôn Vô Cực, đại trưởng lão Huyết Thê Môn và tu sĩ Nguyên Anh hậu kỳ, khiến hội trường đều kiêng dè. Hàn Lập xem Ngũ Hành Ngọc rồi lại kiểm tra bảy hộp ngọc của Khôn Vô Cực, chú ý nhất tới khối Canh tinh lớn. Cuối cùng Hàn Lập chọn đổi Ma Tuỷ Toản lấy Canh tinh, còn Khôn Vô Cực dùng linh áp ép nữ tu lùi bước, thu Ma Tuỷ Toản rồi rời hội để luyện hóa ma khí trong đó. Khi nữ tu định thu lại hộp gỗ chứa Ngũ Hành Ngọc, Hàn Lập bất ngờ ngăn lại và tuyên bố mình cũng muốn vật này."},{"chuong":954,"tieuDe":"Bình Sơn Ấn","tomTat":"Hàn Lập không tiếp tục tranh luận về Ma Tuỷ Toản mà đưa thêm một hộp ngọc cho nữ tử trong quầng sáng bạc, khiến nàng lập tức đồng ý giao Ngũ hành ngọc. Sau giao dịch, hắn dùng Minh Thanh Linh Mục quan sát và nghi người này chính là Thiên Lan Thánh nữ, đồng thời thu được lượng Canh tinh đủ luyện phân nửa bộ kiếm trận. Khi phần trao đổi lắng xuống, người chủ trì tuyên bố bán đấu giá trọng bảo cuối cùng của giao hoán hội. Hai trưởng lão Diệp gia là Ô quan lão giả và trung niên mặt chữ điền xuất hiện, giải thích Bình Sơn Ấn do Diệp gia hao phí lớn để luyện chế và được Trưởng lão hội quyết định đưa ra đấu giá. Người chủ trì mở hộp, thi pháp hiện ra tiểu ấn màu vàng đất và giới thiệu đây là phỏng chế phẩm của Chưởng Thiên Ấn, có uy năng bình sơn khai địa nhưng cưỡng ép dùng quá mức sẽ tổn thương bảo vật. Đại Diễn Thần Quân trấn an Hàn Lập rằng Tam Diễm Phiến do ông nghiên cứu mạnh hơn Bình Sơn Ấn, đồng thời cảnh báo các đại phái Đại Tấn như Thái Nhất Môn, Thiên Ma Tông và Vạn Yêu Cốc đều có phỏng chế phẩm Thông Thiên Linh Bảo."},{"chuong":955,"tieuDe":"Tái Ngộ Cổ Ma","tomTat":"Hàn Lập và Đại Diễn Thần Quân bàn về phỏng chế phẩm Thông thiên linh bảo, trong đó Đại Diễn Thần Quân nhắc Hư Thiên Đỉnh là chỗ dựa lớn nếu Hàn Lập có thể nắm hoàn toàn. Tại giao dịch hội, người chủ trì công bố Diệp gia đưa Bình sơn ấn ra đấu giá với danh sách tài liệu cao cấp và giá khởi điểm ba trăm vạn linh thạch, khiến nhiều tu sĩ xôn xao. Hàn Lập cân nhắc giá trị Ma tủy toản và truyền thuyết Ma long nhận, rồi quyết định rời hội vì không muốn tranh Bình sơn ấn và nhận thấy mình đã thành mục tiêu chú ý. Trước khi đi, hắn truyền âm với lão giả họ Phú, nhận lời hẹn bốn năm sau đến Vân phủ ở Nam vương quận rồi tới Song hạt sơn bàn việc. Sau khi Hàn Lập rời khỏi lối ngầm, vài tu sĩ cũng âm thầm rời theo, cho thấy các bảo vật trên người hắn đã khiến nhiều kẻ để mắt. Bay xa ngàn dặm, Hàn Lập được phi kiếm cảnh báo và ép kẻ ẩn nấp hiện thân, chính là Cổ ma phân hồn đang giữ hai thanh phi kiếm bản mệnh của hắn. Cổ ma nhận ra phi kiếm được luyện từ Kim lôi trúc chuyên phá tà, nhắc chuyện chủ hồn bị Hàn Lập diệt ở Trụy ma cốc, rồi uy hiếp sưu hồn để biết nguồn gốc Kim lôi trúc. Hàn Lập từ chối, lập kim mạc bằng phi kiếm và thả Phệ kim trùng, chuẩn bị giao chiến với Cổ ma phân hồn."},{"chuong":956,"tieuDe":"Ma Diễm Cuồn Cuộn","tomTat":"Khi Hàn Lập đang định mạo hiểm thử giao thủ với Cổ ma phân hồn bị thương, một đầu đà tóc tai bù xù từ giao hoán hội đuổi tới, tay cầm xích hồng viên bát và bích lục thiền trượng. Người này là Ác hỏa đầu đà, tu sĩ Nguyên Anh trung kỳ, vốn cậy Huyết diễm bát và Bàn Long trượng nên muốn nhân cơ hội mưu đoạt bảo vật. Cổ ma mất kiên nhẫn ra tay trước, thuấn di xuyên qua hỏa mạc, phá quang thuẫn, xé thân thể đầu đà rồi bắt nuốt cả Nguyên Anh. Ba tu sĩ Nguyên Anh sơ kỳ vừa tới chứng kiến cảnh ấy liền kinh hãi bỏ chạy, không còn dám tranh bảo. Hàn Lập nghe Đại Diễn Thần Quân cảnh báo rằng nơi này gần địa hạ giao hoán hội nên quyết định thu phi kiếm, phun tinh huyết thi triển huyết độn rút lui. Cổ ma chặn được trước mặt Hàn Lập và phóng lưỡi tím định hạ sát, nhưng bị một tiếng hừ lạnh công kích thần thức làm đau đớn chậm lại, nhờ đó Hàn Lập hóa huyết ảnh thoát khỏi tầm truy kích. Sau khi mất dấu Hàn Lập, Cổ ma nhận ra độn pháp ấy giống Hóa ảnh độn của Thiết sí ma nhưng không hoàn toàn giống, rồi quay sang chuẩn bị săn nhóm tu sĩ mới tới để cắn nuốt Nguyên Anh hồi phục thương thế."},{"chuong":957,"tieuDe":"Thiên Phù Môn","tomTat":"Vân châu được giới thiệu là đại châu duyên hải phía đông Đại Tấn, nơi nhiều hải ngoại tu sĩ qua lại giao dịch tài nguyên, còn Thiên Phù môn đặt sơn môn tại Bạch Trúc sơn gần Khai Giang trấn. Thiên Phù môn từng là cổ phái chế phù huy hoàng nhờ tổ sư Thiên Phù chân nhân vẽ tam đại mật phù uy chấn Đại Tấn, nhưng vì công pháp chủ tu không nổi bật nên suy tàn, hiện chỉ còn hơn trăm người và dựa vào bí thuật chế phù để duy trì truyền thừa. Hai đệ tử gác cửa bàn chuyện Tam Nguyên phường thị, nguồn thu lớn của môn phái, đang bị Linh Phong môn ép sát nhập hoặc đóng cửa, lại nghi có Sát Dương tông đứng sau khiến Thiên Phù môn và hai nhà đồng minh phải bàn đối sách. Hàn Lập sau bốn tháng thoát khỏi Cổ ma bay tới Bạch Trúc sơn, nói mình mang một vật có quan hệ sâu xa với Thiên Phù môn và muốn gặp chưởng môn. Trong lúc chờ truyền báo, hắn dùng thần thức xác nhận môn phái này quả là mạt lưu tiểu phái, đồng thời nhớ mục đích đến đây liên quan mấy ác giao ở Hoa Vân châu và phương pháp luyện chế Hàng Linh phù. Chưởng môn Nhạc Chân ra nghênh tiếp, nhận ra Hàn Lập là tu sĩ cực mạnh nên cung kính mời vào đại điện và trấn an hai khách phái khác cáo lui. Cuối chương, một đạo bạch quang bay vào điện, hiện ra lão giả bạch bào được Nhạc Chân và môn nhân gọi là Ôn sư thúc, Ôn sư bá."},{"chuong":958,"tieuDe":"Lý Sư Điệt","tomTat":"Ôn lão giả đến đại điện, nhận ra Hàn Lập là tu sĩ Nguyên Anh kỳ và cung kính tạ lỗi, khiến Nhạc Chân cùng các tu sĩ Trúc Cơ Thiên Phù môn hoàn toàn kính sợ. Hàn Lập lấy cốt hạp giao cho Thiên Phù môn, bên trong là cốt phiến ghi phương pháp luyện chế Hàng Linh phù do Vân đạo hữu ủy thác đem về, nhờ đó bí thuật trọng yếu của môn phái tránh khỏi thất truyền. Khi được hỏi về Vân sư huynh, Hàn Lập kể sơ chuyện Quỷ vụ và Âm Minh chi địa nhưng giấu các chi tiết liên quan bí mật của mình. Thiên Phù môn muốn nhân cơ hội kết giao Hàn Lập, còn Nhạc Chân dùng kho điển tịch chế phù do các đời chưởng môn sưu tầm để thuyết phục hắn lưu lại vài ngày. Sau khi Hàn Lập rời đi, Ôn lão giả và môn nhân bàn rằng nếu có một Nguyên Anh kỳ làm chỗ dựa thì vấn đề phường thị cùng áp lực từ Linh Phong môn, Sát Dương tông có thể được hóa giải, nhưng họ cũng lo không có lợi ích gì đủ khiến Hàn Lập động tâm. Dương sư điệt đưa Hàn Lập tới Tàng thư các, giới thiệu Lý sư điệt là người phụ trách điển tịch; cuộc gặp khiến cả Hàn Lập lẫn Lý sư điệt đều có phản ứng lạ. Hàn Lập che giấu sự khác thường trước mặt Dương sư điệt, rồi cố ý giữ Lý sư điệt ở lại bên mình, để lộ thâm ý về một ẩn tình chưa được nói rõ."},{"chuong":959,"tieuDe":"Chuyện Hóa Thần","tomTat":"Hàn Lập gặp lão giả giữ lầu của Thiên Phù môn và trực tiếp thử gọi đối phương là Hướng sư huynh hoặc Lý sư huynh, vì nhận ra người này rất giống tu sĩ từng cùng hắn tham dự Huyết Sắc Thí Luyện ở Hoàng Phong Cốc. Lão giả một mực phủ nhận, tự nhận không họ Lý cũng không họ Hướng, rồi vẫn bình thản dẫn Hàn Lập lên tầng hai xem điển tịch chế phù. Sau khi đối phương rời đi, Hàn Lập cùng Đại Diễn Thần Quân bàn luận và đều thừa nhận không thể dò ra tu vi thật của lão giả. Đại Diễn Thần Quân nêu khả năng đáng sợ rằng người này đã tiến vào Hóa Thần kỳ, có thể tự tán linh lực và hóa Nguyên Anh vô hình trong thời gian ngắn. Từ đó Hàn Lập biết thêm tu sĩ Hóa Thần không nhất định đã phi thăng Linh giới, mà dường như còn chịu một loại hạn chế nên không tùy tiện xuất hiện trong tu tiên giới. Dù Đại Diễn khuyên nên rời Thiên Phù môn, Hàn Lập quyết định tiếp tục ở lại vài ngày để tránh làm đối phương sinh nghi. Hai người chuyển sang bàn việc luyện chế khôi lỗi, trong đó Hàn Lập xác định phải lấy được vảy Xích Hỏa Giao trước, rồi hắn bày cấm chế màu xanh nhạt bao phủ tầng hai trước khi yên tâm đọc ngọc giản."},{"chuong":960,"tieuDe":"Mật Phù Cùng Bát Cấp Ác Giao","tomTat":"Hàn Lập ở lại tàng kinh các Thiên Phù Môn ba ngày ba đêm, đọc hết điển tịch chế phù và sao chép các bí thuật đặc thù để nghiên cứu. Từ đó hắn biết rõ tam đại mật phù của Thiên Phù Môn: Hóa linh phù có thể bồi luyện trong đan điền và có công hiệu bảo mệnh đáng chú ý, Hàng linh phù khó luyện vì vật liệu, còn Lục Đinh Thiên Giáp thuật đã thất lạc sau khi Thiên Phù chân nhân tọa hóa. Khi rời tàng kinh các, Hàn Lập nhận thấy Hướng Chi Lễ vẫn ở tầng dưới với biểu hiện dị thường, rồi được Dương sư điệt mời tới đại điện. Tại đây, Ôn lão giả giới thiệu Thường đạo hữu của Kim Hà sơn và Tạ đạo hữu của Minh Dương cốc, hai tu sĩ Kết Đan đến để bái phỏng vị Nguyên Anh vừa ghé Thiên Phù Môn. Hàn Lập hỏi đường tới Lâm Giang phủ và được báo tin đàn ác giao gây biến lớn, trong đó có lam giao bát cấp khiến tu sĩ Nguyên Anh cũng bị thương. Nam Hải môn vì vậy mời cao giai tu sĩ tới Quần Anh đảo chuẩn bị đại hội đồ giao, còn Hàn Lập đặc biệt xác nhận manh mối hồng giao nghi là xích hỏa giao. Cuối chương, Ôn lão giả dò hỏi xuất thân Hàn Lập rồi thay ba phái đề nghị hắn làm khách khanh trưởng lão, một chức danh danh nghĩa ít ràng buộc nhưng giúp tiểu tông môn có chỗ dựa Nguyên Anh."},{"chuong":961,"tieuDe":"Ác Giao","tomTat":"Ba phái Thiên Phù môn, Kim Hà sơn và Minh Dương cốc không dám thật sự ràng buộc Hàn Lập, chỉ xin hắn làm khách khanh danh nghĩa và xuất thủ một lần để đổi lấy mật thuật, bí thuật, linh thạch cùng Hóa linh phù. Nhạc Chân dâng hộp gỗ chứa Hóa linh phù, Hàn Lập dễ dàng gỡ cấm chế, thấy phù có mộc linh khí tinh thuần và linh tính mạnh nên bắt đầu động tâm. Hắn nhận định phù này vốn khó luyện hóa với tu sĩ bình thường, nhưng bản thân đã là Nguyên Anh trung kỳ và chủ tu công pháp mộc thuộc tính nên có thể dùng được, rồi đồng ý nghe rõ phiền toái của ba phái. Sau khi rời Bạch Trúc sơn, Hàn Lập lấy danh khách khanh trưởng lão Thiên Phù môn đến Sát Dương tông, dễ dàng đánh bại trưởng lão Nguyên Anh duy nhất, khiến Linh Phong môn và các tiểu tông môn quanh Khai Giang trấn rút lui. Ở tuyến khác, Nam Hải môn mở đại hội đồ giao với hơn hai trăm Kết Đan và hơn mười Nguyên Anh, nhưng đám ác giao ẩn nấp lâu ngày khiến lực lượng săn giao dần tan rã. Khi phe tu sĩ suy yếu, bát cấp lam giao bắt đầu tập kích các tổ ít người rồi dùng thủy thuật lẩn xuống đáy biển, làm nhân loại tổn thất mà chưa bắt được giao. Hàn Lập cải trang thành trung niên sắc mặt trắng nhợt, trà trộn vào một đội săn giao với thân phận Kết Đan để đục nước béo cò, nhưng đội của hắn lại mãi không gặp ác giao khiến hắn khó hiểu về vận khí của mình."},{"chuong":962,"tieuDe":"Đấu Giao","tomTat":"Đội tu sĩ do một đại hán Nguyên Anh kỳ dẫn đầu được Nam Hải môn phái tới dò xét hải vực phía tây Quỳnh Anh đảo, nơi trước đó từng có tổ tu sĩ bị bát cấp lam giao đánh lén. Hàn Lập đi trong đội nhưng cố ý chỉ thả thần thức trong phạm vi mười dặm quanh mặt biển, vừa đề phòng ác giao vừa tránh lộ hết thực lực. Không lâu sau, yêu khí và yêu vân từ nhiều hướng kéo tới, trong đó có hai cỗ yêu vân bát cấp lam và hồng, khiến đội tu sĩ nhận ra mình bị đàn ác giao phản vây. Đại hán Nguyên Anh kỳ trấn an mọi người, ra lệnh phát truyền âm phù cầu viện và phân công chống địch, nhưng không ai muốn đối đầu bát cấp ác giao thứ hai. Hàn Lập bèn lộ uy thế Nguyên Anh trung kỳ, lao thẳng tới hỏa vân bát cấp và đối diện Xích Hỏa Giao. Hắn yêu cầu yêu giao giao vài tấm bản mệnh lân phiến rồi rút đi, khiến đối phương nổi giận hiện bản thể và phun long nham hóa dịch. Hàn Lập dùng Tử La Cực Hỏa phối hợp Tuyết Tinh Châu áp chế hỏa dịch, lại dựng hai đỉnh băng chặn hỏa sóng. Khi yêu hỏa không hiệu quả, Xích Hỏa Giao thu nhỏ thân hình, hóa thành mũi nhọn lao tới định cận chiến bắt lấy Hàn Lập."},{"chuong":963,"tieuDe":"Diệt Giao","tomTat":"Xích hỏa giao áp sát Hàn Lập nhưng hắn dùng lôi độn né khỏi trảo kích, đồng thời phóng hồng châm trong suốt xuyên thủng mặt ác giao để mở thế phản kích. Hắn tiếp tục dùng Thanh trúc phong vân kiếm, Linh ảnh thuật và tử sắc liên hoa hàn khí làm Xích hỏa giao phán đoán sai rồi chém rời đầu nó. Khi giao hồn thoát ra, Hàn Lập dùng kim sắc điện võng trói lại và lấy bích lục tiểu bình thu giữ, sau đó thu xác giao cùng yêu đan bát cấp. Hàn Lập vốn muốn nhân cơ hội săn thêm yêu thú bát cấp, nhưng Đại Diễn thần quân truyền âm cảnh báo nhiều đội tu sĩ đang đến và Nam Hải môn sẽ không dễ bỏ qua chiến lợi phẩm này. Hàn Lập xác nhận tình thế bằng thần thức, bỏ ý định tiếp tục can dự và ẩn thân rời khỏi chiến trường. Ở phía khác, bát cấp lam giao cảm ứng Xích Hỏa giao bị diệt nên tấn công dữ dội, nhưng khi thấy viện quân tới thì lập tức dẫn đám thất cấp ác giao rút xuống biển. Sau khi bay xa hơn trăm dặm, Hàn Lập chuyển mục tiêu sang tìm một linh đảo không người để bắt đầu luyện chế khôi lỗi cho Đại Diễn thần quân."},{"chuong":964,"tieuDe":"Liệt Hồn","tomTat":"Hàn Lập theo bản đồ hải vực bay nửa tháng tới một đảo nhỏ vô danh hẻo lánh, chọn nơi này làm chỗ bí mật luyện chế khôi lỗi vì có linh mạch nhỏ nhưng không bị thế lực nào chiếm giữ. Hắn mở hang trong núi, đặt Thiên Cơ Phủ, khởi động cấm chế và ảo trận che phủ ngọn núi bằng sương mù, rồi chuyển linh trùng, linh thảo và thổ giáp long vào các khu trong động phủ. Trong mật thất, Đại Diễn Thần Quân giao bạch sắc ngọc giản ghi toàn bộ tư liệu luyện chế con rối, khiến Hàn Lập nhận ra khôi lỗi nếu thành công sẽ có uy lực gần ngang tu sĩ Nguyên Anh hậu kỳ. Khi Hàn Lập hỏi về tinh hồn cấp cao cho khôi lỗi, Đại Diễn Thần Quân quyết định dùng chính tinh hồn của mình dung hợp vào khôi lỗi, dù điều đó khiến Hàn Lập lo ngại ông sẽ thần hình câu diệt. Ông tiếp tục hé lộ mật thuật phân liệt tinh hồn, dự định chia tinh hồn làm hai: phần chứa phần lớn tinh hồn chi lực nhập vào khôi lỗi, phần mang ký ức và tình cảm tọa hóa để vào Luân Hồi. Trong thời gian luyện chế kéo dài, Hàn Lập chăm sóc linh trùng bằng Nghê Thường Thảo và Tuyết Phách hoàn, phát hiện lục dực sương công luyện hóa đan dược rất nhanh và hàn khí tăng mạnh. Nửa năm sau, Đại Diễn Thần Quân yêu cầu thêm Ma Tủy Toản, ngân liên, cương ngân và tấm tàn bia vào phương án luyện chế để tăng uy lực khôi lỗi, nhưng chương dừng lại khi ông chuẩn bị nói rõ về tấm tàn bia."},{"chuong":965,"tieuDe":"Khôi Lỗi Đại Thành","tomTat":"Đại Diễn Thần Quân nhận ra khối tàn bi trong tay Hàn Lập là Hóa Nhất thần nê đã được thượng cổ tu sĩ luyện thành sất linh nhuyễn ngọc, một tài liệu hiếm có khả năng biến hình, tự chữa trị và hấp thu pháp lực công kích. Ông quyết định phối hợp sất linh nhuyễn ngọc với cương ngân để luyện lớp ngoài khôi lỗi, nhờ vậy khôi lỗi sẽ rất khó bị phá hủy trong nhân giới. Trong một năm tiếp theo, Hàn Lập vừa hoàn thiện các bộ phận khôi lỗi vừa dùng tuyết phách hoàn nuôi mười hai con lục dực sương công, khiến chúng tiến giai, mọc cánh trắng và tăng mạnh độn tốc. Khi khôi lỗi lắp ráp hoàn mỹ, Đại Diễn Thần Quân quyết định dùng liệt hồn thuật để đưa một phần tinh hồn của mình nhập vào khôi lỗi, đồng thời phó thác toàn bộ Đại Diễn Quyết cho Hàn Lập tìm người kế thừa. Hàn Lập phối hợp kéo quang đoàn tinh hồn vào thân khôi lỗi, dùng tử diễm đóng băng khôi lỗi để ổn định dung hợp, rồi lấy Trấn Hồn Phù củng cố phần hồn còn lại của Đại Diễn Thần Quân. Ba tháng sau, Hàn Lập rời hoang đảo vô danh; chương chuyển sang Khô trúc đảo, nơi Khô trúc lão nhân nổi danh hải ngoại nhờ hàn trúc phi kiếm, thiên tang thần thụ và vạn mộc đại trận. Dù Khô trúc đảo có uy danh phòng hộ rất lớn, một vị ác khách bất ngờ xuất hiện tại nơi này."},{"chuong":966,"tieuDe":"Khô Trúc Đảo","tomTat":"Hàn Lập cưỡi thanh hồng đến Khô trúc đảo, dùng Minh Thanh Linh Mục quan sát biển sương nhưng vẫn không nhìn xuyên hoàn toàn Vạn Mộc đại trận. Đại Diễn Thần Quân trong ống trúc cho rằng nơi này thích hợp để kiểm nghiệm khôi lỗi vừa luyện thành và có thể giúp Hàn Lập tăng khả năng sử dụng Thất Diễm Phiến. Hàn Lập lấy khôi lỗi trung niên ra thử uy lực, để nó bắn hai cột sáng xuống vụ hải, gây nổ lớn và kinh động tu sĩ trên đảo. Lão giả Kết Đan cầm đầu nhóm tu sĩ ban đầu chất vấn, nhưng lập tức đổi thái độ khi nhận ra Hàn Lập là Nguyên Anh trung kỳ và không nhìn thấu khôi lỗi. Hàn Lập yêu cầu đổi ba lông đuôi Ô Phượng bằng yêu đan cấp cao, còn lão giả không dám tự quyết vì Ô Phượng đang chuẩn bị tiến giai nên phải dùng Truyền Âm Phù xin ý Khô Trúc lão nhân. Khô Trúc lão nhân truyền giọng mời hai khách Nguyên Anh kỳ đến Nghênh Phượng Các và tuyên bố sẽ lập tức xuất quan gặp mặt. Khi theo đoàn tu sĩ vào đảo, Hàn Lập nhận thấy linh khí dồi dào, cây cối quý hiếm dày đặc và phát hiện nơi đây có hơn mười cây Thiên Tang thần thụ, khác hẳn lời đồn chỉ có một gốc."},{"chuong":967,"tieuDe":"Khô Trúc Đảo Lão Nhân","tomTat":"Hàn Lập và khôi lỗi được lão giả dẫn vào khu trung tâm Khô Trúc đảo, nơi Thiên Tang Thần Thụ nhìn như nhiều cây nhưng thực ra chỉ là một bản thể duy nhất. Tại mộc điện trên đỉnh núi, Hàn Lập quan sát bốn mộc linh vệ có mộc linh khí tinh túy, mặc chiến giáp và cầm giáo đều là đỉnh cấp pháp khí mộc thuộc tính. Trong điện, Khô Trúc lão nhân lộ diện với dung mạo thiếu niên tóc bạc, tiếp khách bằng tang mộc trà pha từ lá Thiên Tang Thần Thụ, còn Hàn Lập giới thiệu mình họ Hàn và khôi lỗi là Lệ sư huynh. Khi Hàn Lập đề cập giao dịch Ô phong linh, Khô Trúc từ chối vì Ô phượng đang ở thời kỳ tiến giai mấu chốt, nhưng đặt điều kiện nếu một trong hai người đánh bại ông trong luận bàn thì giao dịch sẽ thành. Hàn Lập để khôi lỗi xuất chiến trước, còn Đại Diễn Thần Quân truyền âm khuyên dùng cơ hội này thử lực phòng ngự của khôi lỗi. Khô Trúc phóng hơn trăm phi kiếm xanh biếc lập kiếm trận, trong khi khôi lỗi dựng cự thuẫn bạc và vòng bảo hộ ngũ sắc. Thấy ký hiệu trên mặt khôi lỗi, Khô Trúc nghi đối phương dùng Linh văn thuật của Nam Cương Độc Thánh môn, rồi vì cảm giác bị coi thường nên thúc kiếm trận bắn kiếm khí rợp trời về phía khôi lỗi."},{"chuong":968,"tieuDe":"Lôi Hỏa Cung","tomTat":"Khôi lỗi dùng cương thuẫn biến hóa thành nhiều quang thuẫn, dễ dàng chặn toàn bộ kiếm quang của Khô Trúc lão nhân, khiến Hàn Lập và Đại Diễn Thần Quân xác nhận pháp bảo phòng ngự này vượt dự tính. Khô Trúc lão nhân tiếp tục thúc kiếm trận hóa thành kiếm luân, phóng cột sáng xanh biếc ép lõm quang thuẫn, nhưng khôi lỗi dùng ngân thuẫn phản xạ công kích khiến đòn thế tan biến. Đại Diễn Thần Quân hài lòng với cương thuẫn nên chuyển sang thử năng lực công kích, để khôi lỗi lấy Lôi Hỏa Cung cùng mũi tên xanh biếc ra, tạo linh áp mạnh đến mức các tu sĩ Kết Đan đứng xa cũng bị ảnh hưởng. Khô Trúc lão nhân cảm nhận nguy hiểm sinh tử, lập tức nhận thua và dựng thêm phòng hộ bằng lệnh bài cùng kiếm quang. Đại Diễn Thần Quân ước tính khôi lỗi có bốn thành khả năng một tên diệt sát Khô Trúc, nhưng Hàn Lập không muốn mạo hiểm kích động cấm chế trên đảo vì mục tiêu chính vẫn là Ô phượng linh. Khô Trúc lão nhân đổi thái độ, sai đồ đệ lấy hộp ngọc chứa Ô phượng linh giao cho Hàn Lập, rồi Hàn Lập cùng khôi lỗi rời Khô Trúc đảo."},{"chuong":969,"tieuDe":"Hàng Thú","tomTat":"Vài ngày sau, Hàn Lập đưa khôi lỗi chứa tinh hồn Đại Diễn Thần Quân tới một hoang đảo vô danh và khuyên lão kéo dài sinh cơ, nhưng Đại Diễn Thần Quân chọn thuận theo tự nhiên trở về Luân Hồi. Trước khi tọa hóa, lão nhắc lại lời hứa cũ khi giúp Hàn Lập nghiên cứu phương pháp phỏng chế Thất Diễm Phiến, yêu cầu hắn sau này tới cực tây chi địa đoạt lại Thiên trúc giáo và lập đệ tử kế thừa khôi lỗi thuật làm giáo chủ. Đại Diễn Thần Quân còn tiết lộ đã khắc toàn bộ công pháp, bí thuật, kiến thức và kinh nghiệm cả đời thành Đại diễn bảo kinh trong ngọc giản rồi tinh hồn hóa thành lục quang tiêu tán, khiến Hàn Lập buồn bã thu lại khôi lỗi và di vật. Sau đó Hàn Lập suy tính luyện Tam Diễm Phiến, nhận ra cần địa hỏa, nhân hỏa và thiên hỏa để luyện linh liêu, nên chọn Ngân xà sơn ở Nam Cương thay cho phế hỏa mạch Bách Xảo Viện. Hắn cũng tổng kết những việc còn dang dở tại Đại Tấn, gồm tìm cách giải Phong hồn chú từ Âm La tông, đoạt lại hai phi kiếm từ Cổ Ma và sưu tầm thêm canh tinh. Trước khi lên đường, Hàn Lập lấy Thiên cơ phủ làm động phủ tạm, thả Thổ giáp long cấp bảy bị phong cấm ra, đưa điều kiện quy thuận hoặc bị giết lấy lân giáp yêu đan. Bằng lời hứa chia hàn tủy giúp vượt lôi kiếp và uy hiếp bằng hỏa kiếm tử diễm, hắn cuối cùng ép Thổ giáp long gào lên khuất phục."},{"chuong":970,"tieuDe":"Song Hạt Sơn","tomTat":"Hàn Lập thu Thiên Cơ Phủ, rời nơi ẩn cư về lục địa rồi không tới Thiên Phù Môn mà đi thẳng Nam Cương. Trên đường, hắn dùng anh hỏa luyện một số tài liệu Tam Diễm Phiến thành linh liêu nhưng chưa thu được lôi hỏa chi lực vì không gặp dông tố. Chương giới thiệu Nam Cương là vùng đặc thù trong Đại Tấn, do hơn mười tông môn địa phương cùng quản lý, bài ngoại và nổi tiếng với độc thuật, côn trùng thuật, tà thuật cùng bùa chú. Tại Song Hạt Sơn thuộc Triều Vân Phủ, Hàn Lập đến đúng kỳ chướng khí bộc phát và gặp nhóm Vương sư tỷ đang bị biến dị Thiết Vĩ Hạt truy đuổi. Hắn nhận ra nàng, dùng thanh hà dọn chướng khí và quang thủ màu xanh bắt sống độc hạt, sau đó hỏi thăm Tào Mộng Dung rồi tặng con độc trùng cho Vương sư tỷ. Khi mưa sấm trái mùa kéo tới, Hàn Lập lên đỉnh núi cao nhất, dùng linh áp và thanh hà đuổi nhóm tu sĩ địa phương khỏi đó. Cuối chương, hắn đứng dưới mây đen, sấm chớp dày đặc trên đỉnh Song Hạt Sơn, đúng lúc có điều kiện để thu lôi hỏa chi lực."},{"chuong":971,"tieuDe":"Khách Tới","tomTat":"Hàn Lập nghe theo lời khuyên của Đại Diễn Thần Quân, bố trí pháp kỳ thành tụ linh pháp trận trên ngọn núi cao nhất để dẫn thiên lôi. Hắn dùng bình ngọc đặc chế phối hợp Tích tà thần lôi thu từng đạo lôi điện, sau mỗi bình lại dùng phù vàng phong miệng, cuối cùng tích đủ năm bình để chuẩn bị chuyển hóa Lôi Hỏa luyện chế. Trong lúc đó, Bạch Dao Di từ bạch hồng hiện thân, tự xưng là tu sĩ Bắc Minh đảo và ngoại sự trưởng lão Tiểu Cực cung, cũng đến theo ước hẹn của lão giả họ Phú. Hàn Lập tự nhận là hải ngoại tán tu, không để nàng giúp thu lôi, rồi cảnh giác khi thấy nàng dùng băng ngọc tu luyện vì hàn tủy liên quan trấn cung chi bảo Tiểu Cực cung đang ở trên người hắn. Hai người ngồi chờ qua ba ngày ba đêm sau cơn mưa lớn, các tu sĩ cấp thấp tình cờ tới đều sợ hãi bỏ chạy. Sáng ngày thứ tư, một đại hán đen xấu cao như thiết tháp cưỡi rùa xanh tới, tự ngồi xuống đọc sách ánh vàng, khiến Hàn Lập nhận ra khách được mời đều là Nguyên Anh trung kỳ và suy đoán mục đích của lão giả họ Phú rất bất thường."},{"chuong":972,"tieuDe":"Bồi Anh Đan Và Âm Chi Mã","tomTat":"Sau khi nhóm Hàn Lập chờ gần nửa tháng trên ngọn núi, lão giả họ Phú cùng Thường Chỉ Phương tới nơi khi chướng khí đã tan phân nửa. Lão giả họ Phú giới thiệu Thường Chỉ Phương là sư muội kiêm nội đường trưởng lão Cửu U tông, đại hán họ Nguyên xuất thân Nam Cương Độc Thánh môn, còn Hàn Lập là hải ngoại tán tu có thần thông kinh người. Khi nhắc tới các tin đồn ở Tấn kinh, ông nói Hàn Lập từng giết Tiếu lão nhân và Ác hỏa đầu đà, nhưng Hàn Lập chỉ nhận đã giết một tu sĩ Nguyên Anh sơ kỳ, còn phủ nhận việc giết Ác hỏa đầu đà. Đại hán họ Nguyên tiếp tục nhắc chuyện quỷ yêu hai đầu bốn tay từng xuất hiện sau đấu giá hội Tấn kinh và cắn nuốt Nguyên Anh tu sĩ, khiến Hàn Lập phải nói mình đã rời đi trước đó. Trước yêu cầu của Bạch Dao Di, lão giả họ Phú lập cấm chế u hỏa rồi tiết lộ kế hoạch đã mưu tính từ ba mươi năm trước liên quan đến thượng cổ kỳ dược Bồi Anh đan. Hàn Lập nhận ra Bồi Anh đan là linh dược trấn tông của một thượng cổ tông môn thời man hoang, có lợi lớn cho Nguyên Anh kỳ tu sĩ và giúp đột phá bình cảnh. Lão giả họ Phú cho biết mình đã có phối phương từ hơn trăm năm trước, nhưng còn thiếu chủ tài liệu là Âm Chi Mã huyết nhục. Ông nói ba mươi năm trước đã vô ý phát hiện tung tích Âm Chi Mã tại Nam Cương, mở ra mục tiêu hành động tiếp theo của nhóm."},{"chuong":973,"tieuDe":"Minh Hà Chi Hiệt","tomTat":"Lão giả họ Phú tiết lộ rằng Âm chi mã không phải không tìm được, mà sào huyệt của nó nằm ở Âm dương quật trong Vạn độc cốc, một tuyệt địa khiến việc bắt giữ vô cùng nguy hiểm. Bạch Dao Di và đại hán họ Nguyên giải thích thêm rằng Âm dương quật là một trong bảy đại tuyệt địa của Đại Tấn, có âm phong làm tổn hại Nguyên Anh, mê cung dưới đất, quỷ vật và lời đồn về Quỷ vương. Để thuyết phục mọi người, lão giả họ Phú nói đã chuẩn bị bảo vật khắc quỷ, mang Tử U Châu để suy yếu âm phong và sẽ dùng Âm chi mã luyện Bồi anh đan chia đều. Khi bị hỏi vì sao không nhờ đồng môn Cửu U tông, lão nói mình có ân oán nội bộ, phần lớn đồng giai trong tông đều mong lão chết, chỉ còn Thường sư muội là đáng tin. Trước khi cho mọi người rời đi suy nghĩ, lão lấy Minh hà chi trang ép nhóm tu sĩ dùng tinh huyết viết độc thệ giữ bí mật về Âm chi mã và Bồi anh đan. Đại hán họ Nguyên nhận lời phó ước nửa năm sau và lập huyết thệ trước, Bạch Dao Di do dự nhưng cũng làm theo. Đến lượt Hàn Lập, một tiếng gầm từ vật trong cơ thể hắn khiến quỷ đầu trong hắc diễm kinh hoàng tán loạn, làm thệ ước không thành. Hàn Lập cam kết vẫn đến đúng hẹn nhưng không thể dùng tà khí này, và Hắc y mỹ phụ lên tiếng khuyên lão giả họ Phú không cần ép hắn nữa."},{"chuong":974,"tieuDe":"Quái Nhân","tomTat":"Sau khi được sư muội khuyên can, lão giả họ Phú không ép Hàn Lập giao dịch Minh hà chi trang nữa, nhưng yêu cầu lưu một tiêu ký trên người hắn trong nửa năm. Hàn Lập kiểm tra thấy pháp quyết chỉ là ấn ký bình thường nên chấp nhận, rồi cùng nhóm tạm chia tay trước chuyến vào Âm dương quật ở Vạn độc cốc. Vì muốn tăng bảo đảm, Hàn Lập tới Ngân xà sơn, chọn hỏa mạch mạnh nhất, dùng kim sắc tiểu kiếm mở khe nứt và lấy linh áp Nguyên Anh xua các tu sĩ xung quanh để chuyên tâm luyện Tam Diễm Phiến. Trong lúc đó, tại một thiên điện của hoàng cung Đại Tấn, hơn mười tu sĩ Nguyên Anh thuộc Diệp gia tụ họp chờ một nhân vật bí ẩn. Quái nhân cao gầy, đầu lớn dị thường xuất hiện, tự nhận là Thất thúc Diệp gia từng chết đi sống lại và đưa truyền âm ngọc giản để xác minh. Sau khi đọc ngọc giản, tu sĩ mặt chữ điền xác nhận cái chết năm xưa của Thất thúc là do Đại trưởng lão an bài. Quái nhân tiết lộ mình đã tiến giai Nguyên Anh hậu kỳ từ hai trăm năm trước và nay tái xuất vì kế hoạch của Diệp gia đã liên quan tới sinh tử tồn vong của gia tộc."},{"chuong":975,"tieuDe":"Nửa Năm","tomTat":"Sau cuộc bàn bạc trong hoàng thành, các trưởng lão Diệp gia rời điện, còn nội bộ Diệp gia chuẩn bị hành động lớn nhằm thoát khỏi khống chế của chính ma lưỡng đạo. Trong mật thất hoàng thành, Cổ ma hút hết ma khí, hóa thành thanh niên giống Hàn Lập, tự nhận thương thế đã hồi phục tám phần và chờ Diệp gia phát động kế hoạch để nhân cơ hội mưu việc riêng. Ở động phủ ngoài thành, Cát Thiên Hào báo với Lâm Ngân Bình tin Hàn Lập từng xuất hiện tại Nam Cương, trong khi Lâm Ngân Bình chờ đội hộ điện tu sĩ Thiên Lan vào kinh và âm thầm lo phải cứu phân thân Thánh thú bị Hàn Lập cấm giữ. Hướng Chi Lễ tái xuất giữa Nam Cương và Châu giao cùng vài tu sĩ Luyện Khí kỳ, đồng thời chương nhắc lại việc lão từng biến mất khỏi Thiên Phù môn khiến môn phái này phải áp chế tin tức. Đại Tấn bước vào cục diện yên ắng trước phong ba, nhiều thế lực lớn bắt đầu nghi ngờ Hoàng tộc Diệp gia nhưng chưa có chứng cứ xác thực. Mấy tháng sau, Hàn Lập hoàn thành luyện chế vài món pháp khí, dùng độn quang tới khu độc vụ Nam Cương để hội hợp lão giả họ Phú, Bạch Dao Di, đại hán họ Nguyên và mỹ phụ. Sau hai ngày khôi phục pháp lực, đại hán họ Nguyên tế Ngọc Như Ý khắc độc đẩy lui độc vụ, dẫn cả nhóm đi bộ vào Vạn Độc cốc để tiến tới Âm Dương Quật."},{"chuong":976,"tieuDe":"Linh Sơn Côn Ngô","tomTat":"Trong Vạn Độc cốc, Hàn Lập dùng hỏa thuật hóa hỏa cầu thành hỏa xà để thiêu sạch độc trùng, giúp đoàn người tiếp tục tiến sâu. Đại hán họ Nguyên dùng Ngọc Như Ý chiếu sáng, phát hiện một khe rãnh khổng lồ phun hắc sắc âm phong, được xác nhận là cửa vào Âm Dương Quật. Lão giả họ Phú giải thích bên trong có Kinh Phách âm phong nguy hiểm với cả tu sĩ Nguyên Anh kỳ, rồi lấy Tử U Châu ra tạo quang tráo bảo hộ cả đoàn đi xuống; Hàn Lập thoáng bị bảo châu ảnh hưởng thần hồn nhưng nhờ Đại Diễn quyết tự vận hành mà tỉnh lại. Cùng lúc đó, tại một tiểu hồ ở Nam Cương, nhóm tu sĩ Diệp gia tụ tập nghe hắc y tu sĩ báo cáo bí mật về Côn Ngô sơn. Diệp gia đã dựa vào tàn bia thượng cổ để truy tìm linh sơn bị phong ấn suốt nhiều năm, biết trong bảo khố có hai kiện thông thiên linh bảo và đang chuẩn bị pháp trận phá cấm. Tu sĩ mặt chữ điền cảnh báo Côn Ngô sơn có thể ẩn chứa bí mật kinh thiên động địa và nguy cơ có vào mà không ra, đồng thời nhờ Cổ ma dưới thân phận Hàn trưởng lão hỗ trợ, hứa giao hai kiện ma khí sau khi xong việc."},{"chuong":977,"tieuDe":"Phân Công Hành Sự","tomTat":"Cổ ma nhận lời hỗ trợ khi đã có ma khí, rồi tu sĩ mặt chữ điền dẫn nhóm tiến xuống đáy tiểu hồ để tránh bị người ngoài phát hiện. Ở Âm Dương Quật cách đó hơn ngàn dặm, nhóm Hàn Lập tiếp tục bị tiểu quỷ do âm khí ngưng kết quấy nhiễu trong lúc truy tìm Âm Chi Mã. Kinh Phách âm phong trong thông đạo hắc sắc hàn băng khiến thần thức bị hạn chế và pháp lực tiêu hao, còn Bạch Dao Di nhận định họ nhiều nhất chỉ chịu thêm khoảng hai tháng. Khi gặp ngã rẽ ba đường, Hàn Lập đề nghị chia nhóm để kịp tra xét, lão giả họ Phú dùng tinh huyết kích phát Tử U Châu cấp Tử U thần quang tạm thời cho đồng đội, rồi mọi người lưu tiêu ký pháp lực và tách làm ba hướng. Bạch Dao Di theo Hàn Lập vào một thông đạo, hai người vừa đi vừa bàn về hung danh Âm Dương Quật và nguy cơ quỷ vật cấp cao. Sau hơn nửa ngày không có kết quả, họ nghe tiếng như luyện thi từ một huyệt động âm phong dữ dội. Bạch Dao Di phát hiện vật bị đóng băng cạnh lối vào, dùng hỏa cầu làm tan băng và thu lấy một thanh lam sắc phi kiếm vẫn còn linh quang."},{"chuong":978,"tieuDe":"Nghiệt Viên","tomTat":"Bạch Dao Di thử lam sắc phi kiếm nhặt được trong huyệt động và nhận ra linh tính của nó vẫn chưa mất, còn Hàn Lập mượn kiếm xem xét rồi xác định nó được luyện hoàn toàn từ Lam nguyên tinh theo lối luyện khí rất cổ. Hai người dùng pháp bảo phòng hộ và nguyệt quang thạch đi sâu vào huyệt động âm hàn, phát hiện một cửa vào tỏa lục quang dẫn tới nhũ động. Trong nhũ động, họ thấy một thây khô bị xích trên thạch trụ, bụng bị rạch mất nội tạng, còn lam sắc phi kiếm tự bay quanh thi thể khiến Bạch Dao Di suy đoán đó là chủ cũ của kiếm. Hàn Lập quan sát hiện trường và kết luận người này bị tà thuật tế sống, đồng thời các pháp trận quanh thạch trụ có lai lịch rất cổ. Khi Bạch Dao Di dùng băng điêu tiểu phiến quét sạch bụi đất để lộ pháp trận, một quỷ vật thân rắn mặt vượn gọi là Nghiệt viên bất ngờ đánh lén cả hai. Hàn Lập dùng quang thủ chặn nó, Bạch Dao Di dùng ngọc tán đỡ ô mang rồi đóng băng quỷ vật, sau đó Hàn Lập bóp nát khối băng. Sau khi nhận định pháp trận là luyện hồn trận có thể từ thời thượng cổ, hai người định rời đi, nhưng Hàn Lập bất chợt thấy bất ổn nên quay lại bắn một đạo kim hồ vào thây khô trên thạch trụ."},{"chuong":979,"tieuDe":"Ngũ Tử Đồng Tâm Ma","tomTat":"Hàn Lập và Bạch Dao Di rời động quật sau khi kim hồ một tiễn phá tan thây khô, nhưng ngay sau đó một bóng đen quỷ dị xuất hiện, gom tro bụi và dùng hắc khí hồi sinh thây khô. Thây khô được tái tạo phun hắc âm phong giải băng cho nghiệt viên, khiến con thú thoát ra rồi bám theo nó như sủng vật. Ở Nam Cương, Âm La tông huy động gần trăm hắc bào tu sĩ vây công trang viên Hà gia, phá cấm chế quầng sáng vàng và đẩy gia tộc này vào cảnh diệt vong. Trung niên hoàng bào Hà gia cầu xin Đại trưởng lão Âm La tông tha mạng nhưng bị cự tuyệt, sau đó dùng linh mãng, Hồn Thiên chuyên và lam sắc lệnh bài chống trả. Ngũ tử đồng tâm ma giết linh mãng, xuyên qua phòng ngự rồi nhập thể trung niên hoàng bào, biến hắn thành khô lâu và thôn phệ Nguyên Anh. Sau trận chiến, Đại trưởng lão Âm La tông ra lệnh giết sạch cả phàm nhân Hà gia, đồng thời truy tìm Hàn Lập ở Nam Cương để đoạt lại Âm La phiên, trấn tông chi bảo của Âm La tông."},{"chuong":980,"tieuDe":"Hắc Tinh","tomTat":"Nửa tháng sau, Hàn Lập ở đáy Âm Dương Quật giữa hai Đại Phong Huyệt, dùng phi kiếm màu vàng, Phệ kim trùng và Ích Tà thần lôi phá đàn bướm đen cùng bướm khổng lồ do Hắc tinh thạch huyễn hóa. Hắn kéo khối Hắc tinh thạch thứ ba khỏi thạch bích, nhận ra vật này không phải Hắc tủy toản mà chứa âm phong cổ quái và lượng lớn âm khí tích tụ lâu năm. Sau đó Hàn Lập tiếp tục tìm Âm chi mã tuyệt, vừa sốt ruột vì chưa thấy linh vật vừa cân nhắc nếu thất bại thì có thể đoạt phương pháp luyện Bồi anh đan từ lão giả họ Phú. Một đạo lục quang truyền tin bay tới, hiện thành tiểu kiếm màu lục kèm ngọc giản đỏ, báo rằng đã phát hiện tung tích Âm chi mã tuyệt. Hàn Lập dùng trận bàn màu trắng xác định vị trí bốn điểm sáng rồi nhanh chóng đến giao lộ, nơi đại hán họ Nguyên và lão giả họ Phú đang chờ. Sau khi Hắc y mỹ phụ và Bạch Dao Di tới, cả nhóm bố trí vài pháp trận đơn giản tại lối vào rồi bay vào thông đạo phía đông để săn bắt linh vật. Ngay sau khi họ rời đi, ba thây khô đen thui, ngực rỗng và mắt xanh lục lạnh lẽo xuất hiện tại giao lộ, lặng lẽ nhìn theo hướng nhóm Hàn Lập vừa đi."},{"chuong":981,"tieuDe":"Thi Lang","tomTat":"Nhóm Hàn Lập đi dọc mặt đông thông đạo, chia nhau thăm dò các hang bên để truy dấu Âm Chi Mã. Tại hang nhỏ do đại hán họ Nguyên phát hiện, Hàn Lập, lão giả họ Phú và đại hán thấy âm phong yếu, hơi ấm, noãn ngọc nguyên quáng, hương thơm lạ và dấu vó ngựa nhỏ, khiến lão giả họ Phú xác nhận Âm Chi Mã từng ở đây. Ngay sau đó thông đạo rung chuyển, Hàn Lập dùng lam quang thị lực nhìn xuyên âm phong và phát hiện một thi lang khổng lồ lông xanh đang tiến tới, trên đầu còn có Âm Chi Mã ẩn nấp. Năm tu sĩ Nguyên Anh lập tức liên thủ, lão giả họ Phú dùng tỏa liên, hắc y mỹ phụ dùng phi kiếm đỏ, đại hán họ Nguyên thả bò cạp có cánh, Hàn Lập thúc phi kiếm kim quang, còn Bạch Dao Di dùng lưới tơ tằm bắt Âm Chi Mã. Thi lang phun thi hỏa xanh biếc chặn toàn bộ pháp bảo, thiêu bò cạp thành khói xanh và ngăn lưới tơ tằm hạ xuống, khiến Bạch Dao Di phải vận hàn khí và dùng quạt băng tạo cốt tuyết phong đối kháng. Khi nhóm tu sĩ tăng cường công kích bằng lưới hỏa liên, cự kiếm đỏ, tử vụ từ hồ lô lam và một đạo tia hồng âm thầm của Hàn Lập, thi hỏa bắt đầu bị áp chế. Thi lang bèn thu nhỏ thân hình, bắn lục mang dày đặc từ lông lưng để cản năm người rồi quay đầu chạy về phía lối vào, làm cả nhóm sửng sốt."},{"chuong":982,"tieuDe":"Sát Hồn Ti","tomTat":"Hàn Lập dùng hồng châm hóa thành hồng tuyến xuyên qua lục diễm hộ thể và thân thể thi lang, khiến nó bị thương rồi nhập vào âm phong trốn đi. Khi mọi người định truy đuổi, Đề Hồn thú trong túi linh thú cảnh báo, giúp Hàn Lập phát hiện ba thây khô từng xuất hiện ở giao lộ đang ẩn nấp bám theo. Lão giả họ Phú đặt việc truy Âm Chi Mã lên hàng đầu, giao Hàn Lập và Hắc y mỹ phụ ở lại đối phó thây khô, còn mình cùng những người khác đuổi theo thi lang. Ba thây khô phun Sát hồn ti, khiến hỏa cầu, kiếm khí và cự kiếm màu hồng của Hắc y mỹ phụ đều bị khắc chế, pháp bảo của nàng còn bị quấn chặt và ô uế. Hàn Lập dùng Tịch tà thần lôi đánh đứt sợi tơ cứu cự kiếm, nhưng Sát hồn ti nhanh chóng ngưng kết trở lại, khiến hắn nhớ đến ghi chép trong Đại Diễn Bảo Kinh về thi sát khí. Hắc y mỹ phụ dùng Phật môn pháp luân tạo màn linh quang bảy màu tạm ngăn Sát hồn ti, còn Hàn Lập nhân cơ hội mở khe màn sáng, thi triển đôi cánh bạc lao ra sau lưng ba thây khô và phun ba đạo kim mang phản kích."},{"chuong":983,"tieuDe":"Ngân Sí Dạ Xoa","tomTat":"Hàn Lập dùng tiểu kim kiếm và Ích Tà thần lôi đánh tan thân thể tam thi, rồi thả Đề Hồn thú ra nuốt sạch hắc khí sát thi, khiến Hắc y mỹ phụ kinh hãi trước năng lực nuốt quỷ vật của linh thú này. Khi ấn ký theo dõi Nguyên đạo hữu biến mất, Hàn Lập và Hắc y mỹ phụ lập tức lần theo thông đạo quay lại tìm nhóm truy bắt Âm Chi Mã. Hai người tới một quảng trường dưới lòng đất có thúy lục cự trúc, cự trận và nhiều cột đá trói hắc kiền thi, rồi phát hiện Nguyên đạo hữu đã chết, còn Phú lão giả và Bạch Dao Di nhiều khả năng bị nhốt trong hai kén Sát Hồn Ti. Một lục mao quái vật đang ăn thi thể Nguyên đạo hữu, cạnh đó có quái vật cùng loại Thi Lang cầm đầu nạn nhân và Âm Chi Mã nằm bất động. Đề Hồn thú phản ứng dữ dội như gặp thiên địch, còn lục mao quái vật để lộ đôi cánh bạc và được Hắc y mỹ phụ nhận ra là Ngân Sí Dạ Xoa. Hàn Lập nhớ ra đây là luyện thi gần kim thân nguyệt thi, có thể sánh Nguyên Anh hậu kỳ, sở hữu ngân sí, thần thông phong thổ và mắt bạc mê hoặc thần thức. Cuối chương, Ngân Sí Dạ Xoa nói tiếng người, coi Hàn Lập và Hắc y mỹ phụ là huyết nhục tươi sống đưa tới miệng."},{"chuong":984,"tieuDe":"Ngân Đồng Huyễn Thuật","tomTat":"Hàn Lập nhận ra Ngân Sí Dạ Xoa khó đối phó nên phóng phi kiếm chém hai kén xám, muốn cứu lão giả họ Phú và hắc y mỹ phụ để liên thủ, nhưng phi kiếm bị Sát Hồn Ti hóa thành bàn tay và lưới xám cản lại. Hắn dùng Tịch Tà Thần Lôi đánh tan tơ xám, đồng thời đàm phán yêu cầu Ngân Sí Dạ Xoa giao Âm Chi Mã và thả người, nhưng đối phương lại đòi giữ Đề Hồn thú nên thương lượng lập tức đổ vỡ. Lão giả họ Phú cố cảnh báo về ảo thuật, song Hàn Lập và hắc y mỹ phụ vẫn bị ngân quang kéo vào một vùng sương mù huyễn cảnh, nơi quảng trường và kén xám đều biến mất. Hắc y mỹ phụ dùng Phật Môn Pháp Luân, đàn phi xà phun lửa và phi kiếm thử phá ảo nhưng đều bị ngân quang xóa sạch hoặc vô hiệu. Hàn Lập bình tĩnh quan sát, dùng kim hồ Tịch Tà Thần Lôi đánh trúng trăng lưỡi liềm trong ảo cảnh, khiến huyễn thuật sụp vỡ và hai người trở lại quảng trường. Sau đó hắc y mỹ phụ phát hiện Ngân Sí Dạ Xoa cầm Tà Nguyệt Huyễn Kính, bảo vật phụ trợ làm Ngân Đồng Huyễn Thuật mạnh hơn nhiều. Trước phi thi có thể còn lợi hại hơn tu sĩ Nguyên Anh hậu kỳ, Hàn Lập triển khai gần như toàn bộ pháp bảo như kim sắc tiểu kiếm, ngân bạch vũ sí, tuyết bạch châu tử bọc Tử La Thiên Hỏa, kim sắc giáp trùng, thất sắc linh quang và tử sắc kính để chuẩn bị quyết chiến."},{"chuong":985,"tieuDe":"Tà Nguyệt Huyễn Kính","tomTat":"Hắc y mỹ phụ thấy Hàn Lập khu động nhiều pháp bảo thì cũng dựng thanh sắc tiểu thuẫn, phóng hai bạch ngọc hồ điệp hộ thân và chuẩn bị liên thủ. Ngân Sí Dạ Xoa bất ngờ đánh xuống đất, khiến thây khô trên cột đá phun hắc khí tạo thành quầng sáng đen bao phủ quảng trường, nhốt cả Hàn Lập, hắc y mỹ phụ lẫn chính nó. Hàn Lập phát hiện trên tứ chi và cổ đối phương có năm vòng huyết sắc, từ đó nhận ra Khốn ma trận vốn là cấm chế giam Ngân Sí Dạ Xoa nhưng đã bị nó lợi dụng ngược để nhốt người xâm nhập. Đề Hồn thú phun hoàng hà truy kích, Phệ kim trùng từ trên cao đánh úp, song Ngân Sí Dạ Xoa dùng ngân mang và thi khí hắc sắc chống trả, khiến đàn trùng tổn thất khoảng một phần ba. Hàn Lập dùng lôi độn áp sát, thúc phi kiếm, tử sắc kính tử và âm thầm bắn một đạo tơ hồng, còn hắc y mỹ phụ biến bạch ngọc hồ điệp thành phong giao cùng tấn công. Ngân Sí Dạ Xoa dùng Tà Nguyệt Huyễn Kính hợp với quang cầu âm hàn, khiến thân ảnh bị kiếm quang, tử quang và phong giao xé nát rồi lại tái hợp nguyên vẹn như chưa hề bị thương. Cuối chương, hắc y mỹ phụ dùng phong long phun phong nhận phá nhỏ các quang cầu, còn Hàn Lập tạm không thúc phi kiếm mà chăm chú quan sát bằng lam quang trong mắt."},{"chuong":986,"tieuDe":"Một Kích Phá Pháp","tomTat":"Hàn Lập phát hiện hai phong giao của Hắc y mỹ phụ càng đánh quang cầu càng hao tổn, trong khi quang cầu bị phá vụn lại nhanh chóng dung hợp và mở rộng. Từ kinh nghiệm từng đối đầu Ôn Thiên Nhân ở Loạn Tinh hải, hắn nhận ra cần dùng thủ đoạn bá đạo để phá loại huyễn thuật cấm chế vặn không gian này. Hàn Lập kích hoạt Hàng linh phù, tạm tăng pháp lực tới đỉnh Nguyên Anh trung kỳ, rồi hợp kim phi kiếm thành cự kiếm, gia trì Ích Tà thần lôi và tử diễm của Tuyết Tinh Châu để chém vỡ quang cầu. Ngân Sí Dạ Xoa buộc phải né khỏi thế thi pháp, dùng sát hồn ti hóa cự chưởng chống đỡ, nhưng Hàn Lập tiếp tục dùng hồng ti đánh lạc hướng rồi xuyên thủng Tà Nguyệt Huyễn Kính. Bảo kính vỡ nát khiến Ngân Sí Dạ Xoa giận dữ, bỏ ý định bắt sống bằng huyễn thuật và tuyên bố sẽ chặt đầu, rút tinh hồn hai đối thủ. Lão cùng Thi lang thổ độn xuống đất, làm pháp trận rung chuyển và phát sinh hoàng quang, hắc khí, trong khi Hắc y mỹ phụ do dự rồi bay về một hướng khác với một món pháp bảo sắc bén trong tay."},{"chuong":987,"tieuDe":"Theo Gió Ẩn Hình","tomTat":"Hắc y mỹ phụ dùng Kim Tiễn đao định phá kén cứu lão giả họ Phú, nhưng thi lang đã hóa thành hình người đầu sói lao ra đánh bay pháp bảo, khiến kế hoạch thất bại. Hàn Lập nhận ra Âm Chi Mã biến mất và dùng Minh Thanh linh mục phát hiện Ngân Sí Dạ Xoa đang đánh lén sau lưng mỹ phụ, liền cảnh báo và phóng kiếm khí hỗ trợ. Dù Hắc y mỹ phụ tế thanh sắc tiểu thuẫn và tăng hộ thể linh quang bằng pháp luân, Ngân Sí Dạ Xoa trong hình thái mới vẫn xuyên thủng phòng ngự, phá hủy thân thể nàng rồi dùng sát hồn ti bắt Nguyên Anh phong thành kén. Hàn Lập không lao vào cứu vì nhìn ra tấm đại võng giấu trên cao, khiến mưu đồ phục kích của Ngân Sí Dạ Xoa thất bại. Ngân Sí Dạ Xoa cho thi lang nuốt một viên châu tăng thi khí để đối phó Đề Hồn thú, còn bản thân dùng phong độn thuật gần như theo gió ẩn hình truy sát Hàn Lập. Hàn Lập liên tục dùng lôi độn né tránh nhưng bị rút ngắn khoảng cách, cuối cùng dừng lại dùng viên châu trắng phun tử diễm, kim sắc tiểu kiếm tạo kiếm quang và điện mãng vàng phản kích. Ngân Sí Dạ Xoa dùng vảy vàng kết thành màn hào quang bảo hộ, va chạm với công kích của Hàn Lập tạo nên một màn hào quang chói mắt."},{"chuong":988,"tieuDe":"Kim Độn Và Băng Diễm Tinh","tomTat":"Hàn Lập dùng lôi độn tránh né rồi vận Thanh Minh Linh mục quan sát, phát hiện Thanh Trúc Phong Vân Kiếm và Tịch Tà Thần Lôi đều bị kim tráo của Ngân Sí Dạ Xoa hóa giải, chỉ tử sắc hỏa diễm có thể đóng băng lớp hào quang này. Ngân Sí Dạ Xoa phá băng thoát ra, bị Hàn Lập nhận ra có kim độn thuật và đang tiến giai theo hướng Kim Thân Nguyệt Thi, rồi thừa nhận bản thân đã bắt đầu tiến giai từ vạn năm trước. Hắn bộc phát khí tức cực mạnh, khiến đôi cánh chuyển sang kim sắc và đánh thức thây khô trên thạch trụ làm hóa thân Thi sát trợ chiến. Trước thế vây công, Hàn Lập buộc phải lấy Tam Diễm Phiến, quán linh lực khiến pháp lực hao tổn nặng rồi kích phát hỏa phượng tam sắc đánh vào hắc sắc cự võng do Sát Hồn Ti kết thành. Cùng lúc, hắn dùng Thanh Trúc Phong Vân Kiếm hộ thân và phun tinh huyết vào Tuyết Tinh Châu, phối hợp Tuyết Phát hoàn tạo băng diễm dựng tường băng tím ngăn mưa phi châm kim mang. Chương hé lộ phi châm của Ngân Sí Dạ Xoa được luyện từ khoáng thạch vô danh qua nhiều ngàn năm, còn băng diễm là biến hóa ngưng tụ hàn khí Tử La Thiên Hỏa mạnh hơn trạng thái ban đầu. Cuối chương, hỏa phượng tam sắc đối đầu Sát Hồn Ti và khiến đám hôi ti hiện ra biến hóa khó tin."},{"chuong":989,"tieuDe":"Linh Phiến Chi Uy","tomTat":"Tam Diễm Phiến trong tay Hàn Lập hóa tam sắc hỏa phượng thành quang luân, cuốn hôi sắc cự võng của Ngân Sí Dạ Xoa vào rồi khiến cả hai biến mất, phá tan thần thông do gần như toàn bộ thi sát chi khí của đối phương ngưng tụ. Ngân Sí Dạ Xoa kinh hãi nhận ra uy lực linh phiến có ẩn hàm chút thiên địa pháp tắc, vượt xa công kích thông thường, đồng thời nhớ lại bản thân bị pháp trận giam hãm nên thiếu pháp khí tương xứng và Tà Nguyệt Huyễn Kính hữu dụng đã bị Hàn Lập hủy. Hàn Lập thấy cơ hội diệt địch liền uống một giọt Vạn Niên Linh Dịch hồi phục pháp lực, chuẩn bị tiếp tục thúc động Tam Diễm Phiến. Đúng lúc đó, trận pháp dưới đất dị biến, linh mang khảm hơn trăm viên linh thạch hiện ra và hợp thành một Truyền Tống Trận cực lớn; Hàn Lập định dùng lôi độn thoát thân nhưng không kịp, bị truyền tống đi cùng Ngân Sí Dạ Xoa. Cùng thời điểm, ba địa phương khác ở Đại Tấn cũng xuất hiện dị biến tương tự, cuốn ba quái vật không rõ lai lịch đi mất. Mạch truyện chuyển tới tiểu hồ vô danh ở Nam Cương, nơi Diệp gia bí mật giải phong ấn Côn Ngô sơn nhưng bạch sắc quang trụ và sáu quang trụ phụ lộ rõ, khiến tu sĩ mặt chữ điền giận dữ chất vấn bạch phát lão giả phụ trách pháp trận. Đại trưởng lão Diệp gia ra mặt điều hành, cho người kiểm tra ẩn nặc pháp trận, xác nhận phong ấn Côn Ngô sơn đã mở khe nhỏ và ra lệnh tu sĩ cấp thấp trong tộc rút đi ẩn trốn một năm. Cuối chương, các trưởng lão quay lại báo ẩn nặc pháp trận đã bị người khác phá hoại, đệ tử trong trận đều biến mất, khiến các tu sĩ Diệp gia biến sắc rối loạn."},{"chuong":990,"tieuDe":"Thiên Tượng Cự Biến","tomTat":"Các tu sĩ Diệp gia đi kiểm tra lần lượt báo pháp trận che giấu bị hủy và đệ tử thao túng biến mất, khiến Đại trưởng lão Diệp gia nhận định vấn đề có thể phát sinh từ nội bộ. Có người nghi ngờ Hàn trưởng lão do Cổ ma hóa thân, nhưng Đại trưởng lão và Thất thúc Diệp gia cùng đứng ra bảo chứng nên nghi ngờ tạm lắng. Sau khi xác nhận hai trận sư đã mất tích khoảng hai ngày, Đại trưởng lão quyết định không chờ điều tra mà lập tức tiến vào Côn Ngô sơn để khai quật bí bảo và đoạt hai kiện thông thiên linh bảo. Bạch phát lão giả dẫn đoàn tới rừng rậm phía bắc tiểu hồ, dùng ngân sắc pháp bàn xác nhận khe phong ấn dưới đất ngàn trượng, rồi Cửu muội thả cự hình ngô công chở các trưởng lão thổ độn xuống đất. Bảy đạo bạch sắc quang trụ làm Nam Cương chấn động, nhiều nhóm tu sĩ nhìn thấy dị tượng, báo tin cho sư môn hoặc trực tiếp bay về phía tiểu hồ, khiến tin bảo khố nhanh chóng lan rộng. Ở một địa điểm không tên có cự đại truyền tống trận, Hàn Lập tỉnh lại, phát hiện vòng giam cầm Ngân Sí Dạ Xoa đã vỡ và lục sắc ngọc phù truyền tống tự hủy trước khi hắn kịp nghiên cứu. Thi lang cũng bị truyền tống tới gần Hàn Lập nhưng bị Ích Tà Thần lôi trọng thương, sau đó Đề Hồn thú phun hoàng hà hút sạch thi khí khiến nó chết hẳn. Ngân Sí Dạ Xoa không muốn liều mạng với Hàn Lập khi đã thoát giam cầm, liền thi triển phong độn rời khỏi nơi này."},{"chuong":991,"tieuDe":"Kình Thiên Cự Sơn","tomTat":"Hàn Lập không truy kích Ngân Sí Dạ Xoa vì đối phương đã thoát khỏi thế bị nhốt, còn Tam Diễm Phiến cũng khó bảo đảm một kích diệt sát. Hắn chuyển sang Đề Hồn thú, kịp ngăn nó nuốt Âm Chi mã đang bị cuốn ra từ thi khí của thi lang, rồi phong cấm linh vật này. Sau khi kiểm kê, Hàn Lập biết hai phi kiếm đã thu hồi nhưng Hắc y mỹ phụ bị Ngân Sí Dạ Xoa nuốt Nguyên Anh, còn tinh hóa phi châm bị đối phương lấy mất. Hắn nhận ra truyền tống trận trong sơn động là loại một chiều, dùng kim hồ phá sát hồn ti cứu lão giả họ Phú và Bạch Dao Di khỏi cự kiển. Ba người thương lượng phần lợi ích, Hàn Lập giao Âm Chi mã cho lão giả họ Phú để đổi hai viên Bồi Anh đan, dù từng thoáng nảy ý giết người đoạt bảo. Sau đó Hàn Lập một mình rời sơn động, vượt thông đạo bậc thang đá, ra bình thai trong khe núi rồi thăm dò cả ngày. Hắn phát hiện một cự sơn khổng lồ lớn vượt xa Thánh sơn Thiên tinh thành, toàn bộ bị bạch quang cấm chế bao phủ và chứa linh lực đáng sợ đến mức Hóa Thần kỳ cũng khó cưỡng ép phá. Cự sơn tuy linh khí dồi dào nhưng im lặng không chim thú, khiến Hàn Lập càng cảm thấy nguy hiểm và quay lại truyền tống trận trong sơn động."},{"chuong":992,"tieuDe":"Tử Vụ, Độc Thánh Môn","tomTat":"Trong sơn động nơi bị truyền tống đến, Hàn Lập bố trí pháp trận ẩn náu kiêm cảnh báo rồi hộ pháp cho lão giả họ Phú và Bạch Dao Di hồi phục. Sau khi ra ngoài dò xét, hai người xác nhận cự sơn này không giống bất kỳ linh sơn nổi danh nào của Đại Tấn, còn Hàn Lập nhận định thần thức bị áp chế và Ngân Xí Dạ Xoa cũng có thể đang ở gần, nên cả nhóm quyết định tạm thời ở lại luyện Bồi Nguyên đan trước khi thăm dò. Ở một tuyến khác trong Côn Ngô sơn, nhóm Diệp gia nghỉ tại thạch đình sau khi vượt phong ấn, đồng thời phát hiện phía trước có Vạn Tu chi môn bị cấm chế ngăn trở. Đúng lúc đó, một đám tử vụ kéo tới, Sư cầm thú thượng cổ ẩn trong sương tập kích, buộc đại trưởng lão Diệp gia và Thất thúc liên thủ chống đỡ. Đại trưởng lão dùng bảo vật truyền thừa là hắc hồng phi đao, lại hao tổn tinh huyết tăng uy lực mới chém trọng thương hung cầm, nhưng nó vẫn phun sóng âm phá thế công rồi dùng lôi độn trốn thoát. Gần Vạn Độc cốc, một đại trưởng lão bí ẩn nhận tin Phổ Vân phủ xuất hiện bảy cột sáng và phong ấn lớn dưới hồ, liền tạm gác việc truy tìm Hàn Lập cùng lão giả họ Phú để kéo thêm trưởng lão họ Ngô, họ Tiêu tới đó. Cùng lúc, Độc Thánh Môn do Hoa sư huynh dẫn hơn phân nửa lực lượng đến Phổ Vân phủ, tiết lộ tổ sư của họ là hậu duệ cổ tu sĩ từng phong ấn Côn Ngô sơn, còn Cảm Linh châu trong môn đã cảm ứng linh sơn xuất thế. Hoa sư huynh vì thế vừa nhắm đến bảo khố trong Côn Ngô sơn, vừa cảnh giác khả năng phong ấn bị một thế lực khác âm thầm phá giải trước."},{"chuong":993,"tieuDe":"Chia Phần Đan","tomTat":"Bên ngoài Phổ Vân phủ, dị tượng bảy cột sáng và phong ấn khổng lồ dưới tiểu hồ đã thu hút mấy trăm tu sĩ tụ tập, trong khi nhóm Độc Thánh môn vẫn không biết Nguyên sư đệ đã chết và tiếp tục chạy tới. Nhiều tu sĩ truyền tin về tông môn, gia tộc hoặc dùng thổ độn thăm dò dưới đất; một số tán tu lão luyện chọn rời đi, còn tu sĩ trẻ tuổi vẫn muốn đánh cược cơ duyên. Trong lòng núi, Hàn Lập, Bạch Dao Di và lão giả họ Phú chờ lò luyện Bồi Nguyên đan, Hàn Lập ngoài mặt bình tĩnh nhưng lo vì Âm Chi mã chỉ có một. Lão giả họ Phú dùng anh hỏa và pháp quyết luyện thành năm viên đan màu xanh biếc, rồi dùng hồ lô sơn son thu lại. Khi chia đan, ông nhắc Thường sư muội và Nguyên đạo hữu đã chết, dặn Bạch Dao Di dùng hộp gỗ mộc thuộc tính bảo quản, tự giữ một viên, chia cho Bạch Dao Di một viên và giao ba viên còn lại cho Hàn Lập. Hàn Lập hiểu lão giả nhường phần lớn để tránh bị hắn trở mặt đoạt đan nên nhận lấy. Sau đó sơn động rung chuyển dữ dội, Bạch Dao Di nghi trong núi còn người khác, lão giả họ Phú nghi Ngân Sí Dạ Xoa, còn Hàn Lập giải khai cấm chế và dẫn hai người rời khỏi sơn động."},{"chuong":994,"tieuDe":"Tấm Bia Đá","tomTat":"Lão giả họ Phú và Bạch Dao Di ra khỏi thông đạo thì thấy Hàn Lập đã đứng lơ lửng trong hạp cốc, lắng nghe tiếng nổ từ phía xa. Vì không quen thuộc nơi này, Hàn Lập đề nghị cả nhóm ẩn thân rồi đi tới nơi phát ra tiếng động để dò xét. Ba người lần lượt dùng thủ đoạn che giấu hành tung, trong đó Hàn Lập dùng Ẩn thân phù khiến hai đồng hành gần như không cảm ứng được hắn bằng thần thức. Trên đường bay, họ phát hiện linh khí nơi đây cực kỳ sung túc nhưng lại không có sinh vật hay linh thảo, khiến Hàn Lập càng cảnh giác trước cấm chế bao phủ cả linh sơn. Hàn Lập dùng linh nhãn phát hiện vùng sương trắng có bậc đá và một tấm bia đá lớn khắc cổ văn, qua đó nhóm nhận ra nơi này chính là Côn Ngô sơn trong truyền thuyết. Lão giả họ Phú suy đoán họ bị cổ truyền tống trận đưa vào ngọn núi bị phong ấn, còn Hàn Lập cho rằng cả linh sơn trải qua năm tháng hấp thu linh khí đã thành một bảo khố. Khi Thổ Giáp long trong túi linh thú truyền cảm ứng rằng bia đá là bảo vật, Hàn Lập thử thu lấy, nhưng tấm bia phát muôn đạo hào quang, trở về nguyên trạng rồi nứt đôi."},{"chuong":995,"tieuDe":"Tinh Bi","tomTat":"Hàn Lập phát hiện tấm bia đá vốn trống không bỗng nứt ra và lộ lam quang, liền dùng thanh sắc kiếm khí gọt bỏ lớp đá ngoài để lộ một khối lam sắc tinh bi có cổ văn. Bạch Dao Di nhận định vật này không phải linh thạch thủy thuộc tính, còn Hàn Lập sau khi đọc cổ văn thì rung động trong lòng nhưng không nói ra, chỉ thu nhỏ tinh bi rồi cất đi. Ba người tiếp tục ẩn nặc lên núi theo tiếng gầm, trong khi tiếng động ấy thực ra đến từ việc Diệp gia đang bày trận phá Vạn Tu chi môn. Quái nhân Diệp gia và Đại trưởng lão Diệp gia quan sát tiến độ phá cấm, bàn về bí bảo chuyên phá cấm và mục tiêu Thông Thiên Linh bảo. Ngân Sí Dạ Xoa bị Quái nhân Diệp gia phát hiện nhờ cảm ứng thi khí, hiện hình đánh bay kiếm quang rồi dùng phong độn biến mất, khiến Diệp gia càng thêm cảnh giác. Ở thạch đình, Hướng Chi Lễ tiến vào Côn Ngô Sơn, nhận ra nguy cơ phong ấn bị mở và lo thứ bị giam có thể khiến Đại Tấn gặp họa. Một giọng nữ bí ẩn vang lên khiến Hướng Chi Lễ kinh hãi gọi tiền bối; nàng tự xưng bổn phi và tiết lộ mình vẫn bị tầng cấm chế cuối do Côn Ngô Tam Lão dùng vạn nhân chi lực bố trí ngăn giữ."},{"chuong":996,"tieuDe":"Huyễn Diệu Thiên Tượng","tomTat":"Hướng Chi Lễ nhận ra nữ tử thần bí chưa thật sự thoát khỏi Cửu chân phục ma trận vì vẫn bị hai kiện Thông thiên linh bảo trấn áp, nhưng điều đó không giúp hắn thoát thân. Nữ tử dùng Huyễn diệu thiên tượng tạo lốc xoáy bạch sắc và ngũ sắc hà quang, hút Hướng Chi Lễ biến mất rồi tự nói mình phải ngủ say, chờ ngày chân chính thoát khốn và trả thù Côn Ngô Tam Lão. Bảy ngày sau, các tuyến trong phong ấn đều bị kéo chậm: Diệp gia rơi vào ảo trận sau Vạn Tu chi môn, còn Hàn Lập cùng hai người khác bị cấm chế cổ quái chặn trên thềm đá. Bên ngoài phong ấn, tiểu hồ vô danh đã tụ tập hơn ngàn tu sĩ, trong đó Độc Thánh môn âm thầm dò ra manh mối cửa vào dưới lòng đất. Kiền lão ma của Âm La tông xuất hiện bằng Ngũ tử đồng tâm ma, khiến Hoa Thiên Kỳ và các trưởng lão Độc Thánh môn không thể yên ổn độc chiếm cơ hội. Một tu sĩ bất ngờ công khai vị trí khe nứt phía bắc phong ấn, kéo Kiền lão ma, Độc Thánh môn và phần lớn tu sĩ quanh hồ đồng loạt độn xuống. Dưới lòng đất sâu hơn nghìn trượng, cửa vào bị bảy tám đệ tử Độc Thánh môn canh giữ giữa tầng bạch quang lôi điện, nhưng một tu sĩ Nguyên Anh trong hồng quang ngang nhiên đòi xông vào và chuẩn bị ra tay."},{"chuong":997,"tieuDe":"Tứ Tán Chân Nhân","tomTat":"Hoa Thiên Kỳ dẫn vài trưởng lão Độc Thánh môn tới nơi, chất vấn Trịnh Vệ vì sao giáo huấn môn hạ của mình, khiến Trịnh Vệ lập tức đổi giọng nói chỉ là đùa. Kiền lão ma hiện thân bằng Ngũ tử đồng tâm ma, nhận ra Trịnh Vệ là Tứ Tán Chân Nhân, kẻ tán tu Nguyên Anh sơ kỳ nổi tiếng gian xảo nhưng khó bị giết nhờ Tứ phương phi thiên ngoa và bí thuật bảo mệnh. Trước sức ép của Kiền lão ma, Hoa Thiên Kỳ tuy giải thích Độc Thánh môn chỉ muốn phá ảo trận trước nhưng vẫn nhường đường, để Kiền lão ma hóa năm đạo bạch ảnh xông vào bạch sắc quang mạc. Hoa Thiên Kỳ lệnh cho các đệ tử Kết Đan rút đi rồi cùng bốn trưởng lão Độc Thánh môn tiến vào trận. Bên ngoài, các tán tu Nguyên Anh e dè ảo trận và Kiền lão ma, nhưng Trịnh Vệ thuyết phục đại hán Nguyên Anh kỳ cùng những người khác, cuối cùng năm tán tu cùng vào trong. Trong ảo trận, Hàn Lập bị nhốt một mình giữa không gian thải vân không trời đất sau khi lão giả họ Phú nhổ linh thảo làm động cấm chế, còn Bạch Dao Di và lão giả họ Phú biến mất. Hàn Lập dùng Minh Thanh Linh Mục, phi kiếm và pháp bảo công kích đều không phá được trận, sau đó trầm tư đối chiếu các thượng cổ kỳ trận và dường như nhận ra mấu chốt."},{"chuong":998,"tieuDe":"Bất Kỳ Nhi Ngộ","tomTat":"Hàn Lập tìm cách phá thượng cổ ảo thuật cấm chế tại cự thạch, nhận ra các đóa vân hà là thủ đoạn tàng vật hóa hình và nhờ điển tịch Tân Như Âm từng tặng mà hiểu được phương pháp phá trận. Hắn dùng thanh sắc đại thủ và thanh sắc anh hỏa luyện hóa năm viên châu ngũ sắc, cho chúng bạo liệt đồng thời để đưa bản thân, Bạch Dao Di và Phú lão giả trở lại thềm đá. Phú lão giả phát hiện gốc linh thảo mình hái chỉ là vật giả, trong hộp ngọc chỉ còn bình ngọc như ý thông thường, nên xấu hổ nhận lời phải thận trọng hơn. Hàn Lập cảnh cáo hai đồng bạn rằng Côn Ngô Sơn không phải di chỉ cổ tu bình thường, lần này hắn chỉ tạm phá trận và chưa chắc lần sau còn làm được. Ba người tiếp tục lên núi tới thạch đình, phát hiện dấu chân nhạt và vết kiếm khí mới, chứng tỏ đã có tu sĩ khác đi qua nơi này. Từ bạch sắc quang mạc, năm bóng trắng chui ra và được Phú lão giả nhận ra là Ngũ tử đồng tâm ma của Kiền lão ma. Thông qua các ma tử, Kiền lão ma nhận ra Phú lão giả, đoán Bạch Dao Di thuộc Bắc Dạ Tiểu Cực cung, rồi gọi đích danh Hàn Lập là người mà Âm La Tông cùng Thiên Lan thánh điện đã tìm kiếm cực khổ."},{"chuong":999,"tieuDe":"Sát Tâm Đại Khởi","tomTat":"Hàn Lập bị Kiền lão ma nhận ra là người từng giết trưởng lão Âm La tông và đoạt Quỷ La Phiên, từ đó hắn cũng nảy ý đối đầu trực diện để tìm phương pháp giải Phong Hồn Chú cho Nam Cung Uyển. Kiền lão ma tách chân thân khỏi năm bạch ảnh, dùng tiểu phiên đen nhánh dò xét rồi tuyên bố chỉ muốn giải quyết ân oán riêng với Hàn Lập. Phú lão giả và Bạch Dao Di can ngăn vì Côn Ngô sơn còn nhiều hung hiểm, ba người vẫn cần liên thủ tìm đường rời núi. Cuộc tranh chấp phơi bày việc tứ trưởng lão Âm La tông chết tại Thiên Nam, Quỷ La Phiên rơi vào tay Hàn Lập, đồng thời Hàn Lập nhắc chuyện đối phương từng âm thầm ra tay với đạo lữ của hắn. Kiền lão ma bị kích phát sát khí bởi Nghịch Tình Đoạn Thiên, còn Hàn Lập lấy Tam Diễm Phiến và chuẩn bị khôi lỗi để ra đòn sát thủ nếu giao chiến bùng nổ. Đúng lúc ngũ ma đồng tử sắp lao tới, ngân quang nổ lớn trên quang mạc và gần mười đạo độn quang bắn ra, khiến cục diện bị cắt ngang."},{"chuong":1000,"tieuDe":"Thạch Khôi Lỗi","tomTat":"Bên ngoài quang mạc, Kiền lão ma đang định ra tay thì thấy tứ lão Độc Thánh môn cùng nhiều tu sĩ Nguyên Anh chật vật thoát ra, bèn tạm dừng thế công để quan sát tình thế. Nhóm mới tới nghi ngờ lão giả họ Phú và đồng bọn liên quan đến việc ảo trận bạo liệt chặn thông đạo, nhưng lão phủ nhận, nói rằng khi mình tới nơi đã có kẻ khác phá cấm trước đó và bản thân cũng bị vây trong cấm chế nhiều ngày. Hoa Thiên Kỳ nhận ra thân phận chấp pháp trưởng lão Cửu U tông của lão giả họ Phú nên tạm thời đứng ra hòa giải, đồng thời hỏi nguyên nhân xung đột giữa nhóm này và Kiền lão ma. Trong khi đó, sâu trong Côn Ngô sơn, đội Diệp gia đang giao chiến với vô số thạch khôi lỗi từ các hành lang tràn ra, cho đến khi bạch bào nho sinh phá được thiên điện nơi sinh ra khôi lỗi theo chỉ điểm của Cổ ma Hàn Lập. Hàn Lập giải thích đây là khôi lỗi đại trận từng được ghi trong cổ thư, nếu chỉ cố thủ thì mọi người sẽ bị tiêu hao pháp lực đến chết, khiến Diệp gia càng thấy hắn có giá trị trong chuyến đoạt bảo. Diệp gia cũng xác nhận hậu thủ đặt trong ảo trận bên ngoài đã phát tác, có thể tự bạo để tạm ngăn các phe khác khoảng năm sáu ngày, nhờ vậy tranh thủ thêm thời gian tiến vào trung tâm. Tuy vẫn lo ngại ngân sí dạ xoa đang âm thầm bám theo, bạch bào nho sinh quyết định trước mắt không truy sát mà chờ tìm chỗ bố trí cấm chế để dụ nó vào vây giết. Sau khi rời thạch điện, nhóm Diệp gia gặp nhiều thềm đá dẫn vào các hướng khác nhau, nhưng vừa định bay lên quảng trường bạch ngọc quan sát thì bị cấm không cấm chế kéo rơi xuống, qua đó xác nhận họ đã thật sự bước vào khu trọng yếu của Côn Ngô sơn."},{"chuong":1001,"tieuDe":"Côn Ngô Điện, Linh Bảo Các, Trấn Ma Tháp","tomTat":"Hoa Thiên Kỳ nghe lão giả họ Phú kể về Hàn Lập, biết hắn đến từ Thiên Nam, từng giết trưởng lão Âm La tông và lấy Quỷ La phiên; Hàn Lập chỉ nói đó là tự vệ. Khi Hàn Lập xác nhận ngọn núi trước mặt là Côn Ngô tiên sơn, các Nguyên Anh tu sĩ chấn động, Hoa Thiên Kỳ liền đề nghị tạm gác ân oán với Kiền lão ma để cùng đuổi nhóm đã vào trước và chia cơ duyên. Hàn Lập kiểm tra lối ra sau khi ảo trận tự bạo, xác nhận thông đạo ngắn hạn không thể thông hành, nên tạm mất cơ hội mưu đồ pháp quyết giải Phong Hồn chú. Kiền lão ma vì không muốn tay không rời động thiên bảo địa nên miễn cưỡng đồng ý hoãn thù, các phe sau đó cùng lên núi. Ở phía trước, nhóm Diệp gia tới quảng trường bạch ngọc, đọc bia ngọc và xác định ba nơi có khả năng chứa Thông Thiên Linh Bảo nhất là Côn Ngô điện, Linh Bảo các và Trấn Ma tháp. Đại trưởng lão Diệp gia và đại đầu quái nhân bàn bạc cách chia người: đại trưởng lão dẫn ba người đi Linh Bảo các, đại đầu quái nhân đi Trấn Ma tháp, còn tu sĩ mặt chữ điền nhận nhiệm vụ đơn độc thăm dò Côn Ngô điện. Trước khi tách ra, đại trưởng lão giao Di Thiên trạc cho tu sĩ mặt chữ điền và dặn mỗi lần phát động bảo vật này phải dùng tinh huyết."},{"chuong":1002,"tieuDe":"Phụ Nhân","tomTat":"Đại đầu quái nhân dẫn ba Cổ ma đi theo một thềm đá có ghi chú, còn tu sĩ mặt chữ điền cầm Di Thiên trạc đi thềm đá giữa. Nho sinh Diệp gia chờ họ biến mất rồi hỏi lão giả họ Phong về khí cụ bố trận, sau đó ra lệnh bày Tử Vi Thất Tinh đại trận tại quảng trường và thả đầu hổ phong, hấp huyết bức vào trận để chặn hậu. Ở phía sau, đoàn Hàn Lập vượt Vạn Tu chi môn, phá ảo trận và các cấm chế Diệp gia, mất một ngày một đêm mới tới thạch điện. Trong điện, Hàn Lập nhận ra những mảnh vụn có thể là thạch linh thượng cổ do tinh hồn yêu thú bị nhốt trong thạch tượng đặc chế. Sư cầm thú bất ngờ tái xuất với thân thể đã khôi phục, định đánh lén ngũ ma tử nhưng bị Kiền lão ma phát hiện và buộc phải bỏ chạy. Hàn Lập vì nhớ trong núi còn Ngân Sí Dạ Xoa nên bỏ ý định khảo sát hành lang, chọn theo đoàn cho an toàn. Sư cầm thú bay tới một đại thụ và gọi ra phụ nhân áo đen, nhưng bà ta không muốn báo thù cho nó mà oán trách chuyện từng bị Khốn Linh trận giam giữ. Ngân Sí Dạ Xoa xuất hiện, cảnh báo bốn linh bài cấm chế trong Côn Ngô điện có thể khiến chúng lại bị con người sai sử, đồng thời nhắc mục tiêu thu hồi bổn mệnh bài để rời khỏi Côn Ngô Sơn."},{"chuong":1003,"tieuDe":"Quần Ma Ẩn Hiện","tomTat":"Trong Côn Ngô sơn, Ngân Sí Dạ Xoa thuyết phục Xú phụ nhân cùng sư cầm thú tham gia kế hoạch lén theo hai nhóm tu sĩ vào Côn Ngô điện để đoạt bổn mệnh bài. Hắn dùng cả uy hiếp bằng yêu đan cấp mười lẫn món nợ nửa viên Thanh Hư đan năm xưa để buộc Xú phụ nhân nhận lời, đồng thời hé lộ quá khứ các yêu vật bị phong ấn trong Khốn Linh trận và từng chịu bạo huyết chú. Sau khi ba yêu vật rời đi, một yêu vật bí ẩn giả dạng đại thụ hiện hai mắt xanh biếc, cho thấy toàn bộ cuộc mật đàm đã bị nghe lén. Nhóm Hàn Lập ra khỏi thạch điện, gặp cấm không rồi tiến đến rừng tử trúc che kín quảng trường bạch ngọc; Hoa Thiên Kỳ nhận định đây là cấm chế lợi hại hơn Băng Diễm Lưỡng Cực trận. Phi kiếm trong cơ thể Hàn Lập vô cớ run lên khiến hắn phát giác cổ ma cũng đang ở trong Côn Ngô sơn, sinh dự cảm bất hảo nhưng giấu chuyện với lão giả họ Phú. Kiền lão ma, Độc Thánh môn và các tu sĩ hợp lực công phá trận tử trúc, trong khi bên ngoài phong ấn lại có thêm một số khách không mời tiến vào."},{"chuong":1004,"tieuDe":"Huyền Thanh Tử","tomTat":"Sau khi ảo trận tự bạo, lối vào phong ấn sâu dưới đất phương bắc hiện thành một khe nứt đầy ngân quang và dao động nguy hiểm, khiến tán tu cùng tiểu thế lực phải lùi xa, chỉ còn ba phe lớn giằng co. Huyền Thanh Tử của Thái Nhất môn khuyên Mộc phu nhân bên Hóa Tiên tông đừng mạo hiểm, đồng thời tiết lộ mình nhận được mật báo rằng phong ấn đang bị người cố ý tìm cách giải khai, nhưng Mộc phu nhân vẫn khẳng định Hóa Tiên tông có quyền tiến vào vì nơi này thuộc phạm vi thế lực của họ. Cát Thiên Hào bên Âm La tông cũng quyết không rút lui, bởi đại trưởng lão bổn môn đã xuống dưới, nên hắn cùng Lâm Ngân Bình và đại tiên sư họ Từ của Thiên Lan thương nghị cách cưỡng vượt khe nứt. Đại tiên sư họ Từ thả Linh Tê khổng tước, dùng ngũ sắc linh quang ngăn cách thiên địa linh khí để mở đường, đưa nhóm Nguyên Anh của Âm La tông và Thiên Lan tiến vào trong ngân sắc hà quang. Sau đó Mộc phu nhân cùng sư muội hợp hai kiện bảo vật kim ngân thành Nhật Nguyệt toa, cũng theo sau tiến vào phong ấn, bỏ lại đệ tử cấp thấp rời khỏi khu vực nguy hiểm. Huyền Thanh Tử không vội xông vào mà dự định chờ Thất Diệu chân nhân của Thiên Ma tông mang Linh Quy phi xa tới, rồi cùng hai đạo sĩ Kết Đan ở lại canh giữ lối vào. Cuối chương, bên trong phong ấn ở Côn Ngô Sơn hiện ra một không gian âm u, nơi một cự vật khổng lồ bị vô số cấm chế phù và xiềng xích đen rỉ máu giam giữ giữa không trung."},{"chuong":1005,"tieuDe":"Cự Vật, Cung Điện Và Phá Trận","tomTat":"Chương mở ra hai không gian bí ẩn trong Côn Ngô sơn: một nơi cự vật bị cấm phù, xiềng xích, cấm chế và gương đồng pháp trận trấn áp, một nơi linh khí sung mãn có cung điện cổ nằm giữa đại pháp trận cùng tám mươi mốt tế đàn thạch nhân. Trong Tử Vi Tinh trận, Hàn Lập tiến qua tử vụ, cự mãng, điện hồ, cự phong và huyết bức, nhận ra các linh trùng linh thú này đã được bồi dưỡng đến mức cực kỳ khó đối phó. Hắn dùng Ích Tà Thần Lôi diệt cự phong, vận linh mục nhìn phá ảo thuật tử trúc quanh quang trụ rồi hợp Thanh Trúc Phong Vân kiếm thành kim sắc cự kiếm chém nát một mắt trận. Sau đó Hàn Lập không vội phá tiếp mà ngồi hồi phục pháp lực, suy tính cách ứng phó Cổ ma và kiểm tra tinh bi màu lam từng tìm được trong Côn Ngô sơn, phát hiện vật này che giấu thần thức, biến đổi nặng nhẹ theo linh lực và mang cổ văn rất xa xưa. Khi các quang trụ còn lại lần lượt bị hủy, Tử Vi Tinh trận tan hoàn toàn, để lộ quảng trường có nhiều bậc thang đá phân hướng. Mọi người phát hiện Độc Thánh môn tứ lão và tu sĩ họ Vệ đã lặng lẽ rời đi trước, khiến Kiền lão ma nổi giận rồi quyết định tự hành động. Cuối chương, năm đạo bạch ảnh của Kiền lão ma bay theo lối thềm đá ghi Côn Ngô điện."},{"chuong":1006,"tieuDe":"Chú Linh Đường","tomTat":"Sau khi phá trận, nhóm tu sĩ chấm dứt liên thủ và chia nhau đi vào các bậc thềm đá khác nhau; Lão giả họ Phú cùng Bạch Dao Di chọn một đường vì e ngại bị yêu vật đánh lén. Hàn Lập ở lại quảng trường một mình, cân nhắc các trọng địa như Côn Ngô điện, Trấn Ma tháp, Linh Bảo các rồi quyết định tránh nơi dễ tranh đoạt do đã có Bồi Anh đan. Hắn chọn Chú Linh đường vì nghi nơi này liên quan luyện khí, tới trước trang viên được quang mạc trắng bao phủ và thử dùng phi kiếm nhưng cấm chế tự khôi phục. Không muốn mất nhiều ngày để Phệ Kim Trùng gặm linh lực cấm chế, Hàn Lập dùng Tam Diễm Phiến phóng tam sắc hỏa diễm mở lỗ hổng, vào trong nhưng tiêu hao gần một phần ba pháp lực. Trong lúc đó, Ngân Sí Dạ Xoa, xú phụ nhân và Sư Cầm Thú xuất hiện ở quảng trường, lần theo dấu tu sĩ để mưu cướp bổn mệnh bài và dùng ẩn nặc thuật che giấu thân hình. Cùng thời điểm, tại thạch đình giữa sườn núi Côn Ngô Sơn, ngũ sắc khổng tước hiện ra nửa người từ trong quang mạc. Hàn Lập kiểm tra các lầu các, thạch ốc và kho hàng trong Chú Linh đường nhưng đều trống rỗng, cuối cùng bước vào Hóa Linh điện đỏ đậm, nơi vừa vào cửa đã nghe tiếng lôi minh vang lên."},{"chuong":1007,"tieuDe":"Cự Đỉnh","tomTat":"Hàn Lập tiến vào một đại điện nóng rực, phát hiện giữa điện có cự đỉnh được mười mấy hỏa trụ liên tục nung luyện, bên trong còn vang tiếng lôi minh như đang luyện chế vật gì. Hắn dùng linh mục tìm ra trận nhãn ở góc điện, phóng kim sắc tiểu kiếm phá trận bàn, khiến hỏa trụ tắt hẳn và lộ ra bên dưới đại điện là một hỏa trì cực phẩm cung cấp địa hỏa suốt nhiều năm. Quan sát cự đỉnh tự sinh hỏa diễm đỏ sậm, Hàn Lập suy đoán nó đã hấp thu địa hỏa hơn vạn năm, từ đỉnh lô bình thường tiến giai thành dị bảo hỏa thuộc tính có linh tính. Để mở đỉnh, hắn bố trí trận kỳ thủy thuộc tính bao phủ đại điện, thả một đôi Lục dực sương công, rồi dùng Tử La Cực Hỏa hóa thành bàn tay tím chụp nắp đỉnh. Cự đỉnh hóa ra xích hồng hỏa điểu chống cự, nhưng bị hàn khí của Lục dực sương công phối hợp tử diễm áp chế, nắp đỉnh bị đánh bật và thân đỉnh bị đông cứng. Ngay lúc đó, một đạo xích mang kèm tiếng chim hót chói tai lao ra định phá quang mạc, song bị Hàn Lập dùng kiếm khí làm suy yếu rồi bắt lại bằng tử sắc bàn tay. Hàn Lập ban đầu tưởng đây là Thái Dương Tinh Hỏa, nhưng một giọng nữ quen thuộc đã lâu không nghe trong thần thức hắn bỗng lên tiếng, nói đó là Thái Âm Chân Hỏa, một trong tam đại chân linh chi hỏa ở nhân giới."},{"chuong":1008,"tieuDe":"Thái Âm Chân Hỏa","tomTat":"Trong đại điện Hóa Linh điện, Ngân Nguyệt tỉnh lại sau nhiều năm tu dưỡng nhưng chỉ mới miễn cưỡng khôi phục, đồng thời hé lộ rằng nàng đã nhớ lại một phần nhỏ ký ức cũ. Nàng nhận ra đoàn hỏa diễm đỏ là âm hỏa chi tinh cấp thấp của Thái Âm Chân Hỏa, một trong nhân giới tam đại chân linh chi hỏa, có linh tính và tiềm lực vượt Tử La Cực Hỏa nếu được bồi dưỡng. Hàn Lập nghe nàng phân tích cách luyện hóa, tạm gác khả năng tìm Thái Dương Tinh Hỏa, rồi dùng tử diễm cùng kim sắc hồ quang phong cấm chân hỏa thành kim cầu và thu vào xích hồng ngọc hạp. Sau đó hắn phá lớp băng trên cự đỉnh, lấy được một khối vật liệu trong suốt bí ẩn có liên hệ với sự sinh ra của chân hỏa. Hàn Lập tiếp tục dùng pháp quyết thu nhỏ cự đỉnh thành chu hồng tiểu đỉnh, thử được thần thông phóng chí dương hỏa nha và vui mừng thu bảo vật này. Trước khi rời Hóa Linh điện, hắn còn chặt tận gốc hơn mười giao long hỏa trụ đã hấp thu địa hỏa nhiều năm, rồi tìm sang các kiến trúc khác nhưng chỉ thu được vài ngọc giản luyện khí bình thường và còn đặt hy vọng vào Chú Linh đường."},{"chuong":1009,"tieuDe":"Âm Phách Ngưng Hình","tomTat":"Hàn Lập trở lại Chú Linh đường, cân nhắc giữa việc ở lại chờ thông đạo khôi phục và tiếp tục tìm kiếm cơ duyên trong Côn Ngô sơn. Sau khi suy đoán các nhóm mạnh như Kiền lão ma có thể đã bị cuốn vào những trọng địa khác, hắn quyết định nhân lúc chưa ai chú ý mà rời đi, dùng Tam Diễm Phiến phá quang mạc rồi xuống núi. Ở Trấn Ma tháp, Diệp Nguyệt Thánh, cổ ma và một lão giả Diệp gia bị đàn ác quỷ tóc đỏ vây khốn; dù pháp bảo liên tục đánh nát chúng, âm khí trong tháp khiến chúng nhanh chóng hồi phục. Diệp Nguyệt Thánh nhận ra đám quỷ này là phân thân của Quỷ Vương, đồng thời Diệp gia cũng để lộ việc đã mất một người ở tầng trước vì bị Ô ảnh xà đánh lén. Lão giả Diệp gia sinh lòng e ngại trước độ nguy hiểm của các tầng dưới, nhưng Diệp Nguyệt Thánh quở trách hắn, cho rằng chính nơi bị trấn áp mạnh nhất mới có khả năng cất giấu thông thiên linh bảo mà Diệp gia mưu tính nhiều năm. Lúc ấy Độc Thánh môn tứ lão xông vào tầng bảy, Hoa Thiên Kỳ nhận ra Diệp Nguyệt Thánh vốn được cho là đã chết và cũng để lộ mục tiêu của họ là kỳ bảo trong Trấn Ma tháp. Diệp Nguyệt Thánh dùng ngân sắc phi xoa ép chân thân Quỷ Vương hiện hình, cổ ma dùng hắc kính nghiền nát các phân thân, nhưng Quỷ Vương vẫn tụ âm khí bao vây mọi người, khiến Hoa Thiên Kỳ biến sắc."},{"chuong":1010,"tieuDe":"Tu Di Ngũ Hành Bích","tomTat":"Hoa Thiên Kỳ thấy tình thế trong đại sảnh hỗn loạn liền quyết đoán dùng tiểu phiên xanh biếc cuốn bốn người Độc Thánh môn lao xuống lối vào tầng kế tiếp, bỏ lại nhóm Diệp gia và cổ ma phía sau. Ngay sau đó, lối xuống bị Tu Di Ngũ Hành Bích phong kín, kiếm quang của đại đầu quái nhân đánh vào cũng bị ngũ sắc hà quang hóa giải, khiến nhóm Diệp gia nhận ra Độc Thánh môn đã mượn được trấn tông chi bảo của Tu Di tông. Cổ ma khuyên mọi người không cần vội truy kích, vì tầng dưới còn nhiều nguy hiểm chưa biết, trước mắt nên thu thập Quỷ Vương đang bị kiềm chế rồi hãy phá bích. Ở phía bên kia, Hoa Thiên Kỳ trấn an đồng môn rằng họ và Diệp gia vốn khó hòa hoãn, mục tiêu lần này là bảo vật có thể là thông thiên linh bảo, hơn nữa hắn còn mang Độc Long châu để tạm thời chống đỡ tu sĩ Nguyên Anh hậu kỳ khi cần. Nhóm Độc Thánh môn đi xuống thạch thất có hai truyền tống trận đen trắng, sau khi Miêu sư đệ xác nhận là truyền tống trận cự ly ngắn, Hoa Thiên Kỳ tránh hắc trận bất an và chọn bạch trận. Họ được đưa tới một không gian như tiên cảnh, linh khí nồng đậm, phía trước là cung điện kim bích đặt trên pháp trận khổng lồ, xung quanh có tế đàn và thạch nhân cầm cự nhận, báo hiệu nơi này ẩn giấu cơ quan trọng đại. Trong lúc đó, Hàn Lập trở lại bạch ngọc quảng trường thì bị nhóm Lâm Ngân Bình, Cát Thiên Hào, hai hắc bào lão giả và một bạch bào thanh niên mai phục vây kín. Người uy hiếp nhất tự xưng là Từ đại tiên sư, một trong tứ đại tiên sư của Đột Ngột, bình thản đối diện Hàn Lập và yêu cầu hắn chỉ giáo."},{"chuong":1011,"tieuDe":"Nhất Phiến Kinh Địch","tomTat":"Bạch bào thanh niên họ Từ chất vấn Hàn Lập về việc từng giết một trưởng lão Nguyên Anh trung kỳ đỉnh phong của Âm La tông tại Thiên Nam, rồi đưa ra điều kiện giao vật trong Hư Thiên Đỉnh và Quỷ La phiên để đổi lấy hòa giải. Hàn Lập thừa nhận chuyện cũ nhưng dứt khoát cự tuyệt, khiến phe Thiên Lan và Âm La tông chuyển sang vây công. Hắn dùng Lôi độn kéo giãn khoảng cách, lấy Tam Diễm phiến phách ra tam sắc hỏa phượng, tạo quầng sáng cực mạnh hủy cốt đao, phi kiếm, ngân ti và ngọc như ý, đồng thời làm Cát Thiên Hào bị thương nặng và tàn phá gần nửa bạch ngọc quảng trường. Hàn Lập không ở lại kiểm tra kết quả mà lập tức bay lên hướng Côn Ngô điện, vừa chạy vừa uống một giọt vạn niên linh thủy để bù pháp lực. Sau khi quầng sáng tan đi, thanh niên họ Từ nhận định Tam Diễm phiến chỉ là pháp bảo phỏng chế thông thiên linh bảo, uy lực lớn nhưng tiêu hao nặng. Cát Thiên Hào cho rằng đây là thời cơ truy sát khi Hàn Lập chưa hồi phục, liền gọi Linh Tê Khổng Tước cùng nhóm còn lại tiếp tục đuổi lên núi."},{"chuong":1012,"tieuDe":"Thanh Đồng Sư","tomTat":"Phe Thiên Lan và Âm La tông tiếp tục truy đuổi Hàn Lập, nhưng Cát Thiên Hào cùng hai lão giả hắc sam do dự vì kiêng kỵ Tam Diễm phiến và bảo đỉnh của hắn. Hàn Lập vượt hết thềm đá dài dẫn tới Côn Ngô điện, đi qua thạch lâm cấm chế đã bị phá hủy rồi tới sườn núi đá có thạch tượng và pháp khí rải rác. Khi ẩn thân tới quảng trường bạch ngọc trước sơn môn, hắn thấy trong quang mạc có ngũ tử ma hóa thân của Kiền lão ma, một trung niên tu sĩ và hai thanh đồng cự sư khôi lỗi đang hỗn chiến. Lối vào phía trước bị quang mạc điện hồ, cấm không cấm chế và quang hà hai bên chặn lại, khiến Hàn Lập quyết định dùng Tam Diễm phiến mở đường trước khi truy binh tới. Trước khi ra tay, hắn dùng Minh Linh mục phát hiện Ngân Sí Dạ Xoa cùng hai bóng mờ yêu vật đang ẩn sau thạch đôn quan sát chiến trường. Khi nhóm thanh niên họ Từ sắp áp sát, Hàn Lập kích phát Tam Diễm phiến phá quang mạc, bại lộ hành tích rồi hóa thành thanh quang lao vào. Kiền lão ma điều ba hóa thân tử ma chặn đường, nhưng Hàn Lập phóng Ích Tà Thần Lôi hóa thành kim sắc điện giao khiến chúng phải né tránh, giúp hắn tiếp tục xông về phía bên kia quang mạc."},{"chuong":1013,"tieuDe":"Vạn Cân Áp Thân","tomTat":"Hàn Lập dùng kim sắc điện giao hóa thành kim võng để đỡ ngân hồ trên quang mạc, rồi dùng Tam Diễm phiến phá thủng cấm chế thoát ra ngoài, khiến Kiền lão ma và trưởng lão Diệp gia nhận ra hắn. Sau khi ra khỏi quang mạc, hắn cố ý bắn kim hồ về phía thạch đôn, ép Ngân Sí Dạ Xoa, sư cầm thú và xú phụ đang ẩn nấp phải hiện hình, làm các phe trước quang mạc cùng rơi vào thế kiêng dè. Hàn Lập bỏ mặc tình thế hỗn loạn để tiến đến sơn môn bằng ngọc bích, nhìn thấy đường đá trắng dẫn về cung điện cổ đại mà hắn đoán là Côn Ngô điện. Dù đã dùng thần thức kiểm tra mà không thấy dấu hiệu cấm chế, vừa bước lên đường đá trắng hắn lập tức bị trọng áp vô hình ép quỳ, hộ thể linh quang chỉ giảm được một phần áp lực. Hắn dựa vào thân thể từng rèn luyện, Thiên Thi châu và kim sắc điện y để cố đứng lên, nhưng trọng lực lại tăng vọt khiến hắn bị ép khuỵu lần nữa. Phía sau, Kiền lão ma dùng ngũ tử đồng tâm ma hợp nhất chế trụ một thanh đồng sư khôi lỗi, còn trưởng lão Diệp gia dùng Di Thiên trạc vây khốn con còn lại. Nhận thấy cấm chế Côn Ngô điện không dễ phá và Hàn Lập đã đi trước, Kiền lão ma đề nghị trưởng lão Diệp gia tạm hợp lực phá cấm rồi vào điện mới tranh đoạt bảo vật."},{"chuong":1014,"tieuDe":"Hóa Tiên Nhị Nữ","tomTat":"Trước Côn Ngô điện, thanh niên họ Từ chất vấn Kiền lão ma vì các phe chỉ bàn bảo vật mà chưa xử lý ba yêu vật, nhưng Kiền lão ma và Ngân Sí Dạ Xoa đều cho thấy trước mắt chưa muốn động thủ. Thanh niên họ Từ công khai nói phe Thiên Lan thánh điện không nhắm bảo vật trong điện mà muốn vật trên người Hàn Lập, còn nếu tìm được Quỷ La phiên thì sẽ trả lại Âm La tông. Các phe tạm đạt hiệp nghị, cùng hợp lực công kích quang mạc chắn đường và cuối cùng đánh vỡ cấm chế. Trong thạch lâm, Mộc phu nhân cùng nữ tử tú lệ Hóa Tiên tông ẩn nấp quan sát, bàn về uy thế Kiền lão ma, thủ đoạn chú thuật của bổn tông và sự đáng chú ý của Hàn Lập qua Ích Tà Thần Lôi, vũ phiến, ngân sí cùng lôi độn thuật. Mộc phu nhân hé lộ Hóa Tiên tông là hậu nhân Côn Ngô tam lão, có trách nhiệm trông coi phong ấn Côn Ngô Sơn, còn Trấn Ma tháp là trận nhãn chân chính và Hóa long tỳ trong Côn Ngô điện là vật cần để gia cố phong ấn. Hai người cũng nhắc tới Thiên tinh bi, Tứ tượng xích, Bát linh xích và Hắc phong kỳ, qua đó mở rộng bí mật về các hậu thủ trấn áp người bị phong ấn có thân phận liên quan thượng giới. Khi quang mạc bị phá, bọn Kiền lão ma tiến về sơn môn, còn nhị nữ Hóa Tiên tông chuẩn bị theo sau để tìm cơ hội hành động."},{"chuong":1015,"tieuDe":"Kim Từ Linh Mộc","tomTat":"Mộc phu nhân cùng nữ tử đồng hành quyết định tiếp tục bám theo nhóm lão quái nhưng giữ khoảng cách, sau khi họ rời đi lại có một nhân ảnh toàn thân màu lục bí mật xuất hiện rồi biến mất. Trước Côn Ngô điện, Hàn Lập đã tiến vào con đường giữa hai hàng cây và bị kim từ trọng quang ép nặng, phải dựa vào nhiều tầng thần thông cùng biến thân bán giao bán nhân để từng bước tiến lên. Cát Thiên Hào nhân cơ hội phóng trường giáo đỏ đánh Hàn Lập nhưng pháp bảo bị cấm chế kéo rơi, khiến mọi người nhận ra pháp bảo kim chúc tính bị khắc chế. Ngân Sí Dạ Xoa giải thích đây là kim từ trọng quang do kim từ linh mộc tạo ra, còn nhóm tu sĩ xác định phải dùng bảo vật phi kim chúc để chặt cây phá cấm. Lâm Ngân Bình thả linh xà bốn chân vào thử, nhưng linh xà bị trọng lực ép nát, chứng minh cấm chế cực kỳ nguy hiểm. Thanh niên họ Từ, Kiền lão ma và các tu sĩ bắt đầu công kích linh mộc, trong khi ba yêu vật giả vờ hỗ trợ nhưng thực tế giữ sức và âm thầm vui mừng. Hàn Lập nhờ Minh Thanh Linh Nhãn cùng lời nhắc của Ngân Nguyệt biết trong cây có Minh ấn đại quang luân hàng ma chú, nhưng cố ý không cảnh báo để ba yêu vật tiến vào kiềm chế các phe nhân loại. Ngân Nguyệt khuyên hắn nhanh chóng vào điện đoạt bảo rồi lợi dụng hỗn loạn rời khỏi Côn Ngô Sơn."},{"chuong":1016,"tieuDe":"Nguyên Sát Thánh Tổ","tomTat":"Hàn Lập tiến gần Côn Ngô Điện nhưng không chủ quan, vì kim từ trọng quang đã khiến pháp lực của hắn hao tổn nghiêm trọng. Hắn uống một giọt vạn niên linh dịch, lập tức khôi phục pháp lực rồi tăng tốc vào cửa điện. Ở tầng bảy Trấn Ma Tháp, cổ ma, Diệp Nguyệt Thánh và một trưởng lão Diệp gia phá vỡ tinh bích, phát hiện hai truyền tống trận đen trắng; cổ ma chọn hắc sắc truyền tống trận dù dấu vết Độc Thánh môn nằm ở trận trắng. Khi trưởng lão Diệp gia nghi ngờ, cổ ma bất ngờ giết ông ta, dùng hắc sắc ma diễm hủy cả thân thể lẫn nguyên anh, còn Diệp Nguyệt Thánh đứng nhìn không cứu. Qua đối thoại, Diệp Nguyệt Thánh thừa nhận phản bội Diệp gia để đổi lấy cơ hội được Nguyên Sát thánh tổ phân thân quán chú ma khí, nhằm tiến giai Hóa Thần kỳ. Cổ ma và Diệp Nguyệt Thánh được truyền tống tới không gian u ám có song thủ ngân lang khổng lồ bị xích đen, phù cấm và quang trụ giam giữ; cổ ma xác nhận đó là hóa thân Nguyên Sát thánh tổ. Cổ ma thi triển bí thuật bằng ma ảnh, tinh huyết và huyết văn để câu thông thần hồn, khiến hắc sắc lang thủ mở mắt. Cùng lúc đó, trong một không gian phong bế gần cung điện, ngân sắc hạp tử trên bàn thờ lóe sáng dưới sự bao bọc của thúy lục mộc xích, báo hiệu phong ấn khác cũng bị chấn động."},{"chuong":1017,"tieuDe":"Dung Hồn","tomTat":"Trong điện, mộc xích trên ngân hạp phát lục quang khiến ngân quang biến mất, còn Hoa Thiên Kỳ đứng bất động, tai mũi chảy máu và chỉ còn dấu hiệu sống rất yếu. Ở không gian cấm chế của ngân lang hai đầu, hắc sắc lang thủ nhận ra Cổ ma là Huyết Diễm, nghe hắn kể chuyện năm xưa suýt bị tu sĩ nhân loại giết và nay tới cứu thánh tổ cùng quái nhân Diệp gia. Hắc sắc lang thủ nói việc giải phong khó hơn dự tính vì Đại chu thiên tinh thần liên là bảo vật Linh giới chuyên khắc thánh tộc, còn không gian giam giữ do một kiện thông thiên linh bảo mở ra. Nàng tiết lộ thân thể Ngân Nguyệt yêu lang có hai chủ thể nguyên thần, Ngân Nguyệt là sủng phi của Thiên Khuê Thần Lang và là chân thân Linh giới hiếm hoi giáng xuống Nhân giới. Cổ tu từng không thể bức thánh tổ ra khỏi thân thể, nên rút lang hồn thứ hai đặt ở cung điện linh khí sung túc, để nó định kỳ trở lại tranh quyền khống chế. Hắc sắc lang thủ vì bị thiếu ma khí và dần rơi vào hạ phong nên dùng Dung hồn, hợp hai tinh hồn thành tân hồn, nhưng tân hồn lại vừa phân liệt do kéo một tu sĩ Hóa Thần vào Huyễn Diệu Thiên Tượng. Cuối chương, quái nhân Diệp gia bị nhìn ra sinh khí sắp cạn và thừa nhận muốn đi theo ma đạo để tránh tọa hóa."},{"chuong":1018,"tieuDe":"Gặp Lại Nguyên Quang","tomTat":"Lang thủ màu đen dụ Quái nhân đầu to bằng lời hứa quán ma nhập thể, dù thừa nhận cơ hội tiến giai chỉ khoảng một nửa, rồi sai hắn tới cung điện khác để giết lang hồn Ngân Nguyệt đang ngủ say. Nó giải thích nơi đó có Diệt Tuyệt Đại Trận do Côn Ngô tam lão bố trí bằng tám mươi mốt khẩu Tru Ma Đao, chuyên khắc chế kẻ mang ma khí, nên bản thân và Huyết Diễm đều khó trực tiếp ra tay. Quái nhân đầu to vì khát vọng Hóa Thần và tăng thọ nguyên vẫn nhận nhiệm vụ, dùng truyền tống trận còn lại rời đi, trong khi lang thủ màu đen cùng Cổ ma lấy năm món ma khí ra chuẩn bị phá cấm Hắc Phong Kỳ để thoát khỏi Trấn Ma tháp. Ở phía Côn Ngô điện, Hàn Lập phát hiện trong điện tràn ngập Bắc Cực Nguyên Quang giống thứ từng gặp tại Trụy Ma Cốc, nhưng lần này quang ti dày đặc phun ra từ hơn trăm cây cột. Kiền lão ma cùng đám tu sĩ, yêu vật đuổi tới phía sau, buộc Hàn Lập phải lập tức hành động; hắn lấy một chiếc nhẫn màu đen trong Lưỡng Nghi Hoàn, tạo màn hào quang bảo hộ rồi xông thẳng vào vùng nguyên quang, khiến các tia sáng tự rẽ sang hai bên. Việc Hàn Lập đi trước khiến các phe truy đuổi kinh hãi và nôn nóng, Ngân Sí Dạ Xoa thúc giục tăng tốc, còn Kiền lão ma tự tin Bắc Cực Nguyên Quang không đủ ngăn mình và dùng huyết ảnh vượt qua từ trường Kim Từ Linh Mộc. Cùng lúc đó, Xú phụ hiện nguyên hình cự quy hai màu trắng đen, chở Ngân Sí Dạ Xoa và Sư cầm thú băng qua vùng cự lực, dù hai yêu bị kim sắc phù văn nhập thể làm suy yếu tạm thời."},{"chuong":1019,"tieuDe":"Đánh Lén","tomTat":"Kiền lão ma hóa huyết ảnh xông vào Côn Ngô Điện, bị ngân ti trong Bắc Cực Nguyên Quang xuyên phá nhưng nhờ huyết quang tự tu bổ mà vẫn lao sâu vào trong. Xú phụ sau khi chở nhị yêu vượt qua thì hao tổn nguyên khí, còn Sư cầm thú và Ngân Sí Dạ Xoa phối hợp kim sắc âm ba với thanh sắc kình phong để dọn ngân ti mở đường. Bên ngoài điện, Lâm Ngân Bình sốt ruột nhưng được thanh niên họ Từ và Cát Thiên Hào thuyết phục tiếp tục phá đại thụ rồi canh cửa, vì mục tiêu chính là Hàn Lập và người đoạt bảo cuối cùng vẫn phải đi ra. Hàn Lập nhờ Minh Thanh linh nhãn nhìn thấu ảo trận trong Bắc Cực Nguyên Quang, vào hậu điện và phát hiện bàn án lục sắc chứa bảo vật được quang tráo bảo vệ. Hắn nghi bức Tam nhân vọng nguyệt đồ có cổ quái nên chém nát, nhưng ngay sau đó nhờ Ngân Nguyệt cảnh báo mới kịp tránh đòn đánh lén từ kim ngân sắc tiêm toa do một nữ tử bí ẩn điều khiển. Khi Hàn Lập định chuyển sang đoạt bảo vật trước, Mộc phu nhân bất ngờ hiện thân, dùng khăn xanh phù văn vây hắn rồi dùng lệnh bài bạc phá quang tráo trên bàn án. Quang tráo tan đi, để lộ bốn huyết sắc mộc bài, tiểu kiếm tử sắc, Hàng ma trượng, thư cuốn màu hồng và ấn tỳ màu xanh khắc ngũ trảo chân long, trong đó ấn tỳ khiến Mộc phu nhân đặc biệt chú ý."},{"chuong":1020,"tieuDe":"Đoạt Bảo","tomTat":"Mộc phu nhân vừa sắp đoạt bảo trên bàn án thì bị Mộc Khôi bí mật theo sau dùng dây mây xanh phục kích, may nhờ bạch sắc quang tráo hộ thân nên thoát nguy. Mộc Khôi lộ diện, hóa lục quang định gom bảo vật, nhưng mảnh vụn Tam nhân vọng nguyệt đồ kích hoạt cấm chế cuối của Côn Ngô tam lão, hiện ba nhân ảnh và điều khiển tiểu kiếm, hàng ma trượng, thư cuốn hợp kích diệt cả thân thể lẫn nguyên thần của nó. Khi Mộc phu nhân thoát trói và định tiếp tục đoạt bảo, Hàn Lập phá khỏi chiếc khăn lớn, dùng Phong Lôi Sí lao tới bàn án tranh nhiếp bảo vật. Mộc phu nhân dùng ngân sắc phi châm và hồng hà cản hắn, nhưng Hàn Lập dùng Tuyết Tinh Châu chống đỡ rồi quạt Tam Diễm Phiến ép nàng phải bỏ bảo né tránh. Uy lực Tam Diễm Phiến khiến các bảo vật rơi xuống, cùng lúc huyết ảnh, ngân sắc quang đoàn và tử vụ từ Bắc Cực Nguyên Quang lao ra làm cục diện hỗn loạn. Hàn Lập nhanh tay thu được một mộc bài không tên và thư cuốn hồng quang, còn Hàng ma trượng bị huyết ảnh đoạt lấy. Khi huyết ảnh tiếp tục định lấy Hóa Long Tỳ, một nữ tử chưa lộ tên khẩn trương ngăn lại và dùng thước ngọc màu trắng ngà phát phật âm, bạch liên, thất sắc cự liên để áp chế huyết ảnh, ngân sắc quang đoàn và tử vụ."},{"chuong":1021,"tieuDe":"Dương Hoàn Chi Oai","tomTat":"Hàn Lập phát hiện Kim Cương Tráo trong cơ thể sinh dị trạng cộng hưởng với cự Liên, liền dùng pháp lực áp chế và quyết định rời khỏi cuộc tranh đoạt vì đã lấy được hai bảo vật. Ở phía Hóa Tiên Tông, nữ tử tú lệ cố duy trì Tứ Tượng Xích để khốn Kiền lão ma cùng hai yêu, giúp phụ nhân Hóa Tiên Tông nhập vào thải Liên lấy Hóa Long Ấn và tiểu kiếm màu tím. Khi pháp lực nữ tử cạn, uy năng Tứ Tượng Xích suy giảm, Kiền lão ma cùng hai yêu thoát khỏi áp chế và chuyển mục tiêu sang phụ nhân vừa đoạt bảo. Hàn Lập bay vào Bắc Cực Nguyên Quang thì gặp xú phụ Huyền Nham Quy bị kẹt tại đó, dựa vào chiến giáp màu xanh để chống ngân sắc quang ti nhưng khó thi triển độn thuật. Xú phụ nhận ra vật Hàn Lập đang giữ, đòi hắn giao ra rồi dùng hắc côn tạo vô số côn ảnh tấn công, khiến Hàn Lập sinh sát tâm. Hàn Lập thúc giục chiếc nhẫn đen Dương Hoàn, điều khiển Bắc Cực Nguyên Quang phá côn ảnh, vây công chiến giáp và đánh một cánh tay xú phụ hóa thành huyết vụ. Trước tử cảnh, xú phụ xin làm linh thú của Hàn Lập và tiết lộ mộc bài hắn lấy trong điện Côn Ngô chính là bổn mạng nguyên bài của nó."},{"chuong":1022,"tieuDe":"Hàng Phục","tomTat":"Hàn Lập lấy Mệnh nguyên bài ra kiểm tra bằng linh mục và thần thức, phá lớp sương xám để thấy đồ án linh quy hắc bạch, từ đó nhận ra xú phụ là Huyền Nham Quy. Vì không yên tâm trước tu vi cao của nàng, hắn dùng Bắc Cực Nguyên Quang, ngân ti và Dương Hoàn gây áp lực, buộc nàng tự nguyện phân liệt gần nửa nguyên thần nhập vào mệnh bài. Hàn Lập hút phần nguyên thần ấy vào bài rồi nuốt mệnh bài, chính thức nắm quyền chế trụ Khuê Linh, sau đó tản Bắc Cực Nguyên Quang và dùng Âm Hoàn che chở nàng. Hắn hứa không giam giữ nàng vĩnh viễn, nói khi mình tọa hóa hoặc phi thăng Linh Giới sẽ trả tự do, rồi cho nàng một giọt Vạn niên linh thủy để hồi phục pháp lực. Khuê Linh dùng linh thủy khôi phục, vận hắc bạch linh quang tái sinh cánh tay cụt trong vài hơi thở, khiến Hàn Lập kinh ngạc trước bất diệt thân thể của yêu thú cấp mười. Nàng tự xưng Khuê Linh, cho biết từng nghe Ngân Sí Dạ Xoa kể về Hàn Lập, rồi nhận nhiệm vụ phối hợp hắn phục kích Kiền lão ma trong Bắc Cực Nguyên Quang. Khuê Linh cảnh báo Kiền lão ma có ma công và độn thuật đặc dị nên khó diệt sát, nhưng Hàn Lập hé lộ nếu thêm một tu sĩ Nguyên Anh hậu kỳ nữa thì tình thế sẽ khác, khiến nàng kinh ngạc tìm quanh mà không thấy ai ẩn nấp."},{"chuong":1023,"tieuDe":"Kiếp Sát Lão Ma","tomTat":"Sau Ngô điện, Mộc phu nhân điều khiển Nhật Nguyệt toa đưa sư muội chạy trốn Kiền lão ma, Ngân Sí Dạ Xoa và sư cầm thú, còn nữ tử tú lệ đã gần cạn pháp lực vì từng cưỡng ép vận dụng Tứ tượng xích. Mộc phu nhân lấy lý do Hóa Tiên Tông thủ hộ bảo vật trong núi và muốn tu bổ phong ấn vì an nguy nhân giới để khuyên Kiền lão ma dừng tay, nhưng lão ma vẫn ép giao bảo vật cùng ngọc thước phỏng chế thông thiên linh bảo. Khi bị dồn tới góc điện phủ, hai nữ tu dùng bạch liên giả phô trương thanh thế khiến truy binh lùi lại, rồi Nhật Nguyệt toa dịch chuyển lao vào Bắc cực nguyên quang. Trong vùng nguyên quang, Mộc phu nhân dùng lệnh bài tạo ngân mạc bảo vệ linh toa và khống chế ảo trận cấm chế để cắt đuôi Kiền lão ma cùng hai yêu. Ngân Sí Dạ Xoa và sư cầm thú vì đã lấy lại bản mạng lệnh bài nên rút lui, còn Kiền lão ma rời theo hướng khác thì bị Hàn Lập chờ sẵn để đòi pháp quyết giải hồn chú của Âm La Tông. Kiền lão ma không chịu giao pháp quyết, Hàn Lập liền gọi xú phụ ra liên thủ và dùng Dương hoàn điều động Bắc cực nguyên quang thành tường, thành võng để vây huyết ảnh. Xú phụ dùng hắc côn trấn áp trong khoảnh khắc, nhưng Kiền lão ma khiến huyết ảnh nổ thành vô số tơ máu rồi tái hợp nguyên vẹn ngoài xa, phá vỡ bước vây bắt đầu tiên."},{"chuong":1024,"tieuDe":"Ngũ Ma Hợp Thể","tomTat":"Hàn Lập nhận ra trạng thái gần như vô hình của Kiền lão ma không phải quỷ phách, mà là ma công khiến thân thể tạm hóa thành hình thái yêu ma gần như bất tử. Hắn cùng Khuê Linh liên thủ vây công bằng Tử La Thiên Hỏa, Bắc Cực Nguyên Quang, Ích Tà Thần Lôi và hắc côn, nhưng Kiền lão ma triệu bản thể Ngũ tử đồng tâm ma để hóa giải thế công. Năm bộ xương phun lân hỏa bích diễm, tạo quang tráo xám trắng, khiến các đòn đánh của Hàn Lập và Khuê Linh đều khó phá vỡ. Khuê Linh phun tinh khí hắc bạch vào hắc côn, biến nó thành cự phủ bạc rồi thi triển Cự đại thuật hóa thành người khổng lồ tám trượng, chém ra phủ mang cực mạnh. Kiền lão ma chặt ngón tay luyện huyết đao ngăn cản nhưng huyết đao bị chém gãy, buộc hắn thúc năm ma hợp thể thành khô lâu khổng lồ. Khô lâu phun Uế âm ma khí hấp thu phủ mang bạc, khiến Khuê Linh nhận ra nguồn gốc đáng sợ của Ngũ tử đồng tâm ma. Hàn Lập tế Dương hoàn để ngưng Bắc Cực Nguyên Quang thành ngân liên, xuyên thủng nhiều lỗ trên khô lâu, nhưng sắc mặt hắn lập tức âm trầm vì đối thủ dường như chưa bị giải quyết."},{"chuong":1025,"tieuDe":"Huyết Ma Châu","tomTat":"Đại khô lâu do Ngũ tử đồng tâm ma hợp thành bị thương nhưng nhanh chóng tự liền, khiến Hàn Lập nhận ra phải xử lý Kiền lão ma trước thay vì cố diệt ma đầu này bằng đòn thường. Khuê Linh dùng ngân sắc cự phủ đối chiến, thi triển Hổ phệ gọi khí linh Bạch hổ một sừng cắn nuốt đầu đại khô lâu, rồi chém nát thân xương và dùng yêu diễm luyện hóa. Kiền lão ma thúc ma công, thi triển Hoá ma vô hình khiến tàn cốt tách thành năm bộ bạch cốt rồi tái hợp thành đại khô lâu. Trong lúc đó, Hàn Lập âm thầm điều khiển Dương Hoàn phóng ngân liên xé nát huyết ảnh Kiền lão ma nhiều lần, buộc lão tụ huyết vụ thành Huyết Ma Châu. Hàn Lập nhận ra châu này chứa nguyên thần và Nguyên Anh của Kiền lão ma, nên chuẩn bị dùng Ích tà thần lôi phối hợp Tam Diễm Phiến để phá châu. Kiền lão ma giả vờ lao tới liều mạng nhưng thực chất chuyển hướng phá Bắc Cực Nguyên Quang để bỏ chạy tìm trợ thủ. Hàn Lập dịch chuyển tới rìa cấm chế, cầm Tam Diễm Phiến và gọi Hư Thiên bảo đỉnh ra ứng biến. Cuối chương, Huyết Ma Châu mất hơn nửa huyết diễm bị một đoàn ngân quang chói mắt có bóng người bên trong đuổi theo bắn ra."},{"chuong":1026,"tieuDe":"Phá Châu","tomTat":"Kiền lão ma bị Hàn Lập chặn phía trước và nhân hình khôi lỗi ép phía sau, khiến thế tiền hậu giáp kích quanh Huyết ma châu hình thành. Lão ma tế Âm La Phiên để chống đỡ, phóng âm phong, hắc vụ và ác quỷ cầm Thác Thiên xoa, nhưng ác quỷ vừa hiện thân đã bị Hỏa điểu tam sắc từ Tam Diễm phiến tiêu diệt. Chương đồng thời hé lộ Âm La Phiên là trấn tông chi bảo của Âm La tông, đủ mười tám cây mới phát huy toàn bộ uy lực và bị tổ huấn hạn chế gom đủ vào một người. Sau khi Kiền lão ma tránh mũi tên xanh biếc ẩn Ích tà thần lôi, một phi đao đen trong suốt bất ngờ xuyên phá Huyết ma châu, làm châu hoàn toàn vỡ nát. Nguyên anh Kiền lão ma hiện ra trong trạng thái quỷ dị, ôm Âm La Phiên bỏ chạy và tìm cách hội hợp với Ngũ tử đồng tâm ma, trong khi Khuê Linh truy đuổi ngũ ma. Hàn Lập dùng Lôi độn thuật và kim võng Ích tà thần lôi chặn đầu, nhân hình khôi lỗi dùng mê hồn thuật chặn tiếp, rồi tiểu đỉnh xuất hiện trên đầu lão ma và phóng ánh sáng mờ màu xanh về phía hắn."},{"chuong":1027,"tieuDe":"Phản Phệ","tomTat":"Thanh quang của Hư Thiên Đỉnh trói chặt huyết sắc nguyên anh Kiền lão ma cùng Âm La Phiên, còn Hàn Lập dùng Lôi Độn Thuật áp sát và thu tiểu đỉnh vào tay. Nhân hình khôi lỗi do hắn bố trí từ trước bất ngờ hiện thân sau lưng nguyên anh, dán kim ngân lưỡng phù để phong bế pháp lực và phá độc chú của lão ma. Hàn Lập hé lộ chuỗi mai phục gồm khôi lỗi ở cửa đại điện, Lôi Hoả Cung, Lôi Mộc Tiễn, Ma Tủy Phi Đao, Ích Tà Thần Lôi, Huyễn Quang tinh và Hư Thiên Đỉnh, đồng thời nhận ra tiểu đỉnh còn bị giới hạn vì hắn mới luyện tầng thứ nhất Thông Thiên Bảo Quyết. Khi Khuê Linh đem năm khô lâu ma đầu tới hỏi cách xử lý, Kiền lão ma kích động chúng phá cấm nhưng lại bị chính Ngũ tử đồng tâm ma phản phệ cắn nuốt nguyên anh. Hàn Lập dùng thanh ti của tiểu đỉnh cách ly năm khô lâu, giữ lại phần thần thức còn sót của nguyên anh rồi thu nguyên anh cùng Âm La Phiên và túi trữ vật của Kiền lão ma. Sau khi vào Bắc Cực Nguyên Quang xử lý nguyên anh, hắn quyết định không luyện hóa Ngũ tử ma thân mà ép chúng thành kim châu, dùng Kim Cương Tráo và Ích Tà Thần Lôi trấn áp rồi cất đi. Cuối chương, Hàn Lập cùng Khuê Linh chuẩn bị tìm một nơi bí ẩn trong núi để tạm lánh vài ngày, chờ khe phong ấn hồi phục bình thường rồi mới rời khỏi nơi này."},{"chuong":1028,"tieuDe":"Linh Bảo Xuất Thế","tomTat":"Hàn Lập cùng Khuê Linh rời Côn Ngô Điện, đi qua Bắc Cực Nguyên Quang bằng khinh thân thuật để tránh hao tổn pháp lực. Bên ngoài điện không còn ai canh giữ, nhưng chiến trường đầy dấu vết giao tranh dữ dội khiến hắn đoán các phe đã xảy ra biến cố lớn. Hàn Lập quyết định không truy cứu mà ưu tiên theo Khuê Linh tìm lối rút khỏi Côn Ngô Sơn, rồi trên đường thấy một khe nứt khổng lồ do bảo vật loại đao kiếm tạo ra. Khi phát hiện một Nguyên Anh Âm La Tông ẩn sau cự thạch, hắn dùng độn thuật chặn đầu, thi triển thanh sắc đại thủ và Ích Tà Thần Lôi bắt sống đối phương. Qua tra hỏi, hắn biết Diệp gia đã kéo đến khai chiến với phe Âm La Tông, nhưng dị tượng bảo quang và phạn âm ở trấn ma tháp khiến mọi tu sĩ bỏ dở giao chiến để lao tới tranh đoạt Thông Thiên Linh Bảo. Nguyên Anh còn tiết lộ thân thể mình bị Tứ Tán Chân Nhân dùng huyết hồng trường đao hút sạch máu huyết, và món đao ấy rất giống Ma Long Nhận trong truyền thuyết, khiến Hàn Lập nghe xong lập tức biến sắc."},{"chuong":1029,"tieuDe":"Ma Nhận Nghi Vấn","tomTat":"Chương mở bằng truyền thuyết về Ma Long Nhận, loại ma nhận luyện từ Ma Tuỷ Toản có thể hấp thu huyết nhục và tinh hồn tu sĩ để tăng uy lực, khiến Hàn Lập nghi ngờ bảo nhận trong tay Tứ Tán chân nhân. Khuê Linh cho rằng nếu đối phương vẫn để Nguyên Anh thoát thì chưa chắc đó là Ma Long Nhận thật, còn Hàn Lập vì nghĩ Côn Ngô Sơn có thể có Thông Thiên Linh Bảo nên bắt đầu dao động. Ngân Nguyệt truyền âm rằng nàng cảm thấy có thứ gì trong Trấn Ma Tháp đang kêu gọi và có thể liên quan ký ức đã mất, khiến Hàn Lập quyết định đi xem. Trước khi lên đường, Hàn Lập diệt Nguyên Anh trưởng lão Âm La Tông, thu thêm một cây Âm La Phiên và biết đủ mười tám cây phiên sẽ có uy lực cực lớn. Trên đường tới Trấn Ma Tháp, Khuê Linh phát hiện dị trạng trong đống đá, Hàn Lập tìm thấy thi cốt lão giả họ Phú của Cửu U Tông với huyết nhục và Nguyên Anh biến mất, tử u châu bị phá hủy, túi trữ vật cùng Bồi Anh Đan không còn. Từ vết thương sau lưng bộ xương, Hàn Lập nghi Tứ Tán chân nhân đã dùng bảo nhận giết người đoạt đan và nhận ra đối phương hành xử quá khác thường so với một tán tu. Sau khi hỏa táng thi cốt, Hàn Lập và Khuê Linh tiếp tục đi lên, tới nơi thì thấy đường đá biến mất, đỉnh núi như bị gọt bay và Trấn Ma Tháp dường như đã lún xuống vực sâu. Khuê Linh kể năm xưa từng cảm ứng một luồng ma khí cực mạnh trong Côn Ngô Sơn, có lẽ chính là thứ bị phong ấn trong tháp."},{"chuong":1030,"tieuDe":"Huyết Đao","tomTat":"Hàn Lập phán đoán yêu ma bị trấn áp lâu năm đã suy yếu, lại có nhiều hậu kỳ tu sĩ đi trước, nên cùng Khuê Linh bay xuống vực sâu. Trong bóng tối thần thức bị hạn chế, hắn mở Minh Thanh Linh Mục để quan sát, nhưng gần đáy vực thì bị một đạo huyết quang mang mùi máu đánh lén. Huyết đao của kẻ ẩn thân phá nhiều lớp phòng ngự, vòng qua Nguyên Cương Thuẫn và buộc Hàn Lập phải dùng Hư Thiên Đỉnh, Phong Lôi Sí cùng Ích Tà Thần Lôi mới phá được thế vây khiến đối phương rút lui. Sau trận, Hàn Lập kiểm tra Nguyên Cương Thuẫn bị chém sâu, nhận xét hung đao giống Ma Long Nhận, rồi cảnh cáo Khuê Linh vì nàng đã do dự không ra tay. Hai người xuống bình đài lớn và biết Trấn Ma Tháp được cổ tu sĩ xây đảo ngược, càng xuống sâu yêu ma bị giam càng mạnh. Trong các tầng đầu, Hàn Lập thấy nhiều dấu vết tranh đấu, một thi thể nghi thuộc Diệp gia ở tầng ba, rồi hai thi thể ở tầng năm gồm đại hán tán tu bị chém nát và một người toàn thân xanh biếc như trúng độc. Đến tầng sáu, hắn phát hiện Bạch Dao Di còn sống nhưng bị phong trong khối băng lớn, bèn dùng tử sắc hỏa diễm hấp thu hàn khí để giải phong cho nàng. Bạch Dao Di tỉnh lại nhận ra Hàn Lập, còn hắn hỏi vì sao một tu sĩ tu công pháp Băng thuộc tính lại tự đóng băng bản thân."},{"chuong":1031,"tieuDe":"Bát Linh Thước","tomTat":"Bạch Dao Di thuật lại rằng nàng bị trọng thương sau khi phải thả bản mệnh phi kiếm và huyền băng hàn khí đối phó cự địch, rồi bị đánh lén đến mức huyền băng hóa thành cự băng. Nàng kể mình và lão giả họ Phú vốn định rời Côn Ngô sơn sau chút thu hoạch, nhưng bị dị tượng Trấn Ma tháp hấp dẫn và bị cuốn vào hỗn chiến giữa Âm La Tông, người mở phong ấn, Ngân Sí Dạ Xoa cùng các tán tu. Hàn Lập báo tin lão giả họ Phú đã chết, khiến Bạch Dao Di kinh sợ và quyết định rút khỏi cuộc tranh bảo, còn hắn tiếp tục tiến sâu, đồng thời bất ngờ hỏi về việc bái phỏng Tiểu Cực Cung. Ở tầng bảy, Hàn Lập theo cảm ứng của Ngân Nguyệt chọn truyền tống trận màu trắng thay vì trận đen có tà khí, rồi cùng Khuê Linh lên tầng tám. Tại tầng tám, nhiều phe đang bị thạch khôi lỗi và cấm chế quanh cung điện công kích trong cục diện hỗn loạn. Trên cung điện lơ lửng Bát Linh Thước, một thông thiên linh bảo đứng đầu hiện linh ảnh linh thú thượng cổ, khiến Khuê Linh nhận ra và Ngân Nguyệt bất ngờ cảm ứng được một nửa khác của mình trong cung điện. Khi Hàn Lập còn muốn hỏi thêm, tu sĩ họ Từ, Ngân Sí Dạ Xoa và các yêu vật phát hiện hắn tới, khiến hắn tạm gác nghi vấn để ứng phó tình thế."},{"chuong":1032,"tieuDe":"Liên Thủ","tomTat":"Hàn Lập xuất hiện trước tế đàn, gặp lại thanh niên họ Từ, Ngân Sí Dạ Xoa và Sư cầm thú trong lúc pháp trận Thạch Khôi Lỗi vẫn khó phá vì thạch nhân bị đánh nát lại tự ngưng tụ. Khuê Linh công khai đứng về phía Hàn Lập, trách hai yêu từng bỏ mặc bản mệnh bài của nàng và nói rõ vì bản mệnh bài đang trong tay Hàn Lập nên nàng buộc phải nghe lệnh. Mộc phu nhân dò hỏi kết quả trận chiến giữa Hàn Lập và Càn lão ma, nhưng Hàn Lập chỉ nói tránh rằng hai người từng luận bàn rồi Càn lão ma rời đi. Đại trưởng lão Diệp gia bí mật truyền âm mời Hàn Lập liên thủ đoạt Bát Linh Thước, hứa Diệp gia chỉ lấy linh thước còn bảo vật khác hoặc trăm vạn linh thạch sẽ dành cho hắn. Hàn Lập ngoài mặt nhận lời nhưng nói với Ngân Nguyệt rằng đây chỉ là ước định miệng, mục đích là mượn Diệp gia kiềm chế các đối thủ. Khi Mộc phu nhân nhắc Thất Diệu chân nhân của Thiên Ma Tông sắp tới, các phe bị ép phải nhanh chóng hành động. Cuối cùng thanh niên họ Từ đồng ý cho Hàn Lập gia nhập phá trận, còn việc ai đoạt được Thông Thiên Linh Bảo sau khi trận vỡ sẽ dựa vào bản lĩnh riêng."},{"chuong":1033,"tieuDe":"Phá Trận Cùng Thoát Khốn","tomTat":"Trong cung điện Côn Ngô Sơn, Mộc Phu Nhân và nữ tử tú lệ của Hóa Tiên Tông bí mật truyền âm khi các tu sĩ hợp lực phá pháp trận. Mộc Phu Nhân giải thích nơi này không phải chỗ trực tiếp phong ấn ma vật vì Hóa Long Tỳ không phản ứng, mà khả năng cao là cửa vào tầng chín Phong Ma tháp, nơi có đầu mối cấm chế khống chế Côn Ngô Sơn. Bà còn xác định Bát Linh Thước là di bảo của Hóa Tiên Tông, dự định dùng Tứ Tượng Thước hoặc trông vào Hướng Lão để thu hồi. Ở một không gian u ám gần đó, cổ ma hai đầu bốn tay thúc năm kiện ma khí rót ma khí vào Ngân Lang, giúp phân hồn Cổ Ma Thánh tổ trong hắc sắc lang thủ phá cấm bằng tử sắc ma diễm, hắc điện và hắc sắc quang hà. Ngân Lang phá được hoàng sắc quang trụ và làm nhiều gương đồng vỡ tan, nhưng Đại Chu Thiên Tinh Thần Liên cùng Thuần Dương Bạch Cốt Hỏa vẫn trói và thiêu đốt khiến việc thoát khốn chưa hoàn tất. Bên ngoài vết nứt phong ấn, Huyền Thanh Tử của Thái Nhất Môn chặn hai ba trăm tu sĩ, dùng lý do khe nứt nguy hiểm và chỉ người có linh toa mới nên vào. La đạo hữu và Vũ đạo hữu lần lượt gây sức ép, trong khi Huyền Thanh Tử thực ra đang thi hành bí lệnh phải ngăn đám đông, chờ liên thủ với Thất Diệu Chân Nhân tiến vào để tránh phong ấn sinh biến."},{"chuong":1034,"tieuDe":"Cấm Ma Hoàn, Băng Hồn Cốc","tomTat":"Thất Diệu Chân Nhân của Thiên Ma Tông xuất hiện trước vết nứt phong ấn, đại diện Thiên Ma Tông và Thái Nhất Môn tuyên bố cấm các tu sĩ khác tiến vào, khiến lão giả họ La và những người còn lại phải lui bước. Nhóm ma tu Nguyên Anh Thiên Ma Tông nhanh chóng dùng pháp kỳ dựng cấm chế đại trận, tạo sương mù che kín miệng vết nứt. Trong pháp trận, Huyền Thanh Tử và Thất Diệu bàn về Kiền lão ma, Âm La Tông, người Thiên Lan Thảo Nguyên đã vào trước, đồng thời nhắc tới kế dương đông kích tây của Diệp gia quanh Thông Thiên Linh Bảo. Thất Diệu cho biết mình mang năm Cấm Ma Hoàn từ Linh giới truyền xuống để khắc chế cổ ma, còn Huyền Thanh Tử có Thiên A Thần Kiếm; cả hai đều nhận lệnh ưu tiên phong ấn cổ ma thay vì giết. Sau đó Thất Diệu lấy Linh Quy Phi Xa, cùng Huyền Thanh Tử bay vào vết nứt phong ấn. Chương chuyển sang Chân Hoàn Sơn của Thái Nhất Môn, giới thiệu Băng Hồn Cốc là cấm địa bí mật lạnh lẽo và ít người biết. Cùng ngày, hôi bào lão giả họ Hô xuyên qua ảo trận ngoài Băng Hồn Cốc, tới trước vách băng cuối cốc và gọi Bạch lão quỷ ra khỏi nơi ẩn thân."},{"chuong":1035,"tieuDe":"Hóa Thần Tu Sĩ","tomTat":"Hôi bào lão giả họ Hô rời Ma Đà Sơn tới Băng Hồn Cốc, báo cho Bạch đạo hữu rằng Hướng Chi Lễ đã vào Côn Ngô Sơn rồi có dấu hiệu gặp nạn vì Nguyên Thần Châu bị nhạt đi. Phong lão quái không thể tự đến cứu nên dùng Phi Kiếm Truyền Thư nhờ Hô và Bạch đi Côn Ngô Sơn, hứa tặng Huyết Khí Đan làm bồi thường. Bạch đạo hữu từ chối vì đang luyện hóa Hỏa Tinh Tảo đã ăn sống để cưỡng ép đột phá bình cảnh, đồng thời bàn với Hô đạo hữu về khốn cảnh phi thăng, Nghịch Linh Thông Đạo và giới hạn của tu sĩ Hóa Thần trong Nhân giới hiện tại. Sau khi bị tiễn khách, Hô đạo hữu vì hai quả Huyết Khí Đan có thể kéo dài thọ nguyên hơn trăm năm nên quyết định tự mình mạo hiểm đi Côn Ngô Sơn. Ở tầng tám Trấn Ma Tháp, Hàn Lập dùng hơn mười khẩu phi kiếm hợp thành cự kiếm chém nát bạch ngọc thạch nhân lần thứ tư, trong khi các tu sĩ tìm cách phá đại trận thạch khôi lỗi gần như bất tử. Khi trận pháp sắp bị phá, Ngân Nguyệt đột nhiên đau đớn trong đầu Hàn Lập và nói trong cung điện dường như có thứ gì thức tỉnh, mang lại cảm giác vừa quen thuộc vừa trọng yếu đối với nàng."},{"chuong":1036,"tieuDe":"Ngân Nguyệt, Tuyết Linh, Lung Mộng","tomTat":"Bên ngoài pháp trận, Hàn Lập chứng kiến linh áp trong cung điện bộc phát, hoàng quang phá đỉnh lao ra hóa thành bàn tay vàng chộp về phía Bát Linh Xích. Một thần bí nhân trong thân xác Hoa Thiên Kỳ xuất hiện, phá đòn đoạt bảo và đánh trọng thương quái nhân đầu to Diệp gia, khiến hắn mất một cánh tay và phải dùng bí thuật thoát thân. Khi thần bí nhân bỏ khăn che mặt, mọi người nhận ra dung mạo Hoa Thiên Kỳ nhưng giọng nói, đồng tử và uy áp đều cho thấy thân thể ông đã bị phụ thể. Ngân Nguyệt từ túi linh thú của Hàn Lập bay ra, hóa thành thiếu phụ áo trắng và bị thần bí nhân gọi là Tuyết Linh. Thần bí nhân tự xưng Lung Mộng, nói nàng và Tuyết Linh vốn là hai nguyên thần tách ra từ Lung nhi do luyện sai bí thuật vô thượng của Ngân Nguyệt tộc, đồng thời hé lộ nguyên thần Tuyết Linh từng bị phân thân Nguyên Sát thánh tổ bức rời thân thể. Ngân Nguyệt nhắc Phệ huyết hồn ấn để khiến Lung Mộng không thể tùy tiện giết mình, nhưng Lung Mộng vẫn đánh bay nàng, buộc Hàn Lập phải ra tay đỡ và dùng Nguyên Cương thuẫn chặn công kích. Ngân Sí Dạ Xoa và Sư Cầm thú nghe các tên Linh Lung, Tuyết Linh thì kinh dị và âm thầm lui về phía truyền tống trận. Cuối chương, Lung Mộng phát hiện khí tức Tuyết Linh trên Hàn Lập rất đậm, suy đoán nàng đã thành linh thú của hắn và châm chọc rằng ngay cả linh giới tam hoàng cũng không dám vọng tưởng chuyện đó."},{"chuong":1037,"tieuDe":"Cửu Chân Phục Ma Trận","tomTat":"Ngân Nguyệt đối chất với Hoa Thiên Kỳ, nói hai bên là một và nhắc tới Lung Linh cùng việc từng áp chế thân thể đối phương ngủ say. Hoa Thiên Kỳ lập tức khống chế cục diện, phá Truyền Tống Trận màu trắng để chặn Ngân Sí Dạ Xoa và Sư cầm thú rút lui, đồng thời nhận ra lai lịch của hai yêu. Bạch bào nho sinh và thanh niên họ Từ đều muốn dùng việc giúp nàng thoát tháp để đổi lấy Bát Linh Xích, nhưng không ai dám tùy tiện lấy bảo khi nàng tỏ vẻ cho phép. Quái nhân đầu to bị vạch từng tiếp xúc phân thân Nguyên Sát thánh tổ, trên người còn dính ma khí và từng định dùng Diệt Hồn Phù đối phó hồn nàng, khiến Hàn Lập chú ý tới mối liên hệ giữa Nguyên Sát và cổ ma Thiên Nam. Mộc phu nhân cảnh báo Hoa Thiên Kỳ có thể là hóa thân cổ ma thánh tổ, dùng Hóa Long Ấn chặn một kích rồi cùng Nữ tử tú lệ dùng Nhật Nguyệt Toa rút đi. Bát Linh Xích sau đó bị kích phát, thất sắc linh quang và tám ảo ảnh linh thú hiện ra, kéo Cửu Chân Phục Ma Trận xuất thế với chín tế đàn và chín cự nhận kim quang. Ma Ảnh hai đầu bốn tay từ ma khí thoát ra liền bị kim sắc đao quang trảm xuống, nhưng một thân ảnh yểu điệu bất ngờ xuất hiện trước Ma Ảnh và dùng ngón tay chống đỡ kim quang."},{"chuong":1038,"tieuDe":"Ma Hiện","tomTat":"Kim quang bị phá mở, nữ tử váy đen xuất hiện bên Ma Ảnh hai đầu bốn tay, khiến Hàn Lập nhận ra cổ ma từng thoát khỏi Trụy Ma Cốc và cảm ứng hai thanh Thanh Trúc Phong Vân Kiếm bị bắt. Ngân Nguyệt vừa thấy nữ tử kia đã kinh hãi, được Hàn Lập đưa sang bên kia Cửu Chân Phục Ma đại trận, rồi tiết lộ thân thể nữ tử ấy chính là thân thể cũ của nàng và Lung Mộng đang bị một luồng tinh hồn Nguyên Sát thánh tổ chiếm giữ. Mộc phu nhân thấy Hóa Long Ấn phản ứng ma khí dữ dội, nhận ra cục diện quá nguy hiểm nên truyền âm với Lâm Ngân Bình và dùng Nhật Nguyệt Toa rút đi, trong khi nhóm Diệp gia âm thầm bố trí hư ảnh che giấu chân thân. Ngân Sí Dạ Xoa nhận ra dung nhan nữ tử váy đen giống Linh Lung tiên tử năm xưa, còn Hàn Lập nhớ Cửu Chân Phục Ma đại trận là pháp trận trừ tà diệt ma hàng đầu Nhân giới. Nữ tử váy đen phá được kim quang của đại trận nhưng vẫn kiêng kị không xông vào, đồng thời chú ý tới Bát Linh Xích đang hiển hóa ngân liên và tám ảo ảnh linh thú. Cổ ma xúi quái nhân đầu to chế trụ Bát Linh Xích để đổi lấy quán ma nhập thể, nhưng Lung Mộng kịp ra tay ngăn lại và cảnh cáo không ai được lấy linh bảo nếu chưa có sự đồng ý của nàng. Cuối chương, nữ tử váy đen triệu Hắc Phong kỳ, nói đã dùng Ma Hóa Thần thông quán chú ma khí để khiến Thông Thiên Linh Bảo tạm thời nghe lệnh, khiến cả không gian chấn động và các tu sĩ đều kinh hãi."},{"chuong":1039,"tieuDe":"Hắc Phong Kỳ","tomTat":"Hàn Lập nhận ra trận chiến trước mắt đã vượt xa cấp Nguyên Anh nên không dám khinh địch, âm thầm sai Khuê Linh độn xuống lòng đất và phát hiện phía sau nhị ma có một Truyền Tống Trận màu đen còn nguyên vẹn. Hắc bào nữ tử dùng Hắc Phong Kỳ cùng Cổ Ma xông vào cấm chế, khiến Cửu Chân Phục Ma Trận phóng kim quang, chín Kim Đao và kim ti công kích nhưng đều bị quang tráo đen cùng hắc động của linh bảo hóa giải. Nhân lúc các phe bị trận chiến thu hút, Hàn Lập lặng lẽ thả mấy ngàn Phệ Kim Trùng từ túi linh thú xuống lòng đất làm bố trí ngầm. Hắc bào nữ tử sau đó đối đáp với Lung Mộng, đề nghị dung hợp nguyên thần nhưng yêu cầu nguyên thần Nguyên Sát làm chủ, còn Lung Mộng kiên quyết cự tuyệt và vạch rõ Hắc Phong Kỳ hiện chỉ được tạm dùng nhờ ma khí. Khi đàm phán thất bại, Hắc bào nữ tử sai Cổ Ma hai đầu bốn tay đến canh Truyền Tống Trận màu đen, phá hỏng ý định thoát thân của Hàn Lập và các phe; Ngân Sí Dạ Xoa cùng Sư Cầm thú cũng dùng thanh quang biến mất. Hàn Lập thi triển Minh Thanh Linh Mục phát hiện nho sinh áo trắng của Diệp gia chỉ là linh khí ảo ảnh, rồi cuối chương phải dựng phòng hộ che chở mình và Ngân Nguyệt trước uy thế hắc phong, mây vàng, lôi điện và đao gió do Hắc Phong Kỳ tạo ra."},{"chuong":1040,"tieuDe":"Thoát Thân","tomTat":"Hàn Lập bị cuốn trong vùng ác phong do Hắc Phong Kỳ gây ra, thần thức vừa ra khỏi vòng bảo hộ đã bị thổi tan, chỉ còn Minh Thanh Linh Mục giúp hắn quan sát lờ mờ gần thân. Hắn cùng Ngân Nguyệt lùi tới góc tường nơi cuồng phong yếu hơn, dùng phi kiếm và Tam Diễm Phiến thử phá bức tường xám nhưng cấm chế phục hồi quá nhanh, còn Tam Diễm Phiến cũng chỉ khoét sâu mà không xuyên thủng. Vì lo phá tường sẽ dẫn động liên hoàn cấm chế và gây động tĩnh khiến Cổ Ma Thánh Tổ chú ý, Hàn Lập nghe lời Ngân Nguyệt, tạm bỏ cách cưỡng phá. Lâm Ngân Bình và thanh niên họ Từ sau đó tìm đến, dựng cách âm kết giới và đề nghị liên thủ đánh lén cổ ma canh Truyền Tống Trận để thoát thân trong lúc Cổ Ma Thánh Tổ còn bị Lung Mộng cầm chân. Hàn Lập cảnh báo cổ ma này từng thoát khỏi vòng vây của ba đại tu sĩ và hơn mười Nguyên Anh kỳ ở Thiên Nam, khiến đối phương nhận ra mức nguy hiểm thật sự. Ngân Sí Dạ Xoa và Sư Cầm Thú cũng hiện thân, cho rằng nếu không rời đi thì yêu thú hay nhân loại đều khó tránh họa, nên cùng xin nhập liên minh tạm thời. Sau khi cân nhắc, Hàn Lập chấp nhận mục tiêu chỉ bức lui cổ ma chứ không diệt sát, rồi dùng bản mạng bài gọi Khuê Linh trở về; sấu phụ xuất hiện sau lưng hắn."},{"chuong":1041,"tieuDe":"Đánh Lén","tomTat":"Khuê Linh hiện ra khiến Hàn Lập kinh ngạc vì nhóm thanh niên họ Từ và Ngân Sí Dạ Xoa truyền âm, nhưng hắn che giấu trước câu hỏi của Lâm Ngân Bình và chỉ nói có người Hóa Tiên Tông đang tìm lối thoát dưới lòng đất. Sau khi thống nhất kế hoạch, Hàn Lập độn xuống đất, thu Ngân Nguyệt vào tay áo, thả khôi lỗi hình người màu bạc ẩn nấp, rồi cầm Tâm Diễm Phiến kích phát Phong Lôi Sí chờ thời cơ. Cổ ma hai đầu bốn cánh đứng trên truyền tống trận màu đen, vừa cảnh giới bốn phía vừa theo dõi cung điện, sau đó bị thanh niên họ Từ và Lâm Ngân Bình hiện thân chính diện kiềm chế. Thanh niên họ Từ dùng Ngọc Tán thanh hàn hóa giải hỏa mãng rồi thả Ngũ Sắc Khổng Tước, khiến cổ ma nhận ra Linh Tê Khổng Tước và dùng tử hoàn cùng ma khí đối kháng ngũ sắc linh quang. Khi cổ ma bị chính diện kéo giữ, hai luồng khói xanh tím từ trên cao đánh xuống, còn Hàn Lập từ dưới trận kỳ xám dùng cự kiếm mang tử hỏa và kim lôi chém lên. Cổ ma nhận ra Hàn Lập, bị thương nặng nhưng nhờ quang tráo đen tránh khỏi nhát chí mạng, rồi lập tức phản kích bằng cự đao đen. Hàn Lập dùng Phong Lôi Sí lôi độn né đòn trong gang tấc, còn cự đao đen của cổ ma cuối chương tách thành hai quang nhận chuẩn bị tiếp tục giao chiến."},{"chuong":1042,"tieuDe":"Trảm Ma","tomTat":"Cổ Ma bỏ qua những đối thủ khác, dồn song đao và ma công truy sát Hàn Lập vì cho rằng hắn tu vi thấp lại đang cô lập, nhưng Hàn Lập đã sớm bố trí Khuê Linh ẩn dưới chân mình. Khi Cổ Ma áp sát, Khuê Linh bất ngờ hiện thân, dùng ngân sắc cự phủ đánh lén, buộc hắn phải chuyển thế đối phó và thi triển ma công cường hóa thân thể, hồi phục thương thế. Hai bên giao phong dữ dội, Khuê Linh thi triển Cự Đại Thuật ép xuống, khiến Cổ Ma không có thời gian hoàn tất bí thuật mạnh hơn. Hàn Lập nhân lúc sơ hở dùng Thất Thần Thứ, bí thuật thần thức cải biến từ Kinh Thần Thứ trong Đại Diễn Quyết, làm Cổ Ma trì trệ trong chớp mắt để phi đao đen vô thanh vô tức chém rụng một đầu của hắn. Cổ Ma tuy chưa chết nhưng đã trọng thương, phải dùng ma khí và độn thuật thoát khỏi thế công, khiến thanh niên họ Từ cùng Ngân Sí Dạ Xoa kinh hãi trước thủ đoạn và sát khí bí ẩn của Hàn Lập. Khi Cổ Ma định chạy về phía nữ nhân áo đen, Hàn Lập tiếp tục dùng ảo thuật, Ích Tà Thần Lôi, cánh độn, tử sắc hỏa giao và mười thanh kim sắc tiểu kiếm để ép sát. Ngay lúc Cổ Ma xoay đầu chống đỡ đòn truy kích, phi đao đen từng chém rụng đầu hắn lại quỷ dị xuất hiện, đẩy trận chiến vào thế nguy hiểm hơn nữa."},{"chuong":1043,"tieuDe":"Thu Hồi Bảo Vật","tomTat":"Hàn Lập thừa lúc Cổ Ma phân tâm để phối hợp phi đao, tử diễm, kim sắc điện hồ và kiếm quang triệt để đánh tan ma khí, khiến nguyên thần Cổ Ma không thể đào thoát. Sau khi bảo vật của Cổ Ma rơi ra, hắn phá hắc ti bao bọc và thu hồi hai thanh Thanh Trúc Phong Vân Kiếm từng mất năm xưa, tuy linh tính hao tổn nhưng vẫn có thể tế luyện khôi phục. Ở truyền tống trận màu đen, thanh niên họ Từ, Ngân Sí Dạ Xoa, Sư Cầm Thú và Lâm Ngân Bình hợp lực công kích màn sáng cấm chế cho đến khi quang tráo rạn vỡ. Khi các bên tranh lượt rút lui, Hàn Lập dùng Tam Diễm Phiến và kim kiếm áp chế cục diện, đề xuất để Lâm Ngân Bình cùng Khuê Linh đi trước, rồi tới Sư Cầm Thú với thanh niên họ Từ, sau cùng là hắn và Ngân Sí Dạ Xoa. Trong cung điện, Hắc bào nữ tử cảm ứng Cổ Ma chết nên phun máu gia trì Hắc Phong Kỳ, làm Cửu Chân Phục Ma trận rạn nứt và Bát Linh Xích khó chống đỡ. Khi Khuê Linh và Lâm Ngân Bình vừa bước vào truyền tống trận, bạch quang lóe lên xuất hiện một bóng người từ ngoài truyền vào. Cùng lúc đó, Hắc bào nữ tử phát động Hỗn độn khai thiên, tạo cột sáng đen chia không gian thành hai nửa sáng tối và phủ bóng đêm lên phía Hàn Lập."},{"chuong":1044,"tieuDe":"Phản Bội","tomTat":"Hắc bào nữ tử dùng không gian thần thông của Hắc Phong kỳ phong kín mảnh không gian nhỏ, khiến nhóm Hàn Lập bị vây và Truyền Tống Trận mất hiệu lực. Hàn Lập kiểm tra pháp trận rồi kết luận trận không hỏng, chỉ bị không gian chi lực phong trụ, nên muốn rời đi phải phá không gian hoặc chờ chủ nhân Hắc Phong kỳ buông cấm chế. Bên ngoài, hắc bào nữ tử nhận định Cửu Chân Phục Ma đại trận gần như bị hủy, Bát Linh Xích không người điều khiển nên chỉ còn dựa vào linh tính tự thân. Ả gọi quái nhân đầu to là Diệp đạo hữu, ép hắn đi lấy Bát Linh Xích, rồi dùng đòn vô hình hủy thân thể hai tu sĩ Diệp gia và lấy ma khí tăng thọ nguyên làm lợi dụ. Tu sĩ mặt chữ điền cứu hai Nguyên Anh đồng tộc, còn quái nhân đầu to cuối cùng cắn răng bay về phía Bát Linh Xích. Lung Mộng từ trong cung điện ngưng tụ cự quyền ngăn hắn nhưng bị hắc bào nữ tử đánh tan. Bạch bào nho sinh vốn ẩn thân tiếp tục phóng Hắc Huyết Nhận chặn đường, chém nứt hoàng sắc cự kiếm của quái nhân đầu to. Hắc bào nữ tử phát hiện vị trí bạch bào nho sinh và bắn trúng ngực hắn đúng chỗ trái tim, nhưng hắn hiện hình mà không tỏ vẻ bị trở ngại."},{"chuong":1045,"tieuDe":"Thôn Anh","tomTat":"Bạch bào nho sinh dùng Hắc Huyết Nhận truy kích Quái nhân đầu to, gọi đối phương là Thất thúc nhưng công khai kết tội đã cấu kết Cổ Ma thánh tổ và vứt bỏ Diệp gia. Hắc bào nữ tử ra tay tập kích nho sinh bằng năm đạo mũi nhọn trong suốt, song Lung Mộng từ trong cung điện tạo bàn tay trắng lớn phá giải và vạch rõ Nguyên Sát khó phá cấm chế Bát Linh Xích vì bị phật tông linh bảo trấn áp nhiều năm. Nguyên Sát kích hoạt Hắc Phong Kỳ, dùng hắc phong trụ và phong nhận phá cốt hoàn, khiến tu sĩ mặt chữ điền dù nhân kiếm hợp nhất vẫn bị phân thây. Ba Nguyên Anh vừa thoát ra liền bị nàng bắt thành quang cầu, phun huyết hà ép nhỏ rồi nuốt vào bụng, khiến Bạch bào nho sinh cứu viện không kịp. Lung Mộng từ chối trách nhiệm cứu người Diệp gia, khẳng định nàng chỉ liên thủ với cá nhân nho sinh, đồng thời giải thích việc thôn phệ Nguyên Anh chỉ tăng pháp lực tạm thời nhưng tiêu hao ma khí rất lớn. Nguyên Sát vẫn chọn hao tổn ma khí để vận dụng thân thể Ngân Lang Hóa Thần kỳ hậu kỳ của Lung Mộng, cuối cùng hiện thành cự lang hai đầu to như núi, khiến cả Bạch bào nho sinh lẫn Quái nhân đầu to kinh hãi."},{"chuong":1046,"tieuDe":"Huyết Nhận Tái Hiện","tomTat":"Khi hắc bào nữ tử đang hiển lộ Ngân Lang yêu thể ở nơi khác, nhóm Hàn Lập, Khuê Linh, thanh niên họ Từ và Lâm Ngân Bình vây được Tứ tán chân nhân, còn Ngân Sí Dạ Xoa và Sư cầm thú đứng xa quan sát. Lâm Ngân Bình chỉ ra hắn từng ẩn nấp gần nàng, còn Hàn Lập vạch việc hắn từng ám toán mình khi vào Trấn Ma Tháp, liên hệ hắn với Bính Huyết Nhận, huyết khí hung thần và nghi vấn thôn phệ các tu sĩ Nguyên Anh đi cùng. Hàn Lập ra tay bằng Phong Trúc Vân Kiếm, chém hỏng lam sắc phi kiếm và đồng thuẫn của Tứ tán chân nhân, trong khi Khuê Linh và thanh niên họ Từ chặn các hướng bỏ chạy. Bị ép đến cùng, Tứ tán chân nhân xuất ra huyết nhận đỏ như máu, đánh bật kim kiếm và bị Hàn Lập nhận ra là phỏng chế Ma Long Nhận, khiến mọi người động dung. Sau khi thấy phi kiếm của mình không tổn hại, Hàn Lập đổi ý không giết hắn mà đề nghị tận dụng uy lực huyết nhận để cùng phá không gian do Hắc Phong Kỳ duy trì, nhân lúc Nguyên Sát thánh tổ đang phân tâm. Thanh niên họ Từ và Ngân Sí Dạ Xoa đồng ý thử, Tứ tán chân nhân cũng nhận lời sau khi được bảo đảm tạm không bị tính sổ. Trong lúc bàn phối hợp, thanh niên họ Từ ép Hàn Lập gọi người ẩn thân bên cạnh ra hỗ trợ nhưng Hàn Lập từ chối bằng lý do công pháp đặc thù. Cuối chương, Tứ tán chân nhân âm thầm truyền âm cho kẻ chưa rõ và mu bàn tay mọc dày bạch mao cứng như kim châm mà không ai hay biết."},{"chuong":1047,"tieuDe":"Đột Ngột Phá Chướng Bích","tomTat":"Tứ Tán chân nhân thoáng để lộ bạch mao trên tay rồi che giấu, cùng lúc Đề Hồn thú trong túi linh thú của Hàn Lập bất an khiến hắn sinh nghi. Để phá chướng bích, mọi người bố trí trận kỳ, trận bàn; Hàn Lập và thanh niên họ Từ cùng chủ trì Phong Viêm Long Liệt trận, tạo Phong Hỏa Giao phối hợp các pháp bảo và thần thông đánh vào một điểm. Hàn Lập tiếp tục dùng Thanh Trúc Phong Vân Kiếm kèm Ích Tà Thần Lôi chém vào khe nứt, khiến hiệu quả phá vách vượt xa công kích của những người khác và làm hắn nghi Hắc Phong kỳ có bản chất ma đạo linh bảo. Khi hắc sắc phi đao phá tầng cuối cùng, lỗ thủng vài trượng mở ra; Hàn Lập cho nhân hình khôi lỗi lao ra trước, đồng thời nhắc Khuê Linh chậm lại nên nàng tránh được đợt phục kích đầu. Bên ngoài chướng bích lập tức bùng lên huyết quang, hắc ti và huyết hải, nhóm đi trước bị chia cắt và áp chế. Quái vật lông trắng mặc trang phục Tứ Tán chân nhân hiện thân, thao túng huyết nhận vây thanh niên họ Từ khiến ông mất một tay một chân; Linh Tê Khổng Tước bị Sư Cầm Thú vây, còn Lâm Ngân Bình bị Ngân Sí Dạ Xoa dùng Sát Hồn Ti công kích. Khuê Linh thuấn di đến bên Hàn Lập, nhận ra quái vật lông trắng và kinh hãi kêu lên."},{"chuong":1048,"tieuDe":"Điều Kiện","tomTat":"Khuê Linh nhận ra bạch mao luyện thi vốn từng là linh thú Linh giới có giao tình với nhóm của nàng, nhưng vì ký ức Linh giới của nàng đã bị xóa nên không thể giải thích vì sao nó trở thành luyện thi. Hàn Lập thất vọng vì không khai thác được tin tức Linh giới, đồng thời nghĩ tới khả năng Ngân Nguyệt còn giữ chút ký ức liên quan. Sau khi ra khỏi vách chắn, hắn thấy Bát Linh thước và Hắc Phong kỳ biến mất, cung điện bị phá hủy nặng, còn truyền tống trận vẫn bị cấm chế ngăn nên phải cân nhắc đường thoát khác. Lâm Ngân Bình cầu Hàn Lập cứu mình và thanh niên họ Từ bằng lời hứa hóa giải ân oán với Thiên Lan thánh điện, nhưng Hàn Lập lạnh nhạt từ chối và không sợ lời uy hiếp về ba đại tiên sư Thiên Lan. Hàn Lập hồi tưởng mình đã phát hiện âm mưu của Vạn Năm Thi Hùng và Ngân Sí Dạ Xoa nhờ Đề Hồn thú cùng thần thức mạnh, rồi suy đoán bạch mao luyện thi chính là Vạn Năm Thi Hùng của Vạn Yêu Cốc. Hắn định chờ thanh niên họ Từ chết để cướp huyết nhận, nhưng thanh niên họ Từ bất ngờ đem bí quyết chuyển hóa Phệ Kim trùng thành thục thể sau cùng ra làm điều kiện cứu mạng. Vạn Năm Thi Hùng thấy Hàn Lập trầm ngâm liền dốc sức thúc huyết nhận hóa mặt quỷ, nuốt ngân câu và thanh sắc viên châu, đẩy thanh niên họ Từ tới mức nguyên anh chuẩn bị bỏ thân chạy trốn."},{"chuong":1049,"tieuDe":"Linh Cầm Cùng Nguyên Anh","tomTat":"Một đạo kim hình cung từ ngoài đánh lên mặt quỷ, khiến nó tiêu tán phân nửa, nhưng phần còn lại vẫn cắn vào thanh niên họ Từ và dùng huyết quang ăn mòn thân thể hắn. Họ Từ buộc phải bạo liệt thân xác để Nguyên Anh thuấn di thoát ra, rồi suýt bị Vạn Năm Thi Hùng dùng hắc khí đại thủ bắt giữ. Nhân hình khôi lỗi của Hàn Lập xuất hiện phá hắc thủ, tạo cơ hội cho Nguyên Anh họ Từ chạy tới Linh Tê Khổng Tước; linh cầm dùng ngũ sắc linh quang phá tử vụ, há miệng tiếp nhận Nguyên Anh và hiện khuôn mặt hư ảnh của chủ nhân. Ở chiến trường khác, Khuê Linh hiện thân, truyền âm khiến Ngân Sí Dạ Xoa thu Sát hồn ti, rồi dùng cự phủ chém đứt cẩm khăn của Lâm Ngân Bình và bắt sống nàng. Hàn Lập dùng Lâm Ngân Bình làm bảo đảm để buộc họ Từ trả lời câu hỏi, đồng thời đối mặt Vạn Năm Thi Hùng để tạm mang hai người Thiên Lan đi. Thi Hùng nhận ra Hàn Lập là tu sĩ Thiên Nam, cảnh cáo hắn không được phá việc của Vạn Yêu cốc lần nữa, sau đó thu huyết hải vào huyết sắc cự nhận và dẫn Ngân Sí Dạ Xoa, Sư Cầm thú rút về hướng cung điện."},{"chuong":1050,"tieuDe":"Thánh Thú Chi Ấn","tomTat":"Hàn Lập truy hỏi thanh niên họ Từ về cách Thiên Lan thánh điện thúc đẩy Phệ Kim Trùng tiến tới thành thục thể. Thanh niên họ Từ trao ngọc giản bí quyết, giải thích phương pháp này dùng thiên địa chi lực quán chú ngũ hành linh khí vào linh trùng, do một trưởng lão am hiểu trùng thuật của thánh điện nghiên cứu hơn một ngàn năm. Sau khi xem pháp quyết, Hàn Lập hiểu bí quyết chỉ rút ngắn thời gian chứ chưa thể lập tức tạo thành thục thể, nhưng vẫn có giá trị rất lớn với đàn trùng của hắn. Giao dịch vừa xong, Hàn Lập trở mặt, hiện Phong Lôi Sí và kim sắc lôi y, đồng thời cho khôi lỗi tập kích phía sau khổng tước linh để ép nguyên anh họ Từ. Nguyên anh họ Từ rời khỏi linh cầm, cầu hòa và nhắc rằng Hàn Lập nay đã đủ tư cách ngồi ngang hàng với Thiên Lan thánh điện. Hắn đề xuất để thánh nữ triệu hoán chân linh Thiên Lan thánh thú, ký Thánh thú chi ấn với Hàn Lập, mời Hàn Lập làm khách khanh trưởng lão, đổi lại Hàn Lập trả thánh thú phân thân. Hàn Lập biết ấn này ràng buộc đôi bên không được sinh sát tâm, nếu vi phạm sẽ chịu thượng cổ nguyền rủa trớ chú, nên tạm thời cân nhắc đề nghị."},{"chuong":1051,"tieuDe":"Sất Niệm Chân Lôi","tomTat":"Hàn Lập từ thế áp đảo nói rõ hắn không sợ Thiên Lan thánh điện, nhưng cũng không muốn vướng vào thánh thú chi ấn hay nội vụ của họ. Hắn đồng ý sẽ trả thánh thú phân thân song không trả ngay, đồng thời yêu cầu thanh niên họ Từ và Lâm Ngân Bình phải để hắn hạ Sất Niệm Chân Lôi vào Nguyên Anh. Thanh niên họ Từ kinh sợ từ chối, nhưng Hàn Lập dùng lời đe dọa, Tam Diễm Phiến, Khuê Linh và nhân hình khôi lỗi để ép hắn khuất phục. Hàn Lập thi triển bí thuật, đưa quang đoàn chứa linh quang ngũ sắc vào Nguyên Anh thanh niên họ Từ, khiến đối phương không dò ra dấu vết và càng sợ đặc tính tụ tán vô hình của Sất Niệm Chân Lôi. Sau đó Hàn Lập cũng gieo cấm chế vào Lâm Ngân Bình đang hôn mê, rồi nói chỉ cần họ ở Côn Ngô Sơn nghe lời trợ giúp thì ra ngoài có thể mỗi bên tự đi. Lâm Ngân Bình tỉnh lại liền phòng bị, nhưng được thanh niên họ Từ truyền âm cho biết bản thân đã bị chế nên lộ vẻ kinh hoảng. Ngay lúc Hàn Lập định nói tiếp, vách tường nơi mọi người từng bị nhốt bị kiếm khí xuyên thủng, Thất Diệu chân nhân và Huyền Thanh Tử phá vách xuất hiện, khiến cục diện lại chuyển biến."},{"chuong":1052,"tieuDe":"Không Gian Toái Liệt","tomTat":"Trước câu hỏi của Huyền Thanh Tử, Thanh niên họ Từ hiện khuôn mặt trên đầu Linh Tê khổng tước và nói thân thể mình đã bị hủy, hiện chỉ còn nguyên thần tạm nương nơi linh cầm. Ông xác nhận cổ ma thánh tổ đã thoát vây, nhưng kẻ phá hủy thân thể mình là Thi hùng Vạn Yêu Cốc nhờ dùng biến hóa che giấu thi khí để ám toán; Thất Diệu chân nhân nhân đó nhắc tới Mê Hình Châu của Cốc chủ Vạn Yêu Cốc. Hàn Lập giới thiệu Khuê Linh, tự xưng là tán tu rồi hỏi cách Huyền Thanh Tử và Thất Diệu chân nhân vào tầng tám, qua đó biết họ dùng Phá Giới Phù phối hợp Thiên A Thần Kiếm chứ không qua truyền tống trận. Khi Kiền lão ma và Âm La Tông được hỏi tới, Hàn Lập nói đã chia tay Kiền lão ma ở điện Côn Ngô, còn Thanh niên họ Từ cho biết nhóm Cát đạo hữu Âm La Tông đã bị Diệp gia đại trưởng lão tập kích đến ngã xuống. Huyền Thanh Tử kêu gọi mọi người hợp tác đối phó Diệp gia và cổ ma vì chuyện này liên quan toàn bộ tu tiên giới, nhưng Lâm Ngân Bình và Thanh niên họ Từ đều dè dặt vì đang bị Hàn Lập hạ cấm chế. Ngay lúc Hàn Lập định nói về cổ ma, cung điện phát nổ, ánh sáng chuyển đen, mặt đất nứt và không gian tầng tám rung chuyển dữ dội; Thất Diệu chân nhân nhận ra cổ ma thánh tổ đang mở phong ấn tầng thứ chín. Trước khe không gian lan tới, Hàn Lập tế Nguyên Cương Thuẫn hộ thân rồi dùng hỏa hồng vật biến thành nửa người nửa giao long, nhưng khe đen vẫn xuất hiện ngay trước mắt khiến hắn khó tránh khỏi nguy cơ bị nuốt vào bóng tối."},{"chuong":1053,"tieuDe":"Đệ Cửu Tầng","tomTat":"Sau biến cố không gian thôn phệ, Hàn Lập bình tĩnh vận pháp lực, chuẩn bị dùng Nguyên Cương Thuẫn tự bảo vệ và nhận ra mình đã bị chuyển đến tầng thứ chín. Trong không gian độc lập này có tế đàn ngọc trắng khổng lồ, siêu trận bằng thạch trụ phát quang và cự lang hai đầu của Nguyên Sát thánh tổ đang chiếm giữ đỉnh tế đàn. Hoa Thiên Kỳ, đại trưởng lão Diệp gia, Vạn Năm Thi Hùng, Ngân Sí Dạ Xoa, Mộc phu nhân cùng nhiều người khác vây công cự lang nhưng bị hắc ma khí áp chế, còn nữ tử tú lệ Hóa Tiên Tông bị hắc khí mê hoặc và trợ giúp cự lang. Hàn Lập nhận ra Hắc Phong Kỳ cùng Bát Linh Thước đang giao phong, rồi phát hiện hai bia đá sau lưng cự lang có vật liệu giống Sất Linh Nhuyễn Ngọc và một ấn tỳ lục sắc hô ứng với trận pháp. Mộc phu nhân cảnh báo cổ ma thánh tổ đang cố giải trừ phong ấn cấm chế trên tế đàn, khiến Huyền Thanh Tử và Thất Diệu chân nhân lập tức ra tay. Thất Diệu phóng Thất Chân Bảo, Huyền Thanh Tử dùng cổ kiếm kích phát kiếm khí lớn, nhưng cả linh hà lẫn kiếm khí đều bị hắc ma khí hóa giải. Khi Huyền Thanh Tử quyết định hộ pháp để Thất Diệu dùng bảo vật khác, hắc ma khí cuộn lên không trung và Hàn Lập phóng hơn mười khẩu kim sắc phi kiếm đánh tan luồng ma khí đang áp sát."},{"chuong":1054,"tieuDe":"Cấm Ma","tomTat":"Quanh tế đàn tầng thứ chín, các bên đều bị ma khí do cự lang Nguyên Sát Thánh Tổ điều khiển giữ chân. Hàn Lập quan sát Bát Linh Xích và Hắc Phong Kỳ, nhận ra hai linh bảo tuy ở trạng thái bất toàn nhưng vẫn bị quá nhiều cường giả chú ý nên không thể tùy tiện tranh đoạt. Hắn thử dùng thần niệm dò xét tế đàn nhưng bị cấm chế bắn ngược, sau đó phát hiện đàn Phệ Kim Trùng đã tới dưới lòng đất tầng chín và âm thầm lệnh cho chúng tản ra. Vạn Niên Thi Hùng và Lung Mộng Yêu Phi thử phá cột đá quanh tế đàn nhưng hầu như không hiệu quả, trong khi cự lang tiếp tục dựa vào ma khí từ khe hở phong ấn để áp chế mọi người. Dưới sự yểm hộ của Huyền Thanh Tử, Thất Diệu chân nhân thi triển Cấm Ma Hoàn, dùng năm vòng xanh khóa cổ và tứ chi cự lang khiến ma khí tạm mất điều khiển. Khi áp lực ma khí suy yếu, liên minh chống cổ ma lập tức rạn vỡ vì các cường giả chuyển sang tranh đoạt Bát Linh Xích và Hắc Phong Kỳ. Hàn Lập liên tưởng Cấm Ma Hoàn với Ngũ Hành Hoàn từng lấy được ở Hư Thiên Điện, rồi nhìn cự lang bị trói và phóng hơn mười khẩu tiểu kiếm vàng ra khỏi tay áo."},{"chuong":1055,"tieuDe":"Xích Minh Cổ","tomTat":"Hàn Lập truyền âm hỏi Ngân Nguyệt về cách đoạt lại thân thể, rồi hợp phi kiếm thành kim sắc cự kiếm để nàng lấy thân khí linh bám lên, chuẩn bị chém hắc thủ và nhập vào lang thể. Cự lang lộ ra đã giả vờ bị Cấm Ma Hoàn khống chế, né cự kiếm, hút ô quang ma hóa thân thể rồi phun gợn sóng đen phá nát Ngũ Thúy Hoàn. Khi cự kiếm bị ma khí vây, Hàn Lập kích phát lượng lớn Ích Tà thần lôi phá ma khí và cứu kiếm trở về. Cự lang tiếp tục vung trảo mang xuyên hư không chém thân Mộc phu nhân, rồi dùng ma khí hóa hắc sắc đại thủ bắt Nguyên Anh của bà. Huyền Thanh Tử mất bình tĩnh, dồn pháp lực vào Thiên A thần kiếm tạo kiếm sơn cứu người, trong khi Hoa Thiên Kỳ do Lung Mộng phụ thể và Vạn Năm Thi Hùng cũng hợp công. Thất Diệu Chân Nhân lấy Xích Minh Cổ ra, làm hỏa linh lực bốc lên mạnh và mời Hàn Lập phối hợp dùng Ích Tà thần lôi đánh ma khí. Cuối chương, cự lang phun hai vật đen hóa thành hai ma vật cánh ưng, chúng phá thạch trụ rồi lao tới tấn công Ngân Sí Dạ Xoa cùng Sư Cầm Thú bằng đao mang đen."},{"chuong":1056,"tieuDe":"Chân Ma Chi Khí","tomTat":"Ngân Sí Dạ Xoa và Sư Cầm Thú lần lượt đánh tan hai ma vật do ma khí ngưng tụ, nhưng chúng lập tức tái sinh và tiếp tục dây dưa, khiến nhị yêu không thể rảnh tay phá hủy các thạch trụ quanh Tế Đàn. Lung Mộng nhận ra đây là thân ngoại hóa thân do phân thần Nguyên Sát Thánh Tổ tạo ra để trì hoãn thời gian, trong khi Ma Hồn trong thân ngân lang đang hấp thu ma khí tinh thuần để cưỡng ép ma hóa thân thể. Nàng quyết định thi triển bí thuật chui vào thân ngân lang, tranh đoạt quyền khống chế với Ma Hồn nhằm tạo ra một khoảnh khắc sơ hở cho Vạn Niên Thi Hùng ra tay. Trong lúc trao đổi, Lung Mộng tiết lộ thứ bị phong ấn dưới Tế Đàn rất có thể là Chân Ma Chi Khí đến từ Cổ Ma giới, một loại ma khí đáng sợ đủ sức ma hóa tu sĩ thượng cổ và lâu dài biến đổi cả Nhân Giới. Nàng cũng giải thích Côn Ngô sơn từng được dùng làm nơi trấn áp Chân Ma Khí nhờ linh mạch dồi dào, đồng thời buộc Thi Hùng tiếp tục hộ pháp nếu còn muốn nhờ nàng tìm nghịch linh thông đạo trở về Linh Giới. Ở phía khác, Hàn Lập dùng Ích Tà Thần Lôi tiêu diệt ma khí nhưng cự lang vẫn phun ra hắc khí áp đảo công kích của chúng tu sĩ. Khi các thạch trụ quanh Tế Đàn phát sáng, hiện ký hiệu thượng cổ và rung động dữ dội, Thất Diệu chân nhân cảm thấy đại họa sắp tới, liền tế tiểu cổ đỏ đậm và thúc Huyền Thanh Tử mau lấy bảo vật đã chuẩn bị ra."},{"chuong":1057,"tieuDe":"Tam Bảo Liên Thủ","tomTat":"Cổ kiếm không thể nhanh chóng phá tan ma khí, Huyền Thanh Tử lo nguyên anh Mộc phu nhân nguy cấp nên lấy ra Bình Sơn Ấn, một pháp bảo phỏng chế Thông Thiên linh bảo từng xuất hiện tại hội đấu giá dưới lòng đất. Thất Diệu chân nhân cũng thúc giục Xích Minh Cổ, ngưng tụ hồng quang thành hồng nhật luân, cùng Bình Sơn Ấn hóa thành cự sơn hợp kích cự lang trên tế đàn. Phân thân Cổ Ma thánh tổ trong thân cự lang không hề nao núng, phun ra hắc sắc quang cầu hút sạch ma khí xung quanh rồi ngạnh kháng hai món bảo vật, thậm chí dần ép lùi hoàng quang và hồng quang. Thấy hai người kia nếu bại thì mình cũng khó thoát, Hàn Lập quyết định ra tay, âm thầm điều nhân hình khôi lỗi tới gần rồi dốc gần hết linh lực thúc động Tam Diễm Phiến. Tam sắc hỏa điểu nhập vào chiến đoàn khiến uy lực tam bảo hợp nhất bùng lên, lập tức đảo ngược thế cục và đẩy hắc quang trở lại về phía cự lang. Sau một kích tiêu hao quá lớn, Hàn Lập lập tức uống linh dịch để khôi phục linh lực, nhưng cự lang trong ô mang bất ngờ phát động Thiên Lang Toản đánh trúng ngân sắc quang tráo, khiến hắn bị đánh bay. Khi đòn tập kích tiếp tục ập tới, nhân hình khôi lỗi kịp hiện ra chắn trước Hàn Lập, nhưng bị hai thanh đoản nhận quái dị găm sâu vào ngực và đan điền."},{"chuong":1058,"tieuDe":"Ma Tượng","tomTat":"Hàn Lập bị Thiên Lang Toản đánh văng và xuyên phá nhiều tầng phòng hộ, nhưng nhờ nội giáp, chiến giáp Phệ Kim Trùng và thân thể rèn bởi Minh Vương Quyết tầng thứ nhất nên tránh bị xuyên thủng đan điền. Hắn bắn quái nhận bạc khỏi bụng, nhận ra đó là lang trảo của Thiên Lang Toản, đồng thời điều khiển hình nhân khôi lỗi nhổ ngân nhận và tự khép vết thương. Ngân Nguyệt giải thích hắc bào nữ tử đang mặc ma giáp do chân ma khí ngưng kết, rồi thừa nhận ký ức trước kia của nàng đang dần thức tỉnh. Hắc giáp nữ tử dẫn động bia đá khảm Hóa Long Tỷ và ma khí dưới tế đàn, triệu hồi một ma tượng đen khổng lồ được nhận ra là Nguyên Sát thánh tổ. Ma tượng dùng Khoa Không Thần Niệm hiện thân, phá thế áp chế của tam bảo và nghiền vỡ hai kiện phỏng chế Thông Thiên Linh Bảo khiến Huyền Thanh Tử, Thất Diệu chân nhân cùng mọi người kinh hãi. Sau khi đối thoại với hắc giáp nữ tử về quan hệ cùng bản nguyên và cái giá triệu hồi, ma tượng lập tức ra tay, búng ma chỉ khiến Sư cầm thú tự bạo."},{"chuong":1059,"tieuDe":"Ma Uy Vô Song","tomTat":"Ngân Sí Dạ Xoa thấy Ma Tượng ra tay thì kinh hãi dùng phong độn bỏ chạy, nhưng bị phá độn, trói cánh rồi bị ma diễm thiêu thành tro, nguyên thần cũng không kịp thoát. Sau khi liên tiếp cường giả cấp Nguyên Anh hậu kỳ bị diệt, đám tu sĩ và yêu vật xác nhận Ma Tượng là tồn tại không thể chống lại nên tản ra chạy trốn; Hàn Lập dùng lôi độn tránh hiểm thì nhận truyền âm của Lung Mộng trong thân Hoa Thiên Kỳ, yêu cầu thả Tuyết Linh để dung hợp thành Linh Lung. Ma Tượng tiếp đó nhắm vào Linh Tê Khổng Tước, phá ngũ sắc linh quang, bóp nổ bản thể Khổng Tước và khiến Nguyên Anh thanh niên họ Từ tự bạo. Ngân Nguyệt tự quyết định mạo hiểm dung hợp nguyên thần với Lung Mộng, hóa thành chồn bạc rời tay áo Hàn Lập bay tới Hoa Thiên Kỳ. Ma Tượng luyện ngũ sắc linh hà thành ngũ sắc linh châu, giao hắc giáp nữ tử tìm cách truyền về Cổ Ma giới. Sau cùng Ma Tượng chuyển mục tiêu sang Hàn Lập; Hàn Lập dựng nhiều tầng phòng ngự bằng khôi lỗi, Thanh Trúc Phong Vân Kiếm, Ích Tà Thần Lôi, Tam Diễm Phiến, Kim Cương Tráo và Minh Vương Quyết, nhưng kim liên cùng Kim Cương Tráo nhanh chóng bị công kích vô hình xuyên phá."},{"chuong":1060,"tieuDe":"Ngao Khiếu Lão Tổ","tomTat":"Thần niệm Nguyên Sát Thánh Tổ áp súc thành viên châu nhũ trắng, phá vỡ phòng ngự của Hàn Lập và buộc hắn dùng Tam Diễm Phiến cùng Hư Thiên Đỉnh chống đỡ. Ma tượng tiếp tục dùng ma chưởng đen trấn áp, phong tỏa Phong Lôi Sí và bắt nát hóa thân, nhưng Hàn Lập nhờ Hóa Linh Phù thế mạng rồi lôi độn thoát khỏi một kiếp. Khi Hàn Lập chuẩn bị liều mạng lần nữa, một nữ tử tóc bạc áo trắng xuất hiện, đánh tan công kích của ma tượng và khiến hắn nhận ra đó là Ngân Nguyệt. Nàng tự xưng là Linh Lung, đại công chúa bộ tộc Ngân Nguyệt, đồng thời cảnh cáo Hàn Lập không được gọi nàng bằng tên cũ. Nguyên Sát nhận ra Linh Lung có liên quan đến Ngao Khiếu yêu vương, còn Linh Lung xác nhận Ngao Khiếu là gia tổ, khiến ma tượng tỏ ra kiêng kị nhưng vẫn không dừng tay. Sau cùng Linh Lung dùng Nghịch Tinh Bàn hút sạch tinh mang công kích của ma tượng, làm Nguyên Sát thất thanh nhận ra bảo vật chỉ tầng cao như Tứ đại yêu vương và Tam Hoàng mới có tư cách sở hữu."},{"chuong":1061,"tieuDe":"Đại Chiến Tái Khởi","tomTat":"Nguyên Sát thánh tổ dùng thần niệm hóa thành người khổng lồ trong suốt, uy hiếp Linh Lung rồi tung tinh trụ công kích, nhưng hơn mười cột đá quanh tế đàn bất ngờ tắt linh quang khiến nguồn hắc ma khí bị cắt. Thân thể tinh hóa của Nguyên Sát vỡ nát và thần niệm tan biến khỏi giới này, song nửa đoạn tinh trụ còn lại vẫn xuyên qua Nghịch Tinh Bàn, đả thương bụng dưới Linh Lung trước khi nàng dùng ngân quang khôi phục. Phân thân Nguyên Sát kiểm tra nền cột đá, phát hiện dấu cắn phá và nhận ra Phệ Kim Trùng là tác nhân làm trận pháp tạm dừng. Khi phe tu sĩ muốn thừa cơ diệt ma, nữ tử giáp đen đặt tay lên Hóa Long Tỳ trên bia đá, khiến hắc mang, ma phong và trụ khí đen tái khởi toàn bộ trận pháp. Huyền Thanh Tử, Vạn Niên Thi Hùng, Thất Diệu chân nhân, Khuê Linh và Lâm Ngân Bình đồng loạt công kích, còn hai hóa thân ma vật cánh ưng phản kích làm đại chiến quanh tế đàn bùng phát lần nữa. Trong lúc đó, Linh Lung yêu cầu Hàn Lập cho mượn Hư Thiên Đỉnh để lấy phân thân Thiên Lan thánh thú làm thân thể tạm thời, nhưng Hàn Lập cảnh giác với trạng thái xa lạ của nàng và dứt khoát từ chối. Linh Lung nổi sát ý với Hàn Lập, nhưng đúng lúc ấy từ hướng tế đàn truyền ra sát khí mạnh và một ma vật ba đầu sáu tay khổng lồ mơ hồ hiện hình trong ma khí."},{"chuong":1062,"tieuDe":"Già Luân Chiến Ma","tomTat":"Linh Lung vừa thấy ma vật xuất hiện liền biến sắc, thúc Hàn Lập cho mượn Hư Thiên Đỉnh vì cho rằng nếu không sẽ không ai cản nổi nó. Cự ma trong sương đột ngột tập kích Huyền Thanh Tử bằng cột sáng đen và Tam thủ Ma Ảnh, khiến lão đạo dù dùng cổ kiếm, độn quang, bát quái kính và ngọc bội hộ thân vẫn bị diệt sát, pháp bảo cùng nguyên anh dường như cũng biến mất. Sau một kích tiêu hao nguyên khí, cự ma suy yếu nên Thi hùng, văn sĩ trung niên và nhóm tu sĩ lập tức vây công. Linh Lung phát hiện chân thân Nguyên Sát Thánh Tổ vẫn ở tế đàn, còn Hàn Lập xác nhận khí linh Ngân Nguyệt trong phi kiếm vẫn liên hệ với mình và dùng kim sắc lôi điện phá hiện các cột hắc khí chỉ như ảo ảnh. Nguyên Sát tiết lộ Thiên Luân Hóa Ma đại pháp, Chân Ma Khí, ma giáp và hóa thân đã được dùng để tạo Già Luân Chiến Ma chưa hoàn chỉnh nhưng có một kích ngang Hóa Thần kỳ. Cự ma sau đó đổi hình thành ba ma dung hợp, chiến giáp đen bao phủ toàn thân, sáu tay cầm sáu binh khí lao vào nhóm Thất Diệu chân nhân. Trên tế đàn, Nguyên Sát tuyên bố chỉ cần phá phong ấn thì Nhân Giới sẽ không thể tiếp tục giam Chân Ma Khí và sớm muộn thành một phần Cổ Ma Giới. Ma khí quanh tế đàn bị hút vào đầu lâu đen có ngũ sắc linh quang, Hắc Phong kỳ hóa thành phong cầu ma khí nguy hiểm, khiến Hàn Lập sai khôi lỗi bắn ô mang để ngăn chặn."},{"chuong":1063,"tieuDe":"Lốc Xoáy","tomTat":"Hàn Lập bắn phi đao Hắc Tuỷ Toản vào phong cầu quấy nhiễu Hắc Phong kỳ khiến lốc xoáy đen rung mãnh liệt, phong cầu như sắp nổ tung. Hắc giáp nữ tử giáng linh áp định giết Hàn Lập nhưng bị Linh Lung ra tay chặn cứu. Hắc giáp nữ tử bỏ thân giáp hoá thành hắc lang hai đầu chui vào phong cầu, dùng vật dạng keo vây khốn phi đao khiến Hàn Lập mất khống chế. Hàn Lập kích phát toàn bộ Ích Tà Thần Lôi trong Thanh Trúc Phong Vân Kiếm ngưng thành kim sắc điện giao dài hơn hai mươi trượng, đánh tan quang cầu ma khí nhưng bị hắc lang phun hai cột sáng đỏ từ thân thể Ngân Lang chặn lại. Hắc lang dung hợp mọi lốc xoáy thành đại lốc xoáy hơn mười trượng, phun quang mang đen bao lấy Hắc Phong kỳ quyết kích nổ Thông Thiên Linh Bảo phá phong ấn. Bát Linh Thước cảm ứng nguy hiểm, tự biến về nguyên hình bắn lên trời biến mất. Linh Lung phun Nghịch Tinh Bàn đối kháng, Hàn Lập cùng đồng bọn đào tẩu, riêng Thất Diệu Chân Nhân bị ma vật ba đầu thuấn di quấn chặt không rời xa được tế đàn."},{"chuong":1064,"tieuDe":"Hắc Động","tomTat":"Linh Lung khống chế Nghịch Tinh Bàn phóng tinh quang vàng nghi binh tấn công quái lang hai đầu, thực chất mượn lực giải phóng Hướng Chi Lễ khỏi Không gian huyền diệu. Hướng Chi Lễ ngưng tụ thành hình phía sau lốc xoáy, hoảng hốt phun lệnh tiễn biến hỏa thú phản kích. Quái lang hai đầu phóng quang trụ đen vào Hắc Phong Kỳ, biến lốc xoáy thành hắc động đường kính gần một xích rồi dịch chuyển lên tế đàn nổ tung, vô số khe không gian bùng nổ chém giết tứ phía. Thất Diệu Chân Nhân ở gần tế đàn nhất, bị khe hở chém thân thể thành nhiều khúc, nguyên anh chạy trốn cũng bị nuốt — tử vong. Khuê Linh bị khe không gian nuốt biến mất, Hàn Lập kiểm tra bổn mạng yêu bài xác nhận nàng đã chết. Hàn Lập bị nhiều khe hở bao vây, chủ động lao về phía khe nhỏ, dùng Hư Thiên Đỉnh phát ánh sáng xanh chặn khe lại, vòng qua thoát nạn. Lâm Ngân Bình tái nhợt nhưng may mắn sống sót, Thi Hùng được huyết quang bảo hộ trấn định. Hàn Lập tự hỏi liệu Thiên Lan thánh thú có âm thầm phù hộ vị thánh nữ."},{"chuong":1065,"tieuDe":"Đào Thoát","tomTat":"Sau vụ bạo dẫn Hắc Phong Kỳ, phong ấn Côn Ngô Sơn bị hư hại nặng — cột đá bốn phía đại bộ phận bị phá, Tế Đàn chỉ còn năm sáu trục trượng. Hắc Lang (phân thần Nguyên Sát Thánh Tổ) ngưng tụ từ hắc khí trong nửa Hắc Phong Kỳ còn sót lại, bị Hướng Chi Lễ tấn công bằng cự kiếm nhưng phản kích rồi phát tiếng rít phá huỷ hoàn toàn Tế Đàn, ma khí đen như mực tràn ra bốn phía — phong ấn chính thức bị mở. Hàn Lập cùng Vạn Niên Thi Hùng, Lâm Ngân Bình, hình người khôi lỗi và Phá Giới Phù hợp lực phá toái vách bình chướng, thoát ra đại sảnh tầng bảy Trấn Ma Tháp. Linh Lung hiện ra từ Nghịch Tinh Bàn, được Hướng Chi Lễ xác nhận danh tính là Linh Lung Vương Phi. Linh Lung cảnh báo thân thể bà rơi vào Chân Ma khí quá ba ngày sẽ bị ma hoá, ma vật khôi phục có thể tạo đại quân Ma Nhân. Hướng Chi Lễ tiết lộ Hoá Long Tỳ đã bị ma vật bóp nát và Phá Giới Phù chỉ còn hai quả. Hàn Lập bình tĩnh gợi ý rằng thượng cổ tu sĩ ắt phải có pháp trận dự phòng ngoài Hoá Long Tỳ."},{"chuong":1066,"tieuDe":"Nghịch Linh Thông Đạo","tomTat":"Hướng Chi Lễ tiết lộ pháp trận Côn Ngô Sơn có pháp khí dự phòng là Khiếu Thiên Tinh Bi, tấm bia đá thất lạc từ thượng cổ. Hàn Lập nghe tên thì cả kinh, nhớ tới tấm bia đá đã lấy được ở sơn môn, lặng lẽ kiểm tra trong trữ vật túi. Hướng Chi Lễ đề xuất kế hoạch tập hợp tu sĩ Nam Cương và toàn Đại Tấn phong ấn rồi hợp lực tiêu diệt Ma vật, Thi Hùng cam kết Vạn Yêu Cốc sẽ phái người trợ giúp. Thi Hùng truyền âm cho Linh Lung về Cốc chủ Vạn Yêu Cốc là người quen cũ của nàng, mời nàng tới cốc chọn thân thể mới nhưng bị từ chối. Linh Lung tuyên bố sẽ quay lại không gian phong ấn đoạt hồi chân thân, chỉ định Hàn Lập đi cùng vì có Ích Tà Thần Lôi, tự tin hơn 50% cơ hội nhờ thiên phú thần thông Ngân tộc. Nàng tiết lộ thân phận đầy đủ: phi tử Thiên Khuê Lang Vương, công chúa Ngân Nguyệt Lang Tộc, tu sĩ hàng lâm từ Linh giới. Linh Lung giải thích Nghịch Linh Thông Đạo không phải thực thể cố định mà do Linh giới dùng Thiên lực nhất thời mở, dùng xong biến mất, muốn mở lại cần đốt Truyền Giới Hương và lượng Cao giai Linh Thạch cực lớn. Nàng hé lộ trên chân thân có ấn ký Nghịch Tinh Bàn, kích phát sẽ mở thông đạo nhỏ riêng cho mình, đồng thời nhắc còn phương pháp khác vào Linh giới nhưng cửu tử nhất sinh, đề xuất giao dịch đổi bí mật lấy phỏng chế Ma Long Nhận và hai tấm Phá Giới Phù."},{"chuong":1067,"tieuDe":"Phong Linh Đại Pháp","tomTat":"Linh Lung hoàn tất giao dịch với Hướng Chi Lễ và Thi Hùng: nhận hai tấm thổ hoàng sắc phù lục cùng Thanh Ma Long Huyết Nhận, đổi lại giao tư liệu về tiết điểm không gian trời sinh bạc nhược có thể liên thông Nhân Giới và Linh Giới. Sau khi mọi người rời đi, chỉ còn Hàn Lập và ngân phát nữ tử trong đại sảnh. Hàn Lập căng thẳng chuẩn bị chiến đấu thì phát hiện Ngân Nguyệt đã nhân lúc thần thức Lung Mộng ngủ say mà đoạt quyền khống chế chủ đạo, đồng thời giải khai phong ấn ký ức về tiểu bình. Ngân Nguyệt đề nghị Hàn Lập thi triển Phong Linh Đại Pháp phong ấn bí mật tiểu bình — bí thuật thành công, kể cả Linh Lung chiếm lại quyền cũng vô pháp cởi bỏ. Ngân Nguyệt bày kế hoạch tiến nhập đệ cửu tầng: dùng phá giải phù phá chướng bích, Huyết Nhận cuốn phân thần Nguyên Sát Thánh Tổ, Hàn Lập kích phát Thiên Tinh Bia trấn áp ma khí, rồi nàng dùng thần thông thôn phệ linh hồn đoạt lại thân thể. Hai người chuẩn bị xong, ngân phát nữ tử bắn hoàng sắc phúc lộc lên không, hiện ra màn chắn không gian trong suốt dẫn vào đệ cửu tầng."},{"chuong":1068,"tieuDe":"Phong Ấn","tomTat":"Hàn Lập phối hợp cùng Khôi Lỗi dùng Tam Diễm Phiến và Lôi Hoả Cung phá tan chướng bích, mở Phong Lôi Sí xuyên vào không gian tràn ngập ma khí nồng đặc. Ngân Nguyệt dùng Huyết Nhận tạo huyết quang bảo hộ, xung phong giao chiến Nguyên Sát Thánh Tổ phân thân (song đầu hắc lang), kìm chân thánh tổ cho Hàn Lập hành động. Hàn Lập vận Minh Thanh Linh Mục xuyên thấu ma khí, phát hiện hai tấm thạch bia luyện từ sá linh nhuyễn ngọc trong đống đá vụn tế đàn. Hắn ẩn thân tiếp cận, nhấn Thiên Tinh Bi vào thạch bia kích hoạt pháp trận phong ấn cổ đại: hơn mười thạch trụ mọc lên hút sạch ma khí, linh đoàn nhũ bạch khổng lồ áp xuống phong ấn hoàn toàn hắc động, chướng bích tái lập. Thánh tổ phân thân mất nguồn ma khí, rơi vào hạ phong, hóa ba lang ảnh tấn công thạch bia nhưng bị Ngân Nguyệt triển khai huyết hải và Hàn Lập dùng Tam Diễm Phiến chém ba Hoả Điểu phối hợp vây khốn. Ngân Nguyệt hóa cự lang bạc định dùng Linh Hồn Thôn Phệ khiến thánh tổ phân thân kinh hoảng phun huyết hỏa diễm phá huyết hải bỏ chạy, nhưng bị thanh ti từ ngân hồ vô hình trói gô."},{"chuong":1069,"tieuDe":"Linh Hồn Cắn Nuốt","tomTat":"Hắc Lang (đầu đen cự lang) cố dùng huyết diễm chống thanh ti Hư Thiên Đỉnh nhưng thất bại, bị trói chặt. Ngân Lang xông vào cơ thể cự lang chiếm đầu bạc, thi triển linh hồn cắn nuốt cắn xé đầu đen. Hàn Lập phun kim quang tiêu tan hắc khí ma hồn, ngân ảnh cuồng trướng gấp đôi nuốt trọn hắc sắc quang ảnh rồi co rút lại — Hắc Lang bị tiêu diệt hoàn toàn, cự lang thành một đầu bạc. Hàn Lập bay đến tế đàn thu được gần nửa Hắc Phong Kỳ (Thông Thiên Linh Bảo hư tổn) và Bát Linh Xích (Thông Thiên Linh Bảo phật môn, rót linh lực chưa phản ứng). Cự lang hóa hình thành nữ tử ngân phát — không phải Ngân Nguyệt mà là Linh Lung, công chúa Ngân Nguyệt đại tộc, lợi dụng lúc Ngân Nguyệt thần niệm hao tổn ngủ say để chiếm quyền kiểm soát. Linh Lung cho Hàn Lập giữ Hư Thiên Đỉnh và Bát Linh Xích trả ơn, trả lại hắc sắc phi đao, nhưng cảnh cáo phải chấm dứt quan hệ với Tuyết Linh, đe dọa giết nếu gặp lại ở linh giới. Hàn Lập im lặng, không cự tuyệt cũng không hứa hẹn. Linh Lung yêu cầu Vạn Niên Linh Dịch, phun Nghịch Tinh Bàn bắt đầu mở Nghịch Linh Thông đạo về linh giới."},{"chuong":1070,"tieuDe":"Thoát Khốn","tomTat":"Nghịch Tinh Bàn phóng tinh quang hóa thành quang luân, phun kim sắc quang trụ phá vỡ tường ngăn tầng thứ chín Trấn Ma tháp, tạo ra thông đạo lớn. Linh Lung trước khi rời đi đã trao cho Hàn Lập ba vật: ngọc giản trắng chứa tư liệu Nghịch tinh thông đạo và không gian tiết điểm, huyết nhận, phá giới phù. Cô dùng thanh ngọc điều khiển Nghịch Tinh Bàn truyền tống Hàn Lập cùng khôi lỗi hình người ra ngoài, rồi mang Nghịch Tinh Bàn tiến nhập thông đạo rời đi, cửa thông đạo vỡ tan tiêu tán hoàn toàn. Bên ngoài, Hướng Chi Lễ cùng Thi Hùng và Lâm Ngân Bình ra khỏi Trấn Ma tháp. Hướng Chi Lễ cảm nhận phong ấn Côn Ngô Sơn bị chấn động nhưng không phát hiện bất thường. Hắn lộ bản sắc Hóa Thần tu sĩ lạnh lùng, tuyên bố Diệp gia gây họa lớn không cần tồn tại nữa, vị trí đệ nhất Đại Tấn sẽ thay đổi. Thi Hùng đại diện Vạn Yêu Cốc đồng ý hủy diệt Diệp gia. Lâm Ngân Bình cung kính chấp nhận trở về Thiên Lan Thảo Nguyên, trong lòng muốn triệu tập nguyên anh tu sĩ bài trừ cấm chế của Hàn Lập trên người. Hướng Chi Lễ nhận phi kiếm truyền thư từ Hô đạo hữu Thiên Ma tông, quyết định hợp lực phong ấn lại Côn Ngô Sơn. Hàn Lập bị truyền tống tới Kim Đồ Sơn thuộc Trung Lâu Phủ, Nam Cương, nhận ra nơi này gần Phổ Vân Phủ, không bị truyền quá xa."},{"chuong":1071,"tieuDe":"Băng Hàn Chi Địa","tomTat":"Hàn Lập xóa trí nhớ nhóm tu sĩ Luyện Khí kỳ từng chỉ đường rồi rời đi. Nghiên cứu ngọc giản trắng, phát hiện hai bộ tư liệu quan trọng: phương pháp bố trí Liên Linh Thông Đạo đại trận do tu sĩ linh giới dùng mở nghịch linh thông đạo (cần linh thạch đỉnh giai khổng lồ, không hợp nhân giới), và hơn mười vị trí Không Gian Tiết Điểm chi tiết hơn thông tin Hướng Chi Lễ. Hắn xác định muốn vào Không Gian Tiết Điểm phải đạt Hóa Thần Sơ Kỳ. Biết mình cần luyện Huyền Băng Đan (chủ tài liệu là Huyền Băng Hoa, chỉ mọc nơi vạn năm huyền băng) để phụ trợ Bồi Anh Đan giải Phong Hồn Chú, Hàn Lập quyết định tới Tiểu Cực Cung ở Bắc Minh Băng Đảo tìm Huyền Băng Hoa và tin tức Thái Dương Tinh Hỏa. Trước mắt phi hành hướng bắc tới Sương Quận — vùng đất băng tuyết phía bắc Đại Tấn — biến dạng thành lão giả mặt dê hung ác, phóng khí thế bao trùm Tuyết Liên Phong, ra lệnh tộc trưởng Lý Trung Khiêm rút toàn bộ Lý gia trong nửa ngày để hắn tiếp nhận ngọn núi làm nơi ẩn cư."},{"chuong":1072,"tieuDe":"Hóa Đan","tomTat":"Hàn Lập dùng kình phong áp chế ba tu sĩ Lý gia (lão tổ Kết Đan kỳ cùng hai lão giả hắc bào), hạn nửa ngày phải rời Tuyết Liên sơn. Lão tổ Lý gia nhận định Hàn Lập ít nhất Nguyên Anh trung kỳ, mạnh hơn cả Long tiền bối, quyết đoán ra lệnh toàn tộc hai ba trăm người triệt thoái trong hai canh giờ. Các thế lực phụ cận nghe tin Nguyên Anh tu sĩ cường chiếm Tuyết Liên sơn đều kinh hãi. Hàn Lập triển khai bộ trận kỳ trận bàn từ túi trữ vật Càn lão ma tạo ảo trận sương mù bao phủ toàn sơn, thả mười hai con Lục Dực Sương Công tương đương Kết Đan kỳ ẩn bên trong canh giữ, tạo hai lớp phòng ngự. Dùng Linh Mục thần thông tìm nơi linh khí nồng nhất, dùng Thổ Độn Thuật đào động phủ trong lòng núi, đặt Thiên Cơ Phủ vào bên trong rồi bế quan. Trong hơn nửa năm bế quan, ngân bào lão giả Nguyên Anh sơ kỳ xông vào sương mù bị Lục Dực Sương Công đánh cánh tay đông cứng trong suốt, phải rút lui. Tuyết Liên sơn mấy ngàn dặm xung quanh trở thành vùng cấm. Hàn Lập hoàn tất luyện hóa Bồi Anh đan, mở mắt, trên mặt ánh huỳnh quang chớp lòe, tu vi đã có đột phá."},{"chuong":1073,"tieuDe":"Mật Thất Luyện Bảo","tomTat":"Hàn Lập kiểm tra pháp lực và Nguyên Anh sau khi dùng Bồi Anh đan, xác nhận Nguyên Anh đã lớn từ hai tấc lên hai tấc rưỡi, pháp lực gia tăng đáng kể, cảm ứng rằng khổ tu hơn trăm năm sẽ đột phá mà không gặp bình cảnh. Hắn tế luyện lại hai thanh Thanh Trúc Phong Vân kiếm bị Cổ Ma ma hóa suốt ba ngày ba đêm bằng thanh diễm và phun máu huyết, loại bỏ hoàn toàn ma khí, phục hồi kim quang xán lạn. Tiếp đó phát hiện Bát Linh xích là phật môn chi bảo, linh lực thường không kích hoạt được, phải dùng phật quang từ Kim Cương tráo mới hiển lộ thông bảo quyết, thu nhớ khẩu quyết tầng thứ nhất cần một năm sơ thành. Nghiên cứu Hắc Phong kỳ (tàn bảo không gian) mấy ngày nhưng cấp bậc vượt tầm lĩnh ngộ, không thu hoạch. Kiểm kê các bảo vật khác gồm hỏa diễm cự đỉnh, thư cuốn Côn Ngô, Hàng Ma trượng và huyết nhận (đã mất uy lực). Cuối cùng mở Kim Cương tráo lộ ra năm bộ khô lâu ngũ tử đồng tâm ma do Càn lão ma tu luyện."},{"chuong":1074,"tieuDe":"Thu Ma","tomTat":"Hàn Lập đánh giá Ngũ tử đồng tâm ma: mỗi con tu vi Nguyên Anh sơ kỳ, liên thủ hợp thể chống được Nguyên Anh hậu kỳ, nhưng hung tính khó thuần và từng phản phệ Càn lão ma. Hắn nghiên cứu ngọc giản ma kinh vô danh lấy từ túi trữ vật Càn lão ma, tìm hiểu quy trình tế luyện gốc (cần thi thể năm tu sĩ Nguyên Anh kỳ, chôn nơi âm khí trăm năm) và phát hiện bí thuật khống ma thay thế dùng máu huyết tự thân kết hợp cấm chế đặc thù. Hàn Lập quyết định dùng phương pháp thay thế: phun huyết châu cho ngũ ma phục, đóng tế châm ngân quang, phóng tiểu nhân thanh khí cùng pháp khí cương ngân nhập vào ngũ ma, gắn dược hoàn bạc lên cổ và tứ chi. Kiểm nghiệm khống chế thành công — ngũ ma nghe lệnh di chuyển, kích hoạt dược hoàn phát thanh diễm trấn áp khi ngũ ma muốn lại gần. Hắn thu ngũ ma vào bình đen dán phù cất vào túi trữ vật, tự tin có đủ đan dược bổ sung nguyên khí để định kỳ dưỡng ma bằng máu. Sau đó Hàn Lập đặt kế hoạch luyện hóa Thái Âm Chân Hỏa lấy từ cự đỉnh để đối phó địch nhân và dung hợp cùng Tử La thiên hỏa, coi đây là việc dài hạn."},{"chuong":1075,"tieuDe":"Bắc Minh Đảo","tomTat":"Sau hơn mười năm bế quan khổ tu tại Tuyết Liên sơn, Hàn Lập hoàn thành việc hút Thái Âm Chân Hỏa vào cơ thể và bước đầu ngưng cố thành công, tự đánh giá thần thông tu vi mạnh hơn nhiều so với trước. Phán đoán chuyện Côn Ngô sơn đã lắng xuống, hắn hóa thanh hồng rời Tuyết Liên sơn trong bão tuyết, nhằm hướng Bắc Minh đảo bay đi để tìm người tại Tiểu Cực cung. Nửa tháng sau, tu sĩ phụ cận phát hiện sương trắng Tuyết Liên sơn biến mất, linh địa bỏ trống, các thế lực tranh đoạt. Bắc Minh đảo thực chất là bán đảo ba mặt giáp biển băng ở cực bắc, phía bắc có tòa băng thành của bắc dạ Tiểu Cực cung — bắc địa đệ nhất tông, thực lực ngang Chính Ma thập đại tông môn nhưng bị xếp ngoài danh sách vì vị trí hẻo lánh. Ngoại cung thu tán tu phải đi bộ xuyên mười vạn lý cực hàn, có đại trận Thận Lâu Thạch dùng mắt trận làm lệch thần niệm tu sĩ bảo vệ. Khi vào vùng cấm chế, ngay cả thần niệm Hàn Lập (Nguyên Anh kỳ) cũng bị lệch phương hướng, không tìm được Tiểu Cực cung. Đúng lúc hắn muốn tìm phương pháp khác thì đụng phải đoàn hơn mười tán tu do Cốc Thiên Khải dẫn đầu, Cốc Thiên Khải cung kính dâng một Định Nguyên bài dẫn đường, Hàn Lập nhận lấy."},{"chuong":1076,"tieuDe":"Băng Thành","tomTat":"Hàn Lập phát hiện trong nhóm đồng hành của Cốc Thiên Khải có nữ tu họ Trữ bị phân thần yêu thú cấp tám ký sinh, dùng Hàng Ma trượng đánh ngã nàng rồi dùng Thần Lôi Độn tiêu diệt triệt để phân thần. Hắn đổi bình đan dược lấy viên bàn dẫn đường từ Cốc Thiên Khải, đồng thời phát hiện viên bàn có chức năng theo dõi vị trí người mang. Suy luận rằng yêu thú muốn trà trộn vào Tiểu Cực cung vì hàn tủy, và Tiểu Cực cung đã biết hàn tủy bị mất nhưng cố tình che giấu. Hàn Lập phi hành xuyên khu vực mưa đá quỷ dị, đến trước Băng Thành — tòa thành trì tiên cảnh phủ sương trắng, phía sau là cự sơn vạn trượng hình trụ phủ băng tuyết trên đỉnh ẩn hiện kiến trúc Tiểu Cực cung. Ngoại cung chấp sự Thạch Vân (Kết Đan kỳ) cùng hai nữ tu ra đón, Hàn Lập xưng đến tìm trưởng lão Bạch Bích Dao bạn cũ, Thạch Vân phóng Truyền Âm phù báo tin. Tu sĩ Nguyên Anh trung kỳ họ Nhâm từ khu gió tuyết xuất hiện, khuôn mặt trắng nõn tóc xám trắng ánh mắt tang thương cổ quái, chủ động hỏi danh tính Hàn Lập."},{"chuong":1077,"tieuDe":"Tuyết Vượn, Băng Bích, Cung Điện","tomTat":"Hàn Lập đến Tiểu Cực cung theo lời hẹn với Bạch Dao Di, được Nhâm Bích — trưởng lão nội cung tự xưng sư huynh của Bạch Dao Di — chủ động dẫn đường. Trên đường đi, Nhâm Bích bóng gió thăm dò lai lịch Hàn Lập, nhưng Hàn Lập cảnh giác chỉ nói mình không phải tu sĩ Đại Tấn. Bạch Dao Di nghe tin Hàn Lập đến liền kết thúc bế quan, gửi Truyền Âm phù mời hắn đến Bạch Ngưng các. Khi bước qua cửa băng thành, mấy con tuyết vượn cấp bốn cấp năm canh giữ hoảng sợ cuộn mình vì cảm nhận được Đề Hồn thú trong túi linh thú của Hàn Lập. Dọc sườn cự sơn, Hàn Lập phát hiện ít nhất ba bốn chỗ cấm chế lợi hại khiến hắn run sợ, suy đoán Tiểu Cực cung có trận pháp đại sư cấp tông sư. Nhâm Bích dùng ngọc bài mở thông đạo trong băng bích cao mấy trăm trượng, đưa Hàn Lập vào Hàn Ly bí cảnh — sơn cốc phong bế bốn bề, ấm áp như mùa xuân, nơi thực sự của Tiểu Cực cung. Hàn Lập nhìn ba tòa đại điện bạch ngọc chiếm một phần ba sơn cốc, trong lòng dâng lên một tia hoảng sợ."},{"chuong":1078,"tieuDe":"Băng Linh Quả","tomTat":"Hàn Lập đến Tiểu Cực cung, phát hiện ba tòa Hư Linh điện bạch ngọc có kiểu dáng y hệt Hư Thiên điện ở Loạn Tinh Hải (thể tích bằng 1/3), được Nhâm Bích cho biết chúng tồn tại từ ngày lập phái và bị phong bế. Hàn Lập tự nhủ bí bảo Hư Thiên đỉnh đã nằm trong tay nên không cần quan tâm thêm. Nhâm Bích dẫn Hàn Lập đến Bạch Ngưng các, nơi đệ tử Nhan nhi nghênh đón. Hàn Lập ăn liền hai quả Băng Linh quả đặc sản Tiểu Cực cung, hấp thu dễ dàng nhờ mang Tử La Cực Hỏa và Thái Âm chân hỏa, khiến Nhâm Bích kinh ngạc vì linh lực Hàn Lập bên ngoài là thuần mộc thuộc tính. Bạch Dao Di xuống lầu tiếp khách, thái độ thân thiện với Hàn Lập nhưng lạnh nhạt với Nhâm Bích. Nhâm Bích lợi dụng dịp để gặp Bạch Dao Di, nói đã tìm được biện pháp giải quyết một việc chưa rõ, bị nàng gạt đi. Hàn Lập thẳng thắn nói có sự tình muốn thỉnh giáo Bạch Dao Di, mục đích cụ thể chưa tiết lộ."},{"chuong":1079,"tieuDe":"Kim Phong Ly Thú","tomTat":"Hàn Lập nhờ Bạch Dao Di tìm linh dược Huyền Băng Hoa để luyện Huyền Băng Đan, nàng nhận lời và sai đệ tử tra xét, hẹn một hai ngày có tin. Ba người — Hàn Lập, Bạch Dao Di và Nhâm Bích (đều Nguyên Anh Trung Kỳ) — trao đổi kinh nghiệm tu luyện suốt nửa ngày, Hàn Lập bày tỏ hứng thú với công pháp băng hàn đỉnh cao của Tiểu Cực Cung. Sau đó Hàn Lập được bố trí ở Quí Tân Lâu, tĩnh tọa hai ngày, trong lòng xác nhận giải trừ Phong Hồn Chú cho Nam Cung Uyển là đại sự hạng nhất, phải luyện Huyền Băng Đan trước khi tìm Thái Dương Chân Hỏa. Sáng ngày thứ ba, đại trưởng lão Hàn Ly thượng nhân — nhân vật cực kỳ thần bí ở phương Bắc, Nguyên Anh Hậu Kỳ — dùng thần niệm xuyên thủng cấm chế dò xét Hàn Lập, bị hắn đánh bật. Hàn Ly truyền âm giọng trẻ con mời gặp, phái đôi Kim Phong Ly Thú dẫn đường. Hàn Lập phát hiện một con thú ẩn hình hoàn toàn, phải vận pháp lực lam quang mới thấy hư ảnh mờ. Đi qua Tiểu Cực Cung, tu sĩ trong cung thấy Phong Ly Thú liền nhường đường. Cuối cùng Hàn Lập đến trước thạch môn cao năm sáu trượng tỏa hào quang vàng nhạt nơi ở của Hàn Ly và dừng bước."},{"chuong":1080,"tieuDe":"Hàn Ly Thượng Nhân","tomTat":"Hàn Lập đi theo Phong Ly thú qua thông đạo băng hàn phủ sương lạnh, dần xuống sâu dưới lòng đất tới đại sảnh xây bằng huyền băng ngàn năm. Tử diễm lưu quang trên người Hàn Lập tự phát chuyển động đề phòng, khiến lão giả trong sảnh kinh ngạc khi nhận ra hắn mang hàn băng chi diễm. Hàn Lập nhận ra ngọn lửa lam nhạt trong cự đỉnh là Kiền lam băng diễm, đồng thời phát hiện cự đỉnh hình dạng giống Hư Thiên đỉnh bảy tám phần, trong lòng nghi vấn quan hệ Tiểu Cực Cung với Hư Thiên điện. Hàn Ly thượng nhân — Đại trưởng lão Tiểu Cực Cung — lộ diện, tiết lộ tên thật là Sư Tương. Lão nhận xét Tử la cực hỏa của Hàn Lập đã qua tinh luyện nhưng chưa thuần khiết, chỉ dùng pháp lực áp súc, và giải thích bí thuật tinh luyện hàn diễm có thể tăng uy lực gấp bội. Hàn Ly cho biết tu vi đã tới nguyên anh hậu kỳ đỉnh phong, dậm chân ba trăm năm, tìm được phương pháp đột phá hóa thần từ thượng cổ điển tịch: cần năm nguyên anh tu sĩ luyện hàn diễm khác nhau cùng kích thích cực hàn. Lão đã có bốn người, Hàn Lập chính là người thứ năm cuối cùng sau hơn mười năm tìm kiếm."},{"chuong":1081,"tieuDe":"Tam Đại Hàn Diễm","tomTat":"Hàn Lập đàm phán với Hàn Ly thượng nhân, đồng ý trợ giúp đột phá cảnh giới đổi lấy ba điều kiện: bí thuật tinh luyện hàn diễm, Tiểu Cực Cung giúp tìm băng linh hoa, và quyền vào tàng kinh các mười ngày. Hàn Lập nhận hai ngọc giản và một ngọc bội rồi rời đi. Sau đó hai thuộc hạ của Hàn Ly (thanh sam trung niên và bạch sam nữ tử) bước ra bàn bạc: thanh sam trung niên lo ngại hàn diễm Hàn Lập hỗn tạp, Hàn Ly nhận định trong đó có bóng dáng kiền lam băng diễm. Thanh sam trung niên báo cáo Vạn Yêu Cốc có động tĩnh bất thường bên ngoài Bắc Minh đảo, nhưng Hàn Ly thọ nguyên chỉ còn mấy năm nên không thể chờ. Hàn Ly tiết lộ hàn tủy bị phản đồ đánh cắp nhưng quyết không công khai, Băng ngọc động sắp mở có thể bổ sung. Hàn Ly ban hàn tủy cho hai người tu luyện Hắc Thủy băng diễm và Phong Ly băng diễm, dặn bạch sam nữ tử tìm Bạch Dao Di điều tra về Hàn Lập. Cuối chương Hàn Ly một mình nhìn cự đỉnh thì thào ba chữ Hư Thiên đỉnh."},{"chuong":1082,"tieuDe":"Băng Hải Yêu Thú","tomTat":"Hàn Lập được dẫn vào mật thất Tàng Kinh Các Tiểu Cực Cung, tự do tra cứu bảy tầng điển tịch, nán lại bảy tám ngày xem được ba tầng. Tại Bạch Ngưng Các, Bạch Dao Di trò chuyện với Nhị tỷ (Đường tỷ) — bạch sam nữ tử lạnh như băng — về lai lịch Hàn Lập. Đường tỷ tiết lộ Đại trưởng lão Hàn Ly quan tâm Hàn Lập vì hắn mang tử sắc hàn diễm, yêu cầu Bạch Dao Di tìm hiểu uy lực chân chính, đồng thời cảnh báo có thể có yêu vật xâm phạm Bắc Minh đảo. Hàn Lập nhận Truyền âm phù báo tin đã tìm thấy Băng Linh Hoa trong sào huyệt Tuyết Hống thú gần vượt phạm vi Bắc Minh đảo, lập tức gặp Bạch Dao Di và hai người rời băng thành phi độn hướng bắc. Trên đường, Bạch Dao Di giới thiệu về băng hải — thiên hạ của yêu thú, có Băng Phượng thập cấp thượng cổ — và giao ước giữa tổ sư khai phái Tiểu Cực Cung với yêu thú mạnh nhất: cao giai yêu thú không được vào trăm vạn dặm quanh Bắc Minh đảo. Sau ba ngày ba đêm phi độn, hai người tới một miệng hố băng thật lớn."},{"chuong":1083,"tieuDe":"Băng Nanh Thú","tomTat":"Hàn Lập cùng Bạch Dao Di đến miệng hố băng là sào huyệt Tuyết Hống thú, nơi đệ tử Bắc Minh đảo phát hiện có Huyền Băng Hoa. Hàn Lập phóng hỏa cầu thăm dò rồi thả 12 con Lục Dực Sương Công xuống hố dẫn dụ yêu thú. Bảy tám Tuyết Hống thú bị đuổi bay ra, Hàn Lập dùng phi kiếm kim hồng trảm sát tất cả. Một yêu thú lông bạc lớn hơn bay lên, Bạch Dao Di nhận ra là Băng Nanh thú thất cấp băng phong thuộc tính hiếm thấy, xin bắt sống thu phục. Hàn Lập phun Tử La Cực Hỏa hóa Hỏa Điểu uy hiếp, dùng cường đại thần thức ngang Nguyên Anh hậu kỳ đánh thú thất thần, đông kết trong khối băng tím. Bạch Dao Di thu Băng Nanh thú vào túi linh thú. Hai người xuống đáy hố phát hiện mạch Vạn Niên Huyền Băng quý hiếm và ba đóa Huyền Băng Hoa đủ luyện đan. Hàn Lập bố trí 12 Lục Dực Sương Công canh gác, chuẩn bị hái hoa luyện đan tại chỗ, trong khi Bạch Dao Di cảm thấy bất an về sự xuất hiện bất thường của yêu thú thất cấp gần Bắc Minh đảo nên rời đi điều tra phụ cận."},{"chuong":1084,"tieuDe":"Nhị Yêu","tomTat":"Sau khi Bạch Dao Di rời đi, Hàn Lập bố trí trận pháp sương mù lam bao phủ khe băng, thả đàn Phệ Kim Trùng canh gác, rồi dùng kim mang cắt ba đóa Huyền Băng Vạn Năm Hoa thu vào hộp ngọc, lấy đỉnh lô lớn ngân quang chuẩn bị luyện chế Huyền Băng Đan. Ba ngày sau, Bạch Dao Di bị trúng kỳ độc quay về trốn vào cấm chế, phía sau là hai yêu thú biến hóa nhân hình truy đuổi — xà yêu nữ bát cấp và nam tử yêu dị lục phát. Xà yêu phát hiện Lục Dực Sương Công thì tham lam muốn nuốt, rồi dùng Mộc bát bắt dính Phệ Kim Trùng và xà lân chém đôi một con chưa tiến hóa. Nam tử yêu dị phóng khói độc và độc châm pháp bảo chí độc. Hàn Lập xuất hiện từ sương mù, dùng Tiểu Thuẩn ngân quang chặn toàn bộ xà lân, tung Thông Linh Hỏa Đỉnh triệu hơn ngàn Chí Dương Hỏa Nha thiêu sạch khói độc lẫn độc châm, rồi hiện đoàn tam sắc quang mang trên tay chuẩn bị chiêu tiếp theo."},{"chuong":1085,"tieuDe":"Băng Hải Yêu Ảnh","tomTat":"Hàn Lập dùng Phong Lôi Sí lôi độn đến sau lưng nam yêu bát cấp, lôi điện phá tan lục ti võng bảo hộ, rồi Tam Diễm Phiến phóng tam sắc hỏa diễm thiêu chết nam yêu trong nháy mắt. Xà yêu nữ hoảng sợ tự nổ thân thể biến thành vô số hỏa xà phân thân chạy trốn, nhưng Hàn Lập dùng lam mang nhãn thuật nhìn ra bản thể, tử sắc hỏa diễm đóng băng toàn thân rồi phi kiếm cắt thân, Kim Hồ bắt nguyên thần thu vào ngọc bình. Bạch Dao Di chứng kiến toàn bộ, cho biết đã trúng khói độc nhưng uống Bách Thảo Đan bức được độc. Hai người rời đi, hai canh giờ sau mây đen bí ẩn kéo tới băng khe rồi biến mất kèm tiếng huýt sáo, cho thấy có kẻ đến tìm dấu vết. Trở về Tiểu Cực Cung, Bạch Dao Di báo cáo Hàn Ly Thượng Nhân: phó cốc chủ Vạn Yêu Cốc Thanh Bối Thương Lang cùng mãnh thú Song Đầu Ô Giao dẫn nhóm yêu thú Hóa Hình tụ hội. Hàn Ly kết luận Vạn Yêu Cốc và yêu thú Băng Hải đã liên thủ, lệnh triệu tập toàn cung thương lượng và tăng gấp đôi canh gác. Hàn Ly cảm tạ Hàn Lập nhưng lịch sự tiễn khách, hứa hai ngày sau giới thiệu hai tán tu nổi tiếng Đại Tấn. Hàn Lập ngồi một mình trong phòng, khép mắt đánh giá tình hình."},{"chuong":1086,"tieuDe":"Hàn Diễm Tu Sĩ","tomTat":"Hàn Lập ở lại Tiểu Cực Cung tu luyện tại Quý Tân Lâu suốt một tháng, dành hai ngày tìm tin tức thái dương tinh hỏa trong tàng kinh các nhưng không có manh mối, đồng thời phát hiện bí thuật đột phá bình cảnh mà Hàn Ly đưa chỉ là một phần. Trưởng lão nội cung Bạch Mộng Hinh — đường tỷ Bạch Dao Di — đến Quý Tân Lâu thử uy lực hàn diễm của Hàn Lập, biến Phong Ly Băng Diễm thành tiểu bạch xà tấn công nhưng bị Tử La cực hỏa hóa hỏa điểu nuốt trọn. Sau khi hài lòng, Bạch Mộng Hinh dẫn Hàn Lập tới đại sảnh huyền băng vạn năm của Hàn Ly thượng nhân, nơi đã có Long phu nhân (đại trưởng lão Liễu Thúy phái, Nguyên Anh hậu kỳ) và Ma Cưu đại sư (tăng nhân Nguyên Anh trung kỳ đỉnh phong) đang chờ. Hàn Ly công bố bí thuật đột phá bình cảnh tiến lên Hóa Thần mà lão nghiên cứu mấy trăm năm, xác suất thành công chỉ ba thành nhưng thọ nguyên sắp hết nên quyết mạo hiểm. Ma Cưu đại sư hỏi về yêu thú cao cấp tụ tập gần Bắc Minh đảo, Hàn Ly trấn an cung đã chuẩn bị hậu sự. Cả nhóm năm tu sĩ Cực Hàn Chi Diễm đồng ý sớm bắt đầu."},{"chuong":1087,"tieuDe":"Hư Linh Điện","tomTat":"Hàn Ly thượng nhân thu nhỏ cự đỉnh ở thượng điện, lộ ra mật đạo dẫn cả nhóm đi xuống băng đạo huyền băng sâu trăm trượng tới một điện phủ ngầm xây bằng ngọc cổ xưa. Trước thạch môn trắng ngà cao ba mươi trượng phủ pháp trận, khoảng mười sáu trưởng lão Tiểu Cực Cung Nguyên Anh sơ kỳ đã chờ sẵn cùng Bạch Dao Di. Diệp trưởng lão — trưởng lão giám sát chấp trưởng giám sát linh bảo — phản đối mở cấm địa Hư Linh Điện cho tu sĩ ngoài cung vào Huyền Ngọc Động, viện dẫn quy tắc chỉ mở khi đại nạn. Hàn Ly dùng luật hai phần ba trưởng lão đồng ý để vô hiệu quyền phản đối, đã tính trước điều nhóm Kim sư đệ ra ngoài. Diệp trưởng lão nhượng bộ rời đi. Mười sáu trưởng lão tế ngọc bội cùng kiểu, niệm chú ngưng tụ thành quang ảnh ngũ sắc một nữ tử — tổ sư thượng cổ sáng lập Tiểu Cực Cung. Quang ảnh giải trừ phong ấn thạch môn. Hàn Ly phóng lam hà chẻ đôi thạch môn nhưng lập tức giật lùi hét cảnh báo: hàn phong bạch sắc mãnh liệt từ Huyền Ngọc Động bùng ra kèm tiếng gầm kinh thiên, càn quét toàn bộ điện phủ."},{"chuong":1088,"tieuDe":"Băng Phách Hàn Liệt Trận","tomTat":"Hàn Lập cùng bốn tu sĩ Hàn Ly thượng nhân, Bạch Mộng Hinh, thanh sam trung niên và tăng nhân áo bào tro tiến vào Linh Hư Điện, mỗi người dùng một loại Cực Hàn Chi Diễm riêng chống chịu gió lạnh dữ dội. Hàn Ly phân phó Bạch Dao Di và đám tu sĩ Tiểu Cực Cung ở ngoài phòng thủ, hẹn thời gian đột phá nhanh thì năm ba ngày chậm thì hơn tháng. Lão dùng trận bàn trắng noãn đóng cửa đá từ bên trong, dẫn đoàn đi qua trận pháp Băng Phách Hàn Liệt gồm 1008 cây vạn năm huyền băng trụ. Qua khỏi trận pháp, trước mặt xuất hiện tòa Tế Đàn trắng tinh khiết cao hơn mười trượng, giữa có thiên môn vàng nhạt dán bùa chú thượng cổ. Hàn Lập phát hiện đồ án cự đỉnh giữa pháp trận tế đàn rất giống Hư Thiên Đỉnh trong cơ thể mình, sắc mặt khẽ biến nhưng lập tức che giấu, nói dối từng gặp pháp trận tương tự. Hàn Ly tinh ý phát hiện nhưng không truy vấn. Cuối cùng Hàn Ly, Bạch Mộng Hinh và thanh sam trung niên phối hợp ba loại cực hàn chi diễm kích hoạt pháp trận, cự đỉnh rơi vào trung tâm khiến pháp trận nứt khe hở, bên dưới ẩn hiện mảng bạch sắc phát sáng mạnh mẽ."},{"chuong":1089,"tieuDe":"Huyền Ngọc Động","tomTat":"Hàn Ly thượng nhân dẫn nhóm Hàn Lập tới Huyền Ngọc Động — mật bảo khố lớn nhất của Hư Linh Điện, giới thiệu giá trị Huyền Ngọc vạn năm gần tuyệt tích ngoại giới có thể khảm pháp bảo tăng uy lực băng hàn, hứa tặng mỗi người một phần dù có giúp đột phá Hoá Thần hay không. Cả nhóm dùng hàn diễm hộ thân bay xuống khe vào động, Hàn Lập dùng Tử La Cực Hoả nhưng bị nhũ bạch hàn quang tấn công mãnh liệt. Hắn bí mật dùng Minh Thanh Linh Mục phát hiện hàn khí có trạng thái thực thể co duỗi như vật sống — hàn khí thông linh mà Tử La Cực Hoả bất lực. Thử nghiệm Thái Âm chân hoả thì hấp thu hàn quang cực nhanh như nước hoà sữa, chứng minh khắc chế thành công. Hàn Lập lén bắn xích diễm nuôi dưỡng Thái Âm chân hoả, bị Âu Dương thanh sam nhân cảm ứng nghi ngờ nhưng che giấu được. Tại đáy động, Hàn Ly thượng nhân phát hiện hàn khí thiên nhiên giao hội chi điểm với quang châu hàn khí cực mạnh, mừng rỡ. Thượng nhân dẫn mọi người tới thạch ốc Thái Dương tinh thạch nghỉ ngơi và nhắc tới đại phiền toái trong động, khiến lão ẩu ngạc nhiên hỏi lại."},{"chuong":1090,"tieuDe":"Âm Linh Thủy, Thái Dương Tinh Thạch","tomTat":"Hàn Ly thượng nhân giải thích Vạn Niên Huyền Ngọc trong động đã được thượng cổ tu sĩ ngưng luyện thành nhất thể với quáng mạch, không thể gỡ bằng vũ lực. Long phu nhân thử đánh bằng quải trượng và thanh sắc tiểu chùy, ngọc nát thành bụi phấn chứng minh điều đó. Bạch Mộng Hinh dùng giọt Âm Thủy đen như mực từ bảo vật trấn phái Tiểu Cực Cung nhỏ lên, Huyền Ngọc tự tách ra trọn vẹn. Hàn Lập nhìn thấy giọt Âm Thủy thì kinh sợ biến sắc nhưng lập tức che giấu. Đoàn người vào thạch ốc bằng Thái Dương tinh thạch tránh hàn khí, Ma Cưu đại sư tiết lộ loại tinh thạch này phải qua Thái Dương tinh hoả ngưng luyện mới hình thành, Hàn Lập mừng thầm có manh mối nhưng Hàn Ly né tránh không cho hỏi thêm. Trên mặt đất, cung chủ Liễu Ngọc nghe Bạch Dao Di và Diệp trưởng lão báo cáo tình hình yêu thú xâm chiếm, kết luận Xa lão yêu chỉ phái phân thân chứ không thể đích thân rời Vạn Yêu Cốc."},{"chuong":1091,"tieuDe":"Quần Yêu Tiếp Cận","tomTat":"Cung chủ Liễu Ngọc bình tĩnh phân tích tình hình, tiết lộ tổ sư năm xưa lưu lại bảo vật chuyên đối phó yêu thú Băng hải nhưng chỉ hiệu quả với đê giai, đồng thời ra lệnh kích phát hơn phân nửa pháp trận cấm chế và cho đệ tử cấp thấp rút lui. Trong Huyền Ngọc động, Hàn Ly thượng nhân kiểm tra tiến độ lĩnh ngộ bí thuật: Hàn Lập, tăng nhân, lão ẩu đều xác nhận đã lĩnh ngộ xong. Hàn Ly thượng nhân cùng Bạch Mộng Hinh, thanh sam trung niên bố trí trận pháp ngũ sắc quang trụ quanh động, năm tu sĩ tiến vào quang trụ bắt đầu đột phá bình cảnh. Hàn Lập thi triển Tử La cực hỏa trong quang trụ tím, phát hiện trận pháp gia tăng uy lực hàn diễm nhưng tiêu hao pháp lực gấp bội, đồng thời quan sát tia Thái Âm chân hỏa lén thả trước đó vẫn đang hấp thu Huyền Ngọc hàn khí mà chưa bị phát giác. Bảy ngày sau, quần yêu chia hai đường giáp công Bắc Minh đảo: từ lục địa chủ yếu là yêu vật Vạn Yêu Cốc cử mấy chục thất cấp xông vào, từ Băng hải hơn ngàn yêu thú không sợ hàn khí xông thẳng tới Tiểu Cực cung. Tiểu Cực cung mở cấm chế hàn nhãn Thiên Nguyên Âm Mạch, hai bên triển khai giết chóc."},{"chuong":1092,"tieuDe":"Tam Đại Yêu Tu","tomTat":"Khắp Bắc Minh Đảo diễn ra giao tranh giữa yêu thú cấp thấp và tu sĩ Kim Đan kỳ trở xuống của Tiểu Cực cung, trong khi tu sĩ Nguyên Anh và bát cấp yêu thú tiết kiệm pháp lực chờ đại chiến. Cung chủ Liễu Ngọc chủ trì cuộc họp trong bí cảnh, nghe báo cáo 37 đệ tử chết trận và 128 yêu thú bị giết, rồi ra lệnh khởi động pháp bảo trấn phái Trấn Hải Chung sau một canh giờ, đồng thời mở toàn bộ cấm chế đại trận và đóng truyền tống trận. Cách băng thành mấy trăm dặm, ba thập cấp yêu tu hội ngộ trên toà băng sơn: Thanh đạo hữu (lão giả cùng hoá thân hài đồng, phe Vạn Yêu cốc) và Phượng tiên tử (đảo chủ Băng Uyên đảo) dẫn tổng cộng hơn ba mươi bát cấp yêu thú, chia hai phe thuỷ hoả bất dung nhưng cùng mục tiêu. Phượng tiên tử tiết lộ mục đích thật không phải vì Hàn tuỷ mà liên quan tới phi thăng linh giới, nàng bế quan hai ngàn năm nay lần đầu tự mình xuất mã. Hài đồng chỉ ra nàng bất mãn Tiểu Cực cung đã lâu, muốn diệt nhất mạch tu sĩ mà Băng Phách tiên tử lưu lại nhân giới và mượn lực lượng Vạn Yêu cốc."}];
